# ── Live theme dict — mutated in-place so all widgets see changes ─────────────
T: Dict[str, str] = {}


def set_theme(name: str, accent: Optional[str] = None) -> None:
    """
    Switch the global theme.  Copies the chosen palette into T,
    then optionally overrides the accent family.
    All widgets that reference T[...] will pick up the change on
    their next redraw — for live updates call wm.apply_theme().
    """
    global T
    base = THEMES.get(name, THEMES["dark"])
    T.clear()
    T.update(base)
    if accent:
        # Override the entire accent family from a single hex value
        T["accent"]          = accent
        T["accent_light"]    = _lighten(accent, 0.15)
        T["accent_dark"]     = _darken(accent, 0.15)
        T["accent_muted"]    = _darken(accent, 0.5)   # was: accent+"44"
        T["bg_selection"]    = _darken(accent, 0.6)   # was: accent+"30"
        T["border_focus"]    = accent
        T["scrollbar_thumb"] = accent
        T["tag_fg"]          = _lighten(accent, 0.12)
        T["tag_bg"]          = _darken(accent, 0.7)   # was: accent+"22"
        T["btn_primary_bg"]  = accent
        # midnight theme keeps inverted fg
        if name == "midnight":
            T["btn_primary_fg"] = "#000000"
            T["fg_on_accent"]   = "#000000"


def _lighten(hex_color: str, amount: float) -> str:
    """Return a lightened version of a hex colour (0 < amount < 1)."""
    r, g, b = _parse_hex(hex_color)
    h, l, s = colorsys.rgb_to_hls(r/255, g/255, b/255)
    l = min(1.0, l + amount)
    r2, g2, b2 = colorsys.hls_to_rgb(h, l, s)
    return "#{:02x}{:02x}{:02x}".format(int(r2*255), int(g2*255), int(b2*255))


def _darken(hex_color: str, amount: float) -> str:
    """Return a darkened version of a hex colour (0 < amount < 1)."""
    r, g, b = _parse_hex(hex_color)
    h, l, s = colorsys.rgb_to_hls(r/255, g/255, b/255)
    l = max(0.0, l - amount)
    r2, g2, b2 = colorsys.hls_to_rgb(h, l, s)
    return "#{:02x}{:02x}{:02x}".format(int(r2*255), int(g2*255), int(b2*255))


def _parse_hex(hex_color: str) -> Tuple[int, int, int]:
    h = hex_color.lstrip("#")
    return int(h[0:2], 16), int(h[2:4], 16), int(h[4:6], 16)


def lerp_color(c1: str, c2: str, t: float) -> str:
    """Linear-interpolate between two hex colours (t in 0..1)."""
    r1, g1, b1 = _parse_hex(c1)
    r2, g2, b2 = _parse_hex(c2)
    r = int(r1 + (r2 - r1) * t)
    g = int(g1 + (g2 - g1) * t)
    b = int(b1 + (b2 - b1) * t)
    return "#{:02x}{:02x}{:02x}".format(r, g, b)


# Initialise with dark theme
set_theme("dark")


