# Global font dict populated by init_fonts() after tk.Tk() is created
FONTS: Dict[str, tuple] = {}

# Preferred font stacks (first available wins)
_UI_STACK   = ["Segoe UI", "SF Pro Display", "Inter", "Helvetica Neue",
               "Noto Sans", "Arial", "TkDefaultFont"]
_MONO_STACK = ["Cascadia Code", "Cascadia Mono", "Consolas", "JetBrains Mono",
               "Fira Code", "Source Code Pro", "Courier New", "TkFixedFont"]


def init_fonts() -> None:
    """
    Must be called AFTER tk.Tk() is instantiated.
    Detects available font families and populates FONTS.
    """
    global FONTS
    available = set(tkfont.families())

    ui_fam   = next((f for f in _UI_STACK   if f in available), "TkDefaultFont")
    mono_fam = next((f for f in _MONO_STACK if f in available), "TkFixedFont")

    FONTS.update({
        # ── Display ──────────────────────────────────────────────────────────
        "display_2xl":  (ui_fam, 36, "bold"),
        "display_xl":   (ui_fam, 28, "bold"),
        "display":      (ui_fam, 22, "bold"),
        # ── Headings ─────────────────────────────────────────────────────────
        "h1":           (ui_fam, 18, "bold"),
        "h2":           (ui_fam, 15, "bold"),
        "h3":           (ui_fam, 13, "bold"),
        "h4":           (ui_fam, 12, "bold"),
        # ── Body ─────────────────────────────────────────────────────────────
        "body":         (ui_fam, 12),
        "body_bold":    (ui_fam, 12, "bold"),
        "body_italic":  (ui_fam, 12, "italic"),
        # ── Small ────────────────────────────────────────────────────────────
        "small":        (ui_fam, 10),
        "small_bold":   (ui_fam, 10, "bold"),
        "micro":        (ui_fam,  9),
        "micro_bold":   (ui_fam,  9, "bold"),
        "nano":         (ui_fam,  8),
        # ── UI chrome ────────────────────────────────────────────────────────
        "btn":          (ui_fam, 11, "bold"),
        "label":        (ui_fam, 11),
        "caption":      (ui_fam,  9),
        "title":        (ui_fam, 11, "bold"),
        "icon_label":   (ui_fam,  9),
        "tab":          (ui_fam, 11),
        "tab_active":   (ui_fam, 11, "bold"),
        "menu_item":    (ui_fam, 11),
        "menu_accel":   (ui_fam,  9),
        "tooltip":      (ui_fam,  9),
        "badge":        (ui_fam,  8, "bold"),
        # ── Clock / topbar ───────────────────────────────────────────────────
        "clock":        (ui_fam, 14, "bold"),
        "clock_sm":     (ui_fam, 10),
        "clock_date":   (ui_fam,  9),
        # ── Monospace ────────────────────────────────────────────────────────
        "mono":         (mono_fam, 12),
        "mono_sm":      (mono_fam, 11),
        "mono_xs":      (mono_fam, 10),
        "mono_bold":    (mono_fam, 12, "bold"),
        # ── Special ──────────────────────────────────────────────────────────
        "app_icon":     (ui_fam, 28),
        "emoji_lg":     (ui_fam, 32),
        "emoji_md":     (ui_fam, 22),
        "emoji_sm":     (ui_fam, 16),
    })


