class UserAccount:
    """Represents a single user account."""
    __slots__ = (
        "username", "display_name", "password_hash",
        "avatar", "role", "created", "last_login",
        "preferences", "is_locked",
    )

    def __init__(
        self,
        username:     str,
        display_name: str,
        password:     str,
        avatar:       str  = "👤",
        role:         str  = "user",
    ):
        self.username      = username
        self.display_name  = display_name
        self.password_hash = hashlib.sha256(password.encode()).hexdigest()
        self.avatar        = avatar
        self.role          = role
        self.created       = datetime.datetime.now().isoformat(timespec="seconds")
        self.last_login:   Optional[str] = None
        self.preferences:  Dict[str, Any] = {}
        self.is_locked     = False

    def check_password(self, password: str) -> bool:
        return self.password_hash == hashlib.sha256(password.encode()).hexdigest()

    def set_password(self, new_password: str) -> None:
        self.password_hash = hashlib.sha256(new_password.encode()).hexdigest()

    def to_dict(self) -> Dict[str, Any]:
        return {
            "username":     self.username,
            "display_name": self.display_name,
            "avatar":       self.avatar,
            "role":         self.role,
            "created":      self.created,
            "last_login":   self.last_login,
        }


class UserManager:
    """
    Manages user accounts, authentication, and sessions.
    Persists nothing to VFS in this build (in-memory only).
    """

    def __init__(self, vfs: VFS):
        self.vfs = vfs
        self._accounts: Dict[str, UserAccount] = {}
        self._current:  Optional[str] = None
        self._session_token: Optional[str] = None
        self._failed_attempts: Dict[str, int] = defaultdict(int)
        self._max_attempts = 5

        # Create default accounts
        self._add_default_accounts()

    def _add_default_accounts(self) -> None:
        self.create_account(
            username="user",
            display_name="User",
            password="password",
            avatar="👤",
            role="admin",
        )
        self.create_account(
            username="guest",
            display_name="Guest",
            password="guest",
            avatar="👥",
            role="guest",
        )

    def create_account(
        self,
        username:     str,
        display_name: str,
        password:     str,
        avatar:       str = "👤",
        role:         str = "user",
    ) -> bool:
        if username in self._accounts:
            return False
        self._accounts[username] = UserAccount(
            username, display_name, password, avatar, role
        )
        return True

    def authenticate(self, username: str, password: str) -> bool:
        account = self._accounts.get(username)
        if account is None:
            return False
        if account.is_locked:
            return False
        if account.check_password(password):
            self._failed_attempts[username] = 0
            return True
        self._failed_attempts[username] += 1
        if self._failed_attempts[username] >= self._max_attempts:
            account.is_locked = True
        return False

    def login(self, username: str) -> bool:
        if username not in self._accounts:
            return False
        account = self._accounts[username]
        if account.is_locked:
            return False
        self._current = username
        account.last_login = datetime.datetime.now().isoformat(timespec="seconds")
        self._session_token = uuid.uuid4().hex
        return True

    def logout(self) -> None:
        self._current       = None
        self._session_token = None

    def lock(self) -> None:
        """Lock the session (requires re-authentication but keeps user set)."""
        self._session_token = None

    def unlock(self, password: str) -> bool:
        if self._current and self.authenticate(self._current, password):
            self._session_token = uuid.uuid4().hex
            return True
        return False

    @property
    def is_logged_in(self) -> bool:
        return self._current is not None and self._session_token is not None

    @property
    def current_username(self) -> Optional[str]:
        return self._current

    def get_current(self) -> Optional[UserAccount]:
        return self._accounts.get(self._current) if self._current else None

    def get_display_name(self) -> str:
        acc = self.get_current()
        return acc.display_name if acc else "Guest"

    def get_avatar(self) -> str:
        acc = self.get_current()
        return acc.avatar if acc else "👤"

    def is_admin(self) -> bool:
        acc = self.get_current()
        return acc is not None and acc.role == "admin"

    def list_accounts(self) -> List[UserAccount]:
        return list(self._accounts.values())

    def change_password(
        self,
        username: str,
        old_password: str,
        new_password: str,
    ) -> bool:
        if not self.authenticate(username, old_password):
            return False
        self._accounts[username].set_password(new_password)
        return True

    def unlock_account(self, username: str) -> bool:
        acc = self._accounts.get(username)
        if acc:
            acc.is_locked = False
            self._failed_attempts[username] = 0
            return True
        return False


# ═══════════════════════════════════════════════════════════════════════════════
#  §08  PROCESS MANAGER
# ═══════════════════════════════════════════════════════════════════════════════

class ProcessRecord:
    """Represents one simulated OS process."""
    __slots__ = (
        "pid", "name", "status", "cpu", "ram",
        "started", "threads", "priority",
        "user", "description", "window_id",
    )

    def __init__(self, pid: int, name: str, user: str = "user"):
        self.pid         = pid
        self.name        = name
        self.status      = "running"
        self.cpu         = round(random.uniform(0.0, 2.5), 2)
        self.ram         = random.randint(10, 180)
        self.started     = datetime.datetime.now().strftime("%H:%M:%S")
        self.threads     = random.randint(1, 8)
        self.priority    = "normal"
        self.user        = user
        self.description = name
        self.window_id:  Optional[int] = None


class ProcessManager:
    """
    Simulates an OS process table.
    Spawns and kills user processes;
    maintains a background list of realistic system processes.
    """

    _SYSTEM_PROCS: List[Tuple[str, int, str]] = [
        ("System Idle Process", 0,    "SYSTEM"),
        ("System",              4,    "SYSTEM"),
        ("Registry",            80,   "SYSTEM"),
        ("smss.exe",            340,  "SYSTEM"),
        ("csrss.exe",           432,  "SYSTEM"),
        ("wininit.exe",         512,  "SYSTEM"),
        ("services.exe",        632,  "SYSTEM"),
        ("lsass.exe",           680,  "SYSTEM"),
        ("svchost.exe",         828,  "SYSTEM"),
        ("svchost.exe",         892,  "SYSTEM"),
        ("svchost.exe",         1000, "SYSTEM"),
        ("fontdrvhost.exe",     1048, "SYSTEM"),
        ("dwm.exe",             1208, "SYSTEM"),
        ("explorer.exe",        2540, "user"),
        ("SearchHost.exe",      3012, "user"),
        ("StartMenuExperienceHost.exe", 3248, "user"),
        ("RuntimeBroker.exe",   3420, "user"),
        ("ShellExperienceHost.exe",     3600, "user"),
        ("taskhostw.exe",       3788, "user"),
        ("audiodg.exe",         4012, "user"),
        ("spoolsv.exe",         4200, "SYSTEM"),
        ("WmiPrvSE.exe",        4400, "NETWORK SERVICE"),
        ("TextInputHost.exe",   4650, "user"),
        ("ctfmon.exe",          4800, "user"),
        ("SecurityHealthService.exe", 4900, "SYSTEM"),
    ]

    def __init__(self):
        self._procs:    Dict[int, ProcessRecord] = {}
        self._next_pid: int = 5000
        self._bus:      Optional[EventBus] = None
        self._init_system_procs()

    def attach_bus(self, bus: EventBus) -> None:
        self._bus = bus

    def _init_system_procs(self) -> None:
        for name, pid, user in self._SYSTEM_PROCS:
            p = ProcessRecord(pid, name, user)
            p.cpu = round(random.uniform(0.0, 1.0), 2)
            p.ram = random.randint(2, 60)
            self._procs[pid] = p

    def spawn(self, name: str, user: str = "user") -> int:
        """Create a new user process and return its PID."""
        pid = self._next_pid
        self._next_pid += 1
        p = ProcessRecord(pid, name, user)
        p.cpu = round(random.uniform(0.1, 3.0), 2)
        p.ram = random.randint(30, 200)
        self._procs[pid] = p
        if self._bus:
            self._bus.emit(EventBus.PROCESS_SPAWNED, pid)
        return pid

    def kill(self, pid: int) -> bool:
        """Kill a process. System processes (pid < 5000) cannot be killed."""
        if pid < 5000:
            return False
        if pid not in self._procs:
            return False
        del self._procs[pid]
        if self._bus:
            self._bus.emit(EventBus.PROCESS_KILLED, pid)
        return True

    def get(self, pid: int) -> Optional[ProcessRecord]:
        return self._procs.get(pid)

    def list_all(self) -> List[ProcessRecord]:
        return list(self._procs.values())

    def list_user(self) -> List[ProcessRecord]:
        return [p for p in self._procs.values() if p.pid >= 5000]

    def list_system(self) -> List[ProcessRecord]:
        return [p for p in self._procs.values() if p.pid < 5000]

    def tick(self) -> None:
        """Simulate realistic CPU/RAM drift for all processes."""
        for p in self._procs.values():
            # System idle absorbs idle cycles
            if p.pid == 0:
                p.cpu = max(0.0, 100.0 - self.total_cpu_excluding_idle())
                continue
            delta_cpu = random.gauss(0, 0.4)
            delta_ram = random.randint(-8, 8)
            p.cpu = max(0.0, min(99.0, p.cpu + delta_cpu))
            p.ram = max(2,   min(4000, p.ram + delta_ram))

    def total_cpu_excluding_idle(self) -> float:
        return sum(p.cpu for p in self._procs.values() if p.pid != 0)

    def total_cpu(self) -> float:
        return min(99.9, self.total_cpu_excluding_idle())

    def total_ram(self) -> int:
        return sum(p.ram for p in self._procs.values())

    def count(self) -> int:
        return len(self._procs)


