#  §09  CLIPBOARD MANAGER
# ═══════════════════════════════════════════════════════════════════════════════

class ClipboardEntry:
    """A single clipboard history entry."""
    __slots__ = ("text", "timestamp", "source", "pinned", "preview")

    def __init__(self, text: str, source: str = "unknown"):
        self.text      = text
        self.timestamp = datetime.datetime.now()
        self.source    = source
        self.pinned    = False
        self.preview   = (text[:60] + "…") if len(text) > 60 else text

    def __eq__(self, other) -> bool:
        return isinstance(other, ClipboardEntry) and self.text == other.text

    def age_str(self) -> str:
        delta = datetime.datetime.now() - self.timestamp
        s = int(delta.total_seconds())
        if s < 60:   return f"{s}s ago"
        if s < 3600: return f"{s//60}m ago"
        return f"{s//3600}h ago"


class ClipboardManager:
    """
    Tracks clipboard history with pin and search support.
    Maximum MAX_HISTORY items in rolling history;
    pinned items are kept separately and never evicted.
    """
    MAX_HISTORY = 50

    def __init__(self, bus: Optional[EventBus] = None):
        self._history: deque  = deque(maxlen=self.MAX_HISTORY)
        self._pinned:  List[ClipboardEntry] = []
        self._current: str    = ""
        self._bus = bus

    def copy(self, text: str, source: str = "app") -> None:
        if not text or text == self._current:
            return
        self._current = text
        entry = ClipboardEntry(text, source)
        # Remove duplicate if exists
        self._history = deque(
            (e for e in self._history if e.text != text),
            maxlen=self.MAX_HISTORY,
        )
        self._history.appendleft(entry)
        if self._bus:
            self._bus.emit(EventBus.CLIPBOARD_CHANGED, text)

    def paste(self) -> str:
        return self._current

    def clear(self) -> None:
        self._current = ""
        self._history.clear()

    def pin(self, text: str) -> None:
        for entry in self._history:
            if entry.text == text:
                entry.pinned = True
                if entry not in self._pinned:
                    self._pinned.append(entry)
                return
        entry = ClipboardEntry(text, "pinned")
        entry.pinned = True
        self._pinned.append(entry)

    def unpin(self, text: str) -> None:
        self._pinned = [e for e in self._pinned if e.text != text]
        for entry in self._history:
            if entry.text == text:
                entry.pinned = False

    def delete_entry(self, text: str) -> None:
        self._history = deque(
            (e for e in self._history if e.text != text),
            maxlen=self.MAX_HISTORY,
        )
        self._pinned = [e for e in self._pinned if e.text != text]
        if self._current == text:
            self._current = self._history[0].text if self._history else ""

    def get_history(self) -> List[ClipboardEntry]:
        return list(self._history)

    def get_pinned(self) -> List[ClipboardEntry]:
        return list(self._pinned)

    def search(self, query: str) -> List[ClipboardEntry]:
        q = query.lower()
        return [e for e in self._history if q in e.text.lower()]


