#  §10  SETTINGS STORE
# ═══════════════════════════════════════════════════════════════════════════════

class SettingsStore:
    """
    Key-value settings store backed by the VFS.
    Supports observers that are notified on save.

    Usage:
        settings.get("theme")             → "dark"
        settings.set("theme", "light")
        settings.save()                   → persists to VFS
        settings.observe(my_callback)     → called after every save
    """

    DEFAULTS: Dict[str, Any] = {
        # Appearance
        "theme":          "dark",
        "accent":         "#6c63ff",
        "wallpaper":      "gradient_purple",
        "transparency":   True,
        "animations":     True,
        # Desktop
        "desktop_icons":  True,
        "icon_size":      "medium",
        # Taskbar
        "taskbar_pos":    "bottom",
        "taskbar_size":   "medium",
        "taskbar_autohide": False,
        # Clock
        "24h_clock":      True,
        "show_seconds":   False,
        "show_date":      True,
        # Notifications
        "notifications":  True,
        "notif_sounds":   False,
        # System
        "font_size":      12,
        "volume":         75,
        "brightness":     100,
        "power_mode":     "balanced",
        "auto_theme":     False,
        # Privacy
        "priv_loc":       False,
        "priv_cam":       False,
        "priv_mic":       True,
        "priv_diag":      True,
        # Region
        "language":       "en-US",
        "date_format":    "YYYY-MM-DD",
        "timezone":       "UTC",
    }

    _PATH = VFS.CONFIG + "/settings.json"

    def __init__(self, vfs: VFS):
        self.vfs = vfs
        self._data: Dict[str, Any] = dict(self.DEFAULTS)
        self._observers: List[Callable] = []
        self._bus: Optional[EventBus] = None
        self._load()

    def attach_bus(self, bus: EventBus) -> None:
        self._bus = bus

    def _load(self) -> None:
        raw = self.vfs.read(self._PATH)
        if raw:
            try:
                loaded = json.loads(raw)
                self._data.update(loaded)
            except Exception:
                pass

    def save(self) -> None:
        self.vfs.write(self._PATH, json.dumps(self._data, indent=2))
        for cb in list(self._observers):
            try:
                cb()
            except Exception:
                pass
        if self._bus:
            self._bus.emit(EventBus.SETTINGS_SAVED, None)

    def get(self, key: str, default: Any = None) -> Any:
        return self._data.get(key, self.DEFAULTS.get(key, default))

    def set(self, key: str, value: Any) -> None:
        self._data[key] = value
        if self._bus:
            self._bus.emit(EventBus.SETTINGS_CHANGED, {"key": key, "value": value})

    def set_many(self, mapping: Dict[str, Any]) -> None:
        self._data.update(mapping)

    def reset(self, key: Optional[str] = None) -> None:
        if key:
            self._data[key] = self.DEFAULTS.get(key)
        else:
            self._data = dict(self.DEFAULTS)

    def observe(self, callback: Callable) -> None:
        if callback not in self._observers:
            self._observers.append(callback)

    def unobserve(self, callback: Callable) -> None:
        self._observers = [c for c in self._observers if c is not callback]

    def all(self) -> Dict[str, Any]:
        return dict(self._data)


