# ── Lookup helpers ─────────────────────────────────────────────────────────────

def app_by_id(app_id: str) -> Optional[Dict]:
    return next((a for a in APP_REGISTRY if a["id"] == app_id), None)

def apps_by_category() -> Dict[str, List[Dict]]:
    result: Dict[str, List[Dict]] = {}
    for app in APP_REGISTRY:
        result.setdefault(app["category"], []).append(app)
    return result

def pinned_apps() -> List[Dict]:
    return [a for a in APP_REGISTRY if a.get("pinned")]


