#  §12  BASE WINDOW  (window-manager chrome)
# ═══════════════════════════════════════════════════════════════════════════════

class BaseWin:
    """
    Parent class for every application window.

    Provides:
      • Title bar with icon, title label, min / max / close traffic-light buttons
      • Drag-to-move  (title bar)
      • Resize handle  (bottom edge)
      • Optional menu bar  — call self._show_menubar(), then self._add_menu(...)
      • Optional toolbar   — call self._show_toolbar()
      • Optional status bar — call self._show_statusbar()
      • client frame  — subclasses pack their widgets here
      • Focus / raise on click
      • Keyboard shortcut registry

    Subclasses override _build() to populate self.client.
    """

    # Absolute minimum dimensions
    MIN_W: int = 300
    MIN_H: int = 180

    # ── Constructor ───────────────────────────────────────────────────────────
    def __init__(
        self,
        wm:        "WM",
        title:     str             = "Window",
        width:     int             = 800,
        height:    int             = 520,
        icon:      str             = "🪟",
        resizable: bool            = True,
        min_size:  Tuple[int, int] = (300, 180),
    ):
        self.wm         = wm
        self.title      = title
        self.icon       = icon
        self._width     = width
        self._height    = height
        self._resizable = resizable
        self.MIN_W, self.MIN_H = min_size

        # State flags
        self._closed    = False
        self._minimized = False
        self._maximized = False
        self._focused   = False

        # Saved geometry before maximize
        self._saved_geom: Optional[Tuple[int, int, int, int]] = None

        # Process
        self._pid = wm.procs.spawn(title)

        # Menu bar state
        self._active_menu_popup: Optional[tk.Toplevel] = None
        self._menubar_visible    = False
        self._toolbar_visible    = False
        self._statusbar_visible  = False
        self._status_var         = tk.StringVar()

        # Keyboard shortcut registry  {keysym: callback}
        self._shortcuts: Dict[str, Callable] = {}

        # ── Stagger placement ─────────────────────────────────────────────────
        n = len(wm._windows)
        x = 48 + (n % 9) * 26
        y = 36 + (n % 7) * 20

        # ── Outer container (placed on WM desktop canvas) ────────────────────
        self.frame = tk.Frame(
            wm.desktop,
            bg=T["win_border"],
            highlightthickness=0,
            relief="flat",
        )
        self.frame.place(x=x, y=y, width=width, height=height)

        # ── Title bar ─────────────────────────────────────────────────────────
        self._titlebar = tk.Frame(
            self.frame,
            bg=T["win_chrome"],
            height=38,
        )
        self._titlebar.pack(fill="x", side="top")
        self._titlebar.pack_propagate(False)

        # Window icon
        self._icon_lbl = tk.Label(
            self._titlebar,
            text=icon,
            bg=T["win_chrome"],
            fg=T["titlebar_fg"],
            font=FONTS.get("body", ()),
            padx=8,
        )
        self._icon_lbl.pack(side="left")

        # Title text
        self._title_var = tk.StringVar(value=title)
        self._title_lbl = tk.Label(
            self._titlebar,
            textvariable=self._title_var,
            font=FONTS.get("title", ()),
            fg=T["titlebar_fg"],
            bg=T["win_chrome"],
            anchor="w",
        )
        self._title_lbl.pack(side="left", fill="x", expand=True)

        # Traffic-light control buttons (right side)
        self._ctrl_frame = tk.Frame(self._titlebar, bg=T["win_chrome"])
        self._ctrl_frame.pack(side="right")
        self._btn_min = self._make_ctrl_btn(self._ctrl_frame, "−", T["min_btn"],  self.minimize)
        self._btn_max = self._make_ctrl_btn(self._ctrl_frame, "□", T["max_btn"],  self.toggle_maximize)
        self._btn_cls = self._make_ctrl_btn(self._ctrl_frame, "✕", T["close_btn"], self.close)

        # ── Drag bindings ─────────────────────────────────────────────────────
        self._drag_ox = self._drag_oy = 0
        for w in (self._titlebar, self._title_lbl, self._icon_lbl):
            w.bind("<ButtonPress-1>",  self._on_drag_start)
            w.bind("<B1-Motion>",       self._on_drag_move)
            w.bind("<Double-Button-1>", self.toggle_maximize)

        # ── Menu bar slot (hidden until _show_menubar called) ─────────────────
        self._menubar_frame = tk.Frame(
            self.frame,
            bg=T["bg_elevated"],
            height=28,
        )

        # ── Toolbar slot ──────────────────────────────────────────────────────
        self._toolbar_frame = tk.Frame(
            self.frame,
            bg=T["bg_surface"],
            height=38,
        )

        # ── Client area ───────────────────────────────────────────────────────
        self.client = tk.Frame(self.frame, bg=T["bg_surface"])
        self.client.pack(fill="both", expand=True)

        # ── Status bar slot ───────────────────────────────────────────────────
        self._statusbar_frame = tk.Frame(
            self.frame,
            bg=T["bg_elevated"],
            height=24,
        )

        # ── Resize handle ─────────────────────────────────────────────────────
        if resizable:
            self._resize_grip = tk.Frame(
                self.frame,
                bg=T["win_border"],
                height=5,
                cursor="sizing",
            )
            self._resize_grip.pack(fill="x", side="bottom")
            self._resize_grip.bind("<ButtonPress-1>",  self._on_resize_start)
            self._resize_grip.bind("<B1-Motion>",       self._on_resize_move)

            # Side resize (right edge)
            self._resize_right = tk.Frame(
                self.frame,
                bg=T["win_border"],
                width=5,
                cursor="sb_h_double_arrow",
            )
            self._resize_right.place(relx=1.0, rely=0, relheight=1.0, anchor="ne", width=5)
            self._resize_right.bind("<ButtonPress-1>",  self._on_rresize_start)
            self._resize_right.bind("<B1-Motion>",       self._on_rresize_move)

        # ── Focus on click anywhere ───────────────────────────────────────────
        self.frame.bind("<ButtonPress-1>",    lambda e: self.focus(), add=True)
        self._titlebar.bind("<ButtonPress-1>", lambda e: self.focus(), add=True)

        # ── Global key handler ────────────────────────────────────────────────
        self.frame.bind("<Key>", self._on_key, add=True)

        # ── Register with WM ─────────────────────────────────────────────────
        wm.register(self)
        self.focus()

        # ── Build app content (subclass) ──────────────────────────────────────
        self._build()

    # ─── Traffic-light button factory ────────────────────────────────────────
    def _make_ctrl_btn(
        self,
        parent: tk.Frame,
        symbol: str,
        color:  str,
        cmd:    Callable,
    ) -> tk.Label:
        btn = tk.Label(
            parent,
            text=symbol,
            bg=T["win_chrome"],
            fg=color,
            font=FONTS.get("body_bold", ()),
            padx=10,
            pady=10,
            cursor="hand2",
            width=3,
        )
        btn.pack(side="left")

        def _hover_in(e, b=btn, c=color):
            b.config(bg=c, fg=T["bg_base"])

        def _hover_out(e, b=btn, c=color):
            b.config(bg=T["win_chrome"], fg=c)

        btn.bind("<Enter>",    _hover_in)
        btn.bind("<Leave>",    _hover_out)
        btn.bind("<Button-1>", lambda e: cmd())
        return btn

    # ─── Chrome slot activators ───────────────────────────────────────────────
    def _show_menubar(self) -> None:
        if self._menubar_visible:
            return
        self._menubar_visible = True
        self._menubar_frame.pack(fill="x", after=self._titlebar)
        fl_separator(self.frame).pack(fill="x", after=self._menubar_frame)

    def _show_toolbar(self) -> None:
        if self._toolbar_visible:
            return
        self._toolbar_visible = True
        self._toolbar_frame.pack(fill="x")

    def _show_statusbar(self) -> None:
        if self._statusbar_visible:
            return
        self._statusbar_visible = True
        fl_separator(self.frame).pack(fill="x", side="bottom")
        self._statusbar_frame.pack(fill="x", side="bottom")
        self._statusbar_frame.pack_propagate(False)
        tk.Label(
            self._statusbar_frame,
            textvariable=self._status_var,
            font=FONTS.get("caption", ()),
            fg=T["fg_tertiary"],
            bg=T["bg_elevated"],
            anchor="w",
            padx=10,
        ).pack(side="left", fill="y")

    def _set_status(self, msg: str) -> None:
        self._status_var.set(msg)

    # ─── Menu bar builder ─────────────────────────────────────────────────────
    def _add_menu(
        self,
        label: str,
        items: List[Tuple],
    ) -> tk.Label:
        """
        Add a top-level menu button to the menu bar.

        items format:
            ("Label", callback)           — normal item
            ("Label", callback, "Ctrl+S") — with accelerator text
            ("---",   None)               — separator
        """
        btn = tk.Label(
            self._menubar_frame,
            text=label,
            font=FONTS.get("menu_item", ()),
            fg=T["fg_secondary"],
            bg=T["bg_elevated"],
            padx=10,
            pady=4,
            cursor="hand2",
        )
        btn.pack(side="left")

        btn.bind("<Button-1>",
                 lambda e, b=btn, it=items: self._open_menu_popup(b, it))
        btn.bind("<Enter>", lambda e, b=btn: b.config(
            fg=T["fg_primary"], bg=T["bg_hover"]))
        btn.bind("<Leave>", lambda e, b=btn: b.config(
            fg=T["fg_secondary"], bg=T["bg_elevated"]))
        return btn

    def _open_menu_popup(
        self,
        anchor_btn: tk.Label,
        items: List[Tuple],
    ) -> None:
        # Close any existing popup
        if self._active_menu_popup:
            try:
                self._active_menu_popup.destroy()
            except Exception:
                pass
            self._active_menu_popup = None

        popup = tk.Toplevel(self.frame)
        popup.overrideredirect(True)
        popup.attributes("-topmost", True)
        popup.config(bg=T["bg_menu"])
        self._active_menu_popup = popup

        for item in items:
            label  = item[0]
            cmd    = item[1] if len(item) > 1 else None
            accel  = item[2] if len(item) > 2 else ""

            if label == "---":
                tk.Frame(popup, height=1, bg=T["border"]).pack(
                    fill="x", padx=6, pady=3)
                continue

            row = tk.Frame(popup, bg=T["bg_menu"], cursor="hand2")
            row.pack(fill="x")

            tk.Label(
                row,
                text=label,
                font=FONTS.get("menu_item", ()),
                fg=T["fg_primary"] if cmd else T["fg_disabled"],
                bg=T["bg_menu"],
                anchor="w",
                padx=14,
                pady=5,
            ).pack(side="left")

            if accel:
                tk.Label(
                    row,
                    text=accel,
                    font=FONTS.get("menu_accel", ()),
                    fg=T["fg_tertiary"],
                    bg=T["bg_menu"],
                    anchor="e",
                    padx=14,
                ).pack(side="right")

            if cmd:
                def _click(e, c=cmd, p=popup):
                    p.destroy()
                    self._active_menu_popup = None
                    c()

                def _enter(e, r=row): r.config(bg=T["bg_hover"])
                def _leave(e, r=row): r.config(bg=T["bg_menu"])

                row.bind("<Button-1>", _click)
                row.bind("<Enter>",    _enter)
                row.bind("<Leave>",    _leave)
                for child in row.winfo_children():
                    child.bind("<Button-1>", _click)
                    child.bind("<Enter>",    _enter)
                    child.bind("<Leave>",    _leave)

        popup.update_idletasks()

        bx = anchor_btn.winfo_rootx()
        by = anchor_btn.winfo_rooty() + anchor_btn.winfo_height()
        popup.geometry(f"+{bx}+{by}")

        popup.bind("<FocusOut>", lambda e: self._close_menu_popup())
        popup.focus_set()

    def _close_menu_popup(self) -> None:
        if self._active_menu_popup:
            try:
                self._active_menu_popup.destroy()
            except Exception:
                pass
            self._active_menu_popup = None

    # ─── Keyboard shortcuts ───────────────────────────────────────────────────
    def bind_shortcut(self, keysym: str, callback: Callable) -> None:
        self._shortcuts[keysym] = callback
        self.frame.bind(f"<{keysym}>", lambda e: callback())

    def _on_key(self, e: tk.Event) -> None:
        key = e.keysym
        cb  = self._shortcuts.get(key)
        if cb:
            cb()

    # ─── Drag logic ───────────────────────────────────────────────────────────
    def _on_drag_start(self, e: tk.Event) -> None:
        if self._maximized:
            return
        self._drag_ox = e.x_root - self.frame.winfo_x()
        self._drag_oy = e.y_root - self.frame.winfo_y()

    def _on_drag_move(self, e: tk.Event) -> None:
        if self._maximized:
            return
        nx = e.x_root - self._drag_ox
        ny = e.y_root - self._drag_oy
        dw = self.wm.desktop.winfo_width()
        dh = self.wm.desktop.winfo_height()
        # Clamp so at least 80px of title bar remains visible
        nx = max(-(self._width - 80),  min(nx, dw - 80))
        ny = max(0, min(ny, dh - 38))
        self.frame.place(x=nx, y=ny)

    # ─── Bottom resize ────────────────────────────────────────────────────────
    def _on_resize_start(self, e: tk.Event) -> None:
        self._resize_start_y  = e.y_root
        self._resize_start_h  = self.frame.winfo_height()

    def _on_resize_move(self, e: tk.Event) -> None:
        dy  = e.y_root - self._resize_start_y
        nh  = max(self.MIN_H, self._resize_start_h + dy)
        self.frame.place(height=nh)
        self._height = nh

    # ─── Right-edge resize ────────────────────────────────────────────────────
    def _on_rresize_start(self, e: tk.Event) -> None:
        self._rresize_start_x = e.x_root
        self._rresize_start_w = self.frame.winfo_width()

    def _on_rresize_move(self, e: tk.Event) -> None:
        dx  = e.x_root - self._rresize_start_x
        nw  = max(self.MIN_W, self._rresize_start_w + dx)
        self.frame.place(width=nw)
        self._width = nw

    # ─── Window state ─────────────────────────────────────────────────────────
    def focus(self) -> None:
        if self._closed:
            return
        try:
            self.frame.tkraise()
        except Exception:
            pass
        self._focused = True
        self.wm.set_focus(self)

    def minimize(self) -> None:
        if self._closed:
            return
        self._minimized = True
        self.frame.place_forget()
        self.wm.bus.emit(EventBus.WINDOW_MINIMIZED, self)

    def restore(self) -> None:
        if self._closed:
            return
        self._minimized = False
        x = self.frame.winfo_x() if self.frame.winfo_x() > -9000 else 60
        y = self.frame.winfo_y() if self.frame.winfo_y() > -9000 else 40
        if self._maximized:
            self.frame.place(
                x=0, y=0,
                width=self.wm.desktop.winfo_width(),
                height=self.wm.desktop.winfo_height(),
            )
        else:
            self.frame.place(x=x, y=y, width=self._width, height=self._height)
        self.focus()
        self.wm.bus.emit(EventBus.WINDOW_RESTORED, self)

    def toggle_maximize(self, e: tk.Event = None) -> None:
        if self._closed:
            return
        if self._maximized:
            # Restore to saved geometry
            self._maximized = False
            if self._saved_geom:
                sx, sy, sw, sh = self._saved_geom
                self.frame.place(x=sx, y=sy, width=sw, height=sh)
            self._btn_max.config(text="□")
        else:
            # Save current geometry
            self._saved_geom = (
                self.frame.winfo_x(),
                self.frame.winfo_y(),
                self._width,
                self._height,
            )
            self._maximized = True
            dw = self.wm.desktop.winfo_width()
            dh = self.wm.desktop.winfo_height()
            self.frame.place(x=0, y=0, width=dw, height=dh)
            self._btn_max.config(text="❐")
        self.focus()
        self.wm.bus.emit(EventBus.WINDOW_MAXIMIZED, self)

    def close(self) -> None:
        if self._closed:
            return
        self._closed = True
        self._close_menu_popup()
        self.wm.procs.kill(self._pid)
        self.wm.unregister(self)
        try:
            self.frame.destroy()
        except Exception:
            pass
        self.wm.bus.emit(EventBus.WINDOW_CLOSED, self)
        self._on_close()

    def _on_close(self) -> None:
        """Override in subclass for cleanup on close."""
        pass

    def set_title(self, title: str) -> None:
        self.title = title
        self._title_var.set(title)

    def set_icon(self, icon: str) -> None:
        self.icon = icon
        self._icon_lbl.config(text=icon)

    # ─── Subclass entry point ─────────────────────────────────────────────────
    def _build(self) -> None:
        """Override in every subclass to build the app UI into self.client."""
        pass


# ═══════════════════════════════════════════════════════════════════════════════
#  §13  WINDOW MANAGER  (WM)
# ═══════════════════════════════════════════════════════════════════════════════

class WM:
    """
    Core window manager.

    Owns:
      • The tk.Tk root and the main layout (topbar / desktop / taskbar)
      • The wallpaper canvas
      • The desktop icon grid
      • The open window registry and focus stack
      • open_*() launcher methods for every application
      • Theme/wallpaper switching

    All app windows are placed as children of self.desktop.
    """

    # ── Wallpaper catalogue ───────────────────────────────────────────────────
    WALLPAPERS: Dict[str, Dict] = {
        "gradient_purple":  {"type": "gradient", "stops": ["#1a1a2e", "#16213e", "#0f3460"]},
        "gradient_ocean":   {"type": "gradient", "stops": ["#0a1628", "#0d2137", "#0f3a60"]},
        "gradient_forest":  {"type": "gradient", "stops": ["#0d1f0d", "#1a3a1a", "#0e2e10"]},
        "gradient_sunset":  {"type": "gradient", "stops": ["#2d1b3d", "#4a1942", "#7a1e3e"]},
        "gradient_slate":   {"type": "gradient", "stops": ["#1a1f2e", "#252b3d", "#1c2640"]},
        "gradient_rose":    {"type": "gradient", "stops": ["#2d1020", "#3d1530", "#1a0810"]},
        "gradient_teal":    {"type": "gradient", "stops": ["#0a1e1e", "#0d2e2e", "#0a2020"]},
        "gradient_amber":   {"type": "gradient", "stops": ["#1e1200", "#2e1c00", "#3a2200"]},
        "solid_dark":       {"type": "solid",    "color": "#0f1117"},
        "solid_light":      {"type": "solid",    "color": "#e8ecf8"},
        "solid_black":      {"type": "solid",    "color": "#000000"},
        "solid_navy":       {"type": "solid",    "color": "#0a0e2a"},
        "mesh_purple":      {"type": "mesh",     "colors": ["#6c63ff", "#3b82f6", "#1a1a2e"]},
        "mesh_rose":        {"type": "mesh",     "colors": ["#f43f5e", "#a855f7", "#1a0810"]},
    }

    def __init__(
        self,
        root:     tk.Tk,
        vfs:      VFS,
        users:    UserManager,
        procs:    ProcessManager,
        settings: SettingsStore,
        clip:     ClipboardManager,
        bus:      EventBus,
    ):
        self.root     = root
        self.vfs      = vfs
        self.users    = users
        self.procs    = procs
        self.settings = settings
        self.clip     = clip
        self.bus      = bus

        self._windows:  List[BaseWin]    = []
        self._focused:  Optional[BaseWin] = None
        self._topbar:   Optional["TopBar"]  = None
        self._taskbar:  Optional["Taskbar"] = None

        # ── Root window styling ───────────────────────────────────────────────
        root.config(bg=T["bg_base"])

        # ── Top bar (32px) ────────────────────────────────────────────────────
        self._topbar_frame = tk.Frame(root, bg=T["bg_topbar"], height=32)
        self._topbar_frame.pack(fill="x", side="top")
        self._topbar_frame.pack_propagate(False)

        # ── Desktop canvas (fills remaining space) ────────────────────────────
        self.desktop = tk.Canvas(
            root,
            bg=T["bg_base"],
            highlightthickness=0,
        )
        self.desktop.pack(fill="both", expand=True)

        # ── Taskbar (56px) ────────────────────────────────────────────────────
        self._taskbar_frame = tk.Frame(root, bg=T["bg_taskbar"], height=56)
        self._taskbar_frame.pack(fill="x", side="bottom")
        self._taskbar_frame.pack_propagate(False)

        # ── Wallpaper canvas (sits behind everything on desktop) ──────────────
        self._wp_canvas = tk.Canvas(
            self.desktop,
            highlightthickness=0,
        )
        self._wp_canvas.place(x=0, y=0, relwidth=1.0, relheight=1.0)
        self._draw_wallpaper()

        # ── Desktop icon area ─────────────────────────────────────────────────
        self._icon_frame = tk.Frame(self.desktop, bg="#1a1a2e")
        self._icon_frame.place(x=10, y=10)
        self._build_desktop_icons()

        # ── Context menu bindings ─────────────────────────────────────────────
        self._wp_canvas.bind("<Button-3>",  self._on_desktop_rclick)
        self._wp_canvas.bind("<Button-1>",  self._on_desktop_click)
        self.desktop.bind("<Configure>",    self._on_desktop_resize)

        # ── Build shell components ────────────────────────────────────────────
        self._topbar  = TopBar(self)
        self._taskbar = Taskbar(self)

        # ── Event subscriptions ───────────────────────────────────────────────
        bus.subscribe(EventBus.WINDOW_OPENED,    lambda d: self._taskbar.refresh())
        bus.subscribe(EventBus.WINDOW_CLOSED,    lambda d: self._taskbar.refresh())
        bus.subscribe(EventBus.WINDOW_MINIMIZED, lambda d: self._taskbar.refresh())
        bus.subscribe(EventBus.WINDOW_RESTORED,  lambda d: self._taskbar.refresh())
        bus.subscribe(EventBus.WALLPAPER_CHANGED,lambda d: self._draw_wallpaper())
        bus.subscribe(EventBus.THEME_CHANGED,    lambda d: self._draw_wallpaper())

        # ── Process tick ─────────────────────────────────────────────────────
        self._proc_tick()

    # ─── Wallpaper rendering ──────────────────────────────────────────────────
    def _draw_wallpaper(self) -> None:
        self._wp_canvas.delete("all")
        w = max(1, self.root.winfo_width()  or SCREEN_W)
        h = max(1, self.root.winfo_height() or SCREEN_H)
        wp_key = self.settings.get("wallpaper", "gradient_purple")
        cfg    = self.WALLPAPERS.get(wp_key, self.WALLPAPERS["gradient_purple"])
        kind   = cfg["type"]

        if kind == "solid":
            self._wp_canvas.create_rectangle(
                0, 0, w, h,
                fill=cfg["color"],
                outline="",
            )

        elif kind == "gradient":
            stops  = cfg["stops"]
            n_segs = 80
            seg_h  = h / n_segs
            for i in range(n_segs):
                t       = i / (n_segs - 1)
                seg_idx = min(int(t * (len(stops) - 1)), len(stops) - 2)
                local_t = (t * (len(stops) - 1)) - seg_idx
                color   = lerp_color(stops[seg_idx], stops[seg_idx + 1], local_t)
                self._wp_canvas.create_rectangle(
                    0,          int(i * seg_h),
                    w,          int((i + 1) * seg_h) + 1,
                    fill=color, outline="",
                )

        elif kind == "mesh":
            # Dark base + soft radial blobs
            base = cfg["colors"][-1]
            self._wp_canvas.create_rectangle(0, 0, w, h, fill=base, outline="")
            for color in cfg["colors"][:-1]:
                for _ in range(3):
                    cx = random.randint(0, w)
                    cy = random.randint(0, h)
                    r  = random.randint(w // 5, w // 2)
                    # Fake radial using concentric ovals with fading alpha
                    for step in range(8, 0, -1):
                        alpha = step / 8
                        faded = lerp_color(base, color, alpha * 0.35)
                        self._wp_canvas.create_oval(
                            cx - r * alpha, cy - r * alpha,
                            cx + r * alpha, cy + r * alpha,
                            fill=faded, outline="",
                        )

        # Subtle star field overlay on dark themes
        if T["name"] in ("dark", "midnight"):
            accent = T["accent"]
            for _ in range(30):
                sx = random.randint(0, w)
                sy = random.randint(0, h)
                sr = random.choice([1, 1, 1, 2])
                self._wp_canvas.create_oval(
                    sx - sr, sy - sr, sx + sr, sy + sr,
                    fill=_darken(accent, 0.45),
                    outline="",
                )

    def _on_desktop_resize(self, e: tk.Event) -> None:
        self._draw_wallpaper()

    # ─── Desktop icon grid ────────────────────────────────────────────────────
    def _build_desktop_icons(self) -> None:
        for w in self._icon_frame.winfo_children():
            w.destroy()

        icons = [
            ("📁", "Files",    self.open_file_manager),
            ("📝", "Editor",   self.open_text_editor),
            ("⌨",  "Terminal", self.open_terminal),
            ("🗑",  "Recycle",  lambda: notify(self.root, "Recycle Bin", "Already empty.", kind="info")),
        ]

        for row_idx, (icon, label, cmd) in enumerate(icons):
            cell = tk.Frame(self._icon_frame, bg="#1a1a2e", cursor="hand2")
            cell.grid(row=row_idx, column=0, pady=6, padx=4)

            icon_lbl = tk.Label(
                cell,
                text=icon,
                font=(FONTS.get("emoji_lg", ("", 32))[0], 30),
                bg="#1a1a2e",
                fg=T["fg_primary"],
            )
            icon_lbl.pack()

            name_lbl = tk.Label(
                cell,
                text=label,
                font=FONTS.get("icon_label", ()),
                fg=T["fg_primary"],
                bg="#1a1a2e",
            )
            name_lbl.pack()

            for widget in (cell, icon_lbl, name_lbl):
                widget.bind("<Double-Button-1>", lambda e, c=cmd: c())
                widget.bind("<Enter>",  lambda e, f=cell: f.config(bg=T["bg_selection"]))
                widget.bind("<Leave>",  lambda e, f=cell: f.config(bg="#1a1a2e"))

    # ─── Desktop right-click menu ─────────────────────────────────────────────
    def _on_desktop_rclick(self, e: tk.Event) -> None:
        items = [
            ("⟳  Refresh Desktop",    self._draw_wallpaper),
            ("🎨  Personalize",        self.open_settings),
            ("─────────────────",      None),
            ("📁  New Folder",          lambda: notify(self.root, "New Folder", "Feature coming soon.", kind="info")),
            ("📄  New Text File",       lambda: self.open_text_editor()),
            ("─────────────────",      None),
            ("📊  Task Manager",        self.open_task_manager),
            ("⚙   Display Settings",   self.open_settings),
            ("─────────────────",      None),
            ("🔍  Search",              self.open_search),
        ]
        self._show_context_menu(e.x_root, e.y_root, items)

    def _on_desktop_click(self, e: tk.Event) -> None:
        pass  # deselect any focused icon in future

    def _show_context_menu(
        self,
        x: int,
        y: int,
        items: List[Tuple],
    ) -> None:
        popup = tk.Toplevel(self.root)
        popup.overrideredirect(True)
        popup.attributes("-topmost", True)
        popup.config(bg=T["bg_menu"])

        for item in items:
            label = item[0]
            cmd   = item[1] if len(item) > 1 else None

            if cmd is None or label.startswith("─"):
                tk.Frame(popup, height=1, bg=T["border"]).pack(
                    fill="x", padx=6, pady=2)
                continue

            row = tk.Frame(popup, bg=T["bg_menu"], cursor="hand2")
            row.pack(fill="x")

            tk.Label(
                row,
                text=label,
                font=FONTS.get("menu_item", ()),
                fg=T["fg_primary"],
                bg=T["bg_menu"],
                anchor="w",
                padx=14,
                pady=6,
            ).pack(side="left")

            def _click(e, c=cmd, p=popup):
                p.destroy()
                c()

            def _enter(e, r=row): r.config(bg=T["bg_hover"])
            def _leave(e, r=row): r.config(bg=T["bg_menu"])

            row.bind("<Button-1>", _click)
            row.bind("<Enter>",    _enter)
            row.bind("<Leave>",    _leave)
            for child in row.winfo_children():
                child.bind("<Button-1>", _click)
                child.bind("<Enter>",    _enter)
                child.bind("<Leave>",    _leave)

        popup.update_idletasks()
        sw = self.root.winfo_screenwidth()
        sh = self.root.winfo_screenheight()
        px = min(x, sw - popup.winfo_width()  - 4)
        py = min(y, sh - popup.winfo_height() - 4)
        popup.geometry(f"+{px}+{py}")
        popup.bind("<FocusOut>", lambda e: popup.destroy() if popup.winfo_exists() else None)
        popup.focus_set()

    # ─── Window registry ──────────────────────────────────────────────────────
    def register(self, win: BaseWin) -> None:
        self._windows.append(win)
        self.bus.emit(EventBus.WINDOW_OPENED, win)

    def unregister(self, win: BaseWin) -> None:
        self._windows = [w for w in self._windows if w is not win]
        if self._focused is win:
            self._focused = self._windows[-1] if self._windows else None

    def set_focus(self, win: BaseWin) -> None:
        self._focused = win
        self.bus.emit(EventBus.WINDOW_FOCUSED, win)
        if self._taskbar:
            self._taskbar.refresh()

    def all_wins(self) -> List[BaseWin]:
        return list(self._windows)

    def focused_win(self) -> Optional[BaseWin]:
        return self._focused

    # ─── Process tick ─────────────────────────────────────────────────────────
    def _proc_tick(self) -> None:
        self.procs.tick()
        self.root.after(PROC_TICK, self._proc_tick)

    # ─── Theme application ────────────────────────────────────────────────────
    def apply_theme(self) -> None:
        theme  = self.settings.get("theme",  "dark")
        accent = self.settings.get("accent", "#6c63ff")
        set_theme(theme, accent)
        self._draw_wallpaper()
        self.bus.emit(EventBus.THEME_CHANGED, theme)

    # ─── App launchers ────────────────────────────────────────────────────────
    def open_file_manager(self):   FileManagerWin(self)
    def open_text_editor(self, file_path=None): TextEditorWin(self, file_path=file_path)
    def open_terminal(self):       TerminalWin(self)
    def open_settings(self):       SettingsWin(self)
    def open_browser(self):        BrowserWin(self)
    def open_mail(self):           MailWin(self)
    def open_calendar(self):       CalendarWin(self)
    def open_calculator(self):     CalculatorWin(self)
    def open_task_manager(self):   TaskManagerWin(self)
    def open_app_store(self):      AppStoreWin(self)
    def open_sticky_notes(self):   StickyNotesWin(self)
    def open_clipboard(self):      ClipboardWin(self)
    def open_password_vault(self): PasswordVaultWin(self)
    def open_weather(self):        WeatherWin(self)
    def open_music(self):          MusicPlayerWin(self)
    def open_news(self):           NewsWin(self)
    def open_search(self):         SearchWin(self)
    def open_network(self):        NetworkWin(self)
    def open_disk_manager(self):   DiskManagerWin(self)
    def open_system_info(self):    SystemInfoWin(self)
    def open_code_editor(self):    CodeEditorWin(self)
    def open_image_viewer(self):   ImageViewerWin(self)


# ═══════════════════════════════════════════════════════════════════════════════
#  §14  TOP BAR
# ═══════════════════════════════════════════════════════════════════════════════

class TopBar:
    """
    The 32-pixel bar at the very top of the screen.

    Left   : PyOS label
    Centre : Global search field
    Right  : Status icons (network, volume, battery) + clock + user name
    """

    def __init__(self, wm: WM):
        self.wm   = wm
        self.root = wm.root
        f = wm._topbar_frame
        f.config(bg=T["bg_topbar"])

        # ── Left: branding ────────────────────────────────────────────────────
        tk.Label(
            f,
            text=f"  PyOS {VERSION}",
            font=FONTS.get("small_bold", ()),
            fg=T["accent"],
            bg=T["bg_topbar"],
            padx=4,
        ).pack(side="left")

        fl_separator(f, orient="v").pack(side="left", fill="y", pady=6)

        # ── Centre: global search ─────────────────────────────────────────────
        search_wrap = tk.Frame(f, bg=T["bg_topbar"])
        search_wrap.pack(side="left", fill="x", expand=True)

        search_pill = tk.Frame(search_wrap, bg=T["bg_input"])
        search_pill.pack(anchor="center")

        tk.Label(
            search_pill,
            text="🔍",
            bg=T["bg_input"],
            font=FONTS.get("small", ()),
            padx=6,
        ).pack(side="left")

        self._search_var = tk.StringVar()
        self._search_entry = tk.Entry(
            search_pill,
            textvariable=self._search_var,
            font=FONTS.get("small", ()),
            bg=T["bg_input"],
            fg=T["fg_tertiary"],
            insertbackground=T["accent"],
            relief="flat",
            bd=0,
            width=26,
        )
        self._search_entry.pack(side="left", pady=3, padx=4)
        self._search_entry.insert(0, "Search apps, files, settings…")

        self._search_entry.bind("<FocusIn>",  self._search_focus_in)
        self._search_entry.bind("<FocusOut>", self._search_focus_out)
        self._search_entry.bind("<Return>",   self._on_search_enter)

        # ── Right: tray ───────────────────────────────────────────────────────
        tray = tk.Frame(f, bg=T["bg_topbar"])
        tray.pack(side="right", padx=6)

        # Status icons
        self._tray_icons: List[tk.Label] = []
        tray_items = [
            ("📡", "Network: Connected"),
            ("🔊", "Volume: 75%"),
            ("🔋", "Battery: Simulated"),
        ]
        for icon, tip in tray_items:
            lbl = tk.Label(
                tray,
                text=icon,
                font=FONTS.get("small", ()),
                fg=T["fg_secondary"],
                bg=T["bg_topbar"],
                padx=3,
                cursor="hand2",
            )
            lbl.pack(side="left")
            _attach_tooltip(lbl, tip)
            self._tray_icons.append(lbl)

        fl_separator(tray, orient="v").pack(side="left", fill="y", pady=6, padx=4)

        # Clock
        self._clock_var = tk.StringVar()
        clock_lbl = tk.Label(
            tray,
            textvariable=self._clock_var,
            font=FONTS.get("clock_sm", ()),
            fg=T["fg_primary"],
            bg=T["bg_topbar"],
            cursor="hand2",
            padx=8,
        )
        clock_lbl.pack(side="left")
        clock_lbl.bind("<Button-1>", lambda e: wm.open_calendar())
        _attach_tooltip(clock_lbl, "Open Calendar")

        # User name
        self._user_lbl = tk.Label(
            tray,
            text=wm.users.get_display_name(),
            font=FONTS.get("small_bold", ()),
            fg=T["fg_secondary"],
            bg=T["bg_topbar"],
            cursor="hand2",
            padx=6,
        )
        self._user_lbl.pack(side="left")
        self._user_lbl.bind("<Button-1>", lambda e: wm.open_settings())
        _attach_tooltip(self._user_lbl, "Account Settings")

        self._update_clock()

    # ── Clock update ──────────────────────────────────────────────────────────
    def _update_clock(self) -> None:
        now = datetime.datetime.now()
        use_24h     = self.wm.settings.get("24h_clock", True)
        show_secs   = self.wm.settings.get("show_seconds", False)

        if use_24h:
            time_fmt = "%H:%M:%S" if show_secs else "%H:%M"
        else:
            time_fmt = "%I:%M:%S %p" if show_secs else "%I:%M %p"

        date_str = now.strftime("%a %d %b")
        self._clock_var.set(f"{now.strftime(time_fmt)}   {date_str}")
        self.root.after(CLOCK_TICK, self._update_clock)

    # ── Search bar behaviour ──────────────────────────────────────────────────
    _PLACEHOLDER = "Search apps, files, settings…"

    def _search_focus_in(self, e: tk.Event) -> None:
        if self._search_var.get() == self._PLACEHOLDER:
            self._search_entry.delete(0, "end")
            self._search_entry.config(fg=T["fg_primary"])

    def _search_focus_out(self, e: tk.Event) -> None:
        if not self._search_var.get():
            self._search_entry.insert(0, self._PLACEHOLDER)
            self._search_entry.config(fg=T["fg_tertiary"])

    def _on_search_enter(self, e: tk.Event) -> None:
        query = self._search_var.get().strip()
        if query and query != self._PLACEHOLDER:
            self.wm.open_search()


# ═══════════════════════════════════════════════════════════════════════════════
#  §15  TASKBAR
# ═══════════════════════════════════════════════════════════════════════════════

class Taskbar:
    """
    The 56-pixel bar at the bottom of the screen.

    Left  : Start button
    Centre: Pinned app icons + running window buttons
    Right : Show-desktop button
    """

    _BTN_W  = 48   # width of each pinned icon slot
    _BTN_H  = 40   # height

    def __init__(self, wm: WM):
        self.wm    = wm
        self.root  = wm.root
        self._frame = wm._taskbar_frame
        self._frame.config(bg=T["bg_taskbar"])

        self._start_menu: Optional["StartMenu"] = None

        # ── Start button ──────────────────────────────────────────────────────
        self._start_btn = tk.Label(
            self._frame,
            text="⊞  Start",
            font=FONTS.get("btn", ()),
            bg=T["accent"],
            fg=T["btn_primary_fg"],
            padx=16,
            pady=11,
            cursor="hand2",
            relief="flat",
        )
        self._start_btn.pack(side="left", padx=(10, 0))
        self._start_btn.bind("<Button-1>", lambda e: self._toggle_start())
        self._start_btn.bind("<Enter>", lambda e: self._start_btn.config(bg=T["accent_light"]))
        self._start_btn.bind("<Leave>", lambda e: self._start_btn.config(bg=T["accent"]))

        fl_separator(self._frame, orient="v").pack(
            side="left", fill="y", pady=10, padx=6)

        # ── Centre: app buttons ────────────────────────────────────────────────
        self._center = tk.Frame(self._frame, bg=T["bg_taskbar"])
        self._center.pack(side="left", fill="x", expand=True)

        # ── Right: show desktop ────────────────────────────────────────────────
        right = tk.Frame(self._frame, bg=T["bg_taskbar"])
        right.pack(side="right", padx=6)

        show_desktop = tk.Label(
            right,
            text="⬜",
            font=FONTS.get("small", ()),
            fg=T["fg_tertiary"],
            bg=T["bg_taskbar"],
            cursor="hand2",
            padx=6,
            pady=8,
        )
        show_desktop.pack()
        show_desktop.bind("<Button-1>", self._show_desktop)
        _attach_tooltip(show_desktop, "Show Desktop")

        self.refresh()

    # ── Start menu toggle ─────────────────────────────────────────────────────
    def _toggle_start(self) -> None:
        if self._start_menu and self._start_menu.visible:
            self._start_menu.hide()
        else:
            if not self._start_menu:
                self._start_menu = StartMenu(self.wm)
            self._start_menu.show()

    # ── Show/restore desktop ──────────────────────────────────────────────────
    def _show_desktop(self, e: tk.Event) -> None:
        any_visible = any(not w._minimized for w in self.wm.all_wins())
        if any_visible:
            for win in self.wm.all_wins():
                if not win._minimized:
                    win.minimize()
        else:
            for win in self.wm.all_wins():
                win.restore()

    # ── Rebuild centre strip ──────────────────────────────────────────────────
    def refresh(self) -> None:
        for w in self._center.winfo_children():
            w.destroy()

        # Pinned apps
        for app in pinned_apps():
            running_wins = [w for w in self.wm.all_wins() if w.title == app["name"]]
            self._add_pinned_btn(app, running_wins)

        # Running but not pinned
        pinned_names = {a["name"] for a in pinned_apps()}
        for win in self.wm.all_wins():
            if win.title not in pinned_names:
                self._add_running_btn(win)

    # ── Pinned icon button ────────────────────────────────────────────────────
    def _add_pinned_btn(
        self,
        app:          Dict,
        running_wins: List[BaseWin],
    ) -> None:
        is_running = len(running_wins) > 0
        is_focused = any(w is self.wm.focused_win() for w in running_wins)

        cell = tk.Frame(
            self._center,
            bg=T["bg_active"] if is_focused else T["bg_taskbar"],
            cursor="hand2",
            width=self._BTN_W,
        )
        cell.pack(side="left", padx=2)
        cell.pack_propagate(False)

        icon_lbl = tk.Label(
            cell,
            text=app["icon"],
            font=FONTS.get("emoji_sm", ()),
            bg=T["bg_active"] if is_focused else T["bg_taskbar"],
            pady=6,
        )
        icon_lbl.pack()

        # Running indicator dot
        if is_running:
            dot_color = T["accent"] if is_focused else T["fg_tertiary"]
            dot = tk.Frame(cell, height=3, bg=dot_color)
            dot.pack(fill="x", padx=8)

        # Click: if running raise/restore, else launch
        launcher = getattr(self.wm, app["launcher"], None)

        def _click(e, wins=running_wins, lnc=launcher, a=app):
            if wins:
                win = wins[0]
                if win._minimized:
                    win.restore()
                elif win is self.wm.focused_win():
                    win.minimize()
                else:
                    win.focus()
            elif lnc:
                lnc()

        for widget in (cell, icon_lbl):
            widget.bind("<Button-1>", _click)
            widget.bind("<Enter>",
                lambda e, c=cell: c.config(bg=T["bg_hover"]))
            widget.bind("<Leave>",
                lambda e, c=cell, f=is_focused:
                    c.config(bg=T["bg_active"] if f else T["bg_taskbar"]))

        _attach_tooltip(cell, app["name"])

    # ── Running-but-not-pinned button ────────────────────────────────────────
    def _add_running_btn(self, win: BaseWin) -> None:
        is_focused = win is self.wm.focused_win()

        cell = tk.Frame(
            self._center,
            bg=T["bg_active"] if is_focused else T["bg_hover"],
            cursor="hand2",
        )
        cell.pack(side="left", padx=2)

        lbl = tk.Label(
            cell,
            text=f"{win.icon}  {win.title[:16]}",
            font=FONTS.get("small", ()),
            fg=T["fg_primary"],
            bg=T["bg_active"] if is_focused else T["bg_hover"],
            padx=10,
            pady=8,
        )
        lbl.pack(side="left")

        dot = tk.Frame(cell, height=3, bg=T["accent"] if is_focused else T["fg_tertiary"])
        dot.pack(side="bottom", fill="x", padx=6)

        def _click(e, w=win):
            if w._minimized:
                w.restore()
            elif w is self.wm.focused_win():
                w.minimize()
            else:
                w.focus()

        for widget in (cell, lbl):
            widget.bind("<Button-1>", _click)
            widget.bind("<Enter>",
                lambda e, c=cell: c.config(bg=T["bg_hover"]))
            widget.bind("<Leave>",
                lambda e, c=cell, f=is_focused:
                    c.config(bg=T["bg_active"] if f else T["bg_hover"]))


# ═══════════════════════════════════════════════════════════════════════════════
#  §16  START MENU
# ═══════════════════════════════════════════════════════════════════════════════

class StartMenu:
    """
    Full-screen-width start menu that rises from the taskbar.

    Layout (560 × 580 popup):
      • Header : user avatar + name + power button
      • Search : live-filtering entry
      • Pinned grid (5 × 2)
      • Separator + "All Apps" label
      • Scrollable full app list grouped by category
      • Footer : Settings shortcut + Shut down
    """

    MENU_W = 540
    MENU_H = 580

    def __init__(self, wm: WM):
        self.wm      = wm
        self.visible = False
        self._win:   Optional[tk.Toplevel] = None

    # ── Show ──────────────────────────────────────────────────────────────────
    def show(self) -> None:
        if self._win and self._win.winfo_exists():
            self._win.destroy()

        self.visible = True
        w = tk.Toplevel(self.wm.root)
        w.overrideredirect(True)
        w.attributes("-topmost", True)
        w.config(bg=T["bg_menu"])
        self._win = w

        sw = self.wm.root.winfo_width()
        sh = self.wm.root.winfo_height()
        mx = max(0, (sw - self.MENU_W) // 2)
        my = sh - self.MENU_H - 60

        w.geometry(f"{self.MENU_W}x{self.MENU_H}+{mx}+{my}")

        # ── Header ────────────────────────────────────────────────────────────
        hdr = tk.Frame(w, bg=T["bg_menu"])
        hdr.pack(fill="x", padx=18, pady=(16, 8))

        tk.Label(
            hdr,
            text=self.wm.users.get_avatar(),
            font=FONTS.get("emoji_md", ()),
            bg=T["bg_menu"],
        ).pack(side="left")

        tk.Label(
            hdr,
            text=f"  {self.wm.users.get_display_name()}",
            font=FONTS.get("h3", ()),
            fg=T["fg_primary"],
            bg=T["bg_menu"],
        ).pack(side="left")

        power_btn = tk.Label(
            hdr,
            text="⏻",
            font=FONTS.get("h2", ()),
            fg=T["fg_tertiary"],
            bg=T["bg_menu"],
            cursor="hand2",
        )
        power_btn.pack(side="right")
        power_btn.bind("<Button-1>", lambda e: (self.hide(), ShutdownDialog(self.wm)))

        fl_separator(w).pack(fill="x", padx=14)

        # ── Search ────────────────────────────────────────────────────────────
        sf = tk.Frame(w, bg=T["bg_input"])
        sf.pack(fill="x", padx=16, pady=10)

        tk.Label(sf, text="🔍", bg=T["bg_input"],
                 font=FONTS.get("body", ())).pack(side="left", padx=8)

        self._sv = tk.StringVar()
        se = tk.Entry(
            sf,
            textvariable=self._sv,
            font=FONTS.get("body", ()),
            bg=T["bg_input"],
            fg=T["fg_primary"],
            insertbackground=T["accent"],
            relief="flat",
            bd=0,
        )
        se.pack(side="left", fill="x", expand=True, pady=7)
        se.bind("<KeyRelease>", lambda e: self._filter())
        se.focus_set()

        # ── Pinned label ──────────────────────────────────────────────────────
        self._pinned_label = tk.Label(
            w,
            text="Pinned",
            font=FONTS.get("h4", ()),
            fg=T["fg_secondary"],
            bg=T["bg_menu"],
            anchor="w",
            padx=18,
        )
        self._pinned_label.pack(fill="x")

        self._pinned_frame = tk.Frame(w, bg=T["bg_menu"])
        self._pinned_frame.pack(fill="x", padx=14, pady=(4, 0))

        fl_separator(w).pack(fill="x", padx=14, pady=6)

        tk.Label(
            w,
            text="All Apps",
            font=FONTS.get("h4", ()),
            fg=T["fg_secondary"],
            bg=T["bg_menu"],
            anchor="w",
            padx=18,
        ).pack(fill="x")

        # ── Scrollable app list ────────────────────────────────────────────────
        list_host = tk.Frame(w, bg=T["bg_menu"])
        list_host.pack(fill="both", expand=True, padx=8, pady=4)

        self._scroll = ScrollableFrame(list_host, bg_key="bg_menu")
        self._scroll.pack(fill="both", expand=True)
        self._list_inner = self._scroll.inner

        # ── Footer ────────────────────────────────────────────────────────────
        fl_separator(w).pack(fill="x", padx=14)
        footer = tk.Frame(w, bg=T["bg_menu"])
        footer.pack(fill="x", padx=16, pady=8)

        for icon, label, cmd in [
            ("⚙", "Settings",  self.wm.open_settings),
            ("⏻", "Shut down", lambda: ShutdownDialog(self.wm)),
        ]:
            fb = tk.Label(
                footer,
                text=f"{icon}  {label}",
                font=FONTS.get("body", ()),
                fg=T["fg_secondary"],
                bg=T["bg_menu"],
                padx=14,
                pady=6,
                cursor="hand2",
            )
            fb.pack(side="right")
            fb.bind("<Button-1>", lambda e, c=cmd: (self.hide(), c()))
            fb.bind("<Enter>", lambda e, b=fb: b.config(
                fg=T["fg_primary"], bg=T["bg_hover"]))
            fb.bind("<Leave>", lambda e, b=fb: b.config(
                fg=T["fg_secondary"], bg=T["bg_menu"]))

        # ── Populate ──────────────────────────────────────────────────────────
        self._build_apps()

        w.bind("<FocusOut>", lambda e: self.hide() if w.winfo_exists() else None)
        w.bind("<Escape>",   lambda e: self.hide())

    # ── Populate pinned grid + app list ───────────────────────────────────────
    def _build_apps(self, query: str = "") -> None:
        # Clear
        for ch in self._pinned_frame.winfo_children():
            ch.destroy()
        for ch in self._list_inner.winfo_children():
            ch.destroy()

        q = query.lower().strip()
        all_apps = APP_REGISTRY if not q else [
            a for a in APP_REGISTRY
            if q in a["name"].lower() or q in a["desc"].lower()
               or q in a["category"].lower()
        ]

        # Pinned icons grid (only shown when no search query)
        if not q:
            self._pinned_label.pack(fill="x")
            self._pinned_frame.pack(fill="x", padx=14, pady=(4, 0))
            pinned = [a for a in APP_REGISTRY if a.get("pinned")][:10]
            for idx, app in enumerate(pinned):
                col = idx % 5
                row = idx // 5
                self._make_pinned_cell(app, row, col)
        else:
            self._pinned_label.pack_forget()
            self._pinned_frame.pack_forget()

        # App list grouped by category
        cats = apps_by_category()
        for cat_name in sorted(cats.keys()):
            cat_apps = [a for a in cats[cat_name] if a in all_apps]
            if not cat_apps:
                continue
            tk.Label(
                self._list_inner,
                text=cat_name,
                font=FONTS.get("micro_bold", ()),
                fg=T["accent"],
                bg=T["bg_menu"],
                anchor="w",
                padx=10,
                pady=8,
            ).pack(fill="x")
            for app in cat_apps:
                self._make_app_row(app)

    def _make_pinned_cell(self, app: Dict, row: int, col: int) -> None:
        cell = tk.Frame(
            self._pinned_frame,
            bg=T["bg_menu"],
            cursor="hand2",
            width=88,
            height=70,
        )
        cell.grid(row=row, column=col, padx=3, pady=4)
        cell.grid_propagate(False)

        tk.Label(
            cell,
            text=app["icon"],
            font=(FONTS.get("emoji_md", ("", 22))[0], 24),
            bg=T["bg_menu"],
        ).place(relx=0.5, y=22, anchor="center")

        tk.Label(
            cell,
            text=app["name"],
            font=FONTS.get("nano", ()),
            fg=T["fg_secondary"],
            bg=T["bg_menu"],
            wraplength=80,
            justify="center",
        ).place(relx=0.5, y=52, anchor="center")

        launcher = getattr(self.wm, app["launcher"], None)

        def _click(e, l=launcher):
            self.hide()
            if l:
                l()

        def _enter(e, c=cell): c.config(bg=T["bg_hover"])
        def _leave(e, c=cell): c.config(bg=T["bg_menu"])

        cell.bind("<Button-1>", _click)
        cell.bind("<Enter>", _enter)
        cell.bind("<Leave>", _leave)
        for ch in cell.winfo_children():
            ch.bind("<Button-1>", _click)
            ch.bind("<Enter>", _enter)
            ch.bind("<Leave>", _leave)

    def _make_app_row(self, app: Dict) -> None:
        row = tk.Frame(self._list_inner, bg=T["bg_menu"], cursor="hand2")
        row.pack(fill="x", padx=4, pady=1)

        tk.Label(
            row,
            text=app["icon"],
            font=FONTS.get("emoji_sm", ()),
            bg=T["bg_menu"],
            width=3,
        ).pack(side="left", padx=8, pady=4)

        info = tk.Frame(row, bg=T["bg_menu"])
        info.pack(side="left", fill="x", expand=True, pady=4)

        tk.Label(
            info,
            text=app["name"],
            font=FONTS.get("body_bold", ()),
            fg=T["fg_primary"],
            bg=T["bg_menu"],
            anchor="w",
        ).pack(fill="x")

        tk.Label(
            info,
            text=app["desc"],
            font=FONTS.get("micro", ()),
            fg=T["fg_tertiary"],
            bg=T["bg_menu"],
            anchor="w",
        ).pack(fill="x")

        launcher = getattr(self.wm, app["launcher"], None)

        def _click(e, l=launcher):
            self.hide()
            if l:
                l()

        def _enter(e, r=row): r.config(bg=T["bg_hover"])
        def _leave(e, r=row): r.config(bg=T["bg_menu"])

        row.bind("<Button-1>", _click)
        row.bind("<Enter>", _enter)
        row.bind("<Leave>", _leave)
        for ch in row.winfo_children():
            ch.bind("<Button-1>", _click)
            ch.bind("<Enter>", _enter)
            ch.bind("<Leave>", _leave)

    # ── Search filter ─────────────────────────────────────────────────────────
    def _filter(self) -> None:
        self._build_apps(query=self._sv.get())

    # ── Hide ──────────────────────────────────────────────────────────────────
    def hide(self) -> None:
        self.visible = False
        if self._win and self._win.winfo_exists():
            self._win.destroy()
        self._win = None


# ═══════════════════════════════════════════════════════════════════════════════
#  §17  FILE MANAGER
# ═══════════════════════════════════════════════════════════════════════════════

class FileManagerWin(BaseWin):
    """
    Two-pane file manager.
    Left  : sidebar (quick-access shortcuts, drives, bookmarks)
    Right : file list (details view) with sortable columns
    Toolbar: back / forward / up / refresh / address bar / search
    Menu   : File / Edit / View
    """

    def __init__(self, wm: WM):
        self._cwd          = VFS.HOME
        self._back_stack:  List[str] = []
        self._fwd_stack:   List[str] = []
        self._selected:    Optional[str] = None
        self._clipboard:   Optional[Tuple[str, str]] = None   # ("copy"|"cut", path)
        self._sort_col     = "name"
        self._sort_rev     = False
        self._view_mode    = "details"
        super().__init__(wm, "File Manager", 920, 580, "📁")

    # ─── Build ────────────────────────────────────────────────────────────────
    def _build(self) -> None:
        self._show_menubar()
        self._build_menus()
        self._show_toolbar()
        self._build_toolbar()
        self._show_statusbar()
        self.client.config(bg=T["bg_surface"])

        # ── Two-pane layout ───────────────────────────────────────────────────
        pane = tk.Frame(self.client, bg=T["bg_surface"])
        pane.pack(fill="both", expand=True)

        # Sidebar
        self._sidebar = tk.Frame(pane, bg=T["bg_sidebar"], width=190)
        self._sidebar.pack(side="left", fill="y")
        self._sidebar.pack_propagate(False)

        fl_separator(pane, orient="v").pack(side="left", fill="y")

        # Main file area
        self._main = tk.Frame(pane, bg=T["bg_surface"])
        self._main.pack(side="left", fill="both", expand=True)

        self._build_column_header()

        # Scrollable file list
        self._file_scroll = ScrollableFrame(self._main, bg_key="bg_surface")
        self._file_scroll.pack(fill="both", expand=True)
        self._file_inner = self._file_scroll.inner

        self._refresh_sidebar()
        self._load_dir()

    # ─── Menus ────────────────────────────────────────────────────────────────
    def _build_menus(self) -> None:
        self._add_menu("File", [
            ("New Folder",       self._new_folder,    "Ctrl+Shift+N"),
            ("New Text File",    self._new_file,      "Ctrl+N"),
            ("---",              None),
            ("Open",             self._open_selected),
            ("Open in Editor",   self._open_in_editor),
            ("---",              None),
            ("Properties",       self._show_properties),
            ("---",              None),
            ("Close",            self.close,          "Ctrl+W"),
        ])
        self._add_menu("Edit", [
            ("Copy",             self._copy,          "Ctrl+C"),
            ("Cut",              self._cut,           "Ctrl+X"),
            ("Paste",            self._paste,         "Ctrl+V"),
            ("---",              None),
            ("Select All",       self._select_all),
            ("---",              None),
            ("Delete",           self._delete_selected, "Del"),
            ("Rename",           self._rename_selected, "F2"),
        ])
        self._add_menu("View", [
            ("Details",          lambda: self._set_view("details")),
            ("---",              None),
            ("Sort by Name",     lambda: self._set_sort("name")),
            ("Sort by Size",     lambda: self._set_sort("size")),
            ("Sort by Modified", lambda: self._set_sort("modified")),
            ("---",              None),
            ("Show Hidden Files", self._toggle_hidden),
            ("---",              None),
            ("Refresh",          self._load_dir,      "F5"),
        ])
        self._add_menu("Bookmarks", [
            ("Add Bookmark",     self._add_bookmark),
            ("Manage Bookmarks", self._manage_bookmarks),
        ])

    # ─── Toolbar ─────────────────────────────────────────────────────────────
    def _build_toolbar(self) -> None:
        tb = self._toolbar_frame
        tb.config(bg=T["bg_elevated"])

        # Nav buttons
        for sym, tip, cmd in [
            ("←", "Back",    self._go_back),
            ("→", "Forward", self._go_forward),
            ("↑", "Up",      self._go_up),
            ("⟳", "Refresh", self._load_dir),
        ]:
            b = fl_icon_button(tb, sym, cmd,
                               bg_key="bg_elevated",
                               fg_key="fg_secondary",
                               tooltip=tip,
                               padx=10, pady=6)
            b.pack(side="left")

        fl_separator(tb, orient="v").pack(side="left", fill="y", pady=6, padx=4)

        # Address bar
        self._path_var = tk.StringVar(value=self._cwd)
        addr_wrap = tk.Frame(tb, bg=T["bg_input"])
        addr_wrap.pack(side="left", fill="x", expand=True, padx=8, pady=5)

        self._addr_entry = tk.Entry(
            addr_wrap,
            textvariable=self._path_var,
            font=FONTS.get("body", ()),
            bg=T["bg_input"],
            fg=T["accent"],
            insertbackground=T["accent"],
            relief="flat",
            bd=0,
        )
        self._addr_entry.pack(fill="x", padx=8, pady=4)
        self._addr_entry.bind("<Return>",
            lambda e: self._nav_to(self._path_var.get().strip()))

        # Search
        fl_separator(tb, orient="v").pack(side="left", fill="y", pady=6, padx=4)
        search_wrap = tk.Frame(tb, bg=T["bg_input"])
        search_wrap.pack(side="right", padx=8, pady=5)

        tk.Label(search_wrap, text="🔍",
                 bg=T["bg_input"],
                 font=FONTS.get("small", ())).pack(side="left", padx=4)

        self._search_var = tk.StringVar()
        se = tk.Entry(search_wrap,
                      textvariable=self._search_var,
                      font=FONTS.get("body", ()),
                      bg=T["bg_input"],
                      fg=T["fg_primary"],
                      insertbackground=T["accent"],
                      relief="flat", bd=0, width=16)
        se.pack(side="left", pady=4)
        se.bind("<Return>", lambda e: self._do_search())

        self._show_hidden = False

    # ─── Column header ────────────────────────────────────────────────────────
    def _build_column_header(self) -> None:
        hdr = tk.Frame(self._main, bg=T["bg_card"])
        hdr.pack(fill="x")

        cols = [
            ("Name",     "name",     280),
            ("Size",     "size",      80),
            ("Type",     "type",     110),
            ("Modified", "modified", 150),
        ]
        for label, key, w in cols:
            lbl = tk.Label(
                hdr,
                text=label + (" ▲" if self._sort_col == key and not self._sort_rev
                              else " ▼" if self._sort_col == key else ""),
                font=FONTS.get("small_bold", ()),
                fg=T["accent"] if self._sort_col == key else T["fg_tertiary"],
                bg=T["bg_card"],
                width=w // 7,
                anchor="w",
                padx=8,
                pady=5,
                cursor="hand2",
            )
            lbl.pack(side="left")
            lbl.bind("<Button-1>", lambda e, k=key: self._set_sort(k))

        fl_separator(self._main).pack(fill="x")

    # ─── Sidebar ──────────────────────────────────────────────────────────────
    def _refresh_sidebar(self) -> None:
        for w in self._sidebar.winfo_children():
            w.destroy()

        def _section(title: str) -> None:
            tk.Label(
                self._sidebar,
                text=f"  {title}",
                font=FONTS.get("micro_bold", ()),
                fg=T["accent"],
                bg=T["bg_sidebar"],
                anchor="w",
                pady=6,
            ).pack(fill="x")

        def _shortcut(label: str, path: str, icon: str = "📁") -> None:
            active = self._cwd == path
            btn = tk.Label(
                self._sidebar,
                text=f"  {icon}  {label}",
                font=FONTS.get("body", ()),
                fg=T["fg_primary"] if active else T["fg_secondary"],
                bg=T["bg_active"] if active else T["bg_sidebar"],
                anchor="w",
                pady=5,
                padx=4,
                cursor="hand2",
            )
            btn.pack(fill="x")
            btn.bind("<Button-1>", lambda e, p=path: self._nav_to(p))
            btn.bind("<Enter>",
                lambda e, b=btn, a=active:
                    b.config(bg=T["bg_hover"] if not a else T["bg_active"]))
            btn.bind("<Leave>",
                lambda e, b=btn, a=active:
                    b.config(bg=T["bg_active"] if a else T["bg_sidebar"]))

        _section("QUICK ACCESS")
        _shortcut("Home",       VFS.HOME,    "🏠")
        _shortcut("Desktop",    VFS.DESKTOP, "🖥")
        _shortcut("Documents",  VFS.DOCS,    "📄")
        _shortcut("Downloads",  VFS.DLOADS,  "⬇")
        _shortcut("Pictures",   VFS.PICS,    "🖼")
        _shortcut("Music",      VFS.MUSIC,   "🎵")
        _shortcut("Videos",     VFS.VIDEOS,  "🎬")

        fl_separator(self._sidebar).pack(fill="x", padx=8, pady=4)
        _section("DEVICES")
        _shortcut("PyOS (C:)",  "/",        "💿")
        _shortcut("Temp",       "/tmp",     "🗂")

        # Bookmarks
        raw = self.wm.vfs.read(VFS.CONFIG + "/bookmarks.json")
        if raw:
            try:
                bookmarks = json.loads(raw)
                if bookmarks:
                    fl_separator(self._sidebar).pack(fill="x", padx=8, pady=4)
                    _section("BOOKMARKS")
                    for bm in bookmarks[:8]:
                        name = VFS.basename(bm) or bm
                        _shortcut(name, bm, "🔖")
            except Exception:
                pass

    # ─── Directory loading ────────────────────────────────────────────────────
    def _load_dir(self) -> None:
        self._path_var.set(self._cwd)
        self._selected = None
        self._refresh_sidebar()
        self._rebuild_column_header()

        for w in self._file_inner.winfo_children():
            w.destroy()

        entries = self.wm.vfs.listdir(
            self._cwd,
            show_hidden=self._show_hidden,
        )

        if not entries:
            tk.Label(
                self._file_inner,
                text="This folder is empty.",
                font=FONTS.get("body", ()),
                fg=T["fg_tertiary"],
                bg=T["bg_surface"],
                pady=40,
            ).pack()
            self._set_status(f"0 items  |  {self._cwd}")
            return

        # Build node list for sorting
        nodes = []
        for name in entries:
            path = self.wm.vfs.join(self._cwd, name)
            node = self.wm.vfs.get_node(path)
            if node:
                nodes.append((name, path, node))

        # Sort
        def _sort_key(t):
            name, path, node = t
            if self._sort_col == "name":
                return (not node.is_dir, name.lower())
            if self._sort_col == "size":
                return (not node.is_dir, node.size)
            if self._sort_col == "modified":
                return (not node.is_dir, node.modified)
            return (not node.is_dir, name.lower())

        nodes.sort(key=_sort_key, reverse=self._sort_rev)

        for i, (name, path, node) in enumerate(nodes):
            self._add_file_row(i, name, path, node)

        dirs  = sum(1 for _, _, n in nodes if n.is_dir)
        files = len(nodes) - dirs
        self._set_status(
            f"{len(nodes)} items  ({dirs} folders, {files} files)  |  {self._cwd}")

    def _rebuild_column_header(self) -> None:
        # Destroy and rebuild the header to reflect new sort
        for w in self._main.winfo_children():
            if isinstance(w, tk.Frame) and w is not self._file_scroll.frame:
                w.destroy()
        self._build_column_header()
        self._file_scroll.frame.pack(fill="both", expand=True)

    # ─── File row ─────────────────────────────────────────────────────────────
    def _add_file_row(
        self,
        idx:  int,
        name: str,
        path: str,
        node: VFSNode,
    ) -> None:
        alt_bg = T["bg_card"] if idx % 2 else T["bg_surface"]
        row = tk.Frame(self._file_inner, bg=alt_bg, cursor="hand2")
        row.pack(fill="x")

        icon = VFS.file_icon(name, node.is_dir)
        size_str = "—" if node.is_dir else VFS.human_size(node.size)
        type_str = "Folder" if node.is_dir else self._type_label(node.extension)
        mod_str  = node.modified[:16] if node.modified else "—"

        # Name column
        name_col = tk.Frame(row, bg=alt_bg)
        name_col.pack(side="left", fill="x", expand=True)

        tk.Label(
            name_col,
            text=f"  {icon}",
            font=FONTS.get("body", ()),
            fg=T["fg_primary"],
            bg=alt_bg,
        ).pack(side="left", pady=5)

        tk.Label(
            name_col,
            text=name,
            font=FONTS.get("body_bold" if node.is_dir else "body", ()),
            fg=T["fg_primary"],
            bg=alt_bg,
            anchor="w",
        ).pack(side="left")

        # Other columns
        for val, w in [(size_str, 80), (type_str, 110), (mod_str, 150)]:
            tk.Label(
                row,
                text=val,
                font=FONTS.get("small", ()),
                fg=T["fg_secondary"],
                bg=alt_bg,
                width=w // 7,
                anchor="w",
                padx=4,
            ).pack(side="left")

        # Events
        def _select(e, r=row, p=path, bg=alt_bg):
            self._selected = p
            for child in self._file_inner.winfo_children():
                child.config(bg=T["bg_selection"] if child is r else
                             (T["bg_card"] if list(self._file_inner.winfo_children()).index(child) % 2
                              else T["bg_surface"]))
                for cc in child.winfo_children():
                    cc.config(bg=child.cget("bg"))

        def _open(e, p=path, is_d=node.is_dir):
            if is_d:
                self._nav_to(p)
            else:
                self._open_file(p)

        def _rclick(e, p=path, is_d=node.is_dir):
            self._item_context_menu(e, p, is_d)

        row.bind("<Button-1>",        _select)
        row.bind("<Double-Button-1>", _open)
        row.bind("<Button-3>",        _rclick)
        row.bind("<Enter>",
            lambda e, r=row, bg=alt_bg:
                r.config(bg=T["bg_hover"]) if self._selected != path else None)
        row.bind("<Leave>",
            lambda e, r=row, bg=alt_bg, p=path:
                r.config(bg=T["bg_selection"] if self._selected == p else bg))

        for child in row.winfo_children():
            child.bind("<Button-1>",        _select)
            child.bind("<Double-Button-1>", _open)
            child.bind("<Button-3>",        _rclick)

    # ─── Navigation ───────────────────────────────────────────────────────────
    def _nav_to(self, path: str) -> None:
        path = self.wm.vfs.expand(path)
        if not self.wm.vfs.is_dir(path):
            notify(self.wm.root, "Not a folder", path, kind="warning")
            return
        self._back_stack.append(self._cwd)
        self._fwd_stack.clear()
        self._cwd = path
        self._load_dir()

    def _go_back(self) -> None:
        if self._back_stack:
            self._fwd_stack.append(self._cwd)
            self._cwd = self._back_stack.pop()
            self._load_dir()

    def _go_forward(self) -> None:
        if self._fwd_stack:
            self._back_stack.append(self._cwd)
            self._cwd = self._fwd_stack.pop()
            self._load_dir()

    def _go_up(self) -> None:
        parent = VFS.dirname(self._cwd)
        if parent != self._cwd:
            self._nav_to(parent)

    # ─── File operations ──────────────────────────────────────────────────────
    def _open_selected(self) -> None:
        if not self._selected:
            return
        node = self.wm.vfs.get_node(self._selected)
        if node and node.is_dir:
            self._nav_to(self._selected)
        else:
            self._open_file(self._selected)

    def _open_file(self, path: str) -> None:
        self.wm.vfs.record_recent(path)
        self.wm.open_text_editor(file_path=path)

    def _open_in_editor(self) -> None:
        if self._selected and self.wm.vfs.is_file(self._selected):
            self.wm.open_text_editor(file_path=self._selected)

    def _new_folder(self) -> None:
        self._input_dialog(
            "New Folder", "Folder name:", "New Folder",
            lambda name: self._do_mkdir(name),
        )

    def _do_mkdir(self, name: str) -> None:
        path = VFS.join(self._cwd, name)
        if self.wm.vfs.mkdir(path):
            self._load_dir()
            notify(self.wm.root, "Folder Created", name, kind="success")
        else:
            notify(self.wm.root, "Error", "Could not create folder", kind="danger")

    def _new_file(self) -> None:
        self._input_dialog(
            "New File", "File name:", "untitled.txt",
            lambda name: self._do_new_file(name),
        )

    def _do_new_file(self, name: str) -> None:
        path = VFS.join(self._cwd, name)
        if self.wm.vfs.write(path, ""):
            self._load_dir()
        else:
            notify(self.wm.root, "Error", "Could not create file", kind="danger")

    def _copy(self) -> None:
        if self._selected:
            self._clipboard = ("copy", self._selected)
            self.wm.clip.copy(self._selected, source="file_manager")
            notify(self.wm.root, "Copied",
                   VFS.basename(self._selected), kind="info")

    def _cut(self) -> None:
        if self._selected:
            self._clipboard = ("cut", self._selected)
            notify(self.wm.root, "Cut",
                   VFS.basename(self._selected), kind="info")

    def _paste(self) -> None:
        if not self._clipboard:
            return
        action, src = self._clipboard
        name = VFS.basename(src)
        dst  = VFS.join(self._cwd, name)
        if action == "copy":
            ok = self.wm.vfs.copy(src, dst)
        else:
            ok = self.wm.vfs.move(src, dst)
            if ok:
                self._clipboard = None
        if ok:
            self._load_dir()
            notify(self.wm.root, "Pasted", name, kind="success")
        else:
            notify(self.wm.root, "Paste Failed", "", kind="danger")

    def _delete_selected(self) -> None:
        if self._selected:
            self._confirm_dialog(
                "Delete",
                f"Delete '{VFS.basename(self._selected)}'?",
                lambda: self._do_delete(self._selected),
            )

    def _do_delete(self, path: str) -> None:
        name = VFS.basename(path)
        if self.wm.vfs.delete(path, recursive=True):
            self._selected = None
            self._load_dir()
            notify(self.wm.root, "Deleted", name, kind="success")
        else:
            notify(self.wm.root, "Cannot Delete", name, kind="danger")

    def _rename_selected(self) -> None:
        if not self._selected:
            return
        old_name = VFS.basename(self._selected)
        self._input_dialog(
            "Rename", "New name:", old_name,
            lambda name: self._do_rename(self._selected, name),
        )

    def _do_rename(self, src: str, new_name: str) -> None:
        dst = VFS.join(VFS.dirname(src), new_name)
        if self.wm.vfs.rename(src, dst):
            self._selected = dst
            self._load_dir()
        else:
            notify(self.wm.root, "Rename Failed", "", kind="danger")

    def _select_all(self) -> None:
        pass   # visual-only; full select-all in a future iteration

    def _toggle_hidden(self) -> None:
        self._show_hidden = not self._show_hidden
        self._load_dir()

    def _set_sort(self, col: str) -> None:
        if self._sort_col == col:
            self._sort_rev = not self._sort_rev
        else:
            self._sort_col = col
            self._sort_rev = False
        self._load_dir()

    def _set_view(self, mode: str) -> None:
        self._view_mode = mode
        self._load_dir()

    # ─── Search ───────────────────────────────────────────────────────────────
    def _do_search(self) -> None:
        q = self._search_var.get().strip()
        if not q:
            self._load_dir()
            return
        for w in self._file_inner.winfo_children():
            w.destroy()
        results = self.wm.vfs.search(VFS.HOME, q)
        tk.Label(
            self._file_inner,
            text=f"Search results for: \"{q}\"",
            font=FONTS.get("body_bold", ()),
            fg=T["accent"],
            bg=T["bg_surface"],
            anchor="w",
            padx=12,
            pady=8,
        ).pack(fill="x")
        for i, path in enumerate(results[:80]):
            node = self.wm.vfs.get_node(path)
            if not node:
                continue
            self._add_file_row(i, node.name, path, node)
        if not results:
            tk.Label(
                self._file_inner,
                text="No results found.",
                font=FONTS.get("body", ()),
                fg=T["fg_tertiary"],
                bg=T["bg_surface"],
                pady=30,
            ).pack()
        self._set_status(f"{len(results)} results for \"{q}\"")

    # ─── Context menu ─────────────────────────────────────────────────────────
    def _item_context_menu(
        self,
        e:     tk.Event,
        path:  str,
        is_dir: bool,
    ) -> None:
        self._selected = path
        items = [
            ("Open",              lambda: self._nav_to(path) if is_dir else self._open_file(path)),
        ]
        if not is_dir:
            items.append(("Open in Text Editor", lambda: self.wm.open_text_editor(file_path=path)))
        items += [
            ("---", None),
            ("Copy",    lambda: (setattr(self, "_selected", path), self._copy())),
            ("Cut",     lambda: (setattr(self, "_selected", path), self._cut())),
            ("---", None),
            ("Rename",  lambda: (setattr(self, "_selected", path), self._rename_selected())),
            ("Delete",  lambda: self._do_delete(path)),
            ("---", None),
            ("Properties", lambda: self._show_properties_for(path)),
        ]
        self.wm._show_context_menu(e.x_root, e.y_root, items)

    # ─── Bookmark management ──────────────────────────────────────────────────
    def _add_bookmark(self) -> None:
        raw = self.wm.vfs.read(VFS.CONFIG + "/bookmarks.json") or "[]"
        try:
            bms = json.loads(raw)
        except Exception:
            bms = []
        if self._cwd not in bms:
            bms.append(self._cwd)
            self.wm.vfs.write(VFS.CONFIG + "/bookmarks.json", json.dumps(bms))
            notify(self.wm.root, "Bookmark Added",
                   VFS.basename(self._cwd), kind="success")
            self._refresh_sidebar()

    def _manage_bookmarks(self) -> None:
        notify(self.wm.root, "Bookmarks", "Edit bookmarks.json in Documents.", kind="info")

    # ─── Properties dialog ────────────────────────────────────────────────────
    def _show_properties(self) -> None:
        if self._selected:
            self._show_properties_for(self._selected)

    def _show_properties_for(self, path: str) -> None:
        node = self.wm.vfs.get_node(path)
        if not node:
            return
        d = tk.Toplevel(self.frame)
        d.title("Properties")
        d.config(bg=T["bg_surface"])
        d.geometry("360x260")
        d.grab_set()

        tk.Label(
            d,
            text=f"{VFS.file_icon(node.name, node.is_dir)}  {node.name}",
            font=FONTS.get("h2", ()),
            fg=T["fg_primary"],
            bg=T["bg_surface"],
            pady=12,
        ).pack()

        fl_separator(d).pack(fill="x", padx=16)

        for label, value in [
            ("Type",        "Folder" if node.is_dir else self._type_label(node.extension)),
            ("Location",    VFS.dirname(path)),
            ("Size",        "—" if node.is_dir else VFS.human_size(node.size)),
            ("Created",     node.created),
            ("Modified",    node.modified),
            ("Permissions", node.permissions),
            ("Owner",       node.owner),
        ]:
            row = tk.Frame(d, bg=T["bg_surface"])
            row.pack(fill="x", padx=20, pady=3)
            tk.Label(
                row,
                text=label + ":",
                font=FONTS.get("small_bold", ()),
                fg=T["fg_secondary"],
                bg=T["bg_surface"],
                width=12,
                anchor="w",
            ).pack(side="left")
            tk.Label(
                row,
                text=str(value),
                font=FONTS.get("small", ()),
                fg=T["fg_primary"],
                bg=T["bg_surface"],
                anchor="w",
            ).pack(side="left")

        fl_button(d, "Close", d.destroy, style="secondary").pack(pady=12)

    # ─── Utility dialogs ──────────────────────────────────────────────────────
    def _input_dialog(
        self,
        title:   str,
        prompt:  str,
        default: str,
        on_ok:   Callable,
    ) -> None:
        d = tk.Toplevel(self.frame)
        d.title(title)
        d.config(bg=T["bg_surface"])
        d.geometry("340x130")
        d.grab_set()

        tk.Label(
            d,
            text=prompt,
            font=FONTS.get("body", ()),
            fg=T["fg_primary"],
            bg=T["bg_surface"],
            pady=14,
        ).pack()

        e = fl_entry(d)
        e.pack(fill="x", padx=20)
        e.insert(0, default)
        e.select_range(0, "end")
        e.focus_set()

        def _ok():
            val = e.get().strip()
            if val:
                d.destroy()
                on_ok(val)

        e.bind("<Return>", lambda ev: _ok())
        fl_button(d, "OK", _ok, style="primary").pack(pady=10)

    def _confirm_dialog(
        self,
        title:   str,
        message: str,
        on_yes:  Callable,
    ) -> None:
        d = tk.Toplevel(self.frame)
        d.title(title)
        d.config(bg=T["bg_surface"])
        d.geometry("320x120")
        d.grab_set()

        tk.Label(
            d,
            text=message,
            font=FONTS.get("body", ()),
            fg=T["fg_primary"],
            bg=T["bg_surface"],
            pady=20,
            wraplength=280,
        ).pack()

        row = tk.Frame(d, bg=T["bg_surface"])
        row.pack()
        fl_button(row, "Delete", lambda: (d.destroy(), on_yes()),
                  style="danger").pack(side="left", padx=8)
        fl_button(row, "Cancel", d.destroy,
                  style="secondary").pack(side="left", padx=8)

    # ─── Helpers ─────────────────────────────────────────────────────────────
    @staticmethod
    def _type_label(ext: str) -> str:
        types = {
            "txt": "Text File",    "md": "Markdown",       "py": "Python Script",
            "js":  "JavaScript",   "ts": "TypeScript",     "html": "HTML File",
            "css": "Stylesheet",   "json": "JSON File",    "xml": "XML File",
            "csv": "CSV File",     "log": "Log File",      "sh": "Shell Script",
            "jpg": "JPEG Image",   "png": "PNG Image",     "gif": "GIF Image",
            "svg": "SVG Image",    "mp3": "Audio File",    "mp4": "Video File",
            "pdf": "PDF Document", "zip": "ZIP Archive",   "tar": "TAR Archive",
            "doc": "Word Doc",     "docx": "Word Doc",     "xls": "Spreadsheet",
        }
        return types.get(ext, f"{ext.upper()} File" if ext else "File")


# ═══════════════════════════════════════════════════════════════════════════════
#  §18  TEXT EDITOR
# ═══════════════════════════════════════════════════════════════════════════════

class TextEditorWin(BaseWin):
    """
    Multi-tab text and code editor.

    Features:
      • Unlimited tabs (open/new/close)
      • Syntax highlighting for Python, JS, HTML, CSS, JSON
      • Line-number gutter
      • Find / Replace dialogs
      • Word-wrap toggle, zoom in/out
      • Auto-save indicator (● modified dot in tab)
      • Status bar: line, column, char count, encoding
    """

    def __init__(self, wm: WM, file_path: Optional[str] = None):
        self._tabs:       List[Dict[str, Any]] = []
        self._active_tab: int = 0
        self._init_file   = file_path
        super().__init__(wm, "Text Editor", 880, 600, "📝")

    # ─── Build ────────────────────────────────────────────────────────────────
    def _build(self) -> None:
        self._show_menubar()
        self._build_menus()
        self._show_statusbar()
        self.client.config(bg=T["bg_surface"])

        # Tab bar
        self._tab_bar = tk.Frame(self.client, bg=T["bg_elevated"], height=34)
        self._tab_bar.pack(fill="x")
        self._tab_bar.pack_propagate(False)

        # New-tab button
        self._new_tab_btn = tk.Label(
            self._tab_bar,
            text=" ＋ ",
            font=FONTS.get("body_bold", ()),
            fg=T["fg_tertiary"],
            bg=T["bg_elevated"],
            padx=6,
            cursor="hand2",
        )
        self._new_tab_btn.pack(side="right", pady=4)
        self._new_tab_btn.bind("<Button-1>", lambda e: self._new_tab())

        # Editor body
        self._editor_host = tk.Frame(self.client, bg=T["bg_input"])
        self._editor_host.pack(fill="both", expand=True)

        # Line-number canvas
        self._lnum_canvas = fl_canvas(self._editor_host, bg_key="bg_elevated")
        self._lnum_canvas.config(width=52)
        self._lnum_canvas.pack(side="left", fill="y")

        # Text widget placeholder (rebuilt per tab)
        self._txt: Optional[tk.Text] = None

        self._new_tab(path=self._init_file)

    # ─── Menus ────────────────────────────────────────────────────────────────
    def _build_menus(self) -> None:
        self._add_menu("File", [
            ("New Tab",       self._new_tab,           "Ctrl+T"),
            ("Open…",         self._open_file_dialog,  "Ctrl+O"),
            ("Save",          self._save,              "Ctrl+S"),
            ("Save As…",      self._save_as,           "Ctrl+Shift+S"),
            ("---",           None),
            ("Close Tab",     self._close_tab,         "Ctrl+W"),
        ])
        self._add_menu("Edit", [
            ("Undo",          lambda: self._txt and self._txt.edit_undo(),  "Ctrl+Z"),
            ("Redo",          lambda: self._txt and self._txt.edit_redo(),  "Ctrl+Y"),
            ("---",           None),
            ("Cut",           lambda: self._txt and self._txt.event_generate("<<Cut>>"),   "Ctrl+X"),
            ("Copy",          lambda: self._txt and self._txt.event_generate("<<Copy>>"),  "Ctrl+C"),
            ("Paste",         lambda: self._txt and self._txt.event_generate("<<Paste>>"), "Ctrl+V"),
            ("Select All",    lambda: self._txt and self._txt.tag_add("sel","1.0","end"),  "Ctrl+A"),
            ("---",           None),
            ("Find…",         self._find_dialog,       "Ctrl+F"),
            ("Replace…",      self._replace_dialog,    "Ctrl+H"),
            ("Go to Line…",   self._goto_line_dialog,  "Ctrl+G"),
        ])
        self._add_menu("View", [
            ("Word Wrap",     self._toggle_wrap),
            ("Line Numbers",  self._toggle_line_numbers),
            ("---",           None),
            ("Zoom In",       lambda: self._zoom(+1),  "Ctrl++"),
            ("Zoom Out",      lambda: self._zoom(-1),  "Ctrl+-"),
            ("Reset Zoom",    lambda: self._zoom(0)),
        ])
        self._add_menu("Format", [
            ("Indent Selection",   self._indent),
            ("Unindent Selection", self._unindent),
            ("---",                None),
            ("UPPERCASE",          lambda: self._transform("upper")),
            ("lowercase",          lambda: self._transform("lower")),
            ("Title Case",         lambda: self._transform("title")),
        ])

    # ─── Tab management ───────────────────────────────────────────────────────
    def _new_tab(
        self,
        title:   str            = "Untitled",
        content: str            = "",
        path:    Optional[str]  = None,
    ) -> None:
        if path and self.wm.vfs.is_file(path):
            content = self.wm.vfs.read(path) or ""
            title   = VFS.basename(path)

        tab = {
            "title":      title,
            "path":       path,
            "modified":   False,
            "wrap":       True,
            "line_nums":  True,
            "font_size":  12,
            "content":    content,
        }
        self._tabs.append(tab)
        self._switch_tab(len(self._tabs) - 1, content=content)

    def _switch_tab(self, idx: int, content: Optional[str] = None) -> None:
        # Save current text back to tab dict
        if self._txt and 0 <= self._active_tab < len(self._tabs):
            self._tabs[self._active_tab]["content"] = self._txt.get("1.0", "end-1c")

        self._active_tab = idx
        self._rebuild_tab_bar()
        self._rebuild_editor(content)

    def _rebuild_tab_bar(self) -> None:
        # Destroy all tab buttons (keep new-tab btn)
        for w in list(self._tab_bar.winfo_children()):
            if w is not self._new_tab_btn:
                w.destroy()

        for i, tab in enumerate(self._tabs):
            active = i == self._active_tab
            modified_dot = " ●" if tab["modified"] else ""
            label = tab["title"][:18] + modified_dot

            f = tk.Frame(
                self._tab_bar,
                bg=T["bg_surface"] if active else T["bg_elevated"],
                cursor="hand2",
            )
            f.pack(side="left")

            tk.Label(
                f,
                text=label,
                font=FONTS.get("tab_active" if active else "tab", ()),
                fg=T["fg_primary"] if active else T["fg_secondary"],
                bg=T["bg_surface"] if active else T["bg_elevated"],
                padx=12,
                pady=6,
            ).pack(side="left")

            close_lbl = tk.Label(
                f,
                text="✕",
                font=FONTS.get("micro", ()),
                fg=T["fg_tertiary"],
                bg=T["bg_surface"] if active else T["bg_elevated"],
                padx=4,
                cursor="hand2",
            )
            close_lbl.pack(side="right")

            if active:
                tk.Frame(self._tab_bar, height=2,
                         bg=T["accent"]).pack(side="left")

            f.bind("<Button-1>", lambda e, i=i: self._switch_tab(i))
            close_lbl.bind("<Button-1>", lambda e, i=i: self._close_tab(i))

            f.bind("<Enter>",
                lambda e, fr=f, a=active:
                    fr.config(bg=T["bg_hover"] if not a else T["bg_surface"]))
            f.bind("<Leave>",
                lambda e, fr=f, a=active:
                    fr.config(bg=T["bg_surface"] if a else T["bg_elevated"]))

    def _rebuild_editor(self, content: Optional[str] = None) -> None:
        # Destroy old text widget
        if self._txt:
            self._txt.destroy()
        # Destroy old scrollbar
        for w in self._editor_host.winfo_children():
            if isinstance(w, tk.Scrollbar):
                w.destroy()

        tab = self._tabs[self._active_tab]
        fam = FONTS.get("mono", ("Consolas", 12))[0]

        self._txt = tk.Text(
            self._editor_host,
            font=(fam, tab["font_size"]),
            bg=T["bg_input"],
            fg=T["fg_primary"],
            insertbackground=T["accent"],
            selectbackground=T["bg_selection"],
            selectforeground=T["fg_primary"],
            relief="flat",
            bd=0,
            undo=True,
            wrap="word" if tab["wrap"] else "none",
            spacing1=2,
            spacing3=2,
            padx=8,
            pady=4,
        )
        self._txt.pack(side="left", fill="both", expand=True)

        vsb = fl_scrollbar(self._editor_host, command=self._txt.yview)
        vsb.pack(side="right", fill="y")
        self._txt.configure(yscrollcommand=vsb.set)

        # Load content
        text = content if content is not None else tab.get("content", "")
        self._txt.insert("1.0", text)
        self._txt.edit_reset()
        self._txt.edit_modified(False)

        # Bindings
        self._txt.bind("<KeyRelease>",    self._on_key)
        self._txt.bind("<ButtonRelease>", self._update_status)
        self._txt.bind("<Control-s>",     lambda e: self._save())
        self._txt.bind("<Control-f>",     lambda e: self._find_dialog())
        self._txt.bind("<Control-z>",     lambda e: self._txt.edit_undo())
        self._txt.bind("<Control-y>",     lambda e: self._txt.edit_redo())

        self._update_line_numbers()
        self._update_status()
        self._apply_syntax()
        self._txt.focus_set()

    def _close_tab(self, idx: Optional[int] = None) -> None:
        if idx is None:
            idx = self._active_tab
        if len(self._tabs) <= 1:
            self.close()
            return
        self._tabs.pop(idx)
        new_idx = max(0, min(self._active_tab, len(self._tabs) - 1))
        self._switch_tab(new_idx)

    # ─── Key events ───────────────────────────────────────────────────────────
    def _on_key(self, e: tk.Event = None) -> None:
        tab = self._tabs[self._active_tab]
        if not tab["modified"] and self._txt and self._txt.edit_modified():
            tab["modified"] = True
            self._rebuild_tab_bar()
        self._update_line_numbers()
        self._update_status()
        # Debounced syntax highlighting
        if hasattr(self, "_syntax_after"):
            self.frame.after_cancel(self._syntax_after)
        self._syntax_after = self.frame.after(400, self._apply_syntax)

    # ─── Line numbers ─────────────────────────────────────────────────────────
    def _update_line_numbers(self) -> None:
        if not self._txt:
            return
        tab = self._tabs[self._active_tab]
        if not tab.get("line_nums", True):
            self._lnum_canvas.config(width=0)
            return
        self._lnum_canvas.config(width=52)
        self._lnum_canvas.delete("all")
        i = self._txt.index("@0,0")
        while True:
            dline = self._txt.dlineinfo(i)
            if dline is None:
                break
            line_num = int(i.split(".")[0])
            self._lnum_canvas.create_text(
                46,
                dline[1] + dline[3] // 2,
                text=str(line_num),
                fill=T["fg_tertiary"],
                font=FONTS.get("mono_xs", ()),
                anchor="e",
            )
            next_i = self._txt.index(f"{i}+1line")
            if next_i == i:
                break
            i = next_i

    # ─── Status bar ───────────────────────────────────────────────────────────
    def _update_status(self, e: tk.Event = None) -> None:
        if not self._txt:
            return
        pos  = self._txt.index("insert")
        ln, col = pos.split(".")
        chars  = len(self._txt.get("1.0", "end-1c"))
        lines  = int(self._txt.index("end-1c").split(".")[0])
        tab    = self._tabs[self._active_tab]
        path   = tab.get("path") or "Unsaved"
        self._set_status(
            f"Ln {ln}, Col {int(col)+1}  │  {lines} lines  │  {chars} chars  │  UTF-8  │  {path}"
        )

    # ─── Syntax highlighting ──────────────────────────────────────────────────
    _PY_KW    = r'\b(False|None|True|and|as|assert|async|await|break|class|continue|def|del|elif|else|except|finally|for|from|global|if|import|in|is|lambda|nonlocal|not|or|pass|raise|return|try|while|with|yield)\b'
    _PY_BTIN  = r'\b(abs|all|any|bin|bool|bytes|callable|chr|dict|dir|divmod|enumerate|eval|exec|filter|float|format|frozenset|getattr|globals|hasattr|hash|help|hex|id|input|int|isinstance|issubclass|iter|len|list|locals|map|max|min|next|object|oct|open|ord|pow|print|property|range|repr|reversed|round|set|setattr|slice|sorted|staticmethod|str|sum|super|tuple|type|vars|zip)\b'
    _PY_DECO  = r'@\w+'
    _PY_NUM   = r'\b\d+\.?\d*([eE][+-]?\d+)?\b'
    _PY_STR   = r'("""[\s\S]*?"""|\'\'\'[\s\S]*?\'\'\'|"[^"\\\n]*"|\'[^\'\\\n]*\')'
    _PY_CMT   = r'#[^\n]*'

    def _apply_syntax(self) -> None:
        if not self._txt:
            return
        tab  = self._tabs[self._active_tab]
        path = tab.get("path", "")
        ext  = path.rsplit(".", 1)[-1].lower() if "." in path else ""

        # Remove all existing syntax tags
        for tag in ("kw", "builtin", "string", "comment", "number",
                    "decorator", "tag_html", "attr", "value"):
            self._txt.tag_remove(tag, "1.0", "end")

        if ext not in ("py", "js", "html", "css", "json"):
            return

        content = self._txt.get("1.0", "end")

        def _tag(pattern, tag_name, flags=0):
            for m in re.finditer(pattern, content, flags):
                s = f"1.0+{m.start()}c"
                e = f"1.0+{m.end()}c"
                self._txt.tag_add(tag_name, s, e)

        if ext == "py":
            self._txt.tag_config("kw",        foreground=T["accent_light"])
            self._txt.tag_config("builtin",   foreground=T["info"])
            self._txt.tag_config("string",    foreground=T["success"])
            self._txt.tag_config("comment",   foreground=T["fg_tertiary"])
            self._txt.tag_config("number",    foreground=T["warning"])
            self._txt.tag_config("decorator", foreground=T["warning"])
            _tag(self._PY_STR,   "string",    re.DOTALL)
            _tag(self._PY_CMT,   "comment")
            _tag(self._PY_KW,    "kw")
            _tag(self._PY_BTIN,  "builtin")
            _tag(self._PY_DECO,  "decorator")
            _tag(self._PY_NUM,   "number")

        elif ext == "json":
            self._txt.tag_config("string",  foreground=T["success"])
            self._txt.tag_config("number",  foreground=T["warning"])
            self._txt.tag_config("kw",      foreground=T["accent_light"])
            _tag(r'"[^"\\]*"',  "string")
            _tag(r'\b\d+\.?\d*\b', "number")
            _tag(r'\b(true|false|null)\b', "kw")

        elif ext in ("html",):
            self._txt.tag_config("tag_html", foreground=T["accent_light"])
            self._txt.tag_config("attr",     foreground=T["warning"])
            self._txt.tag_config("string",   foreground=T["success"])
            self._txt.tag_config("comment",  foreground=T["fg_tertiary"])
            _tag(r'<!--[\s\S]*?-->',       "comment", re.DOTALL)
            _tag(r'<[/!]?\w+',             "tag_html")
            _tag(r'\b\w+=',                "attr")
            _tag(r'"[^"]*"',               "string")

        elif ext == "css":
            self._txt.tag_config("kw",     foreground=T["accent_light"])
            self._txt.tag_config("string", foreground=T["success"])
            self._txt.tag_config("number", foreground=T["warning"])
            self._txt.tag_config("comment",foreground=T["fg_tertiary"])
            _tag(r'/\*[\s\S]*?\*/', "comment", re.DOTALL)
            _tag(r'[\w-]+(?=\s*:)', "kw")
            _tag(r'"[^"]*"',        "string")
            _tag(r'\b\d+\.?\d*(px|em|rem|%|vh|vw|pt)?\b', "number")

    # ─── File operations ──────────────────────────────────────────────────────
    def _open_file_dialog(self) -> None:
        d = tk.Toplevel(self.frame)
        d.title("Open File")
        d.config(bg=T["bg_surface"])
        d.geometry("420x110")
        d.grab_set()

        tk.Label(d, text="File path:", font=FONTS.get("body", ()),
                 fg=T["fg_primary"], bg=T["bg_surface"], pady=12).pack()
        e = fl_entry(d, placeholder=VFS.DOCS + "/")
        e.pack(fill="x", padx=20)
        e.focus_set()

        def _ok():
            path = e.get().strip()
            if path and self.wm.vfs.is_file(path):
                content = self.wm.vfs.read(path) or ""
                self._new_tab(VFS.basename(path), content, path)
            d.destroy()

        fl_button(d, "Open", _ok, style="primary").pack(pady=10)
        e.bind("<Return>", lambda ev: _ok())

    def _save(self) -> None:
        tab = self._tabs[self._active_tab]
        if not tab.get("path"):
            self._save_as()
            return
        content = self._txt.get("1.0", "end-1c") if self._txt else ""
        self.wm.vfs.write(tab["path"], content)
        tab["modified"] = False
        self._txt.edit_modified(False) if self._txt else None
        self._rebuild_tab_bar()
        notify(self.wm.root, "Saved", VFS.basename(tab["path"]), kind="success")

    def _save_as(self) -> None:
        tab = self._tabs[self._active_tab]
        d = tk.Toplevel(self.frame)
        d.title("Save As")
        d.config(bg=T["bg_surface"])
        d.geometry("420x110")
        d.grab_set()

        tk.Label(d, text="Save path:", font=FONTS.get("body", ()),
                 fg=T["fg_primary"], bg=T["bg_surface"], pady=12).pack()
        e = fl_entry(d)
        e.pack(fill="x", padx=20)
        default_path = tab.get("path") or VFS.DOCS + "/" + tab["title"]
        e.insert(0, default_path)
        e.focus_set()

        def _ok():
            path = e.get().strip()
            if path:
                content = self._txt.get("1.0", "end-1c") if self._txt else ""
                self.wm.vfs.write(path, content)
                tab["path"]     = path
                tab["title"]    = VFS.basename(path)
                tab["modified"] = False
                self._rebuild_tab_bar()
                self.set_title(f"Text Editor — {tab['title']}")
                notify(self.wm.root, "Saved", VFS.basename(path), kind="success")
            d.destroy()

        fl_button(d, "Save", _ok, style="primary").pack(pady=10)
        e.bind("<Return>", lambda ev: _ok())

    # ─── Find / Replace ───────────────────────────────────────────────────────
    def _find_dialog(self) -> None:
        d = tk.Toplevel(self.frame)
        d.title("Find")
        d.config(bg=T["bg_surface"])
        d.geometry("380x120")

        row1 = tk.Frame(d, bg=T["bg_surface"])
        row1.pack(fill="x", padx=16, pady=10)
        tk.Label(row1, text="Find:", font=FONTS.get("body", ()),
                 fg=T["fg_primary"], bg=T["bg_surface"], width=8).pack(side="left")
        fe = fl_entry(row1)
        fe.pack(side="left", fill="x", expand=True)
        fe.focus_set()

        self._find_matches:  List[str] = []
        self._find_idx:      int       = 0

        def _find():
            if not self._txt:
                return
            self._txt.tag_remove("found", "1.0", "end")
            q = fe.get()
            if not q:
                return
            self._find_matches = []
            start = "1.0"
            while True:
                pos = self._txt.search(q, start, stopindex="end", nocase=True)
                if not pos:
                    break
                end_pos = f"{pos}+{len(q)}c"
                self._txt.tag_add("found", pos, end_pos)
                self._find_matches.append(pos)
                start = end_pos
            self._txt.tag_config("found",
                background=T["warning_muted"],
                foreground=T["fg_primary"])
            if self._find_matches:
                self._find_idx = 0
                self._txt.see(self._find_matches[0])

        def _next():
            if self._find_matches:
                self._find_idx = (self._find_idx + 1) % len(self._find_matches)
                self._txt.see(self._find_matches[self._find_idx])

        def _prev():
            if self._find_matches:
                self._find_idx = (self._find_idx - 1) % len(self._find_matches)
                self._txt.see(self._find_matches[self._find_idx])

        btn_row = tk.Frame(d, bg=T["bg_surface"])
        btn_row.pack(pady=4)
        fl_button(btn_row, "Find",  _find, style="primary").pack(side="left", padx=4)
        fl_button(btn_row, "Next",  _next, style="secondary").pack(side="left", padx=4)
        fl_button(btn_row, "Prev",  _prev, style="secondary").pack(side="left", padx=4)
        fl_button(btn_row, "Close", d.destroy, style="ghost").pack(side="left", padx=4)
        fe.bind("<Return>", lambda e: _find())

    def _replace_dialog(self) -> None:
        d = tk.Toplevel(self.frame)
        d.title("Find & Replace")
        d.config(bg=T["bg_surface"])
        d.geometry("400x160")

        for label_text, attr in [("Find:", "_rep_find"), ("Replace:", "_rep_with")]:
            r = tk.Frame(d, bg=T["bg_surface"])
            r.pack(fill="x", padx=16, pady=5)
            tk.Label(r, text=label_text, font=FONTS.get("body", ()),
                     fg=T["fg_primary"], bg=T["bg_surface"], width=9).pack(side="left")
            e = fl_entry(r)
            e.pack(side="left", fill="x", expand=True)
            setattr(self, attr, e)

        self._rep_find.focus_set()

        def _replace_all():
            if not self._txt:
                return
            content = self._txt.get("1.0", "end")
            find    = self._rep_find.get()
            rep     = self._rep_with.get()
            if not find:
                return
            new_content = content.replace(find, rep)
            self._txt.delete("1.0", "end")
            self._txt.insert("1.0", new_content)
            count = content.count(find)
            notify(self.wm.root, "Replaced", f"{count} occurrence(s)", kind="success")

        btn_row = tk.Frame(d, bg=T["bg_surface"])
        btn_row.pack(pady=6)
        fl_button(btn_row, "Replace All", _replace_all, style="primary").pack(side="left", padx=4)
        fl_button(btn_row, "Close", d.destroy, style="ghost").pack(side="left", padx=4)

    def _goto_line_dialog(self) -> None:
        d = tk.Toplevel(self.frame)
        d.title("Go to Line")
        d.config(bg=T["bg_surface"])
        d.geometry("280x100")
        d.grab_set()
        tk.Label(d, text="Line number:", font=FONTS.get("body", ()),
                 fg=T["fg_primary"], bg=T["bg_surface"], pady=12).pack()
        e = fl_entry(d)
        e.pack(fill="x", padx=20)
        e.focus_set()

        def _go():
            try:
                ln = int(e.get().strip())
                if self._txt:
                    self._txt.see(f"{ln}.0")
                    self._txt.mark_set("insert", f"{ln}.0")
            except ValueError:
                pass
            d.destroy()

        e.bind("<Return>", lambda ev: _go())
        fl_button(d, "Go", _go, style="primary").pack(pady=6)

    # ─── View toggles ─────────────────────────────────────────────────────────
    def _toggle_wrap(self) -> None:
        tab = self._tabs[self._active_tab]
        tab["wrap"] = not tab.get("wrap", True)
        if self._txt:
            self._txt.config(wrap="word" if tab["wrap"] else "none")

    def _toggle_line_numbers(self) -> None:
        tab = self._tabs[self._active_tab]
        tab["line_nums"] = not tab.get("line_nums", True)
        self._update_line_numbers()

    def _zoom(self, delta: int) -> None:
        tab = self._tabs[self._active_tab]
        if delta == 0:
            tab["font_size"] = 12
        else:
            tab["font_size"] = max(8, min(32, tab.get("font_size", 12) + delta))
        if self._txt:
            fam = FONTS.get("mono", ("Consolas", 12))[0]
            self._txt.config(font=(fam, tab["font_size"]))

    # ─── Format operations ────────────────────────────────────────────────────
    def _indent(self) -> None:
        if not self._txt:
            return
        try:
            sel_start = self._txt.index("sel.first linestart")
            sel_end   = self._txt.index("sel.last lineend")
            lines = self._txt.get(sel_start, sel_end).split("\n")
            indented = "\n".join("    " + l for l in lines)
            self._txt.delete(sel_start, sel_end)
            self._txt.insert(sel_start, indented)
        except tk.TclError:
            pass

    def _unindent(self) -> None:
        if not self._txt:
            return
        try:
            sel_start = self._txt.index("sel.first linestart")
            sel_end   = self._txt.index("sel.last lineend")
            lines = self._txt.get(sel_start, sel_end).split("\n")
            unindented = "\n".join(
                l[4:] if l.startswith("    ") else l.lstrip("\t") for l in lines
            )
            self._txt.delete(sel_start, sel_end)
            self._txt.insert(sel_start, unindented)
        except tk.TclError:
            pass

    def _transform(self, mode: str) -> None:
        if not self._txt:
            return
        try:
            text = self._txt.get("sel.first", "sel.last")
            if mode == "upper":   text = text.upper()
            elif mode == "lower": text = text.lower()
            elif mode == "title": text = text.title()
            self._txt.delete("sel.first", "sel.last")
            self._txt.insert("insert", text)
        except tk.TclError:
            pass


# ═══════════════════════════════════════════════════════════════════════════════
#  §19  TERMINAL
# ═══════════════════════════════════════════════════════════════════════════════

class TerminalWin(BaseWin):
    """
    Full VFS-backed command-line shell with 70+ built-in commands.

    Features:
      • Command history (↑ / ↓)
      • Tab completion
      • Aliases  (ll, la, cls …)
      • Environment variables  (export KEY=VAL)
      • Pipe-style chaining  (cmd1 | cmd2)  — limited simulation
      • Colour-coded output by tag
      • neofetch, python3 exec, man pages
    """

    MOTD = (
        f"PyOS {VERSION} Terminal — type 'help' for a command list\n"
        "─" * 52 + "\n"
    )

    def __init__(self, wm: WM):
        self._cwd      = VFS.HOME
        self._history: List[str] = []
        self._hist_idx = -1
        self._env: Dict[str, str] = {
            "USER":    "user",
            "HOME":    VFS.HOME,
            "PATH":    "/usr/bin:/bin",
            "SHELL":   "/bin/pysh",
            "TERM":    "pyterm-256color",
            "LANG":    "en_US.UTF-8",
            "VERSION": VERSION,
            "PS1":     "user@pyos",
        }
        self._aliases: Dict[str, str] = {
            "ll":   "ls -la",
            "la":   "ls -a",
            "l":    "ls",
            "cls":  "clear",
            "dir":  "ls",
            "md":   "mkdir",
            "del":  "rm",
            "copy": "cp",
            "move": "mv",
        }
        super().__init__(wm, "Terminal", 800, 520, "⌨")

    # ─── Build ────────────────────────────────────────────────────────────────
    def _build(self) -> None:
        self._show_menubar()
        self._add_menu("File", [
            ("New Window", lambda: TerminalWin(self.wm), "Ctrl+N"),
            ("Clear",      self._clear,                  "Ctrl+L"),
            ("---",        None),
            ("Close",      self.close,                   "Ctrl+W"),
        ])
        self._add_menu("Edit", [
            ("Copy",       lambda: None, "Ctrl+C"),
            ("Paste",      lambda: None, "Ctrl+V"),
            ("Select All", lambda: self._out.tag_add("sel","1.0","end")),
        ])
        self._add_menu("Shell", [
            ("Open File Manager Here", lambda: FileManagerWin(self.wm)),
            ("Open Editor Here",       lambda: TextEditorWin(self.wm)),
            ("---",                    None),
            ("View Aliases",           lambda: self._run("alias")),
            ("Edit Env",               lambda: self._run("env")),
        ])

        self._show_statusbar()
        self.client.config(bg=T["term_bg"])

        # ── Output text area ──────────────────────────────────────────────────
        self._out = tk.Text(
            self.client,
            bg=T["term_bg"],
            fg=T["term_fg"],
            font=FONTS.get("mono", ()),
            relief="flat",
            bd=0,
            state="disabled",
            selectbackground="#264f78",
            insertbackground=T["term_cursor"],
            wrap="word",
            padx=12,
            pady=8,
            cursor="xterm",
        )
        vsb = fl_scrollbar(self.client, command=self._out.yview)
        vsb.pack(side="right", fill="y")
        self._out.configure(yscrollcommand=vsb.set)
        self._out.pack(fill="both", expand=True)

        # Colour tags
        self._out.tag_config("prompt",   foreground=T["term_prompt"],  font=FONTS.get("mono_bold", ()))
        self._out.tag_config("path",     foreground=T["term_green"])
        self._out.tag_config("output",   foreground=T["term_fg"])
        self._out.tag_config("error",    foreground=T["term_red"])
        self._out.tag_config("success",  foreground=T["term_green"])
        self._out.tag_config("warn",     foreground=T["term_yellow"])
        self._out.tag_config("accent",   foreground=T["term_prompt"])
        self._out.tag_config("header",   foreground=T["term_purple"],  font=FONTS.get("mono_bold", ()))
        self._out.tag_config("dim",      foreground=T["fg_tertiary"])
        self._out.tag_config("bold",     font=FONTS.get("mono_bold", ()))

        # ── Input row ─────────────────────────────────────────────────────────
        inp_frame = tk.Frame(self.client, bg=T["term_bg"])
        inp_frame.pack(fill="x", pady=(0, 4))

        self._prompt_lbl = tk.Label(
            inp_frame,
            text=self._fmt_prompt(),
            font=FONTS.get("mono_bold", ()),
            bg=T["term_bg"],
            fg=T["term_prompt"],
            padx=12,
        )
        self._prompt_lbl.pack(side="left")

        self._inp = tk.Entry(
            inp_frame,
            bg=T["term_bg"],
            fg=T["term_fg"],
            font=FONTS.get("mono", ()),
            insertbackground=T["term_cursor"],
            selectbackground="#264f78",
            relief="flat",
            bd=0,
        )
        self._inp.pack(side="left", fill="x", expand=True, padx=4)
        self._inp.bind("<Return>",    self._on_enter)
        self._inp.bind("<Up>",        self._hist_up)
        self._inp.bind("<Down>",      self._hist_down)
        self._inp.bind("<Tab>",       self._tab_complete)
        self._inp.bind("<Control-l>", lambda e: self._clear())
        self._inp.bind("<Control-c>", lambda e: self._print("^C\n", "warn"))
        self._inp.bind("<Control-a>", lambda e: (self._inp.icursor(0), "break"))
        self._inp.bind("<Control-e>", lambda e: (self._inp.icursor("end"), "break"))
        self._inp.focus_set()

        self._print(self.MOTD, "dim")
        self._set_status(f"Shell: /bin/pysh  │  {self._cwd}")

    # ─── Prompt ───────────────────────────────────────────────────────────────
    def _fmt_prompt(self) -> str:
        cwd = self._cwd
        if cwd.startswith(VFS.HOME):
            cwd = "~" + cwd[len(VFS.HOME):]
        return f"user@pyos:{cwd}$ "

    # ─── Output ───────────────────────────────────────────────────────────────
    def _print(self, text: str, tag: str = "output") -> None:
        self._out.config(state="normal")
        self._out.insert("end", text, tag)
        self._out.see("end")
        self._out.config(state="disabled")

    def _clear(self) -> None:
        self._out.config(state="normal")
        self._out.delete("1.0", "end")
        self._out.config(state="disabled")

    # ─── Input handling ───────────────────────────────────────────────────────
    def _on_enter(self, e: tk.Event = None) -> None:
        raw = self._inp.get().strip()
        self._inp.delete(0, "end")
        if not raw:
            self._print(self._fmt_prompt() + "\n", "prompt")
            return
        # Expand aliases
        parts0 = raw.split()
        if parts0[0] in self._aliases:
            raw = self._aliases[parts0[0]] + (" " + " ".join(parts0[1:]) if len(parts0) > 1 else "")
        # History
        if not self._history or self._history[0] != raw:
            self._history.insert(0, raw)
        self._hist_idx = -1
        # Echo
        self._print(self._fmt_prompt(), "prompt")
        self._print(raw + "\n", "output")
        # Handle pipes (simple: run each segment, pass output as string)
        if "|" in raw:
            self._run_pipe(raw)
        else:
            self._run(raw)
        self._prompt_lbl.config(text=self._fmt_prompt())
        self._set_status(f"Shell: /bin/pysh  │  {self._cwd}")

    def _hist_up(self, e: tk.Event) -> str:
        if self._hist_idx < len(self._history) - 1:
            self._hist_idx += 1
            self._inp.delete(0, "end")
            self._inp.insert(0, self._history[self._hist_idx])
        return "break"

    def _hist_down(self, e: tk.Event) -> str:
        if self._hist_idx > 0:
            self._hist_idx -= 1
            self._inp.delete(0, "end")
            self._inp.insert(0, self._history[self._hist_idx])
        elif self._hist_idx == 0:
            self._hist_idx = -1
            self._inp.delete(0, "end")
        return "break"

    def _tab_complete(self, e: tk.Event) -> str:
        q = self._inp.get()
        parts = q.split()
        if not parts:
            return "break"
        prefix = parts[-1]
        entries = self.wm.vfs.listdir(self._cwd, show_hidden=True)
        matches = [x for x in entries if x.startswith(prefix)]
        if len(matches) == 1:
            self._inp.delete(0, "end")
            base = " ".join(parts[:-1])
            self._inp.insert(0, (base + " " if base else "") + matches[0])
        elif len(matches) > 1:
            self._print("\n" + "  ".join(matches) + "\n", "accent")
        return "break"

    # ─── Pipe simulation ──────────────────────────────────────────────────────
    def _run_pipe(self, cmdline: str) -> None:
        import io
        segments = [s.strip() for s in cmdline.split("|")]
        pipe_in: Optional[str] = None
        for seg in segments:
            buf = io.StringIO()
            # Capture output for this segment
            orig_print = self._print
            collected: List[str] = []
            def _capture(text, tag="output"):
                collected.append(text)
            self._print = _capture    # type: ignore
            self._run(seg, pipe_input=pipe_in)
            self._print = orig_print  # type: ignore
            pipe_in = "".join(collected)
        if pipe_in:
            self._print(pipe_in, "output")

    # ─── Command dispatcher ───────────────────────────────────────────────────
    def _run(self, cmdline: str, pipe_input: Optional[str] = None) -> None:
        parts = cmdline.strip().split()
        if not parts:
            return
        prog = parts[0]
        args = parts[1:]

        dispatch: Dict[str, Callable] = {
            # Navigation
            "cd":       self._cmd_cd,
            "pwd":      lambda a: self._print(self._cwd + "\n"),
            "ls":       self._cmd_ls,
            "dir":      self._cmd_ls,
            # File ops
            "cat":      self._cmd_cat,
            "more":     self._cmd_cat,
            "less":     self._cmd_cat,
            "head":     self._cmd_head,
            "tail":     self._cmd_tail,
            "mkdir":    self._cmd_mkdir,
            "touch":    self._cmd_touch,
            "rm":       self._cmd_rm,
            "rmdir":    self._cmd_rm,
            "cp":       self._cmd_cp,
            "mv":       self._cmd_mv,
            "find":     self._cmd_find,
            # Text processing
            "echo":     lambda a: self._print(" ".join(a) + "\n"),
            "grep":     self._cmd_grep,
            "wc":       self._cmd_wc,
            "sort":     self._cmd_sort,
            "uniq":     self._cmd_uniq,
            "cut":      self._cmd_cut,
            "tr":       self._cmd_tr,
            "sed":      self._cmd_sed,
            # System
            "clear":    lambda a: self._clear(),
            "reset":    lambda a: self._clear(),
            "whoami":   lambda a: self._print("user\n"),
            "hostname": lambda a: self._print("pyos-pc\n"),
            "id":       lambda a: self._print("uid=1000(user) gid=1000(user) groups=1000(user),4(adm)\n"),
            "uname":    self._cmd_uname,
            "date":     lambda a: self._print(datetime.datetime.now().strftime("%c") + "\n"),
            "cal":      self._cmd_cal,
            "uptime":   self._cmd_uptime,
            "env":      lambda a: [self._print(f"{k}={v}\n", "accent") for k, v in self._env.items()],
            "export":   self._cmd_export,
            "unset":    lambda a: [self._env.pop(k, None) for k in a],
            "printenv": self._cmd_printenv,
            "alias":    self._cmd_alias,
            "history":  lambda a: [self._print(f"  {i+1:>4}  {h}\n", "dim") for i, h in enumerate(reversed(self._history[-20:]))],
            "which":    self._cmd_which,
            "type":     self._cmd_which,
            "man":      self._cmd_man,
            "help":     self._cmd_help,
            # Process
            "ps":       self._cmd_ps,
            "kill":     self._cmd_kill,
            "killall":  self._cmd_killall,
            "top":      self._cmd_top,
            "jobs":     lambda a: self._print("No background jobs.\n", "dim"),
            # Disk / memory
            "df":       self._cmd_df,
            "du":       self._cmd_du,
            "free":     self._cmd_free,
            "lsblk":    self._cmd_lsblk,
            # Network (simulated)
            "ping":     self._cmd_ping,
            "curl":     self._cmd_curl,
            "wget":     self._cmd_wget,
            "ifconfig": self._cmd_ifconfig,
            "ip":       self._cmd_ip,
            "nslookup": self._cmd_nslookup,
            "ssh":      lambda a: self._print("ssh: simulated — no real network\n", "warn"),
            # Python
            "python3":  self._cmd_python,
            "python":   self._cmd_python,
            "pip":      lambda a: self._print("pip: simulated — no real package manager\n", "warn"),
            # Editors
            "nano":     lambda a: TextEditorWin(self.wm, file_path=self._resolve(a[0]) if a else None),
            "vim":      lambda a: TextEditorWin(self.wm, file_path=self._resolve(a[0]) if a else None),
            "vi":       lambda a: TextEditorWin(self.wm, file_path=self._resolve(a[0]) if a else None),
            "code":     lambda a: TextEditorWin(self.wm, file_path=self._resolve(a[0]) if a else None),
            # Fun / info
            "neofetch": self._cmd_neofetch,
            "figlet":   self._cmd_figlet,
            "yes":      lambda a: self._print(((a[0] if a else "y") + "\n") * 8, "dim"),
            "cowsay":   lambda a: self._cmd_cowsay(a),
            "banner":   self._cmd_figlet,
            # Misc
            "sleep":    lambda a: None,
            "true":     lambda a: None,
            "false":    lambda a: self._print("false\n", "error"),
            "test":     lambda a: None,
            "chmod":    lambda a: self._print("chmod: simulated (permissions not enforced)\n", "warn"),
            "chown":    lambda a: self._print("chown: simulated\n", "warn"),
            "ln":       lambda a: self._print("ln: symbolic links not supported\n", "warn"),
            "tar":      lambda a: self._print("tar: archive support not implemented\n", "warn"),
            "zip":      lambda a: self._print("zip: archive support not implemented\n", "warn"),
            "unzip":    lambda a: self._print("unzip: archive support not implemented\n", "warn"),
            "exit":     lambda a: self.close(),
            "logout":   lambda a: self.close(),
            "quit":     lambda a: self.close(),
        }

        handler = dispatch.get(prog)
        if handler:
            try:
                handler(args)
            except Exception as ex:
                self._print(f"{prog}: {ex}\n", "error")
        else:
            self._print(
                f"{prog}: command not found. Try 'help' for a list.\n",
                "error",
            )

    # ─── Individual commands ──────────────────────────────────────────────────

    def _resolve(self, p: str) -> str:
        p = self.wm.vfs.expand(p)
        if p.startswith("/"):
            return p
        if p == "..":
            return VFS.dirname(self._cwd)
        if p == ".":
            return self._cwd
        return VFS.join(self._cwd, p)

    def _cmd_cd(self, args: List[str]) -> None:
        target = VFS.HOME if not args else self._resolve(args[0])
        if self.wm.vfs.is_dir(target):
            self._cwd = target
        else:
            self._print(f"cd: {args[0]}: No such directory\n", "error")

    def _cmd_ls(self, args: List[str]) -> None:
        flags   = [a for a in args if a.startswith("-")]
        paths   = [a for a in args if not a.startswith("-")]
        long    = any("l" in f for f in flags)
        show_all= any("a" in f for f in flags)
        path    = self._resolve(paths[0]) if paths else self._cwd

        entries = self.wm.vfs.listdir(path, show_hidden=show_all)
        if not entries:
            self._print("(empty)\n", "dim")
            return

        if long:
            self._print(f"total {len(entries)}\n", "dim")
            for name in entries:
                fp   = VFS.join(path, name)
                node = self.wm.vfs.get_node(fp)
                if not node:
                    continue
                perm = node.permissions
                sz   = node.size
                mod  = node.modified[:10]
                col  = "accent" if node.is_dir else "output"
                self._print(f"{perm}  1 user user  {sz:>8}  {mod}  {name}\n", col)
        else:
            per_row, row_items = 4, []
            for name in entries:
                fp   = VFS.join(path, name)
                node = self.wm.vfs.get_node(fp)
                icon = VFS.file_icon(name, node.is_dir if node else False)
                row_items.append((f"{icon} {name}", node.is_dir if node else False))
                if len(row_items) == per_row:
                    for item, is_d in row_items:
                        self._print(f"{item:<28}", "accent" if is_d else "output")
                    self._print("\n")
                    row_items = []
            if row_items:
                for item, is_d in row_items:
                    self._print(f"{item:<28}", "accent" if is_d else "output")
                self._print("\n")

    def _cmd_cat(self, args: List[str]) -> None:
        if not args:
            self._print("cat: missing operand\n", "error")
            return
        for a in args:
            p = self._resolve(a)
            content = self.wm.vfs.read(p)
            if content is None:
                self._print(f"cat: {a}: No such file\n", "error")
            else:
                self._print(content + ("" if content.endswith("\n") else "\n"))

    def _cmd_head(self, args: List[str]) -> None:
        n, files = 10, []
        i = 0
        while i < len(args):
            if args[i] == "-n" and i + 1 < len(args):
                n = int(args[i + 1]); i += 2
            else:
                files.append(args[i]); i += 1
        for f in files:
            content = self.wm.vfs.read(self._resolve(f))
            if content:
                for line in content.splitlines()[:n]:
                    self._print(line + "\n")
            else:
                self._print(f"head: {f}: No such file\n", "error")

    def _cmd_tail(self, args: List[str]) -> None:
        n, files = 10, []
        i = 0
        while i < len(args):
            if args[i] == "-n" and i + 1 < len(args):
                n = int(args[i + 1]); i += 2
            else:
                files.append(args[i]); i += 1
        for f in files:
            content = self.wm.vfs.read(self._resolve(f))
            if content:
                for line in content.splitlines()[-n:]:
                    self._print(line + "\n")
            else:
                self._print(f"tail: {f}: No such file\n", "error")

    def _cmd_mkdir(self, args: List[str]) -> None:
        for a in args:
            p = self._resolve(a)
            if self.wm.vfs.mkdir(p):
                self._print(f"mkdir: created '{a}'\n", "success")
            else:
                self._print(f"mkdir: cannot create '{a}'\n", "error")

    def _cmd_touch(self, args: List[str]) -> None:
        for a in args:
            p = self._resolve(a)
            if not self.wm.vfs.exists(p):
                self.wm.vfs.write(p, "")
            else:
                node = self.wm.vfs.get_node(p)
                if node:
                    node.touch()

    def _cmd_rm(self, args: List[str]) -> None:
        flags = [a for a in args if a.startswith("-")]
        paths = [a for a in args if not a.startswith("-")]
        recur = any("r" in f for f in flags)
        for a in paths:
            p = self._resolve(a)
            if self.wm.vfs.delete(p, recursive=recur):
                self._print(f"removed '{a}'\n", "success")
            else:
                self._print(f"rm: cannot remove '{a}'\n", "error")

    def _cmd_cp(self, args: List[str]) -> None:
        if len(args) < 2:
            self._print("cp: missing operand\n", "error"); return
        src = self._resolve(args[0])
        dst = self._resolve(args[1])
        if self.wm.vfs.copy(src, dst):
            self._print(f"'{args[0]}' → '{args[1]}'\n", "success")
        else:
            self._print(f"cp: cannot copy '{args[0]}'\n", "error")

    def _cmd_mv(self, args: List[str]) -> None:
        if len(args) < 2:
            self._print("mv: missing operand\n", "error"); return
        src = self._resolve(args[0])
        dst = self._resolve(args[1])
        if self.wm.vfs.move(src, dst):
            self._print(f"'{args[0]}' → '{args[1]}'\n", "success")
        else:
            self._print(f"mv: cannot move '{args[0]}'\n", "error")

    def _cmd_find(self, args: List[str]) -> None:
        root  = self._cwd
        name_q = None
        i = 0
        while i < len(args):
            if args[i] == "-name" and i + 1 < len(args):
                name_q = args[i + 1]; i += 2
            elif not args[i].startswith("-"):
                root = self._resolve(args[i]); i += 1
            else:
                i += 1
        results = self.wm.vfs.find(root, name=name_q)
        for r in results:
            self._print(r + "\n", "accent")
        if not results:
            self._print("(no results)\n", "dim")

    def _cmd_grep(self, args: List[str]) -> None:
        flags   = [a for a in args if a.startswith("-")]
        non_f   = [a for a in args if not a.startswith("-")]
        if not non_f:
            self._print("grep: usage: grep [-i] PATTERN [FILE…]\n", "error"); return
        pattern = non_f[0]
        files   = non_f[1:]
        ci      = "-i" in flags
        rf      = re.IGNORECASE if ci else 0

        def _search(text: str, label: str) -> None:
            for i, line in enumerate(text.splitlines(), 1):
                if re.search(pattern, line, rf):
                    self._print(f"{label}:{i}: ", "accent")
                    self._print(line + "\n")

        if files:
            for f in files:
                content = self.wm.vfs.read(self._resolve(f))
                if content:
                    _search(content, f)
                else:
                    self._print(f"grep: {f}: No such file\n", "error")

    def _cmd_wc(self, args: List[str]) -> None:
        for a in [x for x in args if not x.startswith("-")]:
            content = self.wm.vfs.read(self._resolve(a))
            if content:
                l = len(content.splitlines())
                w = len(content.split())
                c = len(content)
                self._print(f"{l:>8} {w:>8} {c:>8}  {a}\n", "accent")

    def _cmd_sort(self, args: List[str]) -> None:
        rev   = "-r" in args
        files = [a for a in args if not a.startswith("-")]
        for f in files:
            content = self.wm.vfs.read(self._resolve(f))
            if content:
                lines = sorted(content.splitlines(), reverse=rev)
                self._print("\n".join(lines) + "\n")

    def _cmd_uniq(self, args: List[str]) -> None:
        files = [a for a in args if not a.startswith("-")]
        for f in files:
            content = self.wm.vfs.read(self._resolve(f))
            if content:
                seen: Set[str] = set()
                out:  List[str] = []
                for line in content.splitlines():
                    if line not in seen:
                        seen.add(line); out.append(line)
                self._print("\n".join(out) + "\n")

    def _cmd_cut(self, args: List[str]) -> None:
        self._print("cut: basic implementation — use 'grep' for filtering\n", "warn")

    def _cmd_tr(self, args: List[str]) -> None:
        self._print("tr: transliteration support coming soon\n", "warn")

    def _cmd_sed(self, args: List[str]) -> None:
        if len(args) >= 2 and args[0].startswith("s/"):
            try:
                _, old, new, *_ = args[0].split("/")
                filename = args[1] if len(args) > 1 else None
                if filename:
                    p = self._resolve(filename)
                    content = self.wm.vfs.read(p)
                    if content:
                        result = content.replace(old, new)
                        self._print(result)
                    return
            except Exception:
                pass
        self._print("sed: limited support — use 's/old/new/ file' form\n", "warn")

    def _cmd_uname(self, args: List[str]) -> None:
        if "-a" in args:
            self._print(
                f"PyOS {VERSION} pyos-pc x86_64 Python/{sys.version.split()[0]}\n", "accent")
        else:
            self._print("PyOS\n", "accent")

    def _cmd_cal(self, args: List[str]) -> None:
        now = datetime.datetime.now()
        year  = int(args[1]) if len(args) >= 2 else now.year
        month = int(args[0]) if len(args) >= 1 and args[0].isdigit() else now.month
        self._print(_cal.month(year, month), "accent")

    def _cmd_uptime(self, args: List[str]) -> None:
        fake_uptime = f"0 days, {random.randint(0,23)}:{random.randint(0,59):02}:{random.randint(0,59):02}"
        load = tuple(round(random.uniform(0, 2), 2) for _ in range(3))
        self._print(f"up {fake_uptime},  load average: {load[0]}, {load[1]}, {load[2]}\n", "accent")

    def _cmd_export(self, args: List[str]) -> None:
        for a in args:
            if "=" in a:
                k, v = a.split("=", 1)
                self._env[k] = v
                self._print(f"export {k}={v}\n", "accent")

    def _cmd_printenv(self, args: List[str]) -> None:
        if args:
            for k in args:
                v = self._env.get(k, "")
                self._print(f"{v}\n", "accent")
        else:
            for k, v in self._env.items():
                self._print(f"{k}={v}\n", "accent")

    def _cmd_alias(self, args: List[str]) -> None:
        if not args:
            for k, v in self._aliases.items():
                self._print(f"alias {k}='{v}'\n", "accent")
        else:
            for a in args:
                if "=" in a:
                    k, v = a.split("=", 1)
                    self._aliases[k] = v.strip("'\"")
                    self._print(f"alias set: {k}='{v}'\n", "success")

    def _cmd_which(self, args: List[str]) -> None:
        known = {
            "ls", "cd", "cat", "grep", "find", "rm", "cp", "mv",
            "mkdir", "touch", "echo", "sort", "uniq", "wc",
            "ps", "kill", "top", "df", "du", "free",
            "ping", "curl", "wget", "python3", "python",
            "nano", "vim", "vi", "code", "history", "env", "export",
        }
        for a in args:
            if a in known:
                self._print(f"/usr/bin/{a}\n", "success")
            else:
                self._print(f"{a} not found\n", "error")

    def _cmd_man(self, args: List[str]) -> None:
        pages: Dict[str, str] = {
            "ls":   "ls — list directory contents\nUsage: ls [-la] [path]",
            "cd":   "cd — change the working directory\nUsage: cd [path]",
            "cat":  "cat — concatenate and print files\nUsage: cat FILE…",
            "grep": "grep — search for patterns\nUsage: grep [-i] PATTERN [FILE…]",
            "find": "find — search for files\nUsage: find [path] [-name PATTERN]",
            "rm":   "rm — remove files or directories\nUsage: rm [-r] FILE…",
            "cp":   "cp — copy files\nUsage: cp SRC DST",
            "mv":   "mv — move / rename files\nUsage: mv SRC DST",
            "mkdir":"mkdir — make directories\nUsage: mkdir DIR…",
            "touch":"touch — update file timestamps / create\nUsage: touch FILE…",
            "ps":   "ps — process status\nUsage: ps",
            "kill": "kill — send signal to process\nUsage: kill PID",
            "top":  "top — live process list\nUsage: top",
            "df":   "df — disk free\nUsage: df",
            "free": "free — memory usage\nUsage: free",
            "ping": "ping — send ICMP echoes (simulated)\nUsage: ping HOST",
            "python3": "python3 — Python interpreter\nUsage: python3 [FILE]",
        }
        if not args:
            self._print("What manual page do you want?\n", "warn"); return
        page = pages.get(args[0])
        if page:
            self._print("\n" + page + "\n\n", "accent")
        else:
            self._print(f"man: no manual entry for '{args[0]}'\n", "error")

    def _cmd_help(self, args: List[str]) -> None:
        sections = {
            "Navigation":   "ls  cd  pwd  find",
            "Files":        "cat  head  tail  grep  wc  sort  uniq  sed",
            "Operations":   "mkdir  touch  rm  cp  mv",
            "Text Edit":    "nano  vim  vi  code",
            "System":       "ps  kill  top  df  du  free  uptime  uname  date  cal",
            "Network":      "ping  curl  wget  ifconfig  ip  nslookup",
            "Environment":  "echo  env  export  printenv  alias  history  which  man",
            "Python":       "python3  python  pip",
            "Fun":          "neofetch  figlet  cowsay  yes  banner",
            "Shell":        "clear  exit  logout  sleep  true  false",
        }
        self._print("\nBuilt-in commands:\n\n", "header")
        for section, cmds in sections.items():
            self._print(f"  {section}:\n", "accent")
            self._print(f"    {cmds}\n\n", "output")

    def _cmd_ps(self, args: List[str]) -> None:
        self._print(
            f"{'PID':>6}  {'NAME':<32}  {'CPU':>6}  {'MEM':>6}  STATUS\n",
            "header",
        )
        procs = sorted(self.wm.procs.list_all(), key=lambda p: p.pid)[:30]
        for p in procs:
            self._print(
                f"{p.pid:>6}  {p.name:<32}  {p.cpu:>5.1f}%  {p.ram:>5}M  {p.status}\n",
                "output",
            )

    def _cmd_kill(self, args: List[str]) -> None:
        pids = [a for a in args if a.isdigit() or (a.lstrip("-").isdigit())]
        if not pids:
            self._print("kill: usage: kill PID\n", "error"); return
        for pid_str in pids:
            pid = int(pid_str)
            if self.wm.procs.kill(pid):
                self._print(f"Killed PID {pid}\n", "success")
            else:
                self._print(f"kill: ({pid}) — operation not permitted\n", "error")

    def _cmd_killall(self, args: List[str]) -> None:
        if not args:
            self._print("killall: usage: killall NAME\n", "error"); return
        name = args[0]
        killed = [p.pid for p in self.wm.procs.list_user() if p.name == name]
        for pid in killed:
            self.wm.procs.kill(pid)
        self._print(
            f"killall: {'killed ' + str(len(killed)) + ' process(es)' if killed else 'no processes found'}\n",
            "success" if killed else "warn",
        )

    def _cmd_top(self, args: List[str]) -> None:
        procs = sorted(self.wm.procs.list_all(), key=lambda p: p.cpu, reverse=True)[:16]
        total = self.wm.procs.total_cpu()
        ram   = self.wm.procs.total_ram()
        self._print(
            f"\nCPU: {total:.1f}%   RAM: {VFS.human_size(ram * 1024 * 1024)}   "
            f"Processes: {self.wm.procs.count()}\n\n",
            "header",
        )
        self._print(
            f"{'PID':>6}  {'NAME':<30}  {'CPU':>6}  {'MEM':>6}\n",
            "accent",
        )
        for p in procs:
            col = "error" if p.cpu > 50 else "warn" if p.cpu > 20 else "output"
            self._print(
                f"{p.pid:>6}  {p.name:<30}  {p.cpu:>5.1f}%  {p.ram:>5}M\n",
                col,
            )

    def _cmd_df(self, args: List[str]) -> None:
        self._print(
            f"{'Filesystem':<20}  {'Size':>8}  {'Used':>8}  {'Avail':>8}  Use%\n",
            "header",
        )
        self._print(f"{'pyos-vfs':<20}  {'10.0G':>8}  {'1.4G':>8}  {'8.6G':>8}   14%\n")
        self._print(f"{'tmpfs':<20}  {'2.0G':>8}  {'132M':>8}  {'1.9G':>8}    6%\n")

    def _cmd_du(self, args: List[str]) -> None:
        paths = [a for a in args if not a.startswith("-")] or [self._cwd]
        for p in paths:
            fp   = self._resolve(p)
            size = self.wm.vfs.get_size(fp)
            self._print(f"{VFS.human_size(size):<10}  {fp}\n", "accent")

    def _cmd_free(self, args: List[str]) -> None:
        total = 8192
        used  = min(total, self.wm.procs.total_ram())
        free  = total - used
        self._print(f"{'':>14}  {'total':>8}  {'used':>8}  {'free':>8}\n", "header")
        self._print(f"{'Mem:':<14}  {total:>8}  {used:>8}  {free:>8}\n")
        self._print(f"{'Swap:':<14}  {'4096':>8}  {'0':>8}  {'4096':>8}\n")

    def _cmd_lsblk(self, args: List[str]) -> None:
        self._print("NAME   MAJ:MIN  SIZE  TYPE  MOUNTPOINT\n", "header")
        self._print("sda      8:0    256G  disk\n")
        self._print("└─sda1   8:1    256G  part  /\n")
        self._print("sr0     11:0   1024M  rom\n")

    def _cmd_ping(self, args: List[str]) -> None:
        host = args[0] if args else "8.8.8.8"
        self._print(
            f"PING {host} (simulated, no real network)\n",
            "warn",
        )
        for i in range(4):
            ms = random.randint(8, 80)
            self._print(
                f"64 bytes from {host}: icmp_seq={i+1} ttl=64 time={ms}.{random.randint(0,9)} ms\n",
                "success",
            )
        self._print(f"\n--- {host} ping statistics ---\n4 packets transmitted, 4 received, 0% loss\n")

    def _cmd_curl(self, args: List[str]) -> None:
        url = next((a for a in args if not a.startswith("-")), "")
        if not url:
            self._print("curl: no URL specified\n", "error"); return
        self._print(f'curl: simulated request to {url}\n', "warn")
        self._print('{"status":200,"message":"Simulated response"}\n', "accent")

    def _cmd_wget(self, args: List[str]) -> None:
        url = next((a for a in args if not a.startswith("-")), "")
        if not url:
            self._print("wget: no URL\n", "error"); return
        self._print(f"--{datetime.datetime.now().strftime('%H:%M:%S')}-- {url}\n")
        self._print("Resolving (simulated)... 100%   0K  --:-- 200 OK\n", "success")

    def _cmd_ifconfig(self, args: List[str]) -> None:
        self._print(
            "eth0: flags=4163<UP,BROADCAST,RUNNING,MULTICAST>  mtu 1500\n"
            "      inet 192.168.1.100  netmask 255.255.255.0  broadcast 192.168.1.255\n"
            "      ether 00:0c:29:ab:cd:ef  txqueuelen 1000\n\n"
            "lo: flags=73<UP,LOOPBACK,RUNNING>  mtu 65536\n"
            "    inet 127.0.0.1  netmask 255.0.0.0\n",
            "accent",
        )

    def _cmd_ip(self, args: List[str]) -> None:
        self._cmd_ifconfig([])

    def _cmd_nslookup(self, args: List[str]) -> None:
        host = args[0] if args else "localhost"
        self._print(
            f"Server:  192.168.1.1\nAddress: 192.168.1.1#53\n\n"
            f"Name:    {host}\nAddress: 93.184.216.{random.randint(1,254)}\n",
            "accent",
        )

    def _cmd_python(self, args: List[str]) -> None:
        if not args:
            self._print(
                f"Python {sys.version.split()[0]} (PyOS embedded)\n"
                "Type help() for help.\n>>> (REPL not available in terminal — use Code Editor)\n",
                "accent",
            )
            return
        p = self._resolve(args[0])
        content = self.wm.vfs.read(p)
        if not content:
            self._print(f"python3: {args[0]}: No such file\n", "error"); return
        import io
        buf = io.StringIO()
        old_stdout = sys.stdout
        try:
            sys.stdout = buf
            exec(compile(content, p, "exec"), {"__name__": "__main__"})
        except Exception as ex:
            sys.stdout = old_stdout
            self._print(f"Traceback:\n  {type(ex).__name__}: {ex}\n", "error")
            return
        finally:
            sys.stdout = old_stdout
        out = buf.getvalue()
        if out:
            self._print(out)

    def _cmd_neofetch(self, args: List[str]) -> None:
        theme  = self.wm.settings.get("theme", "dark")
        procs  = self.wm.procs.count()
        wins   = len(self.wm.all_wins())
        accent = T["accent"]
        art = [
            "  ██████╗ ██╗   ██╗ ██████╗  ███████╗",
            "  ██╔══██╗╚██╗ ██╔╝██╔═══██╗ ██╔════╝",
            "  ██████╔╝ ╚████╔╝ ██║   ██║ ███████╗",
            "  ██╔═══╝   ╚██╔╝  ██║   ██║ ╚════██║",
            "  ██║        ██║   ╚██████╔╝ ███████║",
            "  ╚═╝        ╚═╝    ╚═════╝  ╚══════╝",
        ]
        info = [
            "user@pyos-pc",
            "─" * 14,
            f"OS:      PyOS {VERSION} \"{CODENAME}\"",
            f"Kernel:  pykernel {BUILD}",
            f"Shell:   PyShell 2.0",
            f"Theme:   {theme.capitalize()}",
            f"Accent:  {accent}",
            f"Python:  {sys.version.split()[0]}",
            f"Procs:   {procs}",
            f"Windows: {wins}",
            f"Res:     {SCREEN_W}×{SCREEN_H}",
        ]
        self._print("\n")
        for i, line in enumerate(art):
            self._print(line + "  ", "accent")
            if i < len(info):
                self._print(info[i] + "\n", "output")
            else:
                self._print("\n")
        self._print("\n")

    def _cmd_figlet(self, args: List[str]) -> None:
        text = " ".join(args) if args else "PyOS"
        # Very simple banner using block letters for uppercase A-Z, 0-9
        self._print(f"\n  ╔{'═'*(len(text)*2+2)}╗\n", "accent")
        self._print(f"  ║  {text.upper()}  ║\n", "accent")
        self._print(f"  ╚{'═'*(len(text)*2+2)}╝\n\n", "accent")

    def _cmd_cowsay(self, args: List[str]) -> None:
        msg = " ".join(args) if args else "Moo!"
        bar = "-" * (len(msg) + 2)
        self._print(f" {bar}\n< {msg} >\n {bar}\n", "accent")
        self._print("        \\   ^__^\n         \\  (oo)\\_______\n            (__)\\       )\\/\\\n                ||----w |\n                ||     ||\n\n", "dim")


