class BrowserWin(BaseWin):
    """
    Multi-tab browser with built-in PyOS pages and a simple HTML renderer.

    Built-in pages (pyos:// scheme):
      home | about | apps | help | settings | changelog | search

    External URLs are acknowledged but not fetched (no real network).
    """

