# ═══════════════════════════════════════════════════════════════════════════════
#  §23  TASK MANAGER
# ═══════════════════════════════════════════════════════════════════════════════

class TaskManagerWin(BaseWin):
    """
    System task manager with five tabs:
      Processes   — live process table, sortable, End-Task button
      Performance — CPU/RAM live graphs + stats
      App History — per-app resource usage
      Startup     — simulated startup programs
      Users       — logged-in user sessions
    Auto-refreshes every 2 seconds.
    """

    REFRESH_MS = 2000

    def __init__(self, wm: WM):
        self._active_tab  = "Processes"
        self._sel_pid:    Optional[int] = None
        self._sort_col    = "cpu"
        self._sort_rev    = True
        self._cpu_samples: deque = deque([0.0] * 60, maxlen=60)
        self._ram_samples: deque = deque([0.0] * 60, maxlen=60)
        super().__init__(wm, "Task Manager", 840, 580, "📊")

    def _build(self) -> None:
        self._show_menubar()
        self._add_menu("View", [
            ("Refresh Now",    self._refresh,  "F5"),
            ("---",            None),
            ("Always on Top",  lambda: None),
        ])
        self._add_menu("Options", [
            ("Set Refresh Rate", lambda: None),
        ])
        self._show_statusbar()
        self.client.config(bg=T["bg_surface"])

        # ── Tab strip ─────────────────────────────────────────────────────────
        tab_strip = tk.Frame(self.client, bg=T["bg_elevated"])
        tab_strip.pack(fill="x")
        self._tab_btns: Dict[str, tk.Label] = {}
        for name in ["Processes", "Performance", "App History", "Startup", "Users"]:
            btn = tk.Label(
                tab_strip,
                text=name,
                font=FONTS.get("body", ()),
                fg=T["fg_primary"] if name == self._active_tab else T["fg_secondary"],
                bg=T["bg_active"] if name == self._active_tab else T["bg_elevated"],
                padx=18, pady=8, cursor="hand2",
            )
            btn.pack(side="left")
            btn.bind("<Button-1>", lambda e, n=name: self._switch_tab(n))
            btn.bind("<Enter>",
                lambda e, b=btn, n=name:
                    b.config(bg=T["bg_hover"]) if n != self._active_tab else None)
            btn.bind("<Leave>",
                lambda e, b=btn, n=name:
                    b.config(bg=T["bg_active"] if n == self._active_tab else T["bg_elevated"]))
            self._tab_btns[name] = btn

        fl_separator(self.client).pack(fill="x")

        # ── Content host ──────────────────────────────────────────────────────
        self._content = tk.Frame(self.client, bg=T["bg_surface"])
        self._content.pack(fill="both", expand=True)

        self._draw_tab()
        self._schedule_refresh()

    # ─── Tab switching ────────────────────────────────────────────────────────
    def _switch_tab(self, name: str) -> None:
        old = self._active_tab
        self._active_tab = name
        if old in self._tab_btns:
            self._tab_btns[old].config(
                bg=T["bg_elevated"], fg=T["fg_secondary"],
                font=FONTS.get("body", ()))
        self._tab_btns[name].config(
            bg=T["bg_active"], fg=T["fg_primary"],
            font=FONTS.get("body_bold", ()))
        self._draw_tab()

    def _draw_tab(self) -> None:
        for w in self._content.winfo_children():
            w.destroy()
        {
            "Processes":   self._tab_processes,
            "Performance": self._tab_performance,
            "App History": self._tab_app_history,
            "Startup":     self._tab_startup,
            "Users":       self._tab_users,
        }[self._active_tab]()

    # ─── Processes tab ────────────────────────────────────────────────────────
    def _tab_processes(self) -> None:
        f = self._content

        # Toolbar
        tb = tk.Frame(f, bg=T["bg_elevated"])
        tb.pack(fill="x")
        fl_button(tb, "End Task",
                  self._end_task, style="danger").pack(side="left", padx=8, pady=4)
        fl_button(tb, "Refresh",
                  self._refresh, style="secondary").pack(side="left", pady=4)
        tk.Label(tb, text="", bg=T["bg_elevated"]).pack(side="left", fill="x", expand=True)
        self._search_proc_var = tk.StringVar()
        sf = tk.Frame(tb, bg=T["bg_input"])
        sf.pack(side="right", padx=8, pady=4)
        tk.Label(sf, text="🔍", bg=T["bg_input"],
                 font=FONTS.get("small", ())).pack(side="left", padx=4)
        tk.Entry(sf, textvariable=self._search_proc_var,
                 font=FONTS.get("small", ()), bg=T["bg_input"],
                 fg=T["fg_primary"], insertbackground=T["accent"],
                 relief="flat", bd=0, width=18).pack(side="left", pady=4)
        self._search_proc_var.trace_add("write", lambda *a: self._load_processes())

        # Column header
        cols = [
            ("Name",     "name",   300),
            ("PID",      "pid",     60),
            ("CPU %",    "cpu",     80),
            ("Memory",   "ram",     90),
            ("Status",   "status",  80),
            ("Threads",  "threads", 70),
        ]
        hdr = tk.Frame(f, bg=T["bg_card"])
        hdr.pack(fill="x")
        for label, key, w in cols:
            arrow = (" ▼" if self._sort_rev else " ▲") if self._sort_col == key else ""
            lbl = tk.Label(
                hdr,
                text=label + arrow,
                font=FONTS.get("small_bold", ()),
                fg=T["accent"] if self._sort_col == key else T["fg_tertiary"],
                bg=T["bg_card"],
                width=w // 7, anchor="w", padx=8, pady=5, cursor="hand2",
            )
            lbl.pack(side="left")
            lbl.bind("<Button-1>", lambda e, k=key: self._set_sort(k))
        fl_separator(f).pack(fill="x")

        # Scrollable list
        self._proc_scroll = ScrollableFrame(f, bg_key="bg_surface")
        self._proc_scroll.pack(fill="both", expand=True)
        self._proc_inner = self._proc_scroll.inner
        self._load_processes()

        total = self.wm.procs.total_cpu()
        self._set_status(
            f"Processes: {self.wm.procs.count()}  │  "
            f"CPU: {total:.1f}%  │  "
            f"RAM: {VFS.human_size(self.wm.procs.total_ram() * 1024 * 1024)}  │  "
            f"Windows: {len(self.wm.all_wins())}"
        )

    def _load_processes(self) -> None:
        for w in self._proc_inner.winfo_children():
            w.destroy()
        q = self._search_proc_var.get().lower() if hasattr(self, "_search_proc_var") else ""
        procs = self.wm.procs.list_all()
        if q:
            procs = [p for p in procs if q in p.name.lower()]
        key_map = {
            "name": lambda p: p.name.lower(),
            "pid":  lambda p: p.pid,
            "cpu":  lambda p: p.cpu,
            "ram":  lambda p: p.ram,
        }
        procs.sort(key=key_map.get(self._sort_col, lambda p: p.cpu),
                   reverse=self._sort_rev)
        for i, p in enumerate(procs[:80]):
            alt = T["bg_card"] if i % 2 else T["bg_surface"]
            row = tk.Frame(self._proc_inner, bg=alt, cursor="hand2")
            row.pack(fill="x")
            cpu_fg = (T["danger"] if p.cpu > 50 else
                      T["warning"] if p.cpu > 20 else T["fg_primary"])
            for val, w, color in [
                (p.name[:38],      300, T["fg_primary"]),
                (str(p.pid),        60, T["fg_secondary"]),
                (f"{p.cpu:.1f}%",   80, cpu_fg),
                (f"{p.ram} MB",     90, T["fg_secondary"]),
                (p.status,          80, T["success"]),
                (str(p.threads),    70, T["fg_tertiary"]),
            ]:
                tk.Label(row, text=val, font=FONTS.get("small", ()),
                         fg=color, bg=alt,
                         width=w // 7, anchor="w", padx=8, pady=4).pack(side="left")

            def _sel(e, r=row, pid=p.pid, bg=alt):
                self._sel_pid = pid
                for ch in self._proc_inner.winfo_children():
                    ch.config(bg=T["bg_selection"] if ch is r else
                              (T["bg_card"] if list(
                                  self._proc_inner.winfo_children()).index(ch) % 2
                               else T["bg_surface"]))
                    for cc in ch.winfo_children():
                        cc.config(bg=ch.cget("bg"))

            row.bind("<Button-1>", _sel)
            row.bind("<Enter>",
                lambda e, r=row, bg=alt, pid=p.pid:
                    r.config(bg=T["bg_hover"]) if self._sel_pid != pid else None)
            row.bind("<Leave>",
                lambda e, r=row, bg=alt, pid=p.pid:
                    r.config(bg=T["bg_selection"] if self._sel_pid == pid else bg))

    def _set_sort(self, col: str) -> None:
        if self._sort_col == col:
            self._sort_rev = not self._sort_rev
        else:
            self._sort_col = col
            self._sort_rev = True
        if self._active_tab == "Processes":
            self._draw_tab()

    def _end_task(self) -> None:
        if self._sel_pid is None:
            notify(self.wm.root, "Task Manager", "Select a process first", kind="warning")
            return
        if self.wm.procs.kill(self._sel_pid):
            notify(self.wm.root, "Task Manager",
                   f"Process {self._sel_pid} terminated", kind="success")
            self._sel_pid = None
            self._load_processes()
        else:
            notify(self.wm.root, "Task Manager",
                   "Cannot terminate system process", kind="danger")

    # ─── Performance tab ──────────────────────────────────────────────────────
    def _tab_performance(self) -> None:
        f = self._content
        cpu  = self.wm.procs.total_cpu()
        ram  = self.wm.procs.total_ram()
        self._cpu_samples.append(cpu)
        self._ram_samples.append(min(100, ram / 81.92))  # 8192MB → %

        scroll = ScrollableFrame(f, bg_key="bg_surface")
        scroll.pack(fill="both", expand=True)
        inner = scroll.inner

        # ── CPU graph card ────────────────────────────────────────────────────
        cpu_card = tk.Frame(inner, bg=T["bg_card"])
        cpu_card.pack(fill="x", padx=18, pady=10)
        hdr = tk.Frame(cpu_card, bg=T["bg_card"])
        hdr.pack(fill="x", padx=16, pady=(12, 4))
        tk.Label(hdr, text="CPU", font=FONTS.get("h3", ()),
                 fg=T["fg_secondary"], bg=T["bg_card"]).pack(side="left")
        tk.Label(hdr, text=f"{cpu:.1f}%", font=FONTS.get("h2", ()),
                 fg=T["accent"], bg=T["bg_card"]).pack(side="right")

        gw, gh = 700, 110
        cv = tk.Canvas(cpu_card, height=gh, bg=T["bg_input"], highlightthickness=0)
        cv.pack(fill="x", padx=16, pady=6)
        cv.update_idletasks()
        w = cv.winfo_width() or gw
        # Grid lines
        for i in range(1, 4):
            y = gh * i // 4
            cv.create_line(0, y, w, y, fill=T["border"], width=1)
        # CPU line
        samples = list(self._cpu_samples)
        if len(samples) >= 2:
            pts = []
            for i, s in enumerate(samples):
                x = int(i * w / (len(samples) - 1))
                y = int(gh - (s / 100) * (gh - 6))
                pts.extend([x, y])
            if len(pts) >= 4:
                cv.create_line(pts, fill=T["accent"], width=2, smooth=True)
            # Fill under the line
            fill_pts = [0, gh] + pts + [w, gh]
            cv.create_polygon(fill_pts, fill=T["accent_muted"], outline="", smooth=False)
        # Labels
        for pct, y_pct in [(100, 0), (75, 25), (50, 50), (25, 75), (0, 100)]:
            y = int(gh * y_pct / 100)
            cv.create_text(w - 4, y + 2, text=f"{pct}%",
                           font=FONTS.get("nano", ()), fill=T["fg_tertiary"], anchor="e")

        # CPU stats grid
        sg = tk.Frame(cpu_card, bg=T["bg_card"])
        sg.pack(fill="x", padx=16, pady=(4, 14))
        cpu_stats = [
            ("Utilisation",   f"{cpu:.1f}%"),
            ("Processes",     str(self.wm.procs.count())),
            ("Threads",       str(sum(p.threads for p in self.wm.procs.list_all()))),
            ("Open Windows",  str(len(self.wm.all_wins()))),
        ]
        for i, (lbl, val) in enumerate(cpu_stats):
            c_f = tk.Frame(sg, bg=T["bg_card"])
            c_f.grid(row=0, column=i, padx=16, sticky="w")
            tk.Label(c_f, text=lbl, font=FONTS.get("micro", ()),
                     fg=T["fg_tertiary"], bg=T["bg_card"]).pack(anchor="w")
            tk.Label(c_f, text=val, font=FONTS.get("h3", ()),
                     fg=T["fg_primary"], bg=T["bg_card"]).pack(anchor="w")

        # ── RAM graph card ────────────────────────────────────────────────────
        ram_card = tk.Frame(inner, bg=T["bg_card"])
        ram_card.pack(fill="x", padx=18, pady=6)
        hdr2 = tk.Frame(ram_card, bg=T["bg_card"])
        hdr2.pack(fill="x", padx=16, pady=(12, 4))
        tk.Label(hdr2, text="Memory", font=FONTS.get("h3", ()),
                 fg=T["fg_secondary"], bg=T["bg_card"]).pack(side="left")
        tk.Label(hdr2, text=f"{VFS.human_size(ram * 1024 * 1024)} / 8.0 GB",
                 font=FONTS.get("h3", ()), fg=T["info"], bg=T["bg_card"]).pack(side="right")

        # Progress bar style
        bar_host = tk.Frame(ram_card, bg=T["bg_input"], height=22)
        bar_host.pack(fill="x", padx=16, pady=6)
        bar_host.pack_propagate(False)
        pct = min(1.0, ram / 8192)
        bar_fill = tk.Frame(bar_host, bg=T["info"], height=22)
        bar_fill.place(relx=0, rely=0, relwidth=pct, relheight=1)

        ram_stats = [
            ("In Use",       VFS.human_size(ram * 1024 * 1024)),
            ("Available",    VFS.human_size(max(0, (8192 - ram)) * 1024 * 1024)),
            ("Total",        "8.0 GB"),
            ("Usage",        f"{pct*100:.1f}%"),
        ]
        sg2 = tk.Frame(ram_card, bg=T["bg_card"])
        sg2.pack(fill="x", padx=16, pady=(4, 14))
        for i, (lbl, val) in enumerate(ram_stats):
            c_f = tk.Frame(sg2, bg=T["bg_card"])
            c_f.grid(row=0, column=i, padx=16, sticky="w")
            tk.Label(c_f, text=lbl, font=FONTS.get("micro", ()),
                     fg=T["fg_tertiary"], bg=T["bg_card"]).pack(anchor="w")
            tk.Label(c_f, text=val, font=FONTS.get("h3", ()),
                     fg=T["fg_primary"], bg=T["bg_card"]).pack(anchor="w")

    # ─── App History tab ──────────────────────────────────────────────────────
    def _tab_app_history(self) -> None:
        f = self._content
        hdr = tk.Frame(f, bg=T["bg_card"])
        hdr.pack(fill="x")
        for col, w in [("Application", 260), ("CPU Time", 90),
                        ("Network", 90), ("Metered Network", 120)]:
            tk.Label(hdr, text=col, font=FONTS.get("small_bold", ()),
                     fg=T["fg_tertiary"], bg=T["bg_card"],
                     width=w//7, anchor="w", padx=8, pady=5).pack(side="left")
        fl_separator(f).pack(fill="x")
        scroll = ScrollableFrame(f, bg_key="bg_surface")
        scroll.pack(fill="both", expand=True)
        inner = scroll.inner
        for i, app in enumerate(APP_REGISTRY):
            alt = T["bg_card"] if i % 2 else T["bg_surface"]
            row = tk.Frame(inner, bg=alt); row.pack(fill="x")
            cpu_time = f"{random.randint(0,120)}:{random.randint(0,59):02}"
            net_mb   = f"{random.randint(0,500)} MB"
            met_mb   = f"{random.randint(0,50)} MB"
            for val, w in [
                (f"{app['icon']}  {app['name']}", 260),
                (cpu_time, 90), (net_mb, 90), (met_mb, 120),
            ]:
                tk.Label(row, text=val, font=FONTS.get("small", ()),
                         fg=T["fg_primary"] if w == 260 else T["fg_secondary"],
                         bg=alt, width=w//7, anchor="w",
                         padx=8, pady=4).pack(side="left")

    # ─── Startup tab ──────────────────────────────────────────────────────────
    def _tab_startup(self) -> None:
        f = self._content
        hdr = tk.Frame(f, bg=T["bg_card"]); hdr.pack(fill="x")
        for col, w in [("Name", 240), ("Publisher", 180),
                        ("Status", 90), ("Startup Impact", 110)]:
            tk.Label(hdr, text=col, font=FONTS.get("small_bold", ()),
                     fg=T["fg_tertiary"], bg=T["bg_card"],
                     width=w//7, anchor="w", padx=8, pady=5).pack(side="left")
        fl_separator(f).pack(fill="x")
        scroll = ScrollableFrame(f, bg_key="bg_surface")
        scroll.pack(fill="both", expand=True)
        inner = scroll.inner
        startup_items = [
            ("PyOS Shell",          "PyOS Project",      "Enabled",  "Low"),
            ("Desktop Window Mgr",  "PyOS Project",      "Enabled",  "High"),
            ("PyOS Search",         "PyOS Project",      "Enabled",  "Medium"),
            ("Notification Daemon", "PyOS Project",      "Enabled",  "Low"),
            ("Audio Service",       "PyOS Project",      "Enabled",  "Low"),
            ("Clipboard Manager",   "PyOS Project",      "Enabled",  "None"),
            ("Update Service",      "PyOS Project",      "Disabled", "None"),
            ("Crash Reporter",      "PyOS Project",      "Disabled", "None"),
        ]
        for i, (name, pub, status, impact) in enumerate(startup_items):
            alt = T["bg_card"] if i % 2 else T["bg_surface"]
            row = tk.Frame(inner, bg=alt); row.pack(fill="x")
            impact_col = (T["danger"] if impact == "High" else
                          T["warning"] if impact == "Medium" else T["fg_secondary"])
            status_col = T["success"] if status == "Enabled" else T["fg_tertiary"]
            for val, w, fg in [
                (name,   240, T["fg_primary"]),
                (pub,    180, T["fg_secondary"]),
                (status,  90, status_col),
                (impact, 110, impact_col),
            ]:
                tk.Label(row, text=val, font=FONTS.get("small", ()),
                         fg=fg, bg=alt, width=w//7,
                         anchor="w", padx=8, pady=4).pack(side="left")

    # ─── Users tab ────────────────────────────────────────────────────────────
    def _tab_users(self) -> None:
        f = self._content
        hdr = tk.Frame(f, bg=T["bg_card"]); hdr.pack(fill="x")
        for col, w in [("User", 200), ("Status", 100),
                        ("CPU", 80), ("Memory", 90), ("Description", 200)]:
            tk.Label(hdr, text=col, font=FONTS.get("small_bold", ()),
                     fg=T["fg_tertiary"], bg=T["bg_card"],
                     width=w//7, anchor="w", padx=8, pady=5).pack(side="left")
        fl_separator(f).pack(fill="x")
        scroll = ScrollableFrame(f, bg_key="bg_surface")
        scroll.pack(fill="both", expand=True)
        inner = scroll.inner
        for i, acc in enumerate(self.wm.users.list_accounts()):
            alt = T["bg_card"] if i % 2 else T["bg_surface"]
            row = tk.Frame(inner, bg=alt); row.pack(fill="x")
            is_active = acc.username == self.wm.users.current_username
            status = "Active" if is_active else "Disconnected"
            cpu    = f"{random.uniform(0,5):.1f}%" if is_active else "0%"
            ram    = f"{random.randint(200,600)} MB" if is_active else "0 MB"
            desc   = f"{acc.role.title()} Account"
            for val, w, fg in [
                (f"{acc.avatar}  {acc.display_name}", 200, T["fg_primary"]),
                (status,  100, T["success"] if is_active else T["fg_tertiary"]),
                (cpu,      80, T["fg_secondary"]),
                (ram,      90, T["fg_secondary"]),
                (desc,    200, T["fg_tertiary"]),
            ]:
                tk.Label(row, text=val, font=FONTS.get("small", ()),
                         fg=fg, bg=alt, width=w//7,
                         anchor="w", padx=8, pady=5).pack(side="left")

    # ─── Auto refresh ─────────────────────────────────────────────────────────
    def _refresh(self) -> None:
        if not self._closed:
            self._draw_tab()

    def _schedule_refresh(self) -> None:
        if not self._closed:
            self._refresh()
            self.frame.after(self.REFRESH_MS, self._schedule_refresh)


# ═══════════════════════════════════════════════════════════════════════════════
#  §24  MAIL CLIENT
# ═══════════════════════════════════════════════════════════════════════════════

class MailWin(BaseWin):
    """
    Simulated mail client.
    Folders : Inbox · Starred · Sent · Drafts · Trash
    Features: compose, reply, forward, star, delete, search, read pane
    """

    _SEED_MAILS: List[Dict] = [
        {"id": 1, "folder": "inbox", "from": "system@pyos.local",
         "to": "user@pyos.local", "subject": "Welcome to PyOS Mail!",
         "body": "Hello!\n\nWelcome to PyOS Mail. This is your simulated inbox.\n\nYou can compose new messages, reply to emails, star important ones, and move them to folders.\n\nEnjoy PyOS 14!",
         "date": "Today 09:00", "read": False, "starred": True},
        {"id": 2, "folder": "inbox", "from": "noreply@updates.pyos",
         "to": "user@pyos.local", "subject": "PyOS 14 is now available",
         "body": "PyOS 14 Horizon is now available.\n\nNew features include:\n• 4-layer clean architecture\n• Dark, Light and Midnight themes\n• 22 built-in applications\n• 70+ terminal commands\n• New Code Editor with syntax highlighting\n\nEnjoy the upgrade!",
         "date": "Today 08:30", "read": False, "starred": False},
        {"id": 3, "folder": "inbox", "from": "security@pyos.local",
         "to": "user@pyos.local", "subject": "Your account security summary",
         "body": "Security Summary\n\nYour account is secure.\n\n• Last login: Today\n• Active sessions: 1\n• Failed attempts: 0\n• Password strength: Strong\n\nNo action required.",
         "date": "Yesterday", "read": True, "starred": False},
        {"id": 4, "folder": "inbox", "from": "calendar@pyos.local",
         "to": "user@pyos.local", "subject": "Upcoming event reminder",
         "body": "Reminder: You have an event scheduled.\n\nEvent: Team Standup\nDate: Tomorrow\nTime: 09:00\n\nThis is an automated reminder from PyOS Calendar.",
         "date": "Yesterday", "read": True, "starred": True},
        {"id": 5, "folder": "inbox", "from": "newsletter@pyos.dev",
         "to": "user@pyos.local", "subject": "PyOS Developer Newsletter — Vol. 3",
         "body": "Developer Newsletter Vol. 3\n\nWelcome to the latest edition!\n\nTopics this month:\n• Building custom apps for PyOS\n• Using the EventBus for inter-app communication\n• VFS API reference guide\n• Contributing to the PyOS project\n\nHappy coding!",
         "date": "Mon", "read": True, "starred": False},
        {"id": 6, "folder": "sent", "from": "user@pyos.local",
         "to": "friend@example.com", "subject": "Re: PyOS is awesome",
         "body": "Hey!\n\nThanks! I've been using PyOS 14 and it's great. The terminal alone has over 70 commands.\n\nDef worth trying out.\n\nCheers,\nUser",
         "date": "Mon", "read": True, "starred": False},
        {"id": 7, "folder": "drafts", "from": "user@pyos.local",
         "to": "", "subject": "Draft: Ideas for new apps",
         "body": "Things to build next:\n- Weather widget\n- Note sync\n- RSS reader improvements",
         "date": "Sun", "read": True, "starred": False},
        {"id": 8, "folder": "trash", "from": "spam@junk.example",
         "to": "user@pyos.local", "subject": "You've won a prize!!!",
         "body": "Click here to claim your prize!!!\n\n(This is a simulated spam email.)",
         "date": "Last week", "read": False, "starred": False},
    ]

    def __init__(self, wm: WM):
        self._mails:      List[Dict] = [dict(m) for m in self._SEED_MAILS]
        self._folder:     str = "inbox"
        self._selected:   Optional[Dict] = None
        self._next_id:    int = 100
        self._compose_win: Optional[tk.Toplevel] = None
        super().__init__(wm, "Mail", 960, 620, "📧")

    # ─── Build ────────────────────────────────────────────────────────────────
    def _build(self) -> None:
        self._show_menubar()
        self._add_menu("File", [
            ("Compose",    self._compose,     "Ctrl+N"),
            ("---",        None),
            ("Close",      self.close),
        ])
        self._add_menu("Edit", [
            ("Reply",      self._reply),
            ("Forward",    self._forward),
            ("---",        None),
            ("Delete",     self._delete_selected),
            ("Mark as Read", self._mark_read),
        ])
        self._add_menu("View", [
            ("Inbox",      lambda: self._switch_folder("inbox")),
            ("Starred",    lambda: self._switch_folder("starred")),
            ("Sent",       lambda: self._switch_folder("sent")),
            ("Drafts",     lambda: self._switch_folder("drafts")),
            ("Trash",      lambda: self._switch_folder("trash")),
        ])
        self._show_statusbar()
        self.client.config(bg=T["bg_surface"])

        # Three-pane layout: sidebar | list | reader
        pane = tk.Frame(self.client, bg=T["bg_surface"])
        pane.pack(fill="both", expand=True)

        # ── Sidebar ───────────────────────────────────────────────────────────
        sidebar = tk.Frame(pane, bg=T["bg_sidebar"], width=170)
        sidebar.pack(side="left", fill="y")
        sidebar.pack_propagate(False)

        tk.Label(sidebar, text="  📧  Mail",
                 font=FONTS.get("h3", ()), fg=T["accent"],
                 bg=T["bg_sidebar"], pady=14, padx=4).pack(fill="x")

        # Compose button
        fl_button(sidebar, "＋  Compose", self._compose,
                  style="primary").pack(fill="x", padx=10, pady=(0, 10))

        self._folder_btns: Dict[str, tk.Label] = {}
        folders = [
            ("inbox",   "📥", "Inbox"),
            ("starred", "⭐", "Starred"),
            ("sent",    "📤", "Sent"),
            ("drafts",  "📝", "Drafts"),
            ("trash",   "🗑",  "Trash"),
        ]
        for fid, ficon, fname in folders:
            count    = sum(1 for m in self._mails
                          if m["folder"] == fid and not m["read"])
            badge    = f"  {count}" if count and fid == "inbox" else ""
            active   = fid == self._folder
            btn = tk.Label(
                sidebar,
                text=f"  {ficon}  {fname}{badge}",
                font=FONTS.get("body_bold" if active else "body", ()),
                fg=T["fg_primary"] if active else T["fg_secondary"],
                bg=T["bg_active"] if active else T["bg_sidebar"],
                anchor="w", pady=8, padx=6, cursor="hand2",
            )
            btn.pack(fill="x")
            self._folder_btns[fid] = btn
            btn.bind("<Button-1>", lambda e, fid=fid: self._switch_folder(fid))
            btn.bind("<Enter>",
                lambda e, b=btn, fid=fid:
                    b.config(bg=T["bg_hover"]) if fid != self._folder else None)
            btn.bind("<Leave>",
                lambda e, b=btn, fid=fid:
                    b.config(bg=T["bg_active"] if fid == self._folder else T["bg_sidebar"]))

        fl_separator(sidebar).pack(fill="x", padx=8, pady=8)

        # Storage indicator
        tk.Label(sidebar, text="  Storage",
                 font=FONTS.get("micro", ()), fg=T["fg_tertiary"],
                 bg=T["bg_sidebar"], anchor="w", padx=8).pack(fill="x")
        bar = tk.Frame(sidebar, bg=T["bg_input"], height=6)
        bar.pack(fill="x", padx=10, pady=4)
        tk.Frame(bar, bg=T["accent"], height=6).place(relx=0, rely=0, relwidth=0.12, relheight=1)
        tk.Label(sidebar, text="  1.2 MB of 10 GB used",
                 font=FONTS.get("nano", ()), fg=T["fg_tertiary"],
                 bg=T["bg_sidebar"], anchor="w", padx=8).pack(fill="x")

        fl_separator(pane, orient="v").pack(side="left", fill="y")

        # ── Mail list ─────────────────────────────────────────────────────────
        list_pane = tk.Frame(pane, bg=T["bg_surface"], width=320)
        list_pane.pack(side="left", fill="y")
        list_pane.pack_propagate(False)

        # Search bar
        sf = tk.Frame(list_pane, bg=T["bg_input"])
        sf.pack(fill="x", padx=8, pady=8)
        tk.Label(sf, text="🔍", bg=T["bg_input"],
                 font=FONTS.get("small", ())).pack(side="left", padx=4)
        self._search_var = tk.StringVar()
        se = tk.Entry(sf, textvariable=self._search_var,
                      font=FONTS.get("body", ()), bg=T["bg_input"],
                      fg=T["fg_primary"], insertbackground=T["accent"],
                      relief="flat", bd=0)
        se.pack(side="left", fill="x", expand=True, pady=6)
        self._search_var.trace_add("write", lambda *a: self._load_mail_list())

        fl_separator(list_pane).pack(fill="x")

        self._list_scroll = ScrollableFrame(list_pane, bg_key="bg_surface")
        self._list_scroll.pack(fill="both", expand=True)
        self._list_inner = self._list_scroll.inner

        fl_separator(pane, orient="v").pack(side="left", fill="y")

        # ── Read pane ─────────────────────────────────────────────────────────
        self._read_pane = tk.Frame(pane, bg=T["bg_surface"])
        self._read_pane.pack(side="left", fill="both", expand=True)

        self._load_mail_list()
        self._show_empty_reader()
        self._set_status(
            f"Inbox: {sum(1 for m in self._mails if m['folder']=='inbox')} messages  │  "
            f"{sum(1 for m in self._mails if not m['read'] and m['folder']=='inbox')} unread"
        )

    # ─── Folder switching ─────────────────────────────────────────────────────
    def _switch_folder(self, fid: str) -> None:
        self._folder   = fid
        self._selected = None
        for f, btn in self._folder_btns.items():
            active = f == fid
            btn.config(
                bg=T["bg_active"] if active else T["bg_sidebar"],
                fg=T["fg_primary"] if active else T["fg_secondary"],
                font=FONTS.get("body_bold" if active else "body", ()),
            )
        self._load_mail_list()
        self._show_empty_reader()

    # ─── Mail list ────────────────────────────────────────────────────────────
    def _load_mail_list(self) -> None:
        for w in self._list_inner.winfo_children():
            w.destroy()
        q = self._search_var.get().lower().strip()
        if self._folder == "starred":
            mails = [m for m in self._mails if m["starred"]]
        else:
            mails = [m for m in self._mails if m["folder"] == self._folder]
        if q:
            mails = [m for m in mails if
                     q in m["subject"].lower() or
                     q in m["from"].lower() or
                     q in m["body"].lower()]
        if not mails:
            tk.Label(self._list_inner, text="No messages.",
                     font=FONTS.get("body", ()), fg=T["fg_tertiary"],
                     bg=T["bg_surface"], pady=40).pack()
            return
        for m in mails:
            self._add_mail_row(m)

    def _add_mail_row(self, m: Dict) -> None:
        unread  = not m["read"]
        active  = m is self._selected
        bg      = T["bg_selection"] if active else (T["bg_elevated"] if unread else T["bg_surface"])

        row = tk.Frame(self._list_inner, bg=bg, cursor="hand2")
        row.pack(fill="x")

        # Star
        star_lbl = tk.Label(
            row,
            text="⭐" if m["starred"] else "☆",
            font=FONTS.get("small", ()),
            fg=T["warning"] if m["starred"] else T["fg_tertiary"],
            bg=bg, padx=6, pady=6, cursor="hand2",
        )
        star_lbl.pack(side="left")
        star_lbl.bind("<Button-1>",
            lambda e, mail=m, r=row: self._toggle_star(mail, r))

        body = tk.Frame(row, bg=bg)
        body.pack(side="left", fill="x", expand=True, pady=6)

        # Sender + date
        top = tk.Frame(body, bg=bg)
        top.pack(fill="x")
        tk.Label(top,
                 text=m["from"].split("@")[0].replace(".", " ").title(),
                 font=FONTS.get("body_bold" if unread else "body", ()),
                 fg=T["fg_primary"], bg=bg, anchor="w").pack(side="left")
        tk.Label(top, text=m["date"],
                 font=FONTS.get("micro", ()),
                 fg=T["fg_tertiary"], bg=bg).pack(side="right", padx=8)

        # Subject
        tk.Label(body,
                 text=m["subject"][:44],
                 font=FONTS.get("body_bold" if unread else "small", ()),
                 fg=T["accent"] if unread else T["fg_secondary"],
                 bg=bg, anchor="w").pack(fill="x")

        # Preview
        preview = m["body"].replace("\n", " ")[:60] + "…"
        tk.Label(body, text=preview, font=FONTS.get("micro", ()),
                 fg=T["fg_tertiary"], bg=bg, anchor="w").pack(fill="x")

        fl_separator(self._list_inner).pack(fill="x")

        # Unread dot
        if unread:
            tk.Frame(row, width=6, bg=T["accent"]).pack(side="right", fill="y")

        def _click(e, mail=m, r=row):
            self._selected = mail
            self._open_mail(mail)
            self._load_mail_list()

        for widget in (row, body, top):
            widget.bind("<Button-1>", _click)
            widget.bind("<Enter>",
                lambda e, r=row, bg=bg: r.config(bg=T["bg_hover"]))
            widget.bind("<Leave>",
                lambda e, r=row, bg=bg, mail=m:
                    r.config(bg=T["bg_selection"] if mail is self._selected else bg))

    # ─── Reader pane ──────────────────────────────────────────────────────────
    def _show_empty_reader(self) -> None:
        for w in self._read_pane.winfo_children():
            w.destroy()
        tk.Label(self._read_pane, text="📧",
                 font=FONTS.get("emoji_lg", ()), fg=T["fg_tertiary"],
                 bg=T["bg_surface"]).pack(pady=(100, 12))
        tk.Label(self._read_pane, text="Select a message to read",
                 font=FONTS.get("h3", ()), fg=T["fg_tertiary"],
                 bg=T["bg_surface"]).pack()

    def _open_mail(self, m: Dict) -> None:
        m["read"] = True
        for w in self._read_pane.winfo_children():
            w.destroy()

        # Header
        hdr = tk.Frame(self._read_pane, bg=T["bg_elevated"])
        hdr.pack(fill="x", padx=0, pady=0)
        hdr_inner = tk.Frame(hdr, bg=T["bg_elevated"])
        hdr_inner.pack(fill="x", padx=20, pady=14)

        tk.Label(hdr_inner, text=m["subject"],
                 font=FONTS.get("h2", ()), fg=T["fg_primary"],
                 bg=T["bg_elevated"], anchor="w",
                 wraplength=520).pack(fill="x")

        meta = tk.Frame(hdr_inner, bg=T["bg_elevated"])
        meta.pack(fill="x", pady=4)
        tk.Label(meta, text=f"From:  {m['from']}",
                 font=FONTS.get("small", ()), fg=T["fg_secondary"],
                 bg=T["bg_elevated"], anchor="w").pack(fill="x")
        tk.Label(meta, text=f"To:      {m['to']}",
                 font=FONTS.get("small", ()), fg=T["fg_secondary"],
                 bg=T["bg_elevated"], anchor="w").pack(fill="x")
        tk.Label(meta, text=f"Date:  {m['date']}",
                 font=FONTS.get("small", ()), fg=T["fg_tertiary"],
                 bg=T["bg_elevated"], anchor="w").pack(fill="x")

        # Action buttons
        btn_row = tk.Frame(hdr_inner, bg=T["bg_elevated"])
        btn_row.pack(anchor="w", pady=8)
        fl_button(btn_row, "↩ Reply",   lambda: self._reply(),   style="primary"   ).pack(side="left", padx=(0, 6))
        fl_button(btn_row, "→ Forward", lambda: self._forward(), style="secondary" ).pack(side="left", padx=(0, 6))
        fl_button(btn_row, "🗑 Delete",
                  lambda: (self._delete_selected(), self._show_empty_reader()),
                  style="danger").pack(side="left", padx=(0, 6))
        fl_button(btn_row,
                  "⭐" if not m["starred"] else "☆  Unstar",
                  lambda: self._toggle_star(m, None),
                  style="ghost").pack(side="left")

        fl_separator(self._read_pane).pack(fill="x")

        # Body
        body_scroll = ScrollableFrame(self._read_pane, bg_key="bg_surface")
        body_scroll.pack(fill="both", expand=True)
        txt = tk.Text(
            body_scroll.inner,
            font=FONTS.get("body", ()),
            bg=T["bg_surface"],
            fg=T["fg_primary"],
            relief="flat", bd=0,
            wrap="word",
            padx=20, pady=16,
            state="normal",
        )
        txt.insert("1.0", m["body"])
        txt.config(state="disabled")
        txt.pack(fill="both", expand=True)

    # ─── Actions ──────────────────────────────────────────────────────────────
    def _toggle_star(self, m: Dict, row: Optional[tk.Frame]) -> None:
        m["starred"] = not m["starred"]
        self._load_mail_list()

    def _delete_selected(self) -> None:
        if self._selected:
            if self._selected["folder"] == "trash":
                self._mails.remove(self._selected)
            else:
                self._selected["folder"] = "trash"
            self._selected = None
            self._load_mail_list()

    def _mark_read(self) -> None:
        if self._selected:
            self._selected["read"] = True
            self._load_mail_list()

    def _compose(self,
                 to:      str = "",
                 subject: str = "",
                 body:    str = "") -> None:
        d = tk.Toplevel(self.frame)
        d.title("New Message")
        d.config(bg=T["bg_surface"])
        d.geometry("600x480")

        tk.Label(d, text="New Message", font=FONTS.get("h2", ()),
                 fg=T["fg_primary"], bg=T["bg_surface"],
                 pady=14, padx=20).pack(anchor="w")
        fl_separator(d).pack(fill="x")

        for label, default in [("To:", to), ("Subject:", subject)]:
            row = tk.Frame(d, bg=T["bg_surface"])
            row.pack(fill="x", padx=16, pady=4)
            tk.Label(row, text=label, font=FONTS.get("body_bold", ()),
                     fg=T["fg_secondary"], bg=T["bg_surface"], width=9,
                     anchor="w").pack(side="left")
            e = fl_entry(row)
            e.pack(side="left", fill="x", expand=True)
            e.insert(0, default)
            if label == "To:":
                self._compose_to = e
            else:
                self._compose_subj = e

        fl_separator(d).pack(fill="x", pady=4)

        self._compose_body = fl_text(d, font_key="body")
        self._compose_body.pack(fill="both", expand=True, padx=16, pady=4)
        self._compose_body.insert("1.0", body)
        self._compose_body.focus_set()

        btn_row = tk.Frame(d, bg=T["bg_surface"])
        btn_row.pack(fill="x", padx=16, pady=10)
        fl_button(btn_row, "Send",
                  lambda: self._send_mail(d),
                  style="primary").pack(side="left", padx=(0, 8))
        fl_button(btn_row, "Save Draft",
                  lambda: self._save_draft(d),
                  style="secondary").pack(side="left", padx=(0, 8))
        fl_button(btn_row, "Discard",
                  d.destroy, style="ghost").pack(side="left")

    def _send_mail(self, dialog: tk.Toplevel) -> None:
        m = {
            "id":       self._next_id,
            "folder":   "sent",
            "from":     "user@pyos.local",
            "to":       self._compose_to.get().strip(),
            "subject":  self._compose_subj.get().strip() or "(no subject)",
            "body":     self._compose_body.get("1.0", "end-1c"),
            "date":     datetime.datetime.now().strftime("%H:%M"),
            "read":     True,
            "starred":  False,
        }
        self._next_id += 1
        self._mails.append(m)
        dialog.destroy()
        self._switch_folder("sent")
        notify(self.wm.root, "Mail", f"Message sent to {m['to']}", kind="success")

    def _save_draft(self, dialog: tk.Toplevel) -> None:
        m = {
            "id":      self._next_id,
            "folder":  "drafts",
            "from":    "user@pyos.local",
            "to":      self._compose_to.get().strip(),
            "subject": self._compose_subj.get().strip() or "(draft)",
            "body":    self._compose_body.get("1.0", "end-1c"),
            "date":    datetime.datetime.now().strftime("%H:%M"),
            "read":    True,
            "starred": False,
        }
        self._next_id += 1
        self._mails.append(m)
        dialog.destroy()
        notify(self.wm.root, "Mail", "Draft saved", kind="info")

    def _reply(self) -> None:
        if self._selected:
            self._compose(
                to=self._selected["from"],
                subject="Re: " + self._selected["subject"],
                body="\n\n--- Original Message ---\n" + self._selected["body"],
            )

    def _forward(self) -> None:
        if self._selected:
            self._compose(
                subject="Fwd: " + self._selected["subject"],
                body="\n\n--- Forwarded Message ---\n"
                     f"From: {self._selected['from']}\n"
                     f"Date: {self._selected['date']}\n\n"
                     + self._selected["body"],
            )


# ═══════════════════════════════════════════════════════════════════════════════
#  §25  CALENDAR
# ═══════════════════════════════════════════════════════════════════════════════

class CalendarWin(BaseWin):
    """
    Full calendar app with month / week / day views and event management.
    Events are stored in memory (list of dicts).
    """

    _COLORS = ["#6c63ff","#3b82f6","#22c55e","#f59e0b","#ef4444","#a855f7","#14b8a6"]

    def __init__(self, wm: WM):
        now = datetime.date.today()
        self._year    = now.year
        self._month   = now.month
        self._today   = now
        self._view    = "month"
        self._events: List[Dict] = [
            {"id": 1, "title": "PyOS Launch Party",
             "date": now.strftime("%Y-%m-%d"),
             "time": "18:00", "color": "#6c63ff", "desc": "Celebrate PyOS 14!"},
            {"id": 2, "title": "Weekly Standup",
             "date": (now + datetime.timedelta(days=1)).strftime("%Y-%m-%d"),
             "time": "09:00", "color": "#3b82f6", "desc": "Team sync."},
            {"id": 3, "title": "Code Review",
             "date": (now + datetime.timedelta(days=3)).strftime("%Y-%m-%d"),
             "time": "14:00", "color": "#22c55e", "desc": "Review PR #42."},
            {"id": 4, "title": "Birthday",
             "date": (now + datetime.timedelta(days=7)).strftime("%Y-%m-%d"),
             "time": "All day", "color": "#ef4444", "desc": "Don't forget!"},
        ]
        self._next_event_id = 10
        super().__init__(wm, "Calendar", 900, 620, "📅")

    def _build(self) -> None:
        self._show_menubar()
        self._add_menu("File", [
            ("New Event",   self._new_event_dialog, "Ctrl+N"),
            ("---",         None),
            ("Close",       self.close),
        ])
        self._add_menu("View", [
            ("Month",  lambda: self._set_view("month"), "Ctrl+1"),
            ("Week",   lambda: self._set_view("week"),  "Ctrl+2"),
            ("Day",    lambda: self._set_view("day"),   "Ctrl+3"),
        ])
        self._show_statusbar()
        self.client.config(bg=T["bg_surface"])

        # ── Top toolbar ───────────────────────────────────────────────────────
        toolbar = tk.Frame(self.client, bg=T["bg_elevated"])
        toolbar.pack(fill="x")

        fl_icon_button(toolbar, "←", self._prev_period,
                       bg_key="bg_elevated", padx=12, pady=8).pack(side="left")
        fl_icon_button(toolbar, "→", self._next_period,
                       bg_key="bg_elevated", padx=12, pady=8).pack(side="left")
        fl_button(toolbar, "Today", self._go_today,
                  style="secondary", pady=5).pack(side="left", padx=8)

        self._period_var = tk.StringVar()
        tk.Label(toolbar, textvariable=self._period_var,
                 font=FONTS.get("h2", ()), fg=T["fg_primary"],
                 bg=T["bg_elevated"], padx=12).pack(side="left")

        # View buttons
        vf = tk.Frame(toolbar, bg=T["bg_elevated"])
        vf.pack(side="right", padx=8)
        self._view_btns: Dict[str, tk.Label] = {}
        for v_name in ["Month", "Week", "Day"]:
            vb = tk.Label(
                vf,
                text=v_name,
                font=FONTS.get("btn", ()),
                fg=T["btn_primary_fg"] if v_name.lower() == self._view else T["fg_secondary"],
                bg=T["accent"] if v_name.lower() == self._view else T["bg_elevated"],
                padx=12, pady=6, cursor="hand2",
            )
            vb.pack(side="left", padx=2)
            vb.bind("<Button-1>", lambda e, v=v_name.lower(): self._set_view(v))
            self._view_btns[v_name.lower()] = vb

        fl_button(toolbar, "＋ New Event", self._new_event_dialog,
                  style="primary", pady=5).pack(side="right", padx=12)

        fl_separator(self.client).pack(fill="x")

        # ── Main area ─────────────────────────────────────────────────────────
        self._main = tk.Frame(self.client, bg=T["bg_surface"])
        self._main.pack(fill="both", expand=True)

        self._draw_view()

    # ─── View management ──────────────────────────────────────────────────────
    def _set_view(self, v: str) -> None:
        self._view = v
        for name, btn in self._view_btns.items():
            active = name == v
            btn.config(
                bg=T["accent"] if active else T["bg_elevated"],
                fg=T["btn_primary_fg"] if active else T["fg_secondary"],
            )
        self._draw_view()

    def _draw_view(self) -> None:
        for w in self._main.winfo_children():
            w.destroy()
        {"month": self._draw_month,
         "week":  self._draw_week,
         "day":   self._draw_day}[self._view]()
        months = ["January","February","March","April","May","June",
                  "July","August","September","October","November","December"]
        self._period_var.set(f"{months[self._month-1]} {self._year}")

    def _prev_period(self) -> None:
        if self._view == "month":
            self._month -= 1
            if self._month < 1:
                self._month, self._year = 12, self._year - 1
        elif self._view in ("week", "day"):
            self._today -= datetime.timedelta(days=7 if self._view=="week" else 1)
        self._draw_view()

    def _next_period(self) -> None:
        if self._view == "month":
            self._month += 1
            if self._month > 12:
                self._month, self._year = 1, self._year + 1
        elif self._view in ("week", "day"):
            self._today += datetime.timedelta(days=7 if self._view=="week" else 1)
        self._draw_view()

    def _go_today(self) -> None:
        today = datetime.date.today()
        self._year, self._month, self._today = today.year, today.month, today
        self._draw_view()

    # ─── Month view ───────────────────────────────────────────────────────────
    def _draw_month(self) -> None:
        f = self._main
        cal = _cal.monthcalendar(self._year, self._month)
        today = datetime.date.today()

        # Day-of-week headers
        header = tk.Frame(f, bg=T["bg_elevated"])
        header.pack(fill="x")
        days = ["Mon", "Tue", "Wed", "Thu", "Fri", "Sat", "Sun"]
        for d in days:
            tk.Label(header, text=d,
                     font=FONTS.get("small_bold", ()),
                     fg=T["accent"] if d in ("Sat","Sun") else T["fg_secondary"],
                     bg=T["bg_elevated"],
                     width=8, pady=6).pack(side="left", fill="x", expand=True)
        fl_separator(f).pack(fill="x")

        # Calendar grid
        grid = tk.Frame(f, bg=T["bg_surface"])
        grid.pack(fill="both", expand=True)

        for week in cal:
            row = tk.Frame(grid, bg=T["bg_surface"])
            row.pack(fill="both", expand=True)
            for col, day in enumerate(week):
                is_weekend = col >= 5
                is_today   = (day != 0 and
                              datetime.date(self._year, self._month, day) == today)
                cell = tk.Frame(
                    row,
                    bg=T["bg_card"] if is_today else T["bg_surface"],
                    highlightthickness=1,
                    highlightbackground=T["accent"] if is_today else T["border"],
                )
                cell.pack(side="left", fill="both", expand=True)

                # Day number
                lbl = tk.Label(
                    cell,
                    text=str(day) if day != 0 else "",
                    font=FONTS.get("body_bold" if is_today else "body", ()),
                    fg=T["accent"] if is_today else
                       (T["fg_tertiary"] if is_weekend else T["fg_primary"]),
                    bg=T["bg_card"] if is_today else T["bg_surface"],
                    anchor="ne", padx=6, pady=4,
                )
                lbl.pack(fill="x")

                # Events for this day
                if day != 0:
                    date_str = f"{self._year}-{self._month:02}-{day:02}"
                    day_events = [e for e in self._events if e["date"] == date_str]
                    for ev in day_events[:3]:
                        ev_lbl = tk.Label(
                            cell,
                            text=f" {ev['title'][:14]}",
                            font=FONTS.get("nano", ()),
                            fg=T["fg_on_accent"],
                            bg=ev["color"],
                            anchor="w",
                            padx=2, pady=1,
                        )
                        ev_lbl.pack(fill="x", padx=2, pady=1)
                        ev_lbl.bind("<Button-1>",
                            lambda e, ev=ev: self._show_event(ev))

                    if len(day_events) > 3:
                        tk.Label(cell,
                                 text=f"+{len(day_events)-3} more",
                                 font=FONTS.get("nano", ()),
                                 fg=T["fg_tertiary"],
                                 bg=T["bg_card"] if is_today else T["bg_surface"],
                                 anchor="w", padx=4).pack(fill="x")

                    # Click to add event
                    cell.bind("<Double-Button-1>",
                        lambda e, ds=date_str: self._new_event_dialog(date=ds))

                fl_separator(grid, orient="v").pack(side="left", fill="y")
            fl_separator(grid).pack(fill="x")

    # ─── Week view ────────────────────────────────────────────────────────────
    def _draw_week(self) -> None:
        f = self._main
        # Find Monday of current week
        weekday = self._today.weekday()
        monday  = self._today - datetime.timedelta(days=weekday)
        week_days = [monday + datetime.timedelta(days=i) for i in range(7)]
        today = datetime.date.today()

        # Header row
        hdr = tk.Frame(f, bg=T["bg_elevated"])
        hdr.pack(fill="x")
        tk.Label(hdr, text="", bg=T["bg_elevated"], width=5).pack(side="left")
        for d in week_days:
            is_today = d == today
            col = tk.Frame(hdr, bg=T["bg_elevated"])
            col.pack(side="left", fill="x", expand=True)
            tk.Label(col,
                     text=d.strftime("%a"),
                     font=FONTS.get("small_bold", ()),
                     fg=T["accent"] if is_today else T["fg_secondary"],
                     bg=T["bg_elevated"]).pack()
            day_lbl = tk.Label(col,
                     text=str(d.day),
                     font=FONTS.get("h3", ()),
                     fg=T["btn_primary_fg"] if is_today else T["fg_primary"],
                     bg=T["accent"] if is_today else T["bg_elevated"],
                     padx=6, pady=2)
            day_lbl.pack()
        fl_separator(f).pack(fill="x")

        # Scrollable hours grid
        scroll = ScrollableFrame(f, bg_key="bg_surface")
        scroll.pack(fill="both", expand=True)
        inner = scroll.inner

        for hour in range(7, 22):
            row = tk.Frame(inner, bg=T["bg_surface"])
            row.pack(fill="x")
            # Hour label
            tk.Label(row, text=f" {hour:02}:00",
                     font=FONTS.get("micro", ()), fg=T["fg_tertiary"],
                     bg=T["bg_elevated"], width=5, pady=14, anchor="n").pack(side="left")
            fl_separator(row, orient="v").pack(side="left", fill="y")
            for d in week_days:
                date_str = d.strftime("%Y-%m-%d")
                cell = tk.Frame(row, bg=T["bg_surface"],
                                highlightthickness=1,
                                highlightbackground=T["border"])
                cell.pack(side="left", fill="both", expand=True)
                # Events at this hour
                for ev in self._events:
                    if ev["date"] == date_str and ev.get("time","").startswith(f"{hour:02}"):
                        tk.Label(cell,
                                 text=f" {ev['title'][:12]}",
                                 font=FONTS.get("nano", ()),
                                 fg=T["fg_on_accent"], bg=ev["color"],
                                 anchor="w", pady=2).pack(fill="x", padx=2, pady=2)
                cell.bind("<Double-Button-1>",
                    lambda e, ds=date_str, h=hour:
                        self._new_event_dialog(date=ds, time=f"{h:02}:00"))
            fl_separator(inner).pack(fill="x")

    # ─── Day view ─────────────────────────────────────────────────────────────
    def _draw_day(self) -> None:
        f = self._main
        date_str = self._today.strftime("%Y-%m-%d")
        day_events = [e for e in self._events if e["date"] == date_str]

        # Header
        hdr = tk.Frame(f, bg=T["bg_elevated"])
        hdr.pack(fill="x", pady=0)
        tk.Label(hdr,
                 text=self._today.strftime("%A, %B %d, %Y"),
                 font=FONTS.get("h2", ()), fg=T["fg_primary"],
                 bg=T["bg_elevated"], padx=20, pady=14).pack(side="left")
        fl_button(hdr, "＋ Add Event",
                  lambda: self._new_event_dialog(date=date_str),
                  style="primary", pady=5).pack(side="right", padx=16, pady=10)
        fl_separator(f).pack(fill="x")

        # Sidebar with event list
        pane = tk.Frame(f, bg=T["bg_surface"])
        pane.pack(fill="both", expand=True)

        # Event summary sidebar
        ev_sidebar = tk.Frame(pane, bg=T["bg_card"], width=240)
        ev_sidebar.pack(side="left", fill="y")
        ev_sidebar.pack_propagate(False)
        tk.Label(ev_sidebar, text=f"  {len(day_events)} Events",
                 font=FONTS.get("h4", ()), fg=T["fg_secondary"],
                 bg=T["bg_card"], pady=12).pack(fill="x")
        for ev in day_events:
            ec = tk.Frame(ev_sidebar, bg=T["bg_card"], cursor="hand2")
            ec.pack(fill="x", padx=10, pady=4)
            tk.Frame(ec, width=4, bg=ev["color"]).pack(side="left", fill="y")
            ei = tk.Frame(ec, bg=T["bg_card"]); ei.pack(side="left", fill="x", expand=True, padx=8)
            tk.Label(ei, text=ev["time"], font=FONTS.get("micro", ()),
                     fg=T["fg_tertiary"], bg=T["bg_card"], anchor="w").pack(fill="x")
            tk.Label(ei, text=ev["title"], font=FONTS.get("body_bold", ()),
                     fg=T["fg_primary"], bg=T["bg_card"], anchor="w").pack(fill="x")
            ec.bind("<Button-1>", lambda e, ev=ev: self._show_event(ev))

        fl_separator(pane, orient="v").pack(side="left", fill="y")

        # Hourly timeline
        scroll = ScrollableFrame(pane, bg_key="bg_surface")
        scroll.pack(fill="both", expand=True)
        inner = scroll.inner

        for hour in range(0, 24):
            row = tk.Frame(inner, bg=T["bg_surface"])
            row.pack(fill="x")
            tk.Label(row, text=f" {hour:02}:00",
                     font=FONTS.get("small", ()), fg=T["fg_tertiary"],
                     bg=T["bg_elevated"], width=6, pady=20, anchor="n").pack(side="left")
            fl_separator(row, orient="v").pack(side="left", fill="y")
            slot = tk.Frame(row, bg=T["bg_surface"])
            slot.pack(side="left", fill="both", expand=True)
            for ev in day_events:
                if ev.get("time","").startswith(f"{hour:02}"):
                    ev_card = tk.Frame(slot, bg=ev["color"], cursor="hand2")
                    ev_card.pack(fill="x", padx=8, pady=4)
                    tk.Label(ev_card, text=f"  {ev['time']}  {ev['title']}",
                             font=FONTS.get("body_bold", ()),
                             fg=T["fg_on_accent"], bg=ev["color"],
                             anchor="w", pady=8).pack(fill="x")
                    if ev.get("desc"):
                        tk.Label(ev_card, text=f"  {ev['desc']}",
                                 font=FONTS.get("small", ()),
                                 fg=T["fg_secondary"], bg=ev["color"],
                                 anchor="w", pady=2).pack(fill="x")
                    ev_card.bind("<Button-1>", lambda e, ev=ev: self._show_event(ev))
            slot.bind("<Double-Button-1>",
                lambda e, ds=date_str, h=hour:
                    self._new_event_dialog(date=ds, time=f"{h:02}:00"))
            fl_separator(inner).pack(fill="x")

    # ─── Event dialogs ────────────────────────────────────────────────────────
    def _new_event_dialog(self,
                          date: str = "",
                          time: str = "09:00") -> None:
        d = tk.Toplevel(self.frame)
        d.title("New Event")
        d.config(bg=T["bg_surface"])
        d.geometry("400x320")
        d.grab_set()

        tk.Label(d, text="New Event", font=FONTS.get("h2", ()),
                 fg=T["fg_primary"], bg=T["bg_surface"],
                 pady=12, padx=20).pack(anchor="w")
        fl_separator(d).pack(fill="x")

        fields = {}
        for label, default in [
            ("Title:",  ""),
            ("Date:",   date or datetime.date.today().strftime("%Y-%m-%d")),
            ("Time:",   time),
            ("Notes:",  ""),
        ]:
            row = tk.Frame(d, bg=T["bg_surface"]); row.pack(fill="x", padx=16, pady=5)
            tk.Label(row, text=label, font=FONTS.get("body_bold", ()),
                     fg=T["fg_secondary"], bg=T["bg_surface"],
                     width=8, anchor="w").pack(side="left")
            e = fl_entry(row)
            e.pack(side="left", fill="x", expand=True)
            e.insert(0, default)
            fields[label] = e
        fields["Title:"].focus_set()

        # Colour picker
        color_row = tk.Frame(d, bg=T["bg_surface"]); color_row.pack(fill="x", padx=16, pady=5)
        tk.Label(color_row, text="Colour:", font=FONTS.get("body_bold", ()),
                 fg=T["fg_secondary"], bg=T["bg_surface"], width=8, anchor="w").pack(side="left")
        chosen_color = tk.StringVar(value=self._COLORS[0])
        for color in self._COLORS:
            sw = tk.Canvas(color_row, width=22, height=22, bg=T["bg_surface"],
                           highlightthickness=2,
                           highlightbackground=T["accent"] if color == chosen_color.get() else T["bg_surface"],
                           cursor="hand2")
            sw.pack(side="left", padx=2)
            sw.create_oval(2, 2, 20, 20, fill=color, outline="")
            sw.bind("<Button-1>", lambda e, c=color, s=sw: (
                chosen_color.set(c),
                [x.config(highlightbackground=T["bg_surface"]) for x in color_row.winfo_children() if isinstance(x, tk.Canvas)],
                s.config(highlightbackground=T["accent"]),
            ))

        def _save():
            title = fields["Title:"].get().strip()
            if not title:
                return
            ev = {
                "id":    self._next_event_id,
                "title": title,
                "date":  fields["Date:"].get().strip(),
                "time":  fields["Time:"].get().strip() or "All day",
                "desc":  fields["Notes:"].get().strip(),
                "color": chosen_color.get(),
            }
            self._next_event_id += 1
            self._events.append(ev)
            d.destroy()
            self._draw_view()
            notify(self.wm.root, "Calendar", f"Event added: {title}", kind="success")

        btn_row = tk.Frame(d, bg=T["bg_surface"]); btn_row.pack(pady=10)
        fl_button(btn_row, "Save Event", _save, style="primary").pack(side="left", padx=6)
        fl_button(btn_row, "Cancel", d.destroy, style="ghost").pack(side="left", padx=6)
        fields["Title:"].bind("<Return>", lambda e: _save())

    def _show_event(self, ev: Dict) -> None:
        d = tk.Toplevel(self.frame)
        d.title(ev["title"])
        d.config(bg=T["bg_surface"])
        d.geometry("380x240")

        tk.Frame(d, height=6, bg=ev["color"]).pack(fill="x")
        tk.Label(d, text=ev["title"], font=FONTS.get("h2", ()),
                 fg=T["fg_primary"], bg=T["bg_surface"],
                 pady=12, padx=20).pack(anchor="w")

        for label, val in [
            ("📅 Date",  ev["date"]),
            ("🕐 Time",  ev.get("time","All day")),
            ("📝 Notes", ev.get("desc","—")),
        ]:
            row = tk.Frame(d, bg=T["bg_surface"]); row.pack(fill="x", padx=20, pady=4)
            tk.Label(row, text=label, font=FONTS.get("body_bold", ()),
                     fg=T["fg_secondary"], bg=T["bg_surface"], width=10, anchor="w").pack(side="left")
            tk.Label(row, text=val, font=FONTS.get("body", ()),
                     fg=T["fg_primary"], bg=T["bg_surface"], anchor="w").pack(side="left")

        btn_row = tk.Frame(d, bg=T["bg_surface"]); btn_row.pack(pady=12)
        fl_button(btn_row, "Delete",
                  lambda: (self._events.remove(ev), d.destroy(), self._draw_view()),
                  style="danger").pack(side="left", padx=6)
        fl_button(btn_row, "Close", d.destroy,
                  style="secondary").pack(side="left", padx=6)


# ═══════════════════════════════════════════════════════════════════════════════
#  §26  APP STORE
# ═══════════════════════════════════════════════════════════════════════════════

class AppStoreWin(BaseWin):
    """
    App Store with category browsing, search, detail view,
    and simulated install / uninstall with progress bar.
    """

    _FEATURED = ["file_manager", "terminal", "code_editor", "weather", "music_player"]

    _STORE_EXTRAS: List[Dict] = [
        {"id":"markdown_editor","name":"Markdown Editor","icon":"📋",
         "desc":"Write and preview Markdown in real time","category":"Productivity",
         "version":"1.0","size":"0.8 MB","rating":4.7,"installs":"10K+"},
        {"id":"pomodoro","name":"Pomodoro Timer","icon":"🍅",
         "desc":"Focus timer with work/break intervals","category":"Productivity",
         "version":"1.2","size":"0.3 MB","rating":4.9,"installs":"50K+"},
        {"id":"unit_converter","name":"Unit Converter","icon":"🔄",
         "desc":"Convert length, weight, temperature and more","category":"Utilities",
         "version":"2.1","size":"0.2 MB","rating":4.5,"installs":"30K+"},
        {"id":"color_picker","name":"Colour Picker","icon":"🎨",
         "desc":"Pick and convert colours between formats","category":"Development",
         "version":"1.0","size":"0.4 MB","rating":4.6,"installs":"8K+"},
        {"id":"json_viewer","name":"JSON Viewer","icon":"📦",
         "desc":"Pretty-print and validate JSON data","category":"Development",
         "version":"1.3","size":"0.5 MB","rating":4.8,"installs":"20K+"},
        {"id":"habit_tracker","name":"Habit Tracker","icon":"✅",
         "desc":"Track daily habits and build streaks","category":"Productivity",
         "version":"2.0","size":"0.6 MB","rating":4.8,"installs":"45K+"},
        {"id":"budget","name":"Budget Planner","icon":"💰",
         "desc":"Track income, expenses and savings goals","category":"Finance",
         "version":"1.5","size":"1.1 MB","rating":4.4,"installs":"15K+"},
        {"id":"recipe_box","name":"Recipe Box","icon":"🍳",
         "desc":"Save and organise your favourite recipes","category":"Lifestyle",
         "version":"1.0","size":"0.7 MB","rating":4.6,"installs":"12K+"},
    ]

    def __init__(self, wm: WM):
        self._installed: Set[str] = {a["id"] for a in APP_REGISTRY}
        self._all_apps  = APP_REGISTRY + self._STORE_EXTRAS
        self._category  = "All"
        self._detail_app: Optional[Dict] = None
        super().__init__(wm, "App Store", 960, 640, "🛍")

    def _build(self) -> None:
        self._show_menubar()
        self._add_menu("Store", [
            ("Check for Updates", lambda: notify(self.wm.root, "App Store",
                                                  "All apps are up to date!", kind="success")),
            ("---", None),
            ("Close", self.close),
        ])
        self._show_statusbar()
        self.client.config(bg=T["bg_surface"])

        # ── Sidebar ───────────────────────────────────────────────────────────
        layout = tk.Frame(self.client, bg=T["bg_surface"])
        layout.pack(fill="both", expand=True)

        sidebar = tk.Frame(layout, bg=T["bg_sidebar"], width=190)
        sidebar.pack(side="left", fill="y")
        sidebar.pack_propagate(False)

        tk.Label(sidebar, text="  🛍  App Store",
                 font=FONTS.get("h3", ()), fg=T["accent"],
                 bg=T["bg_sidebar"], pady=14, padx=4).pack(fill="x")

        # Search
        sf = tk.Frame(sidebar, bg=T["bg_input"])
        sf.pack(fill="x", padx=10, pady=6)
        tk.Label(sf, text="🔍", bg=T["bg_input"],
                 font=FONTS.get("small", ())).pack(side="left", padx=4)
        self._search_var = tk.StringVar()
        se = tk.Entry(sf, textvariable=self._search_var,
                      font=FONTS.get("small", ()), bg=T["bg_input"],
                      fg=T["fg_primary"], insertbackground=T["accent"],
                      relief="flat", bd=0)
        se.pack(side="left", fill="x", expand=True, pady=5)
        self._search_var.trace_add("write", lambda *a: self._load_app_grid())

        fl_separator(sidebar).pack(fill="x", padx=8, pady=4)

        # Category buttons
        cats = ["All"] + sorted(set(a["category"] for a in self._all_apps))
        self._cat_btns: Dict[str, tk.Label] = {}
        for cat in cats:
            active = cat == self._category
            btn = tk.Label(
                sidebar,
                text=f"  {cat}",
                font=FONTS.get("body_bold" if active else "body", ()),
                fg=T["fg_primary"] if active else T["fg_secondary"],
                bg=T["bg_active"] if active else T["bg_sidebar"],
                anchor="w", pady=7, cursor="hand2",
            )
            btn.pack(fill="x")
            self._cat_btns[cat] = btn
            btn.bind("<Button-1>", lambda e, c=cat: self._set_category(c))
            btn.bind("<Enter>",
                lambda e, b=btn, c=cat:
                    b.config(bg=T["bg_hover"]) if c != self._category else None)
            btn.bind("<Leave>",
                lambda e, b=btn, c=cat:
                    b.config(bg=T["bg_active"] if c == self._category else T["bg_sidebar"]))

        fl_separator(layout, orient="v").pack(side="left", fill="y")

        # ── Main content ──────────────────────────────────────────────────────
        self._content = tk.Frame(layout, bg=T["bg_surface"])
        self._content.pack(side="left", fill="both", expand=True)

        self._load_app_grid()
        count = len([a for a in self._all_apps if a["id"] in self._installed])
        self._set_status(f"{len(self._all_apps)} apps available  │  {count} installed")

    # ─── Category / search ────────────────────────────────────────────────────
    def _set_category(self, cat: str) -> None:
        self._category = cat
        for c, btn in self._cat_btns.items():
            active = c == cat
            btn.config(
                bg=T["bg_active"] if active else T["bg_sidebar"],
                fg=T["fg_primary"] if active else T["fg_secondary"],
                font=FONTS.get("body_bold" if active else "body", ()),
            )
        self._detail_app = None
        self._load_app_grid()

    # ─── App grid ─────────────────────────────────────────────────────────────
    def _load_app_grid(self) -> None:
        for w in self._content.winfo_children():
            w.destroy()
        if self._detail_app:
            self._show_detail(self._detail_app)
            return

        q    = self._search_var.get().lower().strip()
        apps = self._all_apps
        if self._category != "All":
            apps = [a for a in apps if a["category"] == self._category]
        if q:
            apps = [a for a in apps if q in a["name"].lower() or q in a.get("desc","").lower()]

        scroll = ScrollableFrame(self._content, bg_key="bg_surface")
        scroll.pack(fill="both", expand=True)
        inner = scroll.inner

        # Featured banner (only on "All" with no search)
        if self._category == "All" and not q:
            tk.Label(inner, text="  Featured",
                     font=FONTS.get("h3", ()), fg=T["fg_secondary"],
                     bg=T["bg_surface"], anchor="w", pady=12, padx=10).pack(fill="x")
            feat_row = tk.Frame(inner, bg=T["bg_surface"])
            feat_row.pack(fill="x", padx=10, pady=4)
            for app_id in self._FEATURED:
                app = next((a for a in self._all_apps if a["id"] == app_id), None)
                if app:
                    self._make_featured_card(feat_row, app)
            fl_separator(inner).pack(fill="x", padx=10, pady=10)
            tk.Label(inner, text="  All Apps",
                     font=FONTS.get("h3", ()), fg=T["fg_secondary"],
                     bg=T["bg_surface"], anchor="w", pady=4, padx=10).pack(fill="x")

        # App list rows
        for app in apps:
            self._make_app_row(inner, app)

        if not apps:
            tk.Label(inner, text="No apps found.",
                     font=FONTS.get("body", ()), fg=T["fg_tertiary"],
                     bg=T["bg_surface"], pady=40).pack()

    def _make_featured_card(self, parent: tk.Frame, app: Dict) -> None:
        installed = app["id"] in self._installed
        card = tk.Frame(parent, bg=T["bg_card"], cursor="hand2",
                        width=150, height=130)
        card.pack(side="left", padx=6, pady=4)
        card.pack_propagate(False)

        tk.Label(card, text=app["icon"],
                 font=(FONTS.get("emoji_lg", ("", 32))[0], 34),
                 bg=T["bg_card"]).place(relx=0.5, y=38, anchor="center")
        tk.Label(card, text=app["name"],
                 font=FONTS.get("small_bold", ()),
                 fg=T["fg_primary"], bg=T["bg_card"],
                 wraplength=130, justify="center").place(relx=0.5, y=78, anchor="center")
        tk.Label(card,
                 text="Installed" if installed else "Free",
                 font=FONTS.get("nano", ()),
                 fg=T["success"] if installed else T["accent"],
                 bg=T["bg_card"]).place(relx=0.5, y=106, anchor="center")

        card.bind("<Button-1>", lambda e, a=app: self._open_detail(a))
        card.bind("<Enter>", lambda e, c=card: c.config(bg=T["bg_hover"]))
        card.bind("<Leave>", lambda e, c=card: c.config(bg=T["bg_card"]))

    def _make_app_row(self, parent: tk.Frame, app: Dict) -> None:
        installed = app["id"] in self._installed
        row = tk.Frame(parent, bg=T["bg_surface"], cursor="hand2")
        row.pack(fill="x", padx=10, pady=3)

        tk.Label(row, text=app["icon"],
                 font=FONTS.get("emoji_sm", ()),
                 bg=T["bg_surface"], width=3).pack(side="left", padx=10, pady=8)

        info = tk.Frame(row, bg=T["bg_surface"])
        info.pack(side="left", fill="x", expand=True, pady=6)
        tk.Label(info, text=app["name"],
                 font=FONTS.get("body_bold", ()),
                 fg=T["fg_primary"], bg=T["bg_surface"], anchor="w").pack(fill="x")
        tk.Label(info, text=app.get("desc",""),
                 font=FONTS.get("small", ()),
                 fg=T["fg_secondary"], bg=T["bg_surface"], anchor="w").pack(fill="x")
        tk.Label(info, text=f"{app['category']}  ·  v{app.get('version','1.0')}  ·  {app.get('size','—')}",
                 font=FONTS.get("micro", ()),
                 fg=T["fg_tertiary"], bg=T["bg_surface"], anchor="w").pack(fill="x")

        if installed:
            tk.Label(row, text="✓ Installed",
                     font=FONTS.get("small_bold", ()),
                     fg=T["success"], bg=T["bg_surface"],
                     padx=12).pack(side="right")
        else:
            fl_button(row, "Get",
                      lambda a=app: self._install_app(a),
                      style="primary", padx=10, pady=4).pack(side="right", padx=12)

        fl_separator(parent).pack(fill="x", padx=10)

        row.bind("<Button-1>", lambda e, a=app: self._open_detail(a))
        row.bind("<Enter>",    lambda e, r=row: r.config(bg=T["bg_hover"]))
        row.bind("<Leave>",    lambda e, r=row: r.config(bg=T["bg_surface"]))

    # ─── Detail view ──────────────────────────────────────────────────────────
    def _open_detail(self, app: Dict) -> None:
        self._detail_app = app
        self._load_app_grid()

    def _show_detail(self, app: Dict) -> None:
        installed = app["id"] in self._installed
        f = self._content

        # Back button
        back_row = tk.Frame(f, bg=T["bg_surface"])
        back_row.pack(fill="x", padx=16, pady=8)
        fl_button(back_row, "← Back", self._close_detail,
                  style="ghost").pack(side="left")

        scroll = ScrollableFrame(f, bg_key="bg_surface")
        scroll.pack(fill="both", expand=True)
        inner = scroll.inner

        # Hero section
        hero = tk.Frame(inner, bg=T["bg_card"])
        hero.pack(fill="x", padx=16, pady=8)
        hi  = tk.Frame(hero, bg=T["bg_card"])
        hi.pack(fill="x", padx=20, pady=20)

        tk.Label(hi, text=app["icon"],
                 font=(FONTS.get("emoji_lg", ("", 32))[0], 56),
                 bg=T["bg_card"]).pack(side="left", padx=12)

        info = tk.Frame(hi, bg=T["bg_card"])
        info.pack(side="left", fill="x", expand=True, padx=12)
        tk.Label(info, text=app["name"],
                 font=FONTS.get("display", ()),
                 fg=T["fg_primary"], bg=T["bg_card"], anchor="w").pack(fill="x")
        tk.Label(info, text=f"{app['category']}  ·  v{app.get('version','1.0')}  ·  {app.get('size','—')}",
                 font=FONTS.get("body", ()),
                 fg=T["fg_secondary"], bg=T["bg_card"], anchor="w").pack(fill="x")
        rating = app.get("rating", 4.5)
        stars  = "★" * int(rating) + "☆" * (5 - int(rating))
        tk.Label(info, text=f"{stars}  {rating}  ·  {app.get('installs','—')} installs",
                 font=FONTS.get("body", ()),
                 fg=T["warning"], bg=T["bg_card"], anchor="w").pack(fill="x", pady=4)

        # Install / Uninstall button
        if installed:
            fl_button(hi, "✓  Installed · Open",
                      lambda a=app: self._launch_app(a),
                      style="success").pack(side="right", padx=12)
            fl_button(hi, "Uninstall",
                      lambda a=app: self._uninstall_app(a),
                      style="danger").pack(side="right")
        else:
            fl_button(hi, "Get  (Free)",
                      lambda a=app: self._install_app(a),
                      style="primary").pack(side="right", padx=12)

        # Description
        desc_card = tk.Frame(inner, bg=T["bg_card"])
        desc_card.pack(fill="x", padx=16, pady=6)
        dc = tk.Frame(desc_card, bg=T["bg_card"])
        dc.pack(fill="x", padx=18, pady=14)
        tk.Label(dc, text="Description", font=FONTS.get("h3", ()),
                 fg=T["fg_primary"], bg=T["bg_card"]).pack(anchor="w", pady=(0,6))
        tk.Label(dc, text=app.get("desc","No description available."),
                 font=FONTS.get("body", ()), fg=T["fg_secondary"],
                 bg=T["bg_card"], anchor="w", wraplength=600,
                 justify="left").pack(fill="x")

        # Info table
        info_card = tk.Frame(inner, bg=T["bg_card"])
        info_card.pack(fill="x", padx=16, pady=6)
        ic = tk.Frame(info_card, bg=T["bg_card"])
        ic.pack(fill="x", padx=18, pady=14)
        tk.Label(ic, text="Information", font=FONTS.get("h3", ()),
                 fg=T["fg_primary"], bg=T["bg_card"]).pack(anchor="w", pady=(0,8))
        for label, val in [
            ("Version",  app.get("version","1.0")),
            ("Category", app["category"]),
            ("Size",     app.get("size","—")),
            ("Rating",   f"{app.get('rating',4.5)} / 5.0"),
            ("Installs", app.get("installs","—")),
            ("Developer","PyOS Project"),
        ]:
            row = tk.Frame(ic, bg=T["bg_card"])
            row.pack(fill="x", pady=2)
            tk.Label(row, text=label, font=FONTS.get("body_bold", ()),
                     fg=T["fg_secondary"], bg=T["bg_card"],
                     width=12, anchor="w").pack(side="left")
            tk.Label(row, text=val, font=FONTS.get("body", ()),
                     fg=T["fg_primary"], bg=T["bg_card"],
                     anchor="w").pack(side="left")

    def _close_detail(self) -> None:
        self._detail_app = None
        self._load_app_grid()

    # ─── Install / Uninstall ──────────────────────────────────────────────────
    def _install_app(self, app: Dict) -> None:
        # Simulated progress dialog
        d = tk.Toplevel(self.frame)
        d.title(f"Installing {app['name']}")
        d.config(bg=T["bg_surface"])
        d.geometry("340x130")
        d.grab_set()

        tk.Label(d, text=f"{app['icon']}  Installing {app['name']}…",
                 font=FONTS.get("h3", ()), fg=T["fg_primary"],
                 bg=T["bg_surface"], pady=18).pack()

        bar_host = tk.Frame(d, bg=T["bg_input"], height=14)
        bar_host.pack(fill="x", padx=20)
        bar_fill = tk.Frame(bar_host, bg=T["accent"], height=14)
        bar_fill.place(relx=0, rely=0, relwidth=0, relheight=1)

        prog_var = tk.StringVar(value="0%")
        tk.Label(d, textvariable=prog_var, font=FONTS.get("small", ()),
                 fg=T["fg_secondary"], bg=T["bg_surface"]).pack(pady=6)

        def _animate(step: int = 0) -> None:
            if step <= 100:
                bar_fill.place(relwidth=step / 100)
                prog_var.set(f"{step}%")
                d.after(20, lambda: _animate(step + 3))
            else:
                self._installed.add(app["id"])
                d.destroy()
                notify(self.wm.root, "App Store",
                       f"{app['name']} installed successfully!", kind="success")
                self._close_detail()
                self._load_app_grid()

        d.after(100, _animate)

    def _uninstall_app(self, app: Dict) -> None:
        if app["id"] in {a["id"] for a in APP_REGISTRY}:
            notify(self.wm.root, "App Store",
                   "Built-in apps cannot be uninstalled.", kind="warning")
            return
        self._installed.discard(app["id"])
        notify(self.wm.root, "App Store",
               f"{app['name']} uninstalled.", kind="info")
        self._close_detail()
        self._load_app_grid()

    def _launch_app(self, app: Dict) -> None:
        launcher = getattr(self.wm, app.get("launcher",""), None)
        if launcher:
            launcher()
        else:
            notify(self.wm.root, app["name"],
                   "App launched (simulated).", kind="info")


# ═══════════════════════════════════════════════════════════════════════════════
#  §04-EXT  EXTENDED WIDGET LIBRARY  (additional fluent components)
