class FlCard(tk.Frame):
    """
    A styled card widget with optional title, subtitle, icon, and accent border.
    Usage:
        card = FlCard(parent, title="Stats", icon="📊", accent=True)
        card.pack(fill="x", padx=16, pady=6)
        # add children to card.body
    """
    def __init__(
        self,
        parent:   tk.Misc,
        title:    str  = "",
        subtitle: str  = "",
        icon:     str  = "",
        accent:   bool = False,
        bg_key:   str  = "bg_card",
        **kw,
    ):
        super().__init__(parent, bg=T[bg_key], **kw)
        if accent:
            tk.Frame(self, width=4, bg=T["accent"]).pack(side="left", fill="y")
        inner = tk.Frame(self, bg=T[bg_key])
        inner.pack(fill="both", expand=True, padx=14, pady=12)
        if title or icon:
            hdr = tk.Frame(inner, bg=T[bg_key])
            hdr.pack(fill="x", pady=(0, 6))
            if icon:
                tk.Label(hdr, text=icon, font=FONTS.get("body", ()),
                         bg=T[bg_key], fg=T["accent"]).pack(side="left", padx=(0, 6))
            if title:
                tk.Label(hdr, text=title, font=FONTS.get("body_bold", ()),
                         fg=T["fg_primary"], bg=T[bg_key]).pack(side="left")
        if subtitle:
            tk.Label(inner, text=subtitle, font=FONTS.get("small", ()),
                     fg=T["fg_secondary"], bg=T[bg_key], anchor="w").pack(fill="x")
        self.body = inner


class FlProgressBar(tk.Frame):
    """Animated horizontal progress bar."""
    def __init__(
        self,
        parent:    tk.Misc,
        value:     float = 0.0,   # 0.0 – 1.0
        color_key: str   = "accent",
        height:    int   = 8,
        bg_key:    str   = "bg_input",
        **kw,
    ):
        super().__init__(parent, bg=T[bg_key], height=height, **kw)
        self.pack_propagate(False)
        self._fill = tk.Frame(self, bg=T[color_key], height=height)
        self._fill.place(relx=0, rely=0, relwidth=max(0.0, min(1.0, value)), relheight=1)
        self._color_key = color_key

    def set(self, value: float) -> None:
        self._fill.place(relwidth=max(0.0, min(1.0, value)))

    def animate_to(self, target: float, steps: int = 30, delay_ms: int = 16) -> None:
        current = float(self._fill.place_info().get("relwidth", 0))
        delta   = (target - current) / max(1, steps)
        def _step(n: int = 0, cur: float = current) -> None:
            if n >= steps:
                self.set(target)
                return
            cur = max(0.0, min(1.0, cur + delta))
            self.set(cur)
            self._fill.after(delay_ms, lambda: _step(n + 1, cur))
        _step()


class FlTabView(tk.Frame):
    """
    A reusable tab container.
    Usage:
        tv = FlTabView(parent)
        tv.pack(fill="both", expand=True)
        frame1 = tv.add_tab("Overview")
        frame2 = tv.add_tab("Details")
        tv.switch("Overview")
    """
    def __init__(self, parent: tk.Misc, bg_key: str = "bg_surface", **kw):
        super().__init__(parent, bg=T[bg_key], **kw)
        self._bg_key = bg_key
        self._tabs:   Dict[str, tk.Frame] = {}
        self._active: Optional[str] = None

        self._tab_strip = tk.Frame(self, bg=T["bg_elevated"])
        self._tab_strip.pack(fill="x")
        fl_separator(self).pack(fill="x")
        self._host = tk.Frame(self, bg=T[bg_key])
        self._host.pack(fill="both", expand=True)

    def add_tab(self, name: str) -> tk.Frame:
        frame = tk.Frame(self._host, bg=T[self._bg_key])
        self._tabs[name] = frame

        btn = tk.Label(
            self._tab_strip,
            text=name,
            font=FONTS.get("tab", ()),
            fg=T["fg_secondary"],
            bg=T["bg_elevated"],
            padx=16, pady=7, cursor="hand2",
        )
        btn.pack(side="left")
        btn.bind("<Button-1>", lambda e, n=name: self.switch(n))
        btn.bind("<Enter>",
            lambda e, b=btn, n=name:
                b.config(fg=T["fg_primary"]) if n != self._active else None)
        btn.bind("<Leave>",
            lambda e, b=btn, n=name:
                b.config(fg=T["fg_primary"] if n == self._active else T["fg_secondary"]))
        btn._tab_name = name  # type: ignore

        if self._active is None:
            self.switch(name)
        return frame

    def switch(self, name: str) -> None:
        self._active = name
        for child in self._tab_strip.winfo_children():
            tab_name = getattr(child, "_tab_name", None)
            if tab_name:
                active = tab_name == name
                child.config(
                    fg=T["fg_primary"] if active else T["fg_secondary"],
                    bg=T["bg_active"] if active else T["bg_elevated"],
                    font=FONTS.get("tab_active" if active else "tab", ()),
                )
        for tab_name, frame in self._tabs.items():
            if tab_name == name:
                frame.pack(fill="both", expand=True)
            else:
                frame.pack_forget()


class FlDataTable(tk.Frame):
    """
    Scrollable data table widget with sortable columns and row selection.
    columns: list of (header, key, width_px)
    rows: list of dicts
    """
    def __init__(
        self,
        parent:  tk.Misc,
        columns: List[Tuple[str, str, int]],
        rows:    List[Dict],
        on_select: Optional[Callable] = None,
        **kw,
    ):
        super().__init__(parent, bg=T["bg_surface"], **kw)
        self._columns   = columns
        self._rows      = rows
        self._on_select = on_select
        self._selected  = -1
        self._sort_key  = columns[0][1] if columns else ""
        self._sort_rev  = False
        self._build()

    def _build(self) -> None:
        for w in self.winfo_children():
            w.destroy()
        # Header
        hdr = tk.Frame(self, bg=T["bg_card"])
        hdr.pack(fill="x")
        for label, key, w in self._columns:
            arrow = (" ▼" if self._sort_rev else " ▲") if key == self._sort_key else ""
            lbl = tk.Label(
                hdr,
                text=label + arrow,
                font=FONTS.get("small_bold", ()),
                fg=T["accent"] if key == self._sort_key else T["fg_tertiary"],
                bg=T["bg_card"],
                width=w // 7, anchor="w", padx=8, pady=5, cursor="hand2",
            )
            lbl.pack(side="left")
            lbl.bind("<Button-1>", lambda e, k=key: self._sort(k))
        fl_separator(self).pack(fill="x")
        # Rows
        sc = ScrollableFrame(self, bg_key="bg_surface")
        sc.pack(fill="both", expand=True)
        inner = sc.inner
        sorted_rows = sorted(
            enumerate(self._rows),
            key=lambda x: str(x[1].get(self._sort_key, "")),
            reverse=self._sort_rev,
        )
        for display_idx, (orig_idx, row_data) in enumerate(sorted_rows):
            alt = T["bg_card"] if display_idx % 2 else T["bg_surface"]
            row_frame = tk.Frame(inner, bg=alt, cursor="hand2")
            row_frame.pack(fill="x")
            for _, key, w in self._columns:
                val = str(row_data.get(key, ""))
                tk.Label(
                    row_frame,
                    text=val[:40],
                    font=FONTS.get("small", ()),
                    fg=T["fg_primary"],
                    bg=alt,
                    width=w // 7, anchor="w", padx=8, pady=4,
                ).pack(side="left")
            def _click(e, idx=orig_idx, rf=row_frame, bg=alt):
                self._selected = idx
                for ch in inner.winfo_children():
                    ch.config(bg=T["bg_selection"] if ch is rf else
                              (T["bg_card"] if list(inner.winfo_children()).index(ch)%2
                               else T["bg_surface"]))
                    for cc in ch.winfo_children():
                        cc.config(bg=ch.cget("bg"))
                if self._on_select:
                    self._on_select(idx, self._rows[idx])
            row_frame.bind("<Button-1>", _click)
            row_frame.bind("<Enter>",
                lambda e, rf=row_frame, bg=alt: rf.config(bg=T["bg_hover"]))
            row_frame.bind("<Leave>",
                lambda e, rf=row_frame, bg=alt, ri=orig_idx:
                    rf.config(bg=T["bg_selection"] if self._selected == ri else bg))

    def _sort(self, key: str) -> None:
        if self._sort_key == key:
            self._sort_rev = not self._sort_rev
        else:
            self._sort_key = key
            self._sort_rev = False
        self._build()

    def update_rows(self, rows: List[Dict]) -> None:
        self._rows = rows
        self._build()


class FlNotificationBanner(tk.Frame):
    """
    An inline notification banner (not a toast).
    kind: info | success | warning | danger
    """
    def __init__(
        self,
        parent:  tk.Misc,
        message: str,
        kind:    str = "info",
        dismissable: bool = True,
        **kw,
    ):
        colors = {
            "info":    (T["info_muted"],    T["info"]),
            "success": (T["success_muted"], T["success"]),
            "warning": (T["warning_muted"], T["warning"]),
            "danger":  (T["danger_muted"],  T["danger"]),
        }
        icons = {"info": "ℹ", "success": "✓", "warning": "⚠", "danger": "✕"}
        bg, fg = colors.get(kind, colors["info"])
        super().__init__(parent, bg=bg, **kw)
        tk.Label(self, text=icons.get(kind, "ℹ"),
                 font=FONTS.get("body_bold", ()),
                 fg=fg, bg=bg, padx=10).pack(side="left")
        tk.Label(self, text=message, font=FONTS.get("body", ()),
                 fg=T["fg_primary"], bg=bg, anchor="w").pack(side="left", fill="x", expand=True)
        if dismissable:
            close = tk.Label(self, text="✕", font=FONTS.get("small", ()),
                             fg=T["fg_tertiary"], bg=bg, padx=10, cursor="hand2")
            close.pack(side="right")
            close.bind("<Button-1>", lambda e: self.destroy())


class FlSearchBar(tk.Frame):
    """
    A styled search bar with icon, placeholder, clear button and callback.
    """
    def __init__(
        self,
        parent:       tk.Misc,
        placeholder:  str                     = "Search…",
        on_change:    Optional[Callable]      = None,
        on_submit:    Optional[Callable]      = None,
        bg_key:       str                     = "bg_input",
        width:        int                     = 0,
        **kw,
    ):
        super().__init__(parent, bg=T[bg_key], **kw)
        self._on_change = on_change
        self._on_submit = on_submit
        self._placeholder = placeholder
        self.var = tk.StringVar()

        tk.Label(self, text="🔍", bg=T[bg_key],
                 font=FONTS.get("small", ()), padx=6).pack(side="left")

        cfg: Dict[str, Any] = dict(
            textvariable=self.var,
            font=FONTS.get("body", ()),
            bg=T[bg_key], fg=T["fg_tertiary"],
            insertbackground=T["accent"],
            relief="flat", bd=0,
        )
        if width:
            cfg["width"] = width
        self._entry = tk.Entry(self, **cfg)
        self._entry.pack(side="left", fill="x", expand=True, pady=6)
        self._entry.insert(0, placeholder)

        self._clear_btn = tk.Label(self, text="✕",
                                    font=FONTS.get("small", ()),
                                    fg=T["fg_tertiary"], bg=T[bg_key],
                                    cursor="hand2", padx=6)
        self._clear_btn.pack(side="right")
        self._clear_btn.bind("<Button-1>", lambda e: self.clear())

        self._entry.bind("<FocusIn>",   self._on_focus_in)
        self._entry.bind("<FocusOut>",  self._on_focus_out)
        self._entry.bind("<Return>",    lambda e: on_submit and on_submit(self.get()))
        self.var.trace_add("write",
            lambda *a: on_change and on_change(self.get())
            if self.get() != placeholder else None)

    def _on_focus_in(self, e: tk.Event) -> None:
        if self._entry.get() == self._placeholder:
            self._entry.delete(0, "end")
            self._entry.config(fg=T["fg_primary"])

    def _on_focus_out(self, e: tk.Event) -> None:
        if not self._entry.get():
            self._entry.insert(0, self._placeholder)
            self._entry.config(fg=T["fg_tertiary"])

    def get(self) -> str:
        val = self.var.get()
        return "" if val == self._placeholder else val

    def clear(self) -> None:
        self._entry.delete(0, "end")
        self._entry.insert(0, self._placeholder)
        self._entry.config(fg=T["fg_tertiary"])
        if self._on_change:
            self._on_change("")

    def focus(self) -> None:
        self._entry.focus_set()
        self._on_focus_in(None)


# ─── Extended notify with queue support ──────────────────────────────────────

class NotificationCenter:
    """
    Manages a queue of toast notifications so they stack vertically
    instead of overlapping.
    """
    _MARGIN_BOTTOM = 64
    _SPACING       = 80
    _MAX_VISIBLE   = 5

    def __init__(self, root: tk.Tk):
        self.root   = root
        self._queue: List[Dict] = []
        self._active: List[tk.Toplevel] = []

    def push(
        self,
        title:    str,
        message:  str  = "",
        kind:     str  = "info",
        duration: int  = TOAST_DURATION,
    ) -> None:
        self._queue.append({"title": title, "message": message,
                             "kind": kind, "duration": duration})
        self._flush()

    def _flush(self) -> None:
        # Clean up closed windows
        self._active = [w for w in self._active if w.winfo_exists()]
        while self._queue and len(self._active) < self._MAX_VISIBLE:
            item = self._queue.pop(0)
            self._show(item)

    def _show(self, item: Dict) -> None:
        kind_colors = {
            "info":    T["info"],
            "success": T["success"],
            "warning": T["warning"],
            "danger":  T["danger"],
        }
        icons = {"info": "ℹ", "success": "✓", "warning": "⚠", "danger": "✕"}
        bar_color = kind_colors.get(item["kind"], T["accent"])

        w = tk.Toplevel(self.root)
        w.overrideredirect(True)
        w.attributes("-topmost", True)

        pw, ph = 320, 76
        sw = self.root.winfo_screenwidth()
        sh = self.root.winfo_screenheight()

        slot  = len(self._active)
        wx    = sw - pw - 18
        wy    = sh - self._MARGIN_BOTTOM - (ph + 8) * (slot + 1)

        w.geometry(f"{pw}x{ph}+{wx}+{wy}")
        w.config(bg=T["bg_elevated"])
        self._active.append(w)

        tk.Frame(w, width=4, bg=bar_color).pack(side="left", fill="y")

        icon_lbl = tk.Label(w, text=icons.get(item["kind"], "ℹ"),
                            font=(FONTS.get("body", ("", 13))[0], 13),
                            fg=bar_color, bg=T["bg_elevated"], padx=6)
        icon_lbl.pack(side="left")

        body = tk.Frame(w, bg=T["bg_elevated"])
        body.pack(side="left", fill="both", expand=True, padx=8, pady=8)
        tk.Label(body, text=item["title"], font=FONTS.get("body_bold", ()),
                 fg=T["fg_primary"], bg=T["bg_elevated"], anchor="w").pack(fill="x")
        if item["message"]:
            tk.Label(body, text=item["message"][:80],
                     font=FONTS.get("small", ()),
                     fg=T["fg_secondary"], bg=T["bg_elevated"], anchor="w").pack(fill="x")

        close_lbl = tk.Label(w, text="✕", font=FONTS.get("small", ()),
                             fg=T["fg_tertiary"], bg=T["bg_elevated"],
                             cursor="hand2", padx=8)
        close_lbl.pack(side="right", anchor="n", pady=6)
        close_lbl.bind("<Button-1>", lambda e: self._dismiss(w))

        def _auto_dismiss():
            if w.winfo_exists():
                self._dismiss(w)

        w.after(item["duration"], _auto_dismiss)

    def _dismiss(self, w: tk.Toplevel) -> None:
        if w.winfo_exists():
            w.destroy()
        self._active = [x for x in self._active if x.winfo_exists()]
        if self._queue:
            self._flush()


