#  §06-EXT  EXTENDED VFS UTILITIES
# ═══════════════════════════════════════════════════════════════════════════════

class VFSWatcher:
    """
    Polls the VFS for changes to a directory and fires a callback.
    Used by File Manager to auto-refresh.
    """
    def __init__(
        self,
        root:      tk.Misc,
        vfs:       VFS,
        path:      str,
        callback:  Callable,
        interval:  int = 2000,
    ):
        self._root     = root
        self._vfs      = vfs
        self._path     = path
        self._callback = callback
        self._interval = interval
        self._last_snapshot: Set[str] = set()
        self._running  = True
        self._poll()

    def _poll(self) -> None:
        if not self._running:
            return
        current = set(self._vfs.listdir(self._path, show_hidden=True))
        if current != self._last_snapshot:
            self._last_snapshot = current
            try:
                self._callback()
            except Exception:
                pass
        self._root.after(self._interval, self._poll)

    def stop(self) -> None:
        self._running = False


class VFSSearch:
    """
    Full-text search across file contents, not just filenames.
    Searches all text files under root_path for the query string.
    Returns list of (path, line_number, line_text) tuples.
    """
    def __init__(self, vfs: VFS):
        self._vfs = vfs

    def search_content(
        self,
        root_path: str,
        query:     str,
        max_hits:  int = 100,
        case_sensitive: bool = False,
    ) -> List[Tuple[str, int, str]]:
        results: List[Tuple[str, int, str]] = []
        q = query if case_sensitive else query.lower()
        text_exts = {"txt","md","py","js","ts","html","css","json","xml",
                     "yaml","toml","sh","csv","log","rst","ini","cfg"}

        def _walk(path: str) -> None:
            if len(results) >= max_hits:
                return
            node = self._vfs.get_node(path)
            if node is None:
                return
            if node.is_dir and node.children:
                for name in node.children:
                    _walk(path.rstrip("/") + "/" + name)
            elif node.extension in text_exts and node.content:
                content = node.content if case_sensitive else node.content.lower()
                for i, line in enumerate(content.splitlines(), 1):
                    if q in line:
                        results.append((path, i, node.content.splitlines()[i-1]))
                        if len(results) >= max_hits:
                            return

        _walk(root_path)
        return results


