#  §12-EXT  EXTENDED BASEWIN — context menus, snap layouts, window animations
# ═══════════════════════════════════════════════════════════════════════════════

class SnapLayout:
    """
    Provides snap-to-edge and snap-to-half layouts for windows.
    Call SnapLayout.snap(win, mode) to position a window.
    Modes: left_half | right_half | top_half | bottom_half |
           top_left | top_right | bottom_left | bottom_right | maximized
    """

    @staticmethod
    def snap(win: BaseWin, mode: str) -> None:
        d = win.wm.desktop
        dw = d.winfo_width()
        dh = d.winfo_height()
        half_w = dw // 2
        half_h = dh // 2

        layouts = {
            "left_half":    (0,          0,         half_w, dh),
            "right_half":   (half_w,     0,         half_w, dh),
            "top_half":     (0,          0,         dw,     half_h),
            "bottom_half":  (0,          half_h,    dw,     half_h),
            "top_left":     (0,          0,         half_w, half_h),
            "top_right":    (half_w,     0,         half_w, half_h),
            "bottom_left":  (0,          half_h,    half_w, half_h),
            "bottom_right": (half_w,     half_h,    half_w, half_h),
            "maximized":    (0,          0,         dw,     dh),
            "centered":     (dw//4,      dh//8,     dw//2,  3*dh//4),
        }
        geom = layouts.get(mode)
        if geom:
            x, y, w, h = geom
            win._maximized = False
            win.frame.place(x=x, y=y, width=w, height=h)
            win._width  = w
            win._height = h
            win.focus()


def _make_window_context_menu(win: BaseWin) -> None:
    """
    Attaches a right-click context menu to a window's title bar
    for quick snap-layout access.
    """
    def _show_menu(e: tk.Event) -> None:
        items = [
            ("Snap: Left Half",    lambda: SnapLayout.snap(win, "left_half")),
            ("Snap: Right Half",   lambda: SnapLayout.snap(win, "right_half")),
            ("Snap: Top Half",     lambda: SnapLayout.snap(win, "top_half")),
            ("Snap: Bottom Half",  lambda: SnapLayout.snap(win, "bottom_half")),
            ("─────────────────",  None),
            ("Snap: Top Left",     lambda: SnapLayout.snap(win, "top_left")),
            ("Snap: Top Right",    lambda: SnapLayout.snap(win, "top_right")),
            ("Snap: Bottom Left",  lambda: SnapLayout.snap(win, "bottom_left")),
            ("Snap: Bottom Right", lambda: SnapLayout.snap(win, "bottom_right")),
            ("─────────────────",  None),
            ("Centre Window",      lambda: SnapLayout.snap(win, "centered")),
            ("Maximise",           win.toggle_maximize),
            ("─────────────────",  None),
            ("Minimise",           win.minimize),
            ("Close",              win.close),
        ]
        win.wm._show_context_menu(e.x_root, e.y_root, items)

    win._titlebar.bind("<Button-3>", _show_menu)
    win._title_lbl.bind("<Button-3>", _show_menu)
    win._icon_lbl.bind("<Button-3>", _show_menu)


