class WidgetPanel:
    """
    Slide-in sidebar panel on the right edge of the desktop.
    Contains: clock widget, mini calendar, weather summary,
              system stats, quick-action buttons.
    """

    PANEL_W = 320

    def __init__(self, wm: "WM"):
        self.wm      = wm
        self.visible = False
        self._panel: Optional[tk.Frame] = None

    def toggle(self) -> None:
        if self.visible:
            self.hide()
        else:
            self.show()

    def show(self) -> None:
        if self._panel and self._panel.winfo_exists():
            self._panel.destroy()
        self.visible = True
        self._panel  = tk.Frame(
            self.wm.desktop,
            bg=T["bg_elevated"],
            width=self.PANEL_W,
        )
        self._panel.place(
            relx=1.0, rely=0,
            x=-self.PANEL_W, y=0,
            width=self.PANEL_W,
            relheight=1.0,
        )
        self._build()

    def hide(self) -> None:
        self.visible = False
        if self._panel and self._panel.winfo_exists():
            self._panel.destroy()

    def _build(self) -> None:
        f = self._panel

        # Header
        hdr = tk.Frame(f, bg=T["bg_elevated"])
        hdr.pack(fill="x", padx=16, pady=(16, 8))
        tk.Label(hdr, text="Quick Panel",
                 font=FONTS.get("h3", ()), fg=T["fg_primary"],
                 bg=T["bg_elevated"]).pack(side="left")
        tk.Label(hdr, text="✕",
                 font=FONTS.get("body", ()), fg=T["fg_tertiary"],
                 bg=T["bg_elevated"], cursor="hand2").pack(side="right")
        hdr.winfo_children()[-1].bind("<Button-1>", lambda e: self.hide())
        fl_separator(f).pack(fill="x", padx=8)

        scroll = ScrollableFrame(f, bg_key="bg_elevated")
        scroll.pack(fill="both", expand=True)
        inner = scroll.inner
        inner.config(padx=14, pady=8)

        # ── Clock ──────────────────────────────────────────────────────────
        clock_card = tk.Frame(inner, bg=T["bg_card"])
        clock_card.pack(fill="x", pady=6)
        now = datetime.datetime.now()
        tk.Label(clock_card,
                 text=now.strftime("%H:%M"),
                 font=(FONTS.get("display_2xl", ("", 36))[0], 48, "bold"),
                 fg=T["fg_primary"], bg=T["bg_card"],
                 pady=8).pack()
        tk.Label(clock_card,
                 text=now.strftime("%A, %B %d, %Y"),
                 font=FONTS.get("body", ()), fg=T["fg_secondary"],
                 bg=T["bg_card"], pady=4).pack()

        # ── Mini calendar ─────────────────────────────────────────────────
        cal_card = tk.Frame(inner, bg=T["bg_card"])
        cal_card.pack(fill="x", pady=6)
        tk.Label(cal_card,
                 text=now.strftime("%B %Y"),
                 font=FONTS.get("h4", ()), fg=T["accent"],
                 bg=T["bg_card"], pady=8, padx=12).pack(anchor="w")

        cal_grid = tk.Frame(cal_card, bg=T["bg_card"])
        cal_grid.pack(padx=10, pady=(0, 10))
        for col, day in enumerate(["Mo","Tu","We","Th","Fr","Sa","Su"]):
            tk.Label(cal_grid, text=day,
                     font=FONTS.get("micro_bold", ()),
                     fg=T["accent"] if col >= 5 else T["fg_tertiary"],
                     bg=T["bg_card"], width=3).grid(row=0, column=col)

        cal_data = _cal.monthcalendar(now.year, now.month)
        today = datetime.date.today()
        for r, week in enumerate(cal_data):
            for c, d in enumerate(week):
                is_today = (d == today.day)
                lbl = tk.Label(
                    cal_grid,
                    text=str(d) if d else "",
                    font=FONTS.get("small_bold" if is_today else "small", ()),
                    fg=T["btn_primary_fg"] if is_today else
                       (T["fg_tertiary"] if c >= 5 else T["fg_secondary"]),
                    bg=T["accent"] if is_today else T["bg_card"],
                    width=3, pady=2,
                )
                lbl.grid(row=r + 1, column=c)

        # ── System stats ──────────────────────────────────────────────────
        stats_card = tk.Frame(inner, bg=T["bg_card"])
        stats_card.pack(fill="x", pady=6)
        tk.Label(stats_card, text="System",
                 font=FONTS.get("h4", ()), fg=T["fg_secondary"],
                 bg=T["bg_card"], pady=8, padx=12).pack(anchor="w")

        cpu  = self.wm.procs.total_cpu()
        ram  = self.wm.procs.total_ram()
        wins = len(self.wm.all_wins())

        for label, val, pct in [
            ("CPU", f"{cpu:.1f}%",    cpu / 100),
            ("RAM", f"{VFS.human_size(ram*1024*1024)}", min(1.0, ram/8192)),
        ]:
            row = tk.Frame(stats_card, bg=T["bg_card"])
            row.pack(fill="x", padx=12, pady=3)
            tk.Label(row, text=label, font=FONTS.get("small_bold", ()),
                     fg=T["fg_secondary"], bg=T["bg_card"], width=5,
                     anchor="w").pack(side="left")
            bar = FlProgressBar(row, value=pct, height=6)
            bar.pack(side="left", fill="x", expand=True, padx=8)
            tk.Label(row, text=val, font=FONTS.get("micro", ()),
                     fg=T["fg_tertiary"], bg=T["bg_card"], width=8,
                     anchor="e").pack(side="right")

        tk.Label(stats_card,
                 text=f"  {wins} open window{'s' if wins != 1 else ''}  ·  "
                      f"{self.wm.procs.count()} processes",
                 font=FONTS.get("small", ()), fg=T["fg_tertiary"],
                 bg=T["bg_card"], anchor="w",
                 pady=6, padx=12).pack(fill="x")

        # ── Quick actions ─────────────────────────────────────────────────
        qa_card = tk.Frame(inner, bg=T["bg_card"])
        qa_card.pack(fill="x", pady=6)
        tk.Label(qa_card, text="Quick Actions",
                 font=FONTS.get("h4", ()), fg=T["fg_secondary"],
                 bg=T["bg_card"], pady=8, padx=12).pack(anchor="w")

        qa_grid = tk.Frame(qa_card, bg=T["bg_card"])
        qa_grid.pack(padx=10, pady=(0, 12))
        actions = [
            ("🔍", "Search",   self.wm.open_search),
            ("📁", "Files",    self.wm.open_file_manager),
            ("⌨",  "Terminal", self.wm.open_terminal),
            ("⚙",  "Settings", self.wm.open_settings),
            ("📊", "Tasks",    self.wm.open_task_manager),
            ("🔢", "Calc",     self.wm.open_calculator),
        ]
        for i, (icon, label, cmd) in enumerate(actions):
            col_i, row_i = i % 3, i // 3
            cell = tk.Frame(qa_grid, bg=T["bg_elevated"], cursor="hand2",
                            width=80, height=64)
            cell.grid(row=row_i, column=col_i, padx=4, pady=4)
            cell.grid_propagate(False)
            tk.Label(cell, text=icon, font=FONTS.get("emoji_sm", ()),
                     bg=T["bg_elevated"]).place(relx=0.5, y=22, anchor="center")
            tk.Label(cell, text=label, font=FONTS.get("nano", ()),
                     fg=T["fg_secondary"], bg=T["bg_elevated"]).place(relx=0.5, y=46, anchor="center")
            cell.bind("<Button-1>", lambda e, c=cmd: (self.hide(), c()))
            cell.bind("<Enter>", lambda e, cc=cell: cc.config(bg=T["bg_hover"]))
            cell.bind("<Leave>", lambda e, cc=cell: cc.config(bg=T["bg_elevated"]))


class RunDialog:
    """
    Win+R style Run dialog for launching apps by name or command.
    """
    _SHORTCUTS = {
        "files":    "open_file_manager",
        "fm":       "open_file_manager",
        "editor":   "open_text_editor",
        "notepad":  "open_text_editor",
        "terminal": "open_terminal",
        "term":     "open_terminal",
        "shell":    "open_terminal",
        "settings": "open_settings",
        "browser":  "open_browser",
        "mail":     "open_mail",
        "calendar": "open_calendar",
        "calc":     "open_calculator",
        "tasks":    "open_task_manager",
        "store":    "open_app_store",
        "notes":    "open_sticky_notes",
        "clip":     "open_clipboard",
        "vault":    "open_password_vault",
        "weather":  "open_weather",
        "music":    "open_music",
        "news":     "open_news",
        "search":   "open_search",
        "network":  "open_network",
        "disk":     "open_disk_manager",
        "sysinfo":  "open_system_info",
        "code":     "open_code_editor",
        "images":   "open_image_viewer",
        "shutdown": "open_shutdown",
    }

    def __init__(self, wm: "WM"):
        self.wm = wm

    def show(self) -> None:
        d = tk.Toplevel(self.wm.root)
        d.overrideredirect(True)
        d.attributes("-topmost", True)
        d.config(bg=T["bg_elevated"])

        sw = self.wm.root.winfo_width()
        sh = self.wm.root.winfo_height()
        dw, dh = 420, 64
        d.geometry(f"{dw}x{dh}+{(sw-dw)//2}+{sh//3}")

        tk.Label(d, text="⊞", font=FONTS.get("h2", ()),
                 fg=T["accent"], bg=T["bg_elevated"],
                 padx=12).pack(side="left", fill="y")

        e = tk.Entry(d, font=FONTS.get("h3", ()),
                     bg=T["bg_elevated"], fg=T["fg_primary"],
                     insertbackground=T["accent"],
                     relief="flat", bd=0)
        e.pack(side="left", fill="both", expand=True, pady=12)
        e.focus_set()

        tk.Label(d, text="Enter command or app name",
                 font=FONTS.get("small", ()), fg=T["fg_tertiary"],
                 bg=T["bg_elevated"], padx=8).pack(side="bottom", fill="x", pady=4)

        def _run(ev=None) -> None:
            cmd = e.get().strip().lower()
            d.destroy()
            if not cmd:
                return
            launcher_name = self._SHORTCUTS.get(cmd)
            if launcher_name:
                launcher = getattr(self.wm, launcher_name, None)
                if launcher:
                    launcher()
            else:
                notify(self.wm.root, "Run",
                       f"Unknown command: {cmd}", kind="warning")

        e.bind("<Return>", _run)
        e.bind("<Escape>", lambda ev: d.destroy())
        d.bind("<FocusOut>", lambda ev: d.destroy() if d.winfo_exists() else None)


# ─── Attach WidgetPanel + RunDialog to WM ─────────────────────────────────────

def _wm_post_init(wm: "WM") -> None:
    """
    Called after WM.__init__ to attach extended features.
    Adds widget panel toggle button to taskbar and Win+R binding.
    """
    wm._widget_panel = WidgetPanel(wm)
    wm._run_dialog   = RunDialog(wm)

    # Widget panel button on taskbar right side
    wp_btn = tk.Label(
        wm._taskbar_frame,
        text="⊟",
        font=FONTS.get("body", ()),
        fg=T["fg_tertiary"],
        bg=T["bg_taskbar"],
        cursor="hand2",
        padx=8, pady=8,
    )
    wp_btn.pack(side="right", padx=2)
    wp_btn.bind("<Button-1>", lambda e: wm._widget_panel.toggle())
    _attach_tooltip(wp_btn, "Widget Panel")

    # Keyboard shortcut: Ctrl+Space = Run dialog
    wm.root.bind("<Control-space>", lambda e: wm._run_dialog.show())
    wm.root.bind("<Control-r>",     lambda e: wm._run_dialog.show())

    # Attach snap-layout context menus to existing windows
    for win in wm.all_wins():
        _make_window_context_menu(win)

    # Override WM.register to auto-attach snap menu to new windows
    _orig_register = wm.register

    def _register_with_snap(win: BaseWin) -> None:
        _orig_register(win)
        _make_window_context_menu(win)

    wm.register = _register_with_snap  # type: ignore


