class FilePreviewPane:
    """
    Inline file preview for text/code files shown inside File Manager.
    Activated when the user single-clicks a file.
    """

    def __init__(self, parent: tk.Frame):
        self._parent = parent
        self._frame  = tk.Frame(parent, bg=T["bg_elevated"])
        self._visible = False

    def show(self, path: str, vfs: VFS) -> None:
        self._frame.pack(fill="both", expand=True, padx=0, pady=0)
        for w in self._frame.winfo_children():
            w.destroy()
        self._visible = True

        node = vfs.get_node(path)
        if not node:
            return

        # Header
        hdr = tk.Frame(self._frame, bg=T["bg_elevated"])
        hdr.pack(fill="x", padx=12, pady=8)
        tk.Label(hdr,
                 text=f"{VFS.file_icon(node.name)}  {node.name}",
                 font=FONTS.get("h4", ()), fg=T["fg_primary"],
                 bg=T["bg_elevated"]).pack(side="left")
        tk.Label(hdr,
                 text=VFS.human_size(node.size),
                 font=FONTS.get("small", ()), fg=T["fg_tertiary"],
                 bg=T["bg_elevated"]).pack(side="right")

        fl_separator(self._frame).pack(fill="x")

        # Content (text only)
        if node.is_dir:
            entries = len(vfs.listdir(path, show_hidden=True))
            tk.Label(self._frame,
                     text=f"\n📁\n\n{entries} items",
                     font=FONTS.get("h3", ()), fg=T["fg_tertiary"],
                     bg=T["bg_elevated"], justify="center").pack(expand=True)
        elif node.extension in {"txt","md","py","js","json","html","css","sh","log","ini","cfg"}:
            txt = tk.Text(
                self._frame,
                font=FONTS.get("mono_xs", ()),
                bg=T["bg_elevated"], fg=T["fg_secondary"],
                relief="flat", bd=0, state="normal",
                wrap="word", padx=10, pady=6,
            )
            txt.insert("1.0", (node.content or "")[:2000])
            txt.config(state="disabled")
            txt.pack(fill="both", expand=True, padx=4, pady=4)
        else:
            tk.Label(self._frame,
                     text=f"\n{VFS.file_icon(node.name)}\n\n"
                          f"{node.name}\n{VFS.human_size(node.size)}",
                     font=FONTS.get("h3", ()), fg=T["fg_tertiary"],
                     bg=T["bg_elevated"], justify="center").pack(expand=True)

    def hide(self) -> None:
        self._frame.pack_forget()
        self._visible = False


