class WordCountPanel:
    """
    Inline word-count / statistics sidebar for TextEditorWin.
    Shows: chars, words, lines, paragraphs, reading time estimate.
    """

    def __init__(self, parent: tk.Frame):
        self._frame = tk.Frame(parent, bg=T["bg_elevated"], width=160)
        self._frame.pack_propagate(False)
        self._visible = False
        self._stats: Dict[str, tk.StringVar] = {}

        tk.Label(self._frame, text="Document Stats",
                 font=FONTS.get("small_bold", ()), fg=T["accent"],
                 bg=T["bg_elevated"], pady=10, padx=10,
                 anchor="w").pack(fill="x")
        fl_separator(self._frame).pack(fill="x")

        for key, label in [
            ("chars",    "Characters"),
            ("words",    "Words"),
            ("lines",    "Lines"),
            ("paras",    "Paragraphs"),
            ("read_time","Read time"),
        ]:
            row = tk.Frame(self._frame, bg=T["bg_elevated"])
            row.pack(fill="x", padx=10, pady=4)
            tk.Label(row, text=label, font=FONTS.get("small", ()),
                     fg=T["fg_tertiary"], bg=T["bg_elevated"],
                     anchor="w").pack(fill="x")
            var = tk.StringVar(value="—")
            tk.Label(row, textvariable=var, font=FONTS.get("body_bold", ()),
                     fg=T["fg_primary"], bg=T["bg_elevated"],
                     anchor="w").pack(fill="x")
            self._stats[key] = var

    def update(self, text: str) -> None:
        chars  = len(text)
        words  = len(text.split())
        lines  = text.count("\n") + 1 if text else 0
        paras  = len([p for p in text.split("\n\n") if p.strip()])
        rt_sec = words / 200 * 60  # 200 wpm average
        rt_str = (f"{int(rt_sec//60)}m {int(rt_sec%60)}s"
                  if rt_sec >= 60 else f"{int(rt_sec)}s")
        self._stats["chars"].set(f"{chars:,}")
        self._stats["words"].set(f"{words:,}")
        self._stats["lines"].set(f"{lines:,}")
        self._stats["paras"].set(f"{max(1,paras):,}")
        self._stats["read_time"].set(rt_str)

    def toggle(self) -> None:
        if self._visible:
            self._frame.pack_forget()
            self._visible = False
        else:
            self._frame.pack(side="right", fill="y")
            self._visible = True

    def pack(self, **kw) -> None:
        self._frame.pack(**kw)


