class BrowserHistory:
    """Persists browser navigation history across sessions via VFS."""

    _PATH = VFS.CONFIG + "/browser_history.json"
    MAX   = 200

    def __init__(self, vfs: VFS):
        self._vfs     = vfs
        self._entries: List[Dict] = []
        self._load()

    def _load(self) -> None:
        raw = self._vfs.read(self._PATH)
        if raw:
            try:
                self._entries = json.loads(raw)
            except Exception:
                self._entries = []

    def save(self) -> None:
        self._vfs.write(self._PATH,
                        json.dumps(self._entries[-self.MAX:], indent=2))

    def add(self, url: str, title: str = "") -> None:
        self._entries.append({
            "url":   url,
            "title": title,
            "time":  datetime.datetime.now().isoformat(timespec="seconds"),
        })
        if len(self._entries) > self.MAX:
            self._entries = self._entries[-self.MAX:]
        self.save()

    def get_all(self) -> List[Dict]:
        return list(reversed(self._entries))

    def search(self, query: str) -> List[Dict]:
        q = query.lower()
        return [e for e in self._entries
                if q in e["url"].lower() or q in e.get("title","").lower()]

    def clear(self) -> None:
        self._entries = []
        self.save()


class BrowserBookmarks:
    """Stores browser bookmarks in VFS."""

    _PATH = VFS.CONFIG + "/browser_bookmarks.json"

    def __init__(self, vfs: VFS):
        self._vfs      = vfs
        self._bookmarks: List[Dict] = []
        self._load()

    def _load(self) -> None:
        raw = self._vfs.read(self._PATH)
        if raw:
            try:
                self._bookmarks = json.loads(raw)
            except Exception:
                self._bookmarks = []
        if not self._bookmarks:
            self._bookmarks = [
                {"url": "pyos://home",      "title": "PyOS Home",   "folder": ""},
                {"url": "pyos://apps",      "title": "Apps",        "folder": ""},
                {"url": "pyos://help",      "title": "Help",        "folder": ""},
                {"url": "pyos://changelog", "title": "Changelog",   "folder": ""},
            ]

    def save(self) -> None:
        self._vfs.write(self._PATH, json.dumps(self._bookmarks, indent=2))

    def add(self, url: str, title: str, folder: str = "") -> None:
        if not any(b["url"] == url for b in self._bookmarks):
            self._bookmarks.append({"url": url, "title": title, "folder": folder})
            self.save()

    def remove(self, url: str) -> None:
        self._bookmarks = [b for b in self._bookmarks if b["url"] != url]
        self.save()

    def get_all(self) -> List[Dict]:
        return list(self._bookmarks)

    def is_bookmarked(self, url: str) -> bool:
        return any(b["url"] == url for b in self._bookmarks)


