class FontSettingsPanel:
    """
    A reusable panel for the Settings app (or any future UI)
    that lets users preview and set the UI font size.
    """

    def __init__(self, parent: tk.Frame, settings: SettingsStore):
        self._settings = settings
        self._frame    = tk.Frame(parent, bg=T["bg_card"])

        tk.Label(self._frame, text="Font & Text",
                 font=FONTS.get("h3", ()), fg=T["fg_primary"],
                 bg=T["bg_card"], pady=10, padx=12).pack(anchor="w")
        fl_separator(self._frame).pack(fill="x", padx=8)

        row = tk.Frame(self._frame, bg=T["bg_card"])
        row.pack(fill="x", padx=12, pady=10)
        tk.Label(row, text="UI Font Size", font=FONTS.get("body", ()),
                 fg=T["fg_primary"], bg=T["bg_card"]).pack(side="left")

        self._sz_var = tk.IntVar(value=settings.get("font_size", 12))
        sl = tk.Scale(row, from_=9, to=18, orient="horizontal",
                      variable=self._sz_var,
                      bg=T["bg_card"], fg=T["fg_primary"],
                      troughcolor=T["bg_input"], sliderrelief="flat",
                      highlightthickness=0, bd=0, length=180)
        sl.pack(side="right")

        # Preview label
        self._preview = tk.Label(
            self._frame,
            text="The quick brown fox jumps over the lazy dog.",
            font=(FONTS.get("body", ("", 12))[0], self._sz_var.get()),
            fg=T["fg_secondary"], bg=T["bg_card"],
            padx=12, pady=8, wraplength=400, justify="left",
        )
        self._preview.pack(fill="x")
        self._sz_var.trace_add("write", lambda *a: self._update_preview())

    def _update_preview(self) -> None:
        fam = FONTS.get("body", ("", 12))[0]
        self._preview.config(font=(fam, self._sz_var.get()))

    def pack(self, **kw) -> None:
        self._frame.pack(**kw)

    def get_size(self) -> int:
        return self._sz_var.get()



