# ═══════════════════════════════════════════════════════════════════════════════

class StickyNotesWin(BaseWin):
    """
    Desktop sticky notes with 8 colour options, pin-to-top, pop-out,
    word count, resize, and VFS persistence.
    """

    NOTE_COLORS = {
        "Yellow":  ("#fef08a","#713f12"),
        "Blue":    ("#bfdbfe","#1e3a5f"),
        "Green":   ("#bbf7d0","#14532d"),
        "Pink":    ("#fbcfe8","#831843"),
        "Purple":  ("#e9d5ff","#4c1d95"),
        "Orange":  ("#fed7aa","#7c2d12"),
        "Red":     ("#fecaca","#7f1d1d"),
        "Gray":    ("#e5e7eb","#1f2937"),
    }

    def __init__(self, wm: WM):
        self._notes: List[Dict] = []
        self._active_note: Optional[int] = None
        self._next_id = 1
        super().__init__(wm, "Sticky Notes", 780, 520, "🗒")

    def _build(self) -> None:
        self._show_menubar()
        self._add_menu("File", [
            ("New Note",         self._new_note,        "Ctrl+N"),
            ("Delete Note",      self._delete_note,     "Del"),
            ("---",              None),
            ("Export to File",   self._export_notes),
            ("---",              None),
            ("Close",            self.close),
        ])
        self._add_menu("View", [
            ("All Notes",        lambda: None),
            ("Sort by Color",    lambda: None),
            ("Sort by Date",     lambda: None),
        ])
        self._show_statusbar()
        self.client.config(bg=T["bg_surface"])

        # Load saved notes from VFS
        self._load_notes()

        # ── Layout ────────────────────────────────────────────────────────────
        layout = tk.Frame(self.client, bg=T["bg_surface"])
        layout.pack(fill="both", expand=True)

        # Sidebar: note list
        self._sidebar = tk.Frame(layout, bg=T["bg_sidebar"], width=220)
        self._sidebar.pack(side="left", fill="y")
        self._sidebar.pack_propagate(False)

        # Toolbar above sidebar
        sb_toolbar = tk.Frame(self._sidebar, bg=T["bg_sidebar"])
        sb_toolbar.pack(fill="x", padx=8, pady=8)
        fl_button(sb_toolbar, "＋ New Note", self._new_note,
                  style="primary").pack(fill="x")

        fl_separator(self._sidebar).pack(fill="x")
        self._note_list_frame = tk.Frame(self._sidebar, bg=T["bg_sidebar"])
        self._note_list_frame.pack(fill="both", expand=True)

        fl_separator(layout, orient="v").pack(side="left", fill="y")

        # Editor pane
        self._editor_pane = tk.Frame(layout, bg=T["bg_surface"])
        self._editor_pane.pack(side="left", fill="both", expand=True)

        self._refresh_note_list()
        if self._notes:
            self._open_note(0)
        else:
            self._new_note()

    # ─── Note storage ─────────────────────────────────────────────────────────
    def _load_notes(self) -> None:
        raw = self.wm.vfs.read(VFS.CONFIG + "/sticky_notes.json")
        if raw:
            try:
                self._notes = json.loads(raw)
                self._next_id = max((n["id"] for n in self._notes), default=0) + 1
            except Exception:
                self._notes = []

    def _save_notes(self) -> None:
        self.wm.vfs.write(VFS.CONFIG + "/sticky_notes.json",
                          json.dumps(self._notes, indent=2))

    # ─── Note management ──────────────────────────────────────────────────────
    def _new_note(self) -> None:
        note = {
            "id":      self._next_id,
            "title":   f"Note {self._next_id}",
            "content": "",
            "color":   "Yellow",
            "pinned":  False,
            "created": datetime.datetime.now().isoformat(timespec="seconds"),
            "modified":datetime.datetime.now().isoformat(timespec="seconds"),
        }
        self._next_id += 1
        self._notes.append(note)
        self._save_notes()
        self._refresh_note_list()
        self._open_note(len(self._notes) - 1)

    def _delete_note(self) -> None:
        if self._active_note is None or self._active_note >= len(self._notes):
            return
        self._notes.pop(self._active_note)
        self._save_notes()
        self._active_note = None
        self._refresh_note_list()
        if self._notes:
            self._open_note(0)
        else:
            for w in self._editor_pane.winfo_children():
                w.destroy()

    def _refresh_note_list(self) -> None:
        for w in self._note_list_frame.winfo_children():
            w.destroy()

        # Sort: pinned first, then by modified desc
        sorted_notes = sorted(
            enumerate(self._notes),
            key=lambda x: (not x[1]["pinned"], x[1]["modified"]),
            reverse=False,
        )
        for display_idx, (orig_idx, note) in enumerate(sorted_notes):
            bg_pair = self.NOTE_COLORS.get(note["color"], ("#fef08a","#713f12"))
            note_bg, note_fg = bg_pair
            active  = orig_idx == self._active_note

            cell = tk.Frame(
                self._note_list_frame,
                bg=note_bg if not active else T["bg_selection"],
                cursor="hand2",
                highlightthickness=2,
                highlightbackground=T["accent"] if active else note_bg,
            )
            cell.pack(fill="x", padx=8, pady=4)

            top = tk.Frame(cell, bg=cell.cget("bg"))
            top.pack(fill="x", padx=8, pady=(6, 2))

            # Pin indicator
            if note["pinned"]:
                tk.Label(top, text="📌", font=FONTS.get("micro", ()),
                         bg=cell.cget("bg")).pack(side="left")

            title_lbl = tk.Label(
                top,
                text=note["title"][:20],
                font=FONTS.get("small_bold", ()),
                fg=note_fg,
                bg=cell.cget("bg"),
                anchor="w",
            )
            title_lbl.pack(side="left", fill="x", expand=True)

            # Preview
            preview = note["content"].replace("\n"," ")[:40] + ("…" if len(note["content"])>40 else "")
            tk.Label(cell, text=preview,
                     font=FONTS.get("nano", ()),
                     fg=_darken(note_fg, 0.3) if note_fg.startswith("#") else note_fg,
                     bg=cell.cget("bg"),
                     anchor="w", padx=8, pady=6,
                     wraplength=180).pack(fill="x")

            def _click(e, idx=orig_idx): self._open_note(idx)
            for w in [cell, top, title_lbl]:
                w.bind("<Button-1>", _click)

    def _open_note(self, idx: int) -> None:
        if idx >= len(self._notes):
            return
        self._active_note = idx
        self._refresh_note_list()
        note = self._notes[idx]

        for w in self._editor_pane.winfo_children():
            w.destroy()

        bg_pair = self.NOTE_COLORS.get(note["color"], ("#fef08a","#713f12"))
        note_bg, note_fg = bg_pair

        # ── Colour + action toolbar ────────────────────────────────────────
        toolbar = tk.Frame(self._editor_pane, bg=T["bg_elevated"])
        toolbar.pack(fill="x")

        # Title
        title_var = tk.StringVar(value=note["title"])
        title_entry = tk.Entry(
            toolbar,
            textvariable=title_var,
            font=FONTS.get("h3", ()),
            bg=T["bg_elevated"],
            fg=T["fg_primary"],
            insertbackground=T["accent"],
            relief="flat", bd=0,
        )
        title_entry.pack(side="left", fill="x", expand=True, padx=12, pady=8)

        def _save_title(e=None):
            note["title"] = title_var.get().strip() or "Untitled"
            note["modified"] = datetime.datetime.now().isoformat(timespec="seconds")
            self._save_notes()
            self._refresh_note_list()

        title_entry.bind("<FocusOut>", _save_title)
        title_entry.bind("<Return>",   _save_title)

        # Colour picker dots
        for color_name, (cbg, cfg) in self.NOTE_COLORS.items():
            dot = tk.Canvas(toolbar, width=18, height=18,
                            bg=T["bg_elevated"], highlightthickness=2,
                            cursor="hand2",
                            highlightbackground=T["accent"] if color_name==note["color"] else T["bg_elevated"])
            dot.pack(side="left", padx=2)
            dot.create_oval(2, 2, 16, 16, fill=cbg, outline="")
            dot.bind("<Button-1>",
                lambda e, cn=color_name, d=dot:
                    self._set_note_color(idx, cn))

        # Pin toggle
        pin_lbl = tk.Label(toolbar,
                           text="📌" if note["pinned"] else "📍",
                           font=FONTS.get("body", ()),
                           bg=T["bg_elevated"], cursor="hand2", padx=8)
        pin_lbl.pack(side="right")
        pin_lbl.bind("<Button-1>", lambda e: self._toggle_pin(idx))

        # Delete
        tk.Label(toolbar, text="🗑", font=FONTS.get("body", ()),
                 bg=T["bg_elevated"], cursor="hand2",
                 padx=6).pack(side="right") \
            ._bind = lambda: None
        toolbar.winfo_children()[-1].bind("<Button-1>", lambda e: self._delete_note())

        fl_separator(self._editor_pane).pack(fill="x")

        # ── Note body ─────────────────────────────────────────────────────────
        txt_frame = tk.Frame(self._editor_pane, bg=note_bg)
        txt_frame.pack(fill="both", expand=True)

        txt = tk.Text(
            txt_frame,
            font=FONTS.get("body", ()),
            bg=note_bg,
            fg=note_fg,
            insertbackground=note_fg,
            relief="flat", bd=0,
            wrap="word",
            padx=18, pady=14,
            undo=True,
        )
        txt.pack(fill="both", expand=True)
        txt.insert("1.0", note["content"])
        txt.focus_set()

        # Auto-save on key
        def _on_key(e=None):
            note["content"] = txt.get("1.0","end-1c")
            note["modified"]= datetime.datetime.now().isoformat(timespec="seconds")
            wc = len(note["content"].split())
            self._set_status(f"Note: {note['title']}  │  {wc} words  │  {len(note['content'])} chars")
            self._save_notes()

        txt.bind("<KeyRelease>", _on_key)
        self._set_status(f"Note: {note['title']}  │  {len(note['content'].split())} words")

    def _set_note_color(self, idx: int, color: str) -> None:
        if idx < len(self._notes):
            self._notes[idx]["color"] = color
            self._save_notes()
            self._open_note(idx)

    def _toggle_pin(self, idx: int) -> None:
        if idx < len(self._notes):
            self._notes[idx]["pinned"] = not self._notes[idx]["pinned"]
            self._save_notes()
            self._refresh_note_list()
            self._open_note(idx)

    def _export_notes(self) -> None:
        path = VFS.DOCS + "/sticky_notes_export.txt"
        content = ""
        for note in self._notes:
            content += f"=== {note['title']} ({note['color']}) ===\n"
            content += f"Created: {note['created']}\n"
            content += f"Modified: {note['modified']}\n\n"
            content += note["content"] + "\n\n"
        self.wm.vfs.write(path, content)
        notify(self.wm.root, "Exported", f"Saved to {path}", kind="success")


# ═══════════════════════════════════════════════════════════════════════════════
#  §28  CLIPBOARD MANAGER WINDOW
# ═══════════════════════════════════════════════════════════════════════════════

class ClipboardWin(BaseWin):
    """
    Visual clipboard history manager.
    Shows all clipboard entries with pin, copy, delete, and search.
    """

    def __init__(self, wm: WM):
        super().__init__(wm, "Clipboard", 600, 520, "📋")

    def _build(self) -> None:
        self._show_menubar()
        self._add_menu("Edit", [
            ("Clear History", self._clear_history),
            ("Clear Pinned",  self._clear_pinned),
        ])
        self._show_statusbar()
        self.client.config(bg=T["bg_surface"])

        # ── Header ────────────────────────────────────────────────────────────
        hdr = tk.Frame(self.client, bg=T["bg_elevated"])
        hdr.pack(fill="x")

        tk.Label(hdr, text="📋  Clipboard History",
                 font=FONTS.get("h3", ()), fg=T["fg_primary"],
                 bg=T["bg_elevated"], padx=16, pady=10).pack(side="left")

        fl_button(hdr, "Clear All", self._clear_history,
                  style="danger").pack(side="right", padx=10, pady=8)

        # Search
        search_frame = tk.Frame(self.client, bg=T["bg_elevated"])
        search_frame.pack(fill="x")
        self._search_bar = FlSearchBar(
            search_frame,
            placeholder="Search clipboard…",
            on_change=lambda q: self._refresh(query=q),
            bg_key="bg_input",
        )
        self._search_bar.pack(fill="x", padx=12, pady=8)

        fl_separator(self.client).pack(fill="x")

        # ── Tab strip ─────────────────────────────────────────────────────────
        tab_frame = tk.Frame(self.client, bg=T["bg_elevated"])
        tab_frame.pack(fill="x")

        self._tab_var = tk.StringVar(value="all")
        for tab_id, tab_lbl in [("all","All"), ("pinned","Pinned ⭐"), ("text","Text"), ("paths","Paths")]:
            btn = tk.Label(
                tab_frame, text=tab_lbl,
                font=FONTS.get("body", ()),
                fg=T["fg_primary"] if tab_id == "all" else T["fg_secondary"],
                bg=T["bg_active"] if tab_id == "all" else T["bg_elevated"],
                padx=16, pady=7, cursor="hand2",
            )
            btn.pack(side="left")
            btn.bind("<Button-1>",
                lambda e, t=tab_id, b=btn: (
                    self._tab_var.set(t),
                    [x.config(bg=T["bg_elevated"], fg=T["fg_secondary"])
                     for x in tab_frame.winfo_children()],
                    b.config(bg=T["bg_active"], fg=T["fg_primary"]),
                    self._refresh(),
                ))

        fl_separator(self.client).pack(fill="x")

        # ── Content ───────────────────────────────────────────────────────────
        self._scroll = ScrollableFrame(self.client, bg_key="bg_surface")
        self._scroll.pack(fill="both", expand=True)
        self._inner  = self._scroll.inner

        self._refresh()

    def _refresh(self, query: str = "") -> None:
        for w in self._inner.winfo_children():
            w.destroy()

        tab = self._tab_var.get()
        if tab == "pinned":
            entries = self.wm.clip.get_pinned()
        else:
            entries = self.wm.clip.get_history()

        if query:
            entries = [e for e in entries if query.lower() in e.text.lower()]

        if tab == "paths":
            entries = [e for e in entries if "/" in e.text or "\\" in e.text]
        elif tab == "text":
            entries = [e for e in entries if "/" not in e.text]

        if not entries:
            tk.Label(self._inner, text="No clipboard entries.",
                     font=FONTS.get("body", ()), fg=T["fg_tertiary"],
                     bg=T["bg_surface"], pady=40).pack()
            self._set_status("Clipboard is empty")
            return

        for i, entry in enumerate(entries):
            self._add_entry_row(i, entry)

        total = len(self.wm.clip.get_history())
        pinned = len(self.wm.clip.get_pinned())
        self._set_status(f"{total} items  │  {pinned} pinned  │  Current: {self.wm.clip.paste()[:30]}")

    def _add_entry_row(self, idx: int, entry: "ClipboardEntry") -> None:
        alt = T["bg_card"] if idx % 2 else T["bg_surface"]
        row = tk.Frame(self._inner, bg=alt, cursor="hand2")
        row.pack(fill="x")

        # Content preview
        preview_frame = tk.Frame(row, bg=alt)
        preview_frame.pack(side="left", fill="x", expand=True, padx=12, pady=8)

        # Detect type
        text = entry.text
        is_path  = "/" in text or "\\" in text
        is_code  = any(c in text for c in ["def ","class ","import ","function ","const "])
        type_icon = "📁" if is_path else "💻" if is_code else "📄"

        top_row = tk.Frame(preview_frame, bg=alt)
        top_row.pack(fill="x")
        tk.Label(top_row, text=type_icon,
                 font=FONTS.get("small", ()), bg=alt).pack(side="left")
        tk.Label(top_row,
                 text=entry.preview,
                 font=FONTS.get("body_bold" if self.wm.clip.paste()==text else "body", ()),
                 fg=T["accent"] if self.wm.clip.paste()==text else T["fg_primary"],
                 bg=alt, anchor="w").pack(side="left", fill="x", expand=True, padx=6)
        tk.Label(top_row, text=entry.age_str(),
                 font=FONTS.get("micro", ()), fg=T["fg_tertiary"],
                 bg=alt).pack(side="right", padx=8)

        # Source badge
        if entry.source and entry.source != "unknown":
            tk.Label(preview_frame,
                     text=f"  {entry.source}  ",
                     font=FONTS.get("badge", ()),
                     fg=T["accent"], bg=T["tag_bg"],
                     padx=4, pady=1).pack(anchor="w")

        # Action buttons
        btn_row = tk.Frame(row, bg=alt)
        btn_row.pack(side="right", padx=8)

        fl_button(btn_row, "Copy",
                  lambda t=text: (self.wm.clip.copy(t, "clipboard_win"),
                                   notify(self.wm.root, "Copied", "", kind="success"),
                                   self._refresh()),
                  style="secondary", padx=8, pady=3).pack(side="left", padx=2)

        star_text = "⭐" if entry.pinned else "☆"
        fl_button(btn_row, star_text,
                  lambda t=text: (self.wm.clip.pin(t) if not entry.pinned
                                  else self.wm.clip.unpin(t), self._refresh()),
                  style="ghost", padx=6, pady=3).pack(side="left", padx=2)

        fl_button(btn_row, "✕",
                  lambda t=text: (self.wm.clip.delete_entry(t), self._refresh()),
                  style="danger", padx=6, pady=3).pack(side="left", padx=2)

        # Double-click to copy
        row.bind("<Double-Button-1>",
            lambda e, t=text: (self.wm.clip.copy(t, "clipboard_win"),
                                notify(self.wm.root,"Copied","",kind="success")))
        row.bind("<Enter>", lambda e, r=row: r.config(bg=T["bg_hover"]))
        row.bind("<Leave>", lambda e, r=row, bg=alt: r.config(bg=bg))

        fl_separator(self._inner).pack(fill="x")

    def _clear_history(self) -> None:
        self.wm.clip.clear()
        self._refresh()
        notify(self.wm.root, "Clipboard", "History cleared", kind="info")

    def _clear_pinned(self) -> None:
        for e in self.wm.clip.get_pinned():
            self.wm.clip.unpin(e.text)
        self._refresh()


# ═══════════════════════════════════════════════════════════════════════════════
#  §29  PASSWORD VAULT
# ═══════════════════════════════════════════════════════════════════════════════

class PasswordVaultWin(BaseWin):
    """
    Secure password manager.
    Lock screen on open, categories, show/hide passwords,
    password strength meter, generator, full CRUD.
    """

    MASTER_HASH = hashlib.sha256(b"pyos").hexdigest()  # default master: "pyos"

    _CATEGORIES = ["All","Login","Email","Social","Banking",
                   "Work","Shopping","Other"]

    _SEED: List[Dict] = [
        {"id":1,"title":"PyOS Account","username":"user",
         "password":"p@ssw0rd!","url":"pyos://settings",
         "category":"Login","notes":"Main system account","strength":3},
        {"id":2,"title":"Email — Personal","username":"user@example.com",
         "password":"Tr0ub4dor&3","url":"mail://inbox",
         "category":"Email","notes":"","strength":4},
        {"id":3,"title":"GitHub","username":"pyos-dev",
         "password":"gh_t0k3n_abc123","url":"https://github.com",
         "category":"Work","notes":"Dev account","strength":5},
        {"id":4,"title":"Shopping Site","username":"buyer99",
         "password":"letmein123","url":"https://shop.example",
         "category":"Shopping","notes":"","strength":1},
    ]

    def __init__(self, wm: WM):
        self._unlocked   = False
        self._entries:   List[Dict] = [dict(e) for e in self._SEED]
        self._next_id    = 10
        self._category   = "All"
        self._selected:  Optional[int] = None
        self._show_pw:   bool = False
        super().__init__(wm, "Password Vault", 860, 580, "🔐")

    def _build(self) -> None:
        self.client.config(bg=T["bg_surface"])
        self._show_lock_screen()

    # ─── Lock screen ──────────────────────────────────────────────────────────
    def _show_lock_screen(self) -> None:
        for w in self.client.winfo_children():
            w.destroy()

        f = tk.Frame(self.client, bg=T["bg_surface"])
        f.pack(fill="both", expand=True)

        tk.Label(f, text="🔐", font=FONTS.get("emoji_lg", ()),
                 bg=T["bg_surface"], fg=T["fg_primary"]).pack(pady=(80, 12))
        tk.Label(f, text="Password Vault",
                 font=FONTS.get("display", ()), fg=T["fg_primary"],
                 bg=T["bg_surface"]).pack()
        tk.Label(f, text="Enter your master password to unlock",
                 font=FONTS.get("body", ()), fg=T["fg_secondary"],
                 bg=T["bg_surface"]).pack(pady=8)

        pw_wrap = tk.Frame(f, bg=T["bg_input"])
        pw_wrap.pack(pady=16)

        self._lock_entry = tk.Entry(
            pw_wrap, show="●",
            font=FONTS.get("body", ()),
            bg=T["bg_input"], fg=T["fg_primary"],
            insertbackground=T["accent"],
            relief="flat", bd=0, width=26,
        )
        self._lock_entry.pack(padx=16, pady=10)
        self._lock_entry.focus_set()
        self._lock_entry.bind("<Return>", lambda e: self._try_unlock())

        self._lock_err = tk.Label(f, text="",
                                   font=FONTS.get("small", ()),
                                   fg=T["danger"], bg=T["bg_surface"])
        self._lock_err.pack()

        fl_button(f, "Unlock", self._try_unlock, style="primary").pack(pady=8)
        tk.Label(f, text="Default password: pyos",
                 font=FONTS.get("micro", ()), fg=T["fg_tertiary"],
                 bg=T["bg_surface"]).pack(pady=4)

    def _try_unlock(self) -> None:
        pw = self._lock_entry.get()
        if hashlib.sha256(pw.encode()).hexdigest() == self.MASTER_HASH:
            self._unlocked = True
            self._show_vault()
        else:
            self._lock_err.config(text="Incorrect password. Try again.")
            self._lock_entry.delete(0, "end")

    # ─── Vault UI ─────────────────────────────────────────────────────────────
    def _show_vault(self) -> None:
        for w in self.client.winfo_children():
            w.destroy()

        self._show_menubar()
        self._add_menu("File", [
            ("New Entry",    self._new_entry,       "Ctrl+N"),
            ("---",          None),
            ("Lock Vault",   self._lock_vault),
            ("Close",        self.close),
        ])
        self._add_menu("Tools", [
            ("Password Generator", self._open_generator),
            ("Check Strength",     self._check_all_strength),
        ])
        self._show_statusbar()

        # ── Three-pane layout ─────────────────────────────────────────────────
        layout = tk.Frame(self.client, bg=T["bg_surface"])
        layout.pack(fill="both", expand=True)

        # Category sidebar
        sidebar = tk.Frame(layout, bg=T["bg_sidebar"], width=160)
        sidebar.pack(side="left", fill="y")
        sidebar.pack_propagate(False)

        tk.Label(sidebar, text="  Categories",
                 font=FONTS.get("small_bold", ()), fg=T["accent"],
                 bg=T["bg_sidebar"], pady=10).pack(fill="x")

        self._cat_btns_vault: Dict[str, tk.Label] = {}
        for cat in self._CATEGORIES:
            count = (len(self._entries) if cat == "All"
                     else sum(1 for e in self._entries if e["category"] == cat))
            active = cat == self._category
            btn = tk.Label(
                sidebar,
                text=f"  {cat}  ({count})" if count else f"  {cat}",
                font=FONTS.get("body_bold" if active else "body", ()),
                fg=T["fg_primary"] if active else T["fg_secondary"],
                bg=T["bg_active"] if active else T["bg_sidebar"],
                anchor="w", pady=7, cursor="hand2",
            )
            btn.pack(fill="x")
            self._cat_btns_vault[cat] = btn
            btn.bind("<Button-1>", lambda e, c=cat: self._switch_cat(c))
            btn.bind("<Enter>",
                lambda e, b=btn, c=cat:
                    b.config(bg=T["bg_hover"]) if c != self._category else None)
            btn.bind("<Leave>",
                lambda e, b=btn, c=cat:
                    b.config(bg=T["bg_active"] if c == self._category else T["bg_sidebar"]))

        fl_separator(layout, orient="v").pack(side="left", fill="y")

        # Entry list
        list_pane = tk.Frame(layout, bg=T["bg_surface"], width=280)
        list_pane.pack(side="left", fill="y")
        list_pane.pack_propagate(False)

        # Search + new
        top_bar = tk.Frame(list_pane, bg=T["bg_elevated"])
        top_bar.pack(fill="x")
        self._vault_search = FlSearchBar(
            top_bar, placeholder="Search entries…",
            on_change=lambda q: self._load_entry_list(q),
            bg_key="bg_input",
        )
        self._vault_search.pack(fill="x", padx=8, pady=6)

        fl_button(top_bar, "＋ New", self._new_entry,
                  style="primary", pady=4).pack(padx=8, pady=4)
        fl_separator(list_pane).pack(fill="x")

        self._list_scroll = ScrollableFrame(list_pane, bg_key="bg_surface")
        self._list_scroll.pack(fill="both", expand=True)
        self._list_inner  = self._list_scroll.inner

        fl_separator(layout, orient="v").pack(side="left", fill="y")

        # Detail pane
        self._detail_pane = tk.Frame(layout, bg=T["bg_surface"])
        self._detail_pane.pack(side="left", fill="both", expand=True)

        self._load_entry_list()
        self._show_empty_detail()
        self._update_status_bar()

    def _switch_cat(self, cat: str) -> None:
        self._category = cat
        for c, btn in self._cat_btns_vault.items():
            active = c == cat
            btn.config(
                bg=T["bg_active"] if active else T["bg_sidebar"],
                fg=T["fg_primary"] if active else T["fg_secondary"],
                font=FONTS.get("body_bold" if active else "body", ()),
            )
        self._selected = None
        self._load_entry_list()
        self._show_empty_detail()

    def _load_entry_list(self, query: str = "") -> None:
        for w in self._list_inner.winfo_children():
            w.destroy()
        entries = self._entries
        if self._category != "All":
            entries = [e for e in entries if e["category"] == self._category]
        if query:
            q = query.lower()
            entries = [e for e in entries
                       if q in e["title"].lower() or q in e["username"].lower()
                       or q in e.get("url","").lower()]
        if not entries:
            tk.Label(self._list_inner, text="No entries.",
                     font=FONTS.get("body", ()), fg=T["fg_tertiary"],
                     bg=T["bg_surface"], pady=30).pack()
            return
        for entry in entries:
            self._add_entry_row(entry)

    def _add_entry_row(self, entry: Dict) -> None:
        active = entry["id"] == self._selected
        bg     = T["bg_selection"] if active else T["bg_surface"]
        row    = tk.Frame(self._list_inner, bg=bg, cursor="hand2")
        row.pack(fill="x")

        strength = entry.get("strength", 3)
        strength_colors = {1:T["danger"],2:T["warning"],3:T["warning"],4:T["success"],5:T["success"]}
        sc = strength_colors.get(strength, T["fg_tertiary"])

        # Category icon
        cat_icons = {"Login":"🔑","Email":"📧","Social":"👥","Banking":"🏦",
                     "Work":"💼","Shopping":"🛒","Other":"📝"}
        icon = cat_icons.get(entry["category"], "🔑")

        tk.Label(row, text=icon, font=FONTS.get("emoji_sm", ()),
                 bg=bg, width=3).pack(side="left", padx=8, pady=8)

        info = tk.Frame(row, bg=bg)
        info.pack(side="left", fill="x", expand=True, pady=6)
        tk.Label(info, text=entry["title"],
                 font=FONTS.get("body_bold", ()),
                 fg=T["fg_primary"], bg=bg, anchor="w").pack(fill="x")
        tk.Label(info, text=entry["username"],
                 font=FONTS.get("small", ()),
                 fg=T["fg_secondary"], bg=bg, anchor="w").pack(fill="x")

        # Strength dots
        dot_row = tk.Frame(row, bg=bg)
        dot_row.pack(side="right", padx=10)
        for i in range(5):
            dot_bg = sc if i < strength else T["border"]
            tk.Frame(dot_row, width=6, height=6, bg=dot_bg).grid(row=0, column=i, padx=1)

        fl_separator(self._list_inner).pack(fill="x")

        def _click(e, eid=entry["id"]):
            self._selected = eid
            self._load_entry_list(self._vault_search.get())
            self._show_detail(eid)

        row.bind("<Button-1>", _click)
        row.bind("<Enter>",
            lambda e, r=row, bg=bg: r.config(bg=T["bg_hover"]) if not active else None)
        row.bind("<Leave>",
            lambda e, r=row, bg=bg: r.config(bg=bg))

    def _show_empty_detail(self) -> None:
        for w in self._detail_pane.winfo_children():
            w.destroy()
        tk.Label(self._detail_pane, text="🔐",
                 font=FONTS.get("emoji_lg", ()), fg=T["fg_tertiary"],
                 bg=T["bg_surface"]).pack(pady=(80,12))
        tk.Label(self._detail_pane, text="Select an entry to view details",
                 font=FONTS.get("h3", ()), fg=T["fg_tertiary"],
                 bg=T["bg_surface"]).pack()

    def _show_detail(self, entry_id: int) -> None:
        entry = next((e for e in self._entries if e["id"] == entry_id), None)
        if not entry:
            return
        for w in self._detail_pane.winfo_children():
            w.destroy()

        f = self._detail_pane

        # Header
        hdr = tk.Frame(f, bg=T["bg_elevated"])
        hdr.pack(fill="x")
        hi = tk.Frame(hdr, bg=T["bg_elevated"])
        hi.pack(fill="x", padx=18, pady=14)
        cat_icons = {"Login":"🔑","Email":"📧","Social":"👥","Banking":"🏦",
                     "Work":"💼","Shopping":"🛒","Other":"📝"}
        tk.Label(hi,
                 text=cat_icons.get(entry["category"],"🔑"),
                 font=(FONTS.get("emoji_lg",("",32))[0],40),
                 bg=T["bg_elevated"]).pack(side="left", padx=8)
        title_info = tk.Frame(hi, bg=T["bg_elevated"])
        title_info.pack(side="left", fill="x", expand=True, padx=8)
        tk.Label(title_info, text=entry["title"],
                 font=FONTS.get("h2", ()), fg=T["fg_primary"],
                 bg=T["bg_elevated"], anchor="w").pack(fill="x")
        tk.Label(title_info, text=entry["category"],
                 font=FONTS.get("small", ()), fg=T["accent"],
                 bg=T["bg_elevated"], anchor="w").pack(fill="x")

        # Action buttons
        btn_row = tk.Frame(hdr, bg=T["bg_elevated"])
        btn_row.pack(fill="x", padx=18, pady=(0, 10))
        fl_button(btn_row, "✏ Edit",   lambda: self._edit_entry(entry_id),
                  style="secondary").pack(side="left", padx=(0,6))
        fl_button(btn_row, "🗑 Delete", lambda: self._delete_entry(entry_id),
                  style="danger").pack(side="left")

        fl_separator(f).pack(fill="x")

        # Fields
        fields_frame = tk.Frame(f, bg=T["bg_surface"])
        fields_frame.pack(fill="x", padx=20, pady=14)

        for label, key, is_pw in [
            ("Username",  "username",  False),
            ("Password",  "password",  True),
            ("URL",       "url",        False),
            ("Notes",     "notes",      False),
        ]:
            field_row = tk.Frame(fields_frame, bg=T["bg_surface"])
            field_row.pack(fill="x", pady=6)

            tk.Label(field_row, text=label,
                     font=FONTS.get("small_bold", ()),
                     fg=T["fg_tertiary"], bg=T["bg_surface"],
                     width=12, anchor="w").pack(side="left")

            val = entry.get(key, "") or "—"
            display_val = ("•" * min(len(val), 20)) if (is_pw and not self._show_pw) else val

            val_lbl = tk.Label(field_row, text=display_val,
                               font=FONTS.get("mono_sm" if is_pw else "body", ()),
                               fg=T["fg_primary"] if val != "—" else T["fg_tertiary"],
                               bg=T["bg_surface"], anchor="w")
            val_lbl.pack(side="left", fill="x", expand=True)

            # Copy button
            if val != "—":
                fl_button(field_row, "Copy",
                          lambda v=entry.get(key,""):
                              (self.wm.clip.copy(v, "vault"),
                               notify(self.wm.root, "Copied", label, kind="success")),
                          style="ghost", padx=8, pady=2).pack(side="right")

            if is_pw and val != "—":
                fl_button(field_row,
                          "Hide" if self._show_pw else "Show",
                          self._toggle_show_pw,
                          style="ghost", padx=8, pady=2).pack(side="right")

        # Strength meter
        strength = entry.get("strength", 3)
        strength_labels = {1:"Very Weak",2:"Weak",3:"Fair",4:"Strong",5:"Very Strong"}
        strength_colors = {1:T["danger"],2:T["warning"],3:T["warning"],
                           4:T["success"],5:T["success"]}
        sm = tk.Frame(fields_frame, bg=T["bg_surface"])
        sm.pack(fill="x", pady=8)
        tk.Label(sm, text="Strength", font=FONTS.get("small_bold", ()),
                 fg=T["fg_tertiary"], bg=T["bg_surface"],
                 width=12, anchor="w").pack(side="left")
        color = strength_colors.get(strength, T["fg_tertiary"])
        bar_frame = tk.Frame(sm, bg=T["bg_input"], height=8, width=200)
        bar_frame.pack(side="left", padx=8)
        bar_frame.pack_propagate(False)
        tk.Frame(bar_frame, bg=color, height=8).place(
            relwidth=strength/5, relheight=1)
        tk.Label(sm, text=strength_labels.get(strength,"—"),
                 font=FONTS.get("small_bold", ()),
                 fg=color, bg=T["bg_surface"]).pack(side="left", padx=6)

    def _toggle_show_pw(self) -> None:
        self._show_pw = not self._show_pw
        if self._selected:
            self._show_detail(self._selected)

    def _new_entry(self) -> None:
        self._edit_dialog(None)

    def _edit_entry(self, entry_id: int) -> None:
        self._edit_dialog(entry_id)

    def _edit_dialog(self, entry_id: Optional[int]) -> None:
        existing = next((e for e in self._entries if e["id"] == entry_id), None)

        d = tk.Toplevel(self.frame)
        d.title("Edit Entry" if existing else "New Entry")
        d.config(bg=T["bg_surface"])
        d.geometry("480x420")
        d.grab_set()

        tk.Label(d, text="Edit Entry" if existing else "New Password Entry",
                 font=FONTS.get("h2", ()), fg=T["fg_primary"],
                 bg=T["bg_surface"], pady=14, padx=20).pack(anchor="w")
        fl_separator(d).pack(fill="x")

        fields_data = {}
        for label, key, default, show in [
            ("Title *",   "title",    existing["title"]    if existing else "",    True),
            ("Username",  "username", existing["username"] if existing else "",    True),
            ("Password",  "password", existing["password"] if existing else "",    False),
            ("URL",       "url",      existing.get("url","") if existing else "",  True),
            ("Notes",     "notes",    existing.get("notes","") if existing else "",True),
        ]:
            row = tk.Frame(d, bg=T["bg_surface"]); row.pack(fill="x", padx=16, pady=5)
            tk.Label(row, text=label, font=FONTS.get("body_bold", ()),
                     fg=T["fg_secondary"], bg=T["bg_surface"],
                     width=11, anchor="w").pack(side="left")
            e = fl_entry(row)
            if not show:
                e.config(show="●")
            e.pack(side="left", fill="x", expand=True)
            e.insert(0, default)
            fields_data[key] = e
        fields_data["title"].focus_set()

        # Category
        cat_row = tk.Frame(d, bg=T["bg_surface"]); cat_row.pack(fill="x", padx=16, pady=5)
        tk.Label(cat_row, text="Category", font=FONTS.get("body_bold", ()),
                 fg=T["fg_secondary"], bg=T["bg_surface"],
                 width=11, anchor="w").pack(side="left")
        cat_var = tk.StringVar(value=existing.get("category","Login") if existing else "Login")
        for cat in ["Login","Email","Social","Banking","Work","Shopping","Other"]:
            tk.Radiobutton(cat_row, text=cat, variable=cat_var, value=cat,
                           font=FONTS.get("small", ()), fg=T["fg_primary"],
                           bg=T["bg_surface"], selectcolor=T["bg_active"],
                           activebackground=T["bg_surface"],
                           cursor="hand2").pack(side="left", padx=2)

        # Generate button
        gen_row = tk.Frame(d, bg=T["bg_surface"]); gen_row.pack(fill="x", padx=16, pady=4)
        fl_button(gen_row, "Generate Password",
                  lambda: fields_data["password"].delete(0,"end") or
                          fields_data["password"].insert(0, self._generate_password()),
                  style="secondary").pack(side="left")

        def _save():
            title = fields_data["title"].get().strip()
            if not title:
                return
            pw = fields_data["password"].get()
            strength = self._calc_strength(pw)
            new_data = {
                "id":       existing["id"] if existing else self._next_id,
                "title":    title,
                "username": fields_data["username"].get().strip(),
                "password": pw,
                "url":      fields_data["url"].get().strip(),
                "notes":    fields_data["notes"].get().strip(),
                "category": cat_var.get(),
                "strength": strength,
            }
            if existing:
                idx = next(i for i, e in enumerate(self._entries) if e["id"] == entry_id)
                self._entries[idx] = new_data
            else:
                self._next_id += 1
                self._entries.append(new_data)
            d.destroy()
            self._load_entry_list()
            self._show_detail(new_data["id"])
            self._update_status_bar()
            notify(self.wm.root, "Vault",
                   ("Entry updated" if existing else "Entry saved"), kind="success")

        btn_row = tk.Frame(d, bg=T["bg_surface"]); btn_row.pack(pady=10)
        fl_button(btn_row, "Save", _save, style="primary").pack(side="left", padx=6)
        fl_button(btn_row, "Cancel", d.destroy, style="ghost").pack(side="left", padx=6)

    def _delete_entry(self, entry_id: int) -> None:
        self._entries = [e for e in self._entries if e["id"] != entry_id]
        self._selected = None
        self._load_entry_list()
        self._show_empty_detail()
        self._update_status_bar()
        notify(self.wm.root, "Vault", "Entry deleted", kind="info")

    def _lock_vault(self) -> None:
        self._unlocked = False
        self._selected = None
        for w in self.client.winfo_children():
            w.destroy()
        self._show_lock_screen()

    def _open_generator(self) -> None:
        d = tk.Toplevel(self.frame)
        d.title("Password Generator")
        d.config(bg=T["bg_surface"])
        d.geometry("420x340")

        tk.Label(d, text="🔑  Password Generator",
                 font=FONTS.get("h2", ()), fg=T["fg_primary"],
                 bg=T["bg_surface"], pady=14, padx=20).pack(anchor="w")
        fl_separator(d).pack(fill="x")

        result_var = tk.StringVar(value=self._generate_password())
        result_frame = tk.Frame(d, bg=T["bg_input"])
        result_frame.pack(fill="x", padx=20, pady=14)
        result_lbl = tk.Label(result_frame,
                              textvariable=result_var,
                              font=FONTS.get("mono", ()),
                              fg=T["accent"], bg=T["bg_input"],
                              padx=12, pady=10, anchor="w")
        result_lbl.pack(side="left", fill="x", expand=True)

        # Options
        opt_frame = tk.Frame(d, bg=T["bg_surface"])
        opt_frame.pack(fill="x", padx=20)
        length_var = tk.IntVar(value=16)
        upper_var  = tk.BooleanVar(value=True)
        digits_var = tk.BooleanVar(value=True)
        symbols_var= tk.BooleanVar(value=True)

        len_row = tk.Frame(opt_frame, bg=T["bg_surface"]); len_row.pack(fill="x", pady=4)
        tk.Label(len_row, text="Length:", font=FONTS.get("body", ()),
                 fg=T["fg_primary"], bg=T["bg_surface"], width=10, anchor="w").pack(side="left")
        tk.Scale(len_row, from_=8, to=32, orient="horizontal", variable=length_var,
                 bg=T["bg_surface"], fg=T["fg_primary"], troughcolor=T["bg_input"],
                 sliderrelief="flat", highlightthickness=0, length=200).pack(side="left")

        for var, lbl in [(upper_var,"Uppercase"),(digits_var,"Digits"),(symbols_var,"Symbols")]:
            r = tk.Frame(opt_frame, bg=T["bg_surface"]); r.pack(fill="x", pady=2)
            tk.Checkbutton(r, text=lbl, variable=var,
                           font=FONTS.get("body",()),fg=T["fg_primary"],
                           bg=T["bg_surface"], selectcolor=T["accent"],
                           activebackground=T["bg_surface"],cursor="hand2").pack(side="left")

        def _regen():
            result_var.set(self._generate_password(
                length=length_var.get(),
                use_upper=upper_var.get(),
                use_digits=digits_var.get(),
                use_symbols=symbols_var.get(),
            ))

        btn_row = tk.Frame(d, bg=T["bg_surface"]); btn_row.pack(pady=12)
        fl_button(btn_row, "Regenerate", _regen, style="secondary").pack(side="left", padx=6)
        fl_button(btn_row, "Copy",
                  lambda: (self.wm.clip.copy(result_var.get(), "vault"),
                           notify(self.wm.root,"Copied","",kind="success")),
                  style="primary").pack(side="left", padx=6)
        fl_button(btn_row, "Close", d.destroy, style="ghost").pack(side="left", padx=6)

    def _generate_password(
        self,
        length:      int  = 16,
        use_upper:   bool = True,
        use_digits:  bool = True,
        use_symbols: bool = True,
    ) -> str:
        chars = string.ascii_lowercase
        if use_upper:   chars += string.ascii_uppercase
        if use_digits:  chars += string.digits
        if use_symbols: chars += "!@#$%^&*()-_=+[]{}|;:,.<>?"
        return "".join(random.choice(chars) for _ in range(length))

    @staticmethod
    def _calc_strength(pw: str) -> int:
        if len(pw) < 6:  return 1
        score = 1
        if len(pw) >= 10: score += 1
        if any(c.isupper() for c in pw): score += 1
        if any(c.isdigit() for c in pw): score += 1
        if any(c in "!@#$%^&*()-_=+[]{}|;:,.<>?" for c in pw): score += 1
        return min(5, score)

    def _check_all_strength(self) -> None:
        weak = [e["title"] for e in self._entries if e.get("strength",3) <= 2]
        if weak:
            notify(self.wm.root, "Vault",
                   f"{len(weak)} weak password(s) found: {', '.join(weak[:3])}", kind="warning")
        else:
            notify(self.wm.root, "Vault", "All passwords are strong!", kind="success")

    def _update_status_bar(self) -> None:
        total  = len(self._entries)
        weak   = sum(1 for e in self._entries if e.get("strength",3) <= 2)
        strong = sum(1 for e in self._entries if e.get("strength",3) >= 4)
        self._set_status(
            f"{total} entries  │  {strong} strong  │  {weak} weak  │  Vault locked on close")


