#  §30  WEATHER
# ═══════════════════════════════════════════════════════════════════════════════

class WeatherWin(BaseWin):
    """
    Full weather application with:
      • Hero current conditions display
      • 7-day forecast strip
      • Hourly breakdown for today
      • Wind / humidity / UV / pressure stats
      • City search with simulated locations
      • Animated weather icons using canvas
      • Celsius / Fahrenheit toggle
      • Weather alerts panel
    """

    CITIES: Dict[str, Dict] = {
        "London":       {"temp":12,"feels":9,"humidity":78,"wind":22,"uv":3,"pressure":1012,"condition":"Cloudy","code":"cloud"},
        "New York":     {"temp":18,"feels":15,"humidity":65,"wind":18,"uv":6,"pressure":1018,"condition":"Sunny","code":"sun"},
        "Tokyo":        {"temp":22,"feels":21,"humidity":70,"wind":12,"uv":7,"pressure":1010,"condition":"Partly Cloudy","code":"partly"},
        "Sydney":       {"temp":26,"feels":25,"humidity":60,"wind":15,"uv":9,"pressure":1008,"condition":"Sunny","code":"sun"},
        "Paris":        {"temp":14,"feels":11,"humidity":80,"wind":25,"uv":2,"pressure":1005,"condition":"Rainy","code":"rain"},
        "Berlin":       {"temp":8, "feels":5, "humidity":85,"wind":30,"uv":1,"pressure":1000,"condition":"Stormy","code":"storm"},
        "Dubai":        {"temp":38,"feels":42,"humidity":40,"wind":10,"uv":11,"pressure":1006,"condition":"Sunny","code":"sun"},
        "Moscow":       {"temp":-2,"feels":-7,"humidity":90,"wind":20,"uv":1,"pressure":998, "condition":"Snowy","code":"snow"},
        "Mumbai":       {"temp":32,"feels":38,"humidity":88,"wind":8, "uv":10,"pressure":1007,"condition":"Humid","code":"partly"},
        "Cairo":        {"temp":30,"feels":32,"humidity":35,"wind":14,"uv":10,"pressure":1012,"condition":"Sunny","code":"sun"},
        "Toronto":      {"temp":5, "feels":0, "humidity":72,"wind":28,"uv":2,"pressure":1015,"condition":"Windy","code":"wind"},
        "Singapore":    {"temp":30,"feels":36,"humidity":90,"wind":10,"uv":9,"pressure":1009,"condition":"Thunderstorm","code":"thunder"},
        "PyOS City":    {"temp":21,"feels":20,"humidity":55,"wind":10,"uv":5,"pressure":1013,"condition":"Perfect","code":"sun"},
    }

    CONDITION_ICONS = {
        "sun":     "☀️", "partly": "⛅", "cloud": "☁️",
        "rain":    "🌧️", "storm":  "⛈️", "snow":  "❄️",
        "wind":    "💨", "thunder":"🌩️", "fog":   "🌫️",
    }

    CONDITION_COLORS = {
        "sun":    ("#ff9500","#ffcc02"),
        "partly": ("#4a9eff","#a8d0ff"),
        "cloud":  ("#8e8e93","#c7c7cc"),
        "rain":   ("#007aff","#5ac8fa"),
        "storm":  ("#5856d6","#a29bfe"),
        "snow":   ("#e5e5ea","#f2f2f7"),
        "wind":   ("#34c759","#a8e6cf"),
        "thunder":("#ff3b30","#ff9f0a"),
        "fog":    ("#aeaeb2","#d1d1d6"),
    }

    def __init__(self, wm: WM):
        self._city    = "PyOS City"
        self._celsius = True
        self._alerts: List[str] = []
        super().__init__(wm, "Weather", 860, 620, "🌤")

    def _build(self) -> None:
        self._show_menubar()
        self._add_menu("View", [
            ("Celsius",    lambda: self._set_unit(True)),
            ("Fahrenheit", lambda: self._set_unit(False)),
            ("---",        None),
            ("Refresh",    self._draw_all, "F5"),
        ])
        self._add_menu("Locations", [
            (city, lambda c=city: self._switch_city(c))
            for city in self.CITIES
        ])
        self._show_statusbar()
        self.client.config(bg=T["bg_surface"])
        self._draw_all()

    def _draw_all(self) -> None:
        for w in self.client.winfo_children():
            w.destroy()

        data = self.CITIES.get(self._city, self.CITIES["PyOS City"])
        code = data["code"]
        grad_colors = self.CONDITION_COLORS.get(code, ("#1a1a2e","#0f3460"))

        # ── Search bar ────────────────────────────────────────────────────────
        search_bar = tk.Frame(self.client, bg=T["bg_elevated"])
        search_bar.pack(fill="x")

        FlSearchBar(
            search_bar,
            placeholder="Search city…",
            on_submit=lambda q: self._search_city(q),
            bg_key="bg_input",
        ).pack(side="left", fill="x", expand=True, padx=12, pady=8)

        unit_btn = fl_button(
            search_bar,
            "°C / °F",
            lambda: self._set_unit(not self._celsius),
            style="secondary",
            pady=5,
        )
        unit_btn.pack(side="right", padx=8, pady=6)

        fl_separator(self.client).pack(fill="x")

        # Scrollable content
        scroll = ScrollableFrame(self.client, bg_key="bg_base")
        scroll.pack(fill="both", expand=True)
        inner = scroll.inner
        inner.config(bg=T["bg_base"])

        # ── Hero card ─────────────────────────────────────────────────────────
        hero = tk.Canvas(inner, height=220, highlightthickness=0)
        hero.pack(fill="x", padx=0, pady=0)
        hero.update_idletasks()
        hw = hero.winfo_width() or 860

        # Gradient background
        for i in range(40):
            t2 = i / 39
            color = lerp_color(grad_colors[0], grad_colors[1], t2)
            hero.create_rectangle(0, i*6, hw, (i+1)*6+1, fill=color, outline="")

        # Weather icon (large)
        icon = self.CONDITION_ICONS.get(code, "🌤")
        hero.create_text(hw//2 - 120, 110, text=icon,
                         font=(FONTS.get("body",("",13))[0], 72),
                         fill="white", anchor="center")

        # Temperature
        temp = data["temp"]
        display_temp = temp if self._celsius else int(temp * 9/5 + 32)
        unit_str = "°C" if self._celsius else "°F"
        hero.create_text(hw//2 + 40, 90,
                         text=f"{display_temp}{unit_str}",
                         font=(FONTS.get("body",("",13))[0], 64, "bold"),
                         fill="white", anchor="center")

        # City name
        hero.create_text(hw//2 + 40, 148,
                         text=self._city,
                         font=(FONTS.get("body",("",13))[0], 18, "bold"),
                         fill="white", anchor="center")

        # Condition
        hero.create_text(hw//2 + 40, 174,
                         text=data["condition"],
                         font=(FONTS.get("body",("",13))[0], 13),
                         fill="#e0e0e0",
                         anchor="center")

        # Feels like
        feels = data["feels"]
        display_feels = feels if self._celsius else int(feels * 9/5 + 32)
        hero.create_text(hw//2 + 40, 196,
                         text=f"Feels like {display_feels}{unit_str}",
                         font=(FONTS.get("body",("",13))[0], 11),
                         fill="#cccccc",
                         anchor="center")

        # ── Stats row ─────────────────────────────────────────────────────────
        stats_row = tk.Frame(inner, bg=T["bg_card"])
        stats_row.pack(fill="x", padx=0, pady=0)

        stats = [
            ("💧", "Humidity",   f"{data['humidity']}%"),
            ("💨", "Wind",       f"{data['wind']} km/h"),
            ("🌡",  "Pressure",  f"{data['pressure']} hPa"),
            ("☀",  "UV Index",  str(data['uv'])),
        ]
        for icon_s, label, value in stats:
            cell = tk.Frame(stats_row, bg=T["bg_card"])
            cell.pack(side="left", fill="x", expand=True, padx=2, pady=12)
            tk.Label(cell, text=icon_s, font=FONTS.get("h2",()),
                     bg=T["bg_card"], fg=T["accent"]).pack()
            tk.Label(cell, text=value, font=FONTS.get("h3",()),
                     bg=T["bg_card"], fg=T["fg_primary"]).pack()
            tk.Label(cell, text=label, font=FONTS.get("micro",()),
                     bg=T["bg_card"], fg=T["fg_tertiary"]).pack()

        fl_separator(inner).pack(fill="x")

        # ── 7-day forecast ────────────────────────────────────────────────────
        tk.Label(inner, text="  7-Day Forecast",
                 font=FONTS.get("h3",()),
                 fg=T["fg_secondary"], bg=T["bg_base"],
                 anchor="w", pady=12, padx=10).pack(fill="x")

        forecast_strip = tk.Frame(inner, bg=T["bg_base"])
        forecast_strip.pack(fill="x", padx=10, pady=4)

        days_ahead = ["Today","Tomorrow","Mon","Tue","Wed","Thu","Fri"]
        base_temp  = data["temp"]
        base_code  = code

        # Realistic temperature variation
        variations = [0, random.randint(-3,3), random.randint(-4,4),
                      random.randint(-5,5), random.randint(-3,6),
                      random.randint(-6,3), random.randint(-4,5)]
        forecast_codes = [
            base_code,
            random.choice([base_code, "partly", "cloud"]),
            random.choice(list(self.CONDITION_ICONS.keys())),
            random.choice(list(self.CONDITION_ICONS.keys())),
            random.choice([base_code, "rain", "partly"]),
            random.choice(list(self.CONDITION_ICONS.keys())),
            random.choice([base_code, "sun", "partly"]),
        ]

        for i, (day, var, fc) in enumerate(zip(days_ahead, variations, forecast_codes)):
            t = base_temp + var
            display_t = t if self._celsius else int(t*9/5+32)
            low_t = t - random.randint(3, 8)
            display_low = low_t if self._celsius else int(low_t*9/5+32)
            fc_icon = self.CONDITION_ICONS.get(fc, "⛅")

            cell = tk.Frame(forecast_strip, bg=T["bg_card"],
                            highlightthickness=1 if i==0 else 0,
                            highlightbackground=T["accent"])
            cell.pack(side="left", fill="x", expand=True, padx=3, pady=4)

            tk.Label(cell, text=day, font=FONTS.get("small_bold" if i==0 else "small",()),
                     fg=T["accent"] if i==0 else T["fg_secondary"],
                     bg=T["bg_card"], pady=6).pack()
            tk.Label(cell, text=fc_icon,
                     font=(FONTS.get("body",("",13))[0], 22),
                     bg=T["bg_card"]).pack()
            tk.Label(cell, text=f"{display_t}{unit_str}",
                     font=FONTS.get("body_bold",()),
                     fg=T["fg_primary"], bg=T["bg_card"]).pack()
            tk.Label(cell, text=f"{display_low}{unit_str}",
                     font=FONTS.get("small",()),
                     fg=T["fg_tertiary"], bg=T["bg_card"], pady=(0,6)).pack()

        # ── Hourly forecast ───────────────────────────────────────────────────
        tk.Label(inner, text="  Today's Hourly",
                 font=FONTS.get("h3",()),
                 fg=T["fg_secondary"], bg=T["bg_base"],
                 anchor="w", pady=12, padx=10).pack(fill="x")

        hourly_canvas_host = tk.Frame(inner, bg=T["bg_base"])
        hourly_canvas_host.pack(fill="x", padx=10, pady=4)

        now_hour = datetime.datetime.now().hour
        hour_frame = tk.Frame(hourly_canvas_host, bg=T["bg_base"])
        hour_frame.pack(fill="x")

        for offset in range(0, 24, 2):
            h  = (now_hour + offset) % 24
            t3 = base_temp + random.randint(-4, 4)
            display_t3 = t3 if self._celsius else int(t3*9/5+32)
            fc3 = random.choice([base_code, "partly", "cloud", "sun"])
            ic3 = self.CONDITION_ICONS.get(fc3, "⛅")

            hcell = tk.Frame(hour_frame, bg=T["bg_card"])
            hcell.pack(side="left", fill="x", expand=True, padx=2, pady=2)
            tk.Label(hcell, text=f"{h:02}:00",
                     font=FONTS.get("micro",()),
                     fg=T["accent"] if h==now_hour else T["fg_tertiary"],
                     bg=T["bg_card"], pady=4).pack()
            tk.Label(hcell, text=ic3,
                     font=(FONTS.get("body",("",13))[0], 16),
                     bg=T["bg_card"]).pack()
            tk.Label(hcell, text=f"{display_t3}°",
                     font=FONTS.get("small",()),
                     fg=T["fg_primary"], bg=T["bg_card"], pady=(0,6)).pack()

        # ── Air quality / extras ──────────────────────────────────────────────
        extra_card = tk.Frame(inner, bg=T["bg_card"])
        extra_card.pack(fill="x", padx=10, pady=10)
        eci = tk.Frame(extra_card, bg=T["bg_card"])
        eci.pack(fill="x", padx=16, pady=12)

        tk.Label(eci, text="Additional Info",
                 font=FONTS.get("h3",()),
                 fg=T["fg_primary"], bg=T["bg_card"],
                 anchor="w").pack(fill="x", pady=(0,8))

        aqi = random.randint(20, 120)
        aqi_label = ("Good" if aqi < 50 else "Moderate" if aqi < 100 else "Unhealthy")
        aqi_color = (T["success"] if aqi < 50 else T["warning"] if aqi < 100 else T["danger"])

        extra_stats = [
            ("🌅 Sunrise",     "06:24 AM"),
            ("🌇 Sunset",      "19:48 PM"),
            ("🌊 Dew Point",   f"{base_temp - random.randint(5,12)}{unit_str}"),
            ("👁  Visibility", f"{random.randint(5,20)} km"),
            ("🌬  Gust Speed", f"{data['wind'] + random.randint(5,15)} km/h"),
            ("🏭 Air Quality", f"AQI {aqi} — {aqi_label}"),
        ]
        g = tk.Frame(eci, bg=T["bg_card"])
        g.pack(fill="x")
        for i, (lbl, val) in enumerate(extra_stats):
            col_i, row_i = i % 2, i // 2
            cell = tk.Frame(g, bg=T["bg_card"])
            cell.grid(row=row_i, column=col_i, padx=12, pady=4, sticky="w")
            tk.Label(cell, text=lbl, font=FONTS.get("small",()),
                     fg=T["fg_tertiary"], bg=T["bg_card"]).pack(anchor="w")
            color = aqi_color if "Air" in lbl else T["fg_primary"]
            tk.Label(cell, text=val, font=FONTS.get("body_bold",()),
                     fg=color, bg=T["bg_card"]).pack(anchor="w")
        for i in range(2): g.columnconfigure(i, weight=1)

        self._set_status(
            f"{self._city}  ·  {data['condition']}  ·  "
            f"Updated: {datetime.datetime.now().strftime('%H:%M')}")

    def _switch_city(self, city: str) -> None:
        self._city = city
        self._draw_all()

    def _set_unit(self, celsius: bool) -> None:
        self._celsius = celsius
        self._draw_all()

    def _search_city(self, query: str) -> None:
        q = query.strip().lower()
        match = next(
            (city for city in self.CITIES if q in city.lower()), None)
        if match:
            self._city = match
            self._draw_all()
            notify(self.wm.root, "Weather", f"Showing: {match}", kind="success")
        else:
            notify(self.wm.root, "Weather",
                   f"City not found: {query}. Try London, Tokyo, Paris…", kind="warning")


# ═══════════════════════════════════════════════════════════════════════════════
#  §31  MUSIC PLAYER
# ═══════════════════════════════════════════════════════════════════════════════

class MusicPlayerWin(BaseWin):
    """
    Full-featured simulated music player.
      • Playlist management (add / remove / reorder)
      • Album art canvas with animated visualiser bars
      • Progress bar with click-to-seek
      • Shuffle / repeat / volume / mute controls
      • Queue view and Now Playing info
      • Lyrics panel (simulated)
      • Mini-player toggle
      • Keyboard shortcuts: space=play/pause, n=next, p=prev
    """

    _SEED_TRACKS: List[Dict] = [
        {"id":1,"title":"Chill Wave",       "artist":"Artist A","album":"Chillscapes",  "duration":210,"genre":"Ambient",  "year":2023,"color":"#6c63ff"},
        {"id":2,"title":"Night Drive",       "artist":"Artist B","album":"Midnight Vol.1","duration":183,"genre":"Synthwave","year":2022,"color":"#3b82f6"},
        {"id":3,"title":"Sunset Groove",     "artist":"Artist C","album":"Golden Hour",  "duration":245,"genre":"Jazz",     "year":2023,"color":"#f59e0b"},
        {"id":4,"title":"Pixel Dreams",      "artist":"Artist D","album":"Retro Futures","duration":198,"genre":"Electronic","year":2021,"color":"#22c55e"},
        {"id":5,"title":"Deep Blue",         "artist":"Artist A","album":"Ocean EP",     "duration":262,"genre":"Ambient",  "year":2022,"color":"#0ea5e9"},
        {"id":6,"title":"Urban Jungle",      "artist":"Artist E","album":"City Sounds",  "duration":177,"genre":"Hip-Hop", "year":2023,"color":"#ef4444"},
        {"id":7,"title":"Mountain Echo",     "artist":"Artist F","album":"Wilderness",   "duration":230,"genre":"Folk",    "year":2021,"color":"#14b8a6"},
        {"id":8,"title":"Electric Rain",     "artist":"Artist B","album":"Midnight Vol.2","duration":215,"genre":"Synthwave","year":2023,"color":"#a855f7"},
        {"id":9,"title":"Golden Memory",     "artist":"Artist C","album":"Golden Hour",  "duration":194,"genre":"Jazz",    "year":2023,"color":"#f97316"},
        {"id":10,"title":"Neon City Lights", "artist":"Artist D","album":"Retro Futures","duration":221,"genre":"Electronic","year":2022,"color":"#ec4899"},
        {"id":11,"title":"Quiet Storm",      "artist":"Artist F","album":"Wilderness",   "duration":250,"genre":"Folk",    "year":2022,"color":"#10b981"},
        {"id":12,"title":"Binary Sunset",    "artist":"Artist A","album":"Chillscapes",  "duration":238,"genre":"Ambient", "year":2021,"color":"#8b5cf6"},
    ]

    def __init__(self, wm: WM):
        self._tracks      = [dict(t) for t in self._SEED_TRACKS]
        self._current_idx = 0
        self._playing     = False
        self._shuffle     = False
        self._repeat      = "none"    # none | one | all
        self._volume      = 80
        self._muted       = False
        self._progress    = 0.0       # 0.0 – 1.0
        self._elapsed     = 0         # seconds
        self._queue:      deque = deque(maxlen=50)
        self._liked:      Set[int] = set()
        self._vis_bars:   List[float] = [random.random() for _ in range(20)]
        self._mini_mode   = False
        super().__init__(wm, "Music", 860, 600, "🎵")

    def _build(self) -> None:
        self._show_menubar()
        self._add_menu("File", [
            ("Add Track",    self._add_track_dialog),
            ("---",          None),
            ("Close",        self.close),
        ])
        self._add_menu("Playback", [
            ("Play / Pause",  self._toggle_play,  "Space"),
            ("Next",          self._next_track,   "N"),
            ("Previous",      self._prev_track,   "P"),
            ("---",           None),
            ("Shuffle",       self._toggle_shuffle),
            ("Repeat",        self._cycle_repeat),
        ])
        self._add_menu("View", [
            ("Mini Player",   self._toggle_mini),
            ("Lyrics",        self._show_lyrics_panel),
        ])
        self._show_statusbar()
        self.client.config(bg=T["bg_base"])

        # Keyboard shortcuts
        self.frame.bind("<space>",   lambda e: self._toggle_play())
        self.frame.bind("<n>",       lambda e: self._next_track())
        self.frame.bind("<p>",       lambda e: self._prev_track())
        self.frame.bind("<m>",       lambda e: self._toggle_mute())
        self.frame.focus_set()

        self._draw_player()
        self._tick()

    def _draw_player(self) -> None:
        for w in self.client.winfo_children():
            w.destroy()

        track = self._tracks[self._current_idx]
        album_color = track["color"]

        # ── Left pane: album art + controls ───────────────────────────────────
        left = tk.Frame(self.client, bg=T["bg_base"], width=300)
        left.pack(side="left", fill="y")
        left.pack_propagate(False)

        # Album art canvas
        self._art_canvas = tk.Canvas(left, width=280, height=280,
                                      bg=T["bg_base"], highlightthickness=0)
        self._art_canvas.pack(padx=10, pady=18)
        self._draw_album_art(album_color, track["title"])

        # Track info
        tk.Label(left,
                 text=track["title"],
                 font=FONTS.get("h2",()),
                 fg=T["fg_primary"], bg=T["bg_base"],
                 wraplength=260, justify="center").pack(padx=10)
        tk.Label(left,
                 text=f"{track['artist']}  ·  {track['album']}",
                 font=FONTS.get("body",()),
                 fg=T["fg_secondary"], bg=T["bg_base"],
                 wraplength=260, justify="center").pack(pady=2)
        tk.Label(left,
                 text=f"{track['genre']}  ·  {track['year']}",
                 font=FONTS.get("small",()),
                 fg=T["fg_tertiary"], bg=T["bg_base"]).pack()

        # Like button
        like_btn = tk.Label(
            left,
            text="❤" if track["id"] in self._liked else "♡",
            font=FONTS.get("h2",()),
            fg=T["danger"] if track["id"] in self._liked else T["fg_tertiary"],
            bg=T["bg_base"],
            cursor="hand2",
        )
        like_btn.pack(pady=4)
        like_btn.bind("<Button-1>", lambda e: self._toggle_like(track["id"]))

        # Progress bar
        prog_frame = tk.Frame(left, bg=T["bg_base"])
        prog_frame.pack(fill="x", padx=20, pady=8)

        elapsed_lbl = tk.Label(prog_frame,
                                text=self._fmt_time(self._elapsed),
                                font=FONTS.get("small",()),
                                fg=T["fg_tertiary"], bg=T["bg_base"])
        elapsed_lbl.pack(side="left")
        self._elapsed_lbl = elapsed_lbl

        total_lbl = tk.Label(prog_frame,
                              text=self._fmt_time(track["duration"]),
                              font=FONTS.get("small",()),
                              fg=T["fg_tertiary"], bg=T["bg_base"])
        total_lbl.pack(side="right")

        self._prog_host = tk.Frame(left, bg=T["bg_input"], height=5,
                                    cursor="hand2")
        self._prog_host.pack(fill="x", padx=20)
        self._prog_fill = tk.Frame(self._prog_host, bg=album_color, height=5)
        self._prog_fill.place(relx=0, rely=0,
                               relwidth=self._progress, relheight=1)
        self._prog_host.bind("<Button-1>", self._seek)

        # Playback controls
        ctrl_frame = tk.Frame(left, bg=T["bg_base"])
        ctrl_frame.pack(pady=14)

        shuffle_fg = T["accent"] if self._shuffle else T["fg_tertiary"]
        repeat_icons = {"none":"🔁","one":"🔂","all":"🔁"}
        repeat_fg = T["accent"] if self._repeat != "none" else T["fg_tertiary"]

        for sym, tip, cmd, fg_c in [
            ("⏮", "Previous", self._prev_track,    T["fg_secondary"]),
            ("⏪", "Rewind",   lambda: None,         T["fg_tertiary"]),
            ("⏸" if self._playing else "▶", "Play/Pause", self._toggle_play, T["fg_primary"]),
            ("⏩", "Forward",  lambda: None,          T["fg_tertiary"]),
            ("⏭", "Next",     self._next_track,      T["fg_secondary"]),
        ]:
            btn = tk.Label(ctrl_frame, text=sym,
                           font=(FONTS.get("body",("",13))[0], 22),
                           fg=fg_c, bg=T["bg_base"],
                           cursor="hand2", padx=8)
            btn.pack(side="left")
            btn.bind("<Button-1>", lambda e, c=cmd: c())
            _attach_tooltip(btn, tip)

        # Shuffle / repeat / volume row
        extra_row = tk.Frame(left, bg=T["bg_base"])
        extra_row.pack(fill="x", padx=16, pady=4)

        tk.Label(extra_row, text="🔀", font=FONTS.get("body",()),
                 fg=shuffle_fg, bg=T["bg_base"],
                 cursor="hand2").pack(side="left", padx=4)
        tk.Label(extra_row, text=repeat_icons[self._repeat],
                 font=FONTS.get("body",()),
                 fg=repeat_fg, bg=T["bg_base"],
                 cursor="hand2").pack(side="left", padx=4)
        extra_row.winfo_children()[0].bind("<Button-1>", lambda e: self._toggle_shuffle())
        extra_row.winfo_children()[1].bind("<Button-1>", lambda e: self._cycle_repeat())

        # Volume slider
        vol_frame = tk.Frame(extra_row, bg=T["bg_base"])
        vol_frame.pack(side="right")
        vol_icon = "🔇" if self._muted else ("🔈" if self._volume < 40 else "🔊")
        vol_lbl = tk.Label(vol_frame, text=vol_icon,
                           font=FONTS.get("small",()),
                           fg=T["fg_secondary"], bg=T["bg_base"],
                           cursor="hand2")
        vol_lbl.pack(side="left")
        vol_lbl.bind("<Button-1>", lambda e: self._toggle_mute())
        self._vol_var = tk.IntVar(value=0 if self._muted else self._volume)
        vol_sl = tk.Scale(vol_frame, from_=0, to=100, orient="horizontal",
                          variable=self._vol_var, length=100,
                          bg=T["bg_base"], fg=T["fg_primary"],
                          troughcolor=T["bg_input"], sliderrelief="flat",
                          highlightthickness=0, bd=0, showvalue=False,
                          command=lambda v: setattr(self, "_volume", int(v)))
        vol_sl.pack(side="left")

        # ── Right pane: playlist ──────────────────────────────────────────────
        fl_separator(self.client, orient="v").pack(side="left", fill="y")
        right = tk.Frame(self.client, bg=T["bg_surface"])
        right.pack(side="left", fill="both", expand=True)

        # Playlist header
        pl_hdr = tk.Frame(right, bg=T["bg_elevated"])
        pl_hdr.pack(fill="x")
        tk.Label(pl_hdr, text="Playlist",
                 font=FONTS.get("h3",()),
                 fg=T["fg_primary"], bg=T["bg_elevated"],
                 padx=14, pady=10).pack(side="left")
        tk.Label(pl_hdr, text=f"{len(self._tracks)} tracks",
                 font=FONTS.get("small",()),
                 fg=T["fg_tertiary"], bg=T["bg_elevated"]).pack(side="right", padx=14)
        fl_separator(right).pack(fill="x")

        # Track list
        pl_scroll = ScrollableFrame(right, bg_key="bg_surface")
        pl_scroll.pack(fill="both", expand=True)
        pl_inner  = pl_scroll.inner

        for i, t in enumerate(self._tracks):
            self._add_playlist_row(pl_inner, i, t)

        # Now playing status
        self._set_status(
            f"{'▶ Playing' if self._playing else '⏸ Paused'}  ·  "
            f"{track['title']} — {track['artist']}  ·  "
            f"Shuffle: {'On' if self._shuffle else 'Off'}  ·  "
            f"Repeat: {self._repeat.title()}")

    def _add_playlist_row(self, parent: tk.Frame, idx: int, track: Dict) -> None:
        active = idx == self._current_idx
        bg     = T["bg_selection"] if active else (T["bg_card"] if idx%2 else T["bg_surface"])

        row = tk.Frame(parent, bg=bg, cursor="hand2")
        row.pack(fill="x")

        # Track number / playing indicator
        num_text = "▶" if active and self._playing else str(idx+1)
        num_fg   = T["accent"] if active else T["fg_tertiary"]
        tk.Label(row, text=num_text, font=FONTS.get("small",()),
                 fg=num_fg, bg=bg, width=4, anchor="center").pack(side="left", pady=8)

        # Color dot
        dot = tk.Canvas(row, width=8, height=8, bg=bg, highlightthickness=0)
        dot.pack(side="left", padx=4)
        dot.create_oval(0,0,8,8, fill=track["color"], outline="")

        # Info
        info = tk.Frame(row, bg=bg)
        info.pack(side="left", fill="x", expand=True, pady=6)
        tk.Label(info, text=track["title"],
                 font=FONTS.get("body_bold" if active else "body",()),
                 fg=T["accent"] if active else T["fg_primary"],
                 bg=bg, anchor="w").pack(fill="x")
        tk.Label(info, text=f"{track['artist']}  ·  {track['album']}",
                 font=FONTS.get("small",()),
                 fg=T["fg_secondary"], bg=bg, anchor="w").pack(fill="x")

        # Like indicator
        if track["id"] in self._liked:
            tk.Label(row, text="❤", font=FONTS.get("small",()),
                     fg=T["danger"], bg=bg, padx=4).pack(side="right")

        # Duration
        tk.Label(row, text=self._fmt_time(track["duration"]),
                 font=FONTS.get("small",()),
                 fg=T["fg_tertiary"], bg=bg, padx=10).pack(side="right")

        fl_separator(parent).pack(fill="x")

        def _dbl(e, i=idx): self._play_track(i)
        row.bind("<Double-Button-1>", _dbl)
        row.bind("<Enter>", lambda e, r=row: r.config(bg=T["bg_hover"]))
        row.bind("<Leave>",
            lambda e, r=row, bg=bg: r.config(bg=T["bg_selection"] if idx==self._current_idx else bg))

    def _draw_album_art(self, color: str, title: str) -> None:
        cv = self._art_canvas
        cv.delete("all")
        w, h = 280, 280

        # Background gradient
        for i in range(20):
            t2 = i / 19
            c  = lerp_color(color, T["bg_base"], t2 * 0.6)
            cv.create_rectangle(0, i*14, w, (i+1)*14+1, fill=c, outline="")

        # Vinyl record effect
        cx, cy, r = 140, 140, 110
        cv.create_oval(cx-r, cy-r, cx+r, cy+r, fill="#111", outline=color, width=2)
        for ring_r in range(100, 30, -15):
            cv.create_oval(cx-ring_r, cy-ring_r, cx+ring_r, cy+ring_r,
                           fill="", outline="#222", width=1)
        # Center label
        cv.create_oval(cx-35, cy-35, cx+35, cy+35, fill=color, outline="")
        cv.create_oval(cx-5, cy-5, cx+5, cy+5, fill="#111", outline="")

        # Music note
        cv.create_text(cx, cy-60, text="♪",
                       font=(FONTS.get("body",("",13))[0], 28),
                       fill="white")

        # Visualiser bars (animated)
        bar_w  = 8
        bar_gap = 3
        total_w = len(self._vis_bars) * (bar_w + bar_gap)
        start_x = (w - total_w) // 2
        for i, amp in enumerate(self._vis_bars):
            bh = max(4, int(amp * 60))
            x1 = start_x + i * (bar_w + bar_gap)
            y1 = h - 20 - bh
            bar_color = lerp_color(color, "#ffffff", amp * 0.5)
            cv.create_rectangle(x1, y1, x1+bar_w, h-20,
                                 fill=bar_color, outline="")

    # ─── Playback controls ────────────────────────────────────────────────────
    def _toggle_play(self) -> None:
        self._playing = not self._playing
        self._draw_player()

    def _play_track(self, idx: int) -> None:
        self._current_idx = idx
        self._elapsed     = 0
        self._progress    = 0.0
        self._playing     = True
        self._draw_player()

    def _next_track(self) -> None:
        if self._shuffle:
            self._current_idx = random.randint(0, len(self._tracks)-1)
        elif self._repeat == "one":
            pass
        else:
            self._current_idx = (self._current_idx + 1) % len(self._tracks)
        self._elapsed  = 0
        self._progress = 0.0
        self._draw_player()

    def _prev_track(self) -> None:
        if self._elapsed > 3:
            self._elapsed  = 0
            self._progress = 0.0
        else:
            self._current_idx = (self._current_idx - 1) % len(self._tracks)
            self._elapsed  = 0
            self._progress = 0.0
        self._draw_player()

    def _toggle_shuffle(self) -> None:
        self._shuffle = not self._shuffle
        self._draw_player()

    def _cycle_repeat(self) -> None:
        modes = ["none","one","all"]
        self._repeat = modes[(modes.index(self._repeat)+1) % 3]
        self._draw_player()

    def _toggle_mute(self) -> None:
        self._muted = not self._muted
        self._draw_player()

    def _toggle_like(self, track_id: int) -> None:
        if track_id in self._liked:
            self._liked.discard(track_id)
        else:
            self._liked.add(track_id)
        self._draw_player()

    def _seek(self, e: tk.Event) -> None:
        w = self._prog_host.winfo_width()
        if w > 0:
            self._progress = max(0.0, min(1.0, e.x / w))
            track = self._tracks[self._current_idx]
            self._elapsed = int(self._progress * track["duration"])
            self._prog_fill.place(relwidth=self._progress)
            if hasattr(self, "_elapsed_lbl"):
                self._elapsed_lbl.config(text=self._fmt_time(self._elapsed))

    def _add_track_dialog(self) -> None:
        d = tk.Toplevel(self.frame)
        d.title("Add Track"); d.config(bg=T["bg_surface"])
        d.geometry("400x300"); d.grab_set()
        tk.Label(d, text="Add Track", font=FONTS.get("h2",()),
                 fg=T["fg_primary"], bg=T["bg_surface"],
                 pady=14, padx=20).pack(anchor="w")
        fl_separator(d).pack(fill="x")
        fields = {}
        for label, default in [("Title","New Track"),("Artist","Unknown"),
                                ("Album","Unknown Album"),("Duration (sec)","180")]:
            row = tk.Frame(d, bg=T["bg_surface"]); row.pack(fill="x", padx=16, pady=5)
            tk.Label(row, text=label, font=FONTS.get("body_bold",()),
                     fg=T["fg_secondary"], bg=T["bg_surface"],
                     width=14, anchor="w").pack(side="left")
            e = fl_entry(row); e.pack(side="left", fill="x", expand=True)
            e.insert(0, default)
            fields[label] = e
        fields["Title"].focus_set()
        def _ok():
            try: dur = int(fields["Duration (sec)"].get())
            except: dur = 180
            new_t = {
                "id":       max(t["id"] for t in self._tracks) + 1,
                "title":    fields["Title"].get().strip() or "New Track",
                "artist":   fields["Artist"].get().strip() or "Unknown",
                "album":    fields["Album"].get().strip() or "Unknown Album",
                "duration": dur,
                "genre":    "Other",
                "year":     datetime.date.today().year,
                "color":    random.choice(list(ACCENT_PRESETS.values())),
            }
            self._tracks.append(new_t)
            d.destroy()
            self._draw_player()
            notify(self.wm.root, "Music", f"Added: {new_t['title']}", kind="success")
        fl_button(d, "Add Track", _ok, style="primary").pack(pady=12)

    def _toggle_mini(self) -> None:
        self._mini_mode = not self._mini_mode
        if self._mini_mode:
            self.frame.place(width=320, height=100)
        else:
            self.frame.place(width=860, height=600)
        self._draw_player()

    def _show_lyrics_panel(self) -> None:
        track = self._tracks[self._current_idx]
        d = tk.Toplevel(self.frame)
        d.title(f"Lyrics — {track['title']}")
        d.config(bg=T["bg_surface"]); d.geometry("440x360")
        tk.Label(d, text=f"♪  {track['title']}",
                 font=FONTS.get("h2",()),
                 fg=T["fg_primary"], bg=T["bg_surface"],
                 pady=12, padx=20).pack(anchor="w")
        tk.Label(d, text=f"{track['artist']}  ·  {track['album']}",
                 font=FONTS.get("body",()),
                 fg=T["fg_secondary"], bg=T["bg_surface"],
                 padx=20).pack(anchor="w")
        fl_separator(d).pack(fill="x", pady=8)
        txt = fl_text(d, font_key="body")
        txt.pack(fill="both", expand=True, padx=16, pady=8)
        lyrics = (
            f"[Simulated lyrics for \"{track['title']}\"]\n\n"
            f"Verse 1:\nLost in the rhythm of the night\n"
            f"Every beat a guiding light\nFloating through the melody\n"
            f"Finding peace in harmony\n\nChorus:\nOh, {track['title']}\n"
            f"Take me far away\nIn the music I'll stay\n"
            f"Through the night and the day\n\nVerse 2:\n"
            f"Notes cascade like morning rain\nEvery measure breaks the chain\n"
            f"In this world of sound and tone\nNever truly feeling alone\n"
        )
        txt.insert("1.0", lyrics)
        txt.config(state="disabled")

    # ─── Tick / animation ─────────────────────────────────────────────────────
    def _tick(self) -> None:
        if self._closed:
            return
        if self._playing:
            track = self._tracks[self._current_idx]
            dur   = track["duration"]
            self._elapsed = min(dur, self._elapsed + 1)
            self._progress = self._elapsed / dur if dur > 0 else 0

            if hasattr(self, "_prog_fill") and self._prog_fill.winfo_exists():
                self._prog_fill.place(relwidth=self._progress)
            if hasattr(self, "_elapsed_lbl") and self._elapsed_lbl.winfo_exists():
                self._elapsed_lbl.config(text=self._fmt_time(self._elapsed))

            if self._elapsed >= dur:
                self._next_track()
                return

        # Animate visualiser bars
        if hasattr(self, "_art_canvas") and self._art_canvas.winfo_exists():
            for i in range(len(self._vis_bars)):
                if self._playing:
                    self._vis_bars[i] = max(0.05, min(1.0,
                        self._vis_bars[i] + random.gauss(0, 0.15)))
                else:
                    self._vis_bars[i] = max(0.02, self._vis_bars[i] * 0.9)
            track = self._tracks[self._current_idx]
            self._draw_album_art(track["color"], track["title"])

        self.frame.after(1000, self._tick)

    @staticmethod
    def _fmt_time(seconds: int) -> str:
        return f"{seconds//60}:{seconds%60:02}"


# ═══════════════════════════════════════════════════════════════════════════════
#  §32  NEWS READER
# ═══════════════════════════════════════════════════════════════════════════════

class NewsWin(BaseWin):
    """
    Simulated news reader.
      • Category tabs: Top Stories, Tech, Science, World, Business, Health, Sports
      • Article list with thumbnail placeholder, headline, summary, source, time
      • Full article reader pane with formatted text
      • Bookmark / save articles
      • Share (copy link to clipboard)
      • Search across articles
      • Reading time estimate
      • Font size adjustment
    """

