    # Temperature special handling
    @staticmethod
    def _convert_temp(value: float, from_unit: str, to_unit: str) -> float:
        # Normalise to Celsius first
        if "°C" in from_unit or "Celsius" in from_unit: c = value
        elif "°F" in from_unit or "Fahrenheit" in from_unit: c = (value - 32) * 5/9
        elif "K" in from_unit and "Rankine" not in from_unit: c = value - 273.15
        else: c = (value - 491.67) * 5/9    # Rankine
        # Convert from Celsius to target
        if "°C" in to_unit or "Celsius" in to_unit: return c
        elif "°F" in to_unit or "Fahrenheit" in to_unit: return c * 9/5 + 32
        elif "K" in to_unit and "Rankine" not in to_unit: return c + 273.15
        else: return (c + 273.15) * 9/5     # Rankine

