    def _switch_cat(self, cat: str) -> None:
        self._category = cat
        for c, btn in self._cat_btns.items():
            active = c == cat
            btn.config(
                bg=T["bg_active"] if active else T["bg_sidebar"],
                fg=T["fg_primary"] if active else T["fg_secondary"],
                font=FONTS.get("small_bold" if active else "body",()),
            )
        # Rebuild menus
        units = list(self.UNITS[cat].keys())
        self._from_unit_var.set(units[0])
        self._to_unit_var.set(units[min(1,len(units)-1)])
        self._rebuild_menus(units)
        self._convert()

    def _rebuild_menus(self, units: List[str]) -> None:
        # Rebuild OptionMenu options
        for menu_widget, var in [(self._from_menu, self._from_unit_var),
                                  (self._to_menu,   self._to_unit_var)]:
            menu_widget["menu"].delete(0,"end")
            for unit in units:
                menu_widget["menu"].add_command(
                    label=unit,
                    command=lambda u=unit, v=var: v.set(u)
                )

    def _convert(self) -> None:
        try:
            value = float(self._from_var.get() or "0")
        except ValueError:
            self._to_var.set("Invalid")
            return

        from_unit = self._from_unit_var.get()
        to_unit   = self._to_unit_var.get()
        cat       = self._category

        try:
            if cat == "Temperature":
                result = self._convert_temp(value, from_unit, to_unit)
            else:
                units  = self.UNITS[cat]
                fu     = units.get(from_unit, 1.0)
                tu     = units.get(to_unit,   1.0)
                result = value * fu / tu

            # Format result
            if abs(result) >= 1e9 or (abs(result) < 0.001 and result != 0):
                result_str = f"{result:.6e}"
            elif result == int(result) and abs(result) < 1e12:
                result_str = f"{int(result):,}"
            else:
                result_str = f"{result:,.8g}"

            self._to_var.set(result_str)
            self._formula_var.set(
                f"{value:g} {from_unit.split('(')[0].strip()} = "
                f"{result_str} {to_unit.split('(')[0].strip()}"
            )
            self._set_status(
                f"{value:g} {from_unit.split('(')[0].strip()} → "
                f"{result_str} {to_unit.split('(')[0].strip()}")
        except Exception as ex:
            self._to_var.set("Error")
            self._formula_var.set(str(ex))

    def _swap(self) -> None:
        from_u = self._from_unit_var.get()
        to_u   = self._to_unit_var.get()
        old_to = self._to_var.get()
        self._from_unit_var.set(to_u)
        self._to_unit_var.set(from_u)
        self._from_var.set(old_to)
        self._convert()

    def _copy_result(self) -> None:
        result = self._to_var.get()
        if result and result not in ("Error","Invalid"):
            self.wm.clip.copy(result, "unit_converter")
            entry = self._formula_var.get()
            if entry and entry not in self._history:
                self._history.insert(0, entry)
                self._history = self._history[:10]
                self._rebuild_history()
            notify(self.wm.root,"Copied",result,kind="success")

    def _rebuild_history(self) -> None:
        for w in self._hist_frame.winfo_children():
            w.destroy()
        for item in self._history[:5]:
            row = tk.Frame(self._hist_frame, bg=T["bg_surface"]); row.pack(fill="x")
            tk.Label(row, text=item, font=FONTS.get("small",()),
                     fg=T["fg_tertiary"], bg=T["bg_surface"],
                     anchor="w", pady=2).pack(side="left")
            if item in self._favourites:
                tk.Label(row, text="⭐", font=FONTS.get("micro",()),
                         bg=T["bg_surface"]).pack(side="right")

    def _save_favourite(self) -> None:
        entry = self._formula_var.get()
        if entry and entry not in self._favourites:
            self._favourites.append(entry)
            self._rebuild_history()
            notify(self.wm.root,"Saved","Conversion favourited",kind="success")


