# ═══════════════════════════════════════════════════════════════════════════════
#  §52  JSON VIEWER / EDITOR  (new bonus app)
# ═══════════════════════════════════════════════════════════════════════════════

class JsonViewerWin(BaseWin):
    """
    JSON viewer and editor.
      • Tree view (collapsible nodes) + raw editor side-by-side
      • Syntax highlighting in raw editor
      • Validate / format / minify
      • JSONPath query (simulated)
      • Schema-like summary stats
      • Copy node value to clipboard
      • Export formatted JSON to VFS
      • Load from VFS file
      • Search within keys and values
      • Convert between JSON / Python dict display
    """

    def __init__(self, wm: WM, file_path: Optional[str] = None):
        self._file_path  = file_path
        self._json_data  = None
        self._raw_text   = ""
        self._expanded:  Set[str] = set()
        self._search_q   = ""
        super().__init__(wm, "JSON Viewer", 880, 580, "📦")

    def _build(self) -> None:
        self._show_menubar()
        self._add_menu("File", [
            ("Open…",          self._open_dialog),
            ("Load from Clipboard", self._load_clipboard),
            ("---",            None),
            ("Save Formatted", self._save_formatted),
            ("Save Minified",  self._save_minified),
            ("Close",          self.close),
        ])
        self._add_menu("Edit", [
            ("Format / Prettify",  self._format_json, "Ctrl+Shift+F"),
            ("Minify",             self._minify_json),
            ("Sort Keys",          self._sort_keys),
            ("---",                None),
            ("Validate",           self._validate_json),
        ])
        self._add_menu("Tools", [
            ("JSONPath Query",     self._jsonpath_dialog),
            ("Schema Summary",     self._schema_summary),
            ("Convert to Python",  self._to_python),
        ])
        self._show_statusbar()
        self.client.config(bg=T["bg_surface"])

        # Toolbar
        self._show_toolbar()
        tb = self._toolbar_frame; tb.config(bg=T["bg_elevated"])
        for label, tip, cmd in [
            ("{}","Format",   self._format_json),
            ("{}‣","Minify",  self._minify_json),
            ("✓","Validate",  self._validate_json),
            ("↕","Sort Keys", self._sort_keys),
        ]:
            b = tk.Label(tb, text=label, font=FONTS.get("body_bold",()),
                          fg=T["fg_secondary"], bg=T["bg_elevated"],
                          padx=10, pady=6, cursor="hand2")
            b.pack(side="left")
            b.bind("<Button-1>", lambda e, c=cmd: c())
            b.bind("<Enter>", lambda e, b2=b: b2.config(fg=T["fg_primary"],bg=T["bg_hover"]))
            b.bind("<Leave>", lambda e, b2=b: b2.config(fg=T["fg_secondary"],bg=T["bg_elevated"]))
            _attach_tooltip(b, tip)

        fl_separator(tb, orient="v").pack(side="left", fill="y", pady=4, padx=4)

        # Search
        self._search_bar = FlSearchBar(tb, placeholder="Search keys/values…",
                                        on_change=self._do_search,
                                        bg_key="bg_input", width=20)
        self._search_bar.pack(side="right", padx=8, pady=4)

        fl_separator(self.client).pack(fill="x")

        # Split layout
        layout = tk.Frame(self.client, bg=T["bg_surface"])
        layout.pack(fill="both", expand=True)

        # Tree pane (left)
        self._tree_frame = tk.Frame(layout, bg=T["bg_surface"])
        self._tree_frame.pack(side="left", fill="both", expand=True)

        tree_hdr = tk.Frame(self._tree_frame, bg=T["bg_elevated"])
        tree_hdr.pack(fill="x")
        tk.Label(tree_hdr, text="Tree View",
                 font=FONTS.get("small_bold",()),
                 fg=T["fg_secondary"], bg=T["bg_elevated"],
                 padx=10, pady=6).pack(side="left")
        fl_button(tree_hdr, "Expand All", self._expand_all,
                  style="ghost", pady=3).pack(side="right", padx=4)
        fl_button(tree_hdr, "Collapse All", self._collapse_all,
                  style="ghost", pady=3).pack(side="right", padx=4)

        self._tree_scroll = ScrollableFrame(self._tree_frame, bg_key="bg_surface")
        self._tree_scroll.pack(fill="both", expand=True)
        self._tree_inner = self._tree_scroll.inner

        fl_separator(layout, orient="v").pack(side="left", fill="y")

        # Raw editor pane (right)
        self._raw_frame = tk.Frame(layout, bg=T["bg_input"])
        self._raw_frame.pack(side="left", fill="both", expand=True)

        raw_hdr = tk.Frame(self._raw_frame, bg=T["bg_elevated"])
        raw_hdr.pack(fill="x")
        tk.Label(raw_hdr, text="Raw JSON",
                 font=FONTS.get("small_bold",()),
                 fg=T["fg_secondary"], bg=T["bg_elevated"],
                 padx=10, pady=6).pack(side="left")
        fl_button(raw_hdr, "Apply", self._apply_raw,
                  style="primary", pady=3).pack(side="right", padx=8, pady=4)

        self._raw_txt = fl_text(self._raw_frame, font_key="mono_sm")
        self._raw_txt.pack(fill="both", expand=True)
        self._raw_txt.bind("<Control-Return>", lambda e: self._apply_raw())

        # Syntax tags for raw JSON
        self._raw_txt.tag_config("string",  foreground=T["success"])
        self._raw_txt.tag_config("number",  foreground=T["warning"])
        self._raw_txt.tag_config("bool",    foreground=T["accent_light"])
        self._raw_txt.tag_config("null",    foreground=T["fg_tertiary"])
        self._raw_txt.tag_config("key",     foreground=T["info"])

        # Load demo or file
        if self._file_path:
            content = self.wm.vfs.read(self._file_path) or "{}"
            self._load_json_text(content)
        else:
            demo = json.dumps({
                "pyos": {
                    "version": VERSION,
                    "codename": CODENAME,
                    "build": BUILD,
                    "features": ["multi-tab editor","terminal","file manager","22 apps"],
                    "settings": {
                        "theme": "dark",
                        "accent": "#6c63ff",
                        "wallpaper": "gradient_purple",
                    },
                    "stats": {
                        "total_apps": len(APP_REGISTRY),
                        "is_open_source": True,
                        "price": None,
                    },
                }
            }, indent=2)
            self._load_json_text(demo)

    def _load_json_text(self, text: str) -> None:
        self._raw_text = text
        self._raw_txt.delete("1.0","end")
        self._raw_txt.insert("1.0", text)
        self._apply_raw_syntax()
        try:
            self._json_data = json.loads(text)
            self._rebuild_tree()
            self._update_status()
        except json.JSONDecodeError as ex:
            self._json_data = None
            notify(self.wm.root,"JSON Error",str(ex),kind="danger")
            self._set_status(f"Invalid JSON: {ex}")

    def _apply_raw_syntax(self) -> None:
        txt = self._raw_txt
        content = txt.get("1.0","end")
        for tag in ("string","number","bool","null","key"):
            txt.tag_remove(tag,"1.0","end")
        patterns = [
            ("key",    r'"[^"]+"\s*:'),
            ("string", r':\s*"[^"]*"'),
            ("number", r':\s*-?\d+\.?\d*'),
            ("bool",   r'\b(true|false)\b'),
            ("null",   r'\bnull\b'),
        ]
        for tag, pat in patterns:
            for m in re.finditer(pat, content):
                s = f"1.0+{m.start()}c"; e = f"1.0+{m.end()}c"
                txt.tag_add(tag, s, e)

    def _rebuild_tree(self) -> None:
        for w in self._tree_inner.winfo_children(): w.destroy()
        if self._json_data is None: return
        self._render_node(self._tree_inner, self._json_data, "$", 0)

    def _render_node(self, parent: tk.Frame, data: Any,
                      path: str, depth: int) -> None:
        indent = depth * 18
        bg = T["bg_surface"]

        if isinstance(data, dict):
            is_expanded = path in self._expanded
            toggle_text = "▾" if is_expanded else "▸"
            count = len(data)
            row = tk.Frame(parent, bg=bg); row.pack(fill="x")
            if indent: tk.Frame(row, width=indent, bg=bg).pack(side="left")
            toggle = tk.Label(row, text=toggle_text,
                               font=FONTS.get("small",()),
                               fg=T["accent"], bg=bg, cursor="hand2", width=2)
            toggle.pack(side="left")
            key_lbl = tk.Label(row,
                                text=f"{path.split('.')[-1]} " if path!="$" else "root ",
                                font=FONTS.get("small_bold",()),
                                fg=T["info"], bg=bg)
            key_lbl.pack(side="left")
            tk.Label(row, text=f"{{...}} {count} keys",
                     font=FONTS.get("small",()),
                     fg=T["fg_tertiary"], bg=bg).pack(side="left")

            children_frame = tk.Frame(parent, bg=bg)
            if is_expanded:
                children_frame.pack(fill="x")
                q = self._search_q.lower()
                for key, val in data.items():
                    child_path = f"{path}.{key}"
                    if not q or q in key.lower() or q in str(val).lower():
                        self._render_node(children_frame, val, child_path, depth+1)

            def _toggle(e, p=path, cf=children_frame):
                if p in self._expanded:
                    self._expanded.discard(p)
                else:
                    self._expanded.add(p)
                self._rebuild_tree()
            toggle.bind("<Button-1>", _toggle)
            row.bind("<Button-1>", _toggle)

        elif isinstance(data, list):
            is_expanded = path in self._expanded
            row = tk.Frame(parent, bg=bg); row.pack(fill="x")
            if indent: tk.Frame(row, width=indent, bg=bg).pack(side="left")
            toggle = tk.Label(row, text="▾" if is_expanded else "▸",
                               font=FONTS.get("small",()),
                               fg=T["accent"], bg=bg, cursor="hand2", width=2)
            toggle.pack(side="left")
            tk.Label(row,
                     text=f"{path.split('.')[-1]} " if path!="$" else "root ",
                     font=FONTS.get("small_bold",()),
                     fg=T["info"], bg=bg).pack(side="left")
            tk.Label(row, text=f"[...] {len(data)} items",
                     font=FONTS.get("small",()),
                     fg=T["fg_tertiary"], bg=bg).pack(side="left")

            if is_expanded:
                child_f = tk.Frame(parent, bg=bg); child_f.pack(fill="x")
                for i, item in enumerate(data[:50]):
                    self._render_node(child_f, item, f"{path}[{i}]", depth+1)
                if len(data) > 50:
                    tk.Label(child_f, text=f"  … and {len(data)-50} more",
                             font=FONTS.get("small",()),
                             fg=T["fg_tertiary"], bg=bg,
                             padx=indent+20).pack(anchor="w")

            def _toggle2(e, p=path):
                if p in self._expanded: self._expanded.discard(p)
                else: self._expanded.add(p)
                self._rebuild_tree()
            toggle.bind("<Button-1>", _toggle2)
            row.bind("<Button-1>", _toggle2)

        else:
            # Leaf value
            row = tk.Frame(parent, bg=bg); row.pack(fill="x")
            if indent: tk.Frame(row, width=indent, bg=bg).pack(side="left")
            tk.Frame(row, width=14, bg=bg).pack(side="left")

            key_name = path.split(".")[-1].strip("[]")
            tk.Label(row, text=f"{key_name}: ",
                     font=FONTS.get("small_bold",()),
                     fg=T["info"], bg=bg).pack(side="left")

            # Value colour and display
            if data is None:
                val_str = "null"; val_col = T["fg_tertiary"]
            elif isinstance(data, bool):
                val_str = str(data).lower(); val_col = T["accent_light"]
            elif isinstance(data, (int, float)):
                val_str = str(data); val_col = T["warning"]
            else:
                val_str = f'"{data}"'; val_col = T["success"]

            val_lbl = tk.Label(row, text=val_str[:60]+(("…") if len(str(val_str))>60 else ""),
                                font=FONTS.get("mono_xs",()),
                                fg=val_col, bg=bg, cursor="hand2")
            val_lbl.pack(side="left")

            # Copy on click
            val_lbl.bind("<Button-1>",
                lambda e, v=str(data): (self.wm.clip.copy(v,"json"),
                                         notify(self.wm.root,"Copied","",kind="info")))

    def _expand_all(self) -> None:
        def _walk(data: Any, path: str):
            if isinstance(data, (dict,list)):
                self._expanded.add(path)
                items = data.items() if isinstance(data,dict) else enumerate(data)
                for k, v in items:
                    _walk(v, f"{path}.{k}" if isinstance(data,dict) else f"{path}[{k}]")
        if self._json_data: _walk(self._json_data, "$")
        self._rebuild_tree()

    def _collapse_all(self) -> None:
        self._expanded.clear()
        self._rebuild_tree()

    def _apply_raw(self) -> None:
        text = self._raw_txt.get("1.0","end-1c")
        self._load_json_text(text)

    def _format_json(self) -> None:
        try:
            raw  = self._raw_txt.get("1.0","end-1c")
            data = json.loads(raw)
            pretty = json.dumps(data, indent=2, ensure_ascii=False)
            self._load_json_text(pretty)
            notify(self.wm.root,"JSON","Formatted",kind="success")
        except json.JSONDecodeError as ex:
            notify(self.wm.root,"JSON Error",str(ex),kind="danger")

    def _minify_json(self) -> None:
        try:
            raw  = self._raw_txt.get("1.0","end-1c")
            data = json.loads(raw)
            mini = json.dumps(data, separators=(",",":"))
            self._load_json_text(mini)
            notify(self.wm.root,"JSON","Minified",kind="success")
        except json.JSONDecodeError as ex:
            notify(self.wm.root,"JSON Error",str(ex),kind="danger")

    def _sort_keys(self) -> None:
        try:
            raw  = self._raw_txt.get("1.0","end-1c")
            data = json.loads(raw)
            sorted_data = json.dumps(data, indent=2, sort_keys=True)
            self._load_json_text(sorted_data)
            notify(self.wm.root,"JSON","Keys sorted",kind="success")
        except json.JSONDecodeError as ex:
            notify(self.wm.root,"JSON Error",str(ex),kind="danger")

    def _validate_json(self) -> None:
        try:
            raw = self._raw_txt.get("1.0","end-1c")
            json.loads(raw)
            notify(self.wm.root,"JSON","Valid JSON ✓",kind="success")
            self._set_status("✅  Valid JSON")
        except json.JSONDecodeError as ex:
            notify(self.wm.root,"JSON Error",str(ex),kind="danger")
            self._set_status(f"❌  {ex}")

    def _do_search(self, query: str) -> None:
        self._search_q = query
        self._rebuild_tree()

    def _jsonpath_dialog(self) -> None:
        d = tk.Toplevel(self.frame); d.title("JSONPath Query")
        d.config(bg=T["bg_surface"]); d.geometry("480x320"); d.grab_set()
        tk.Label(d, text="JSONPath Query",
                 font=FONTS.get("h2",()),
                 fg=T["fg_primary"], bg=T["bg_surface"],
                 pady=12, padx=20).pack(anchor="w")
        fl_separator(d).pack(fill="x")
        row = tk.Frame(d, bg=T["bg_surface"]); row.pack(fill="x",padx=16,pady=10)
        tk.Label(row, text="Path:", font=FONTS.get("body",()),
                 fg=T["fg_primary"], bg=T["bg_surface"], width=8).pack(side="left")
        qe = fl_entry(row, placeholder="$.pyos.version"); qe.pack(side="left",fill="x",expand=True); qe.focus_set()
        result_var = tk.StringVar()
        tk.Label(d, textvariable=result_var, font=FONTS.get("mono_sm",()),
                 fg=T["success"], bg=T["bg_surface"],
                 padx=20, pady=8, wraplength=420, anchor="w").pack(fill="x")
        def _query():
            path_expr = qe.get().strip().lstrip("$.")
            try:
                data = self._json_data
                if not data: return
                for key in path_expr.split("."):
                    if key.endswith("]"):
                        k, idx = key[:-1].split("[")
                        data   = data[k][int(idx)]
                    else:
                        data = data[key]
                result_var.set(f"Result: {json.dumps(data, indent=2)[:200]}")
            except (KeyError,IndexError,TypeError) as ex:
                result_var.set(f"Error: {ex}")
        fl_button(d,"Query",_query,style="primary").pack(padx=16,anchor="w")
        qe.bind("<Return>",lambda e:_query())

    def _schema_summary(self) -> None:
        if not self._json_data:
            notify(self.wm.root,"JSON","No data loaded",kind="warning"); return
        def _summarise(data, depth=0):
            if isinstance(data, dict):
                return f"object ({len(data)} keys)"
            elif isinstance(data, list):
                types = set(type(v).__name__ for v in data)
                return f"array ({len(data)} items, types: {', '.join(types)})"
            else:
                return f"{type(data).__name__}: {str(data)[:30]}"
        d = tk.Toplevel(self.frame); d.title("Schema Summary")
        d.config(bg=T["bg_surface"]); d.geometry("440x320")
        scroll = ScrollableFrame(d, bg_key="bg_surface")
        scroll.pack(fill="both",expand=True,padx=10,pady=10)
        inner = scroll.inner
        if isinstance(self._json_data, dict):
            for key, val in self._json_data.items():
                row = tk.Frame(inner, bg=T["bg_surface"]); row.pack(fill="x",pady=2)
                tk.Label(row, text=key, font=FONTS.get("body_bold",()),
                         fg=T["info"], bg=T["bg_surface"], anchor="w",
                         width=20).pack(side="left")
                tk.Label(row, text=_summarise(val), font=FONTS.get("small",()),
                         fg=T["fg_secondary"], bg=T["bg_surface"], anchor="w").pack(side="left")

    def _to_python(self) -> None:
        if not self._json_data: return
        py_str = repr(self._json_data)
        path   = VFS.DOCS + "/json_as_python.py"
        self.wm.vfs.write(path, f"data = {py_str}\n")
        notify(self.wm.root,"Exported",f"Python dict saved to {path}",kind="success")

    def _open_dialog(self) -> None:
        d = tk.Toplevel(self.frame); d.title("Open JSON File")
        d.config(bg=T["bg_surface"]); d.geometry("380x110"); d.grab_set()
        e = fl_entry(d, placeholder=VFS.DOCS+"/*.json"); e.pack(fill="x",padx=16,pady=20); e.focus_set()
        def _ok():
            p = e.get().strip()
            if p and self.wm.vfs.is_file(p):
                content = self.wm.vfs.read(p) or "{}"
                self._file_path = p
                self._load_json_text(content)
            d.destroy()
        fl_button(d,"Open",_ok,style="primary").pack(pady=4)
        e.bind("<Return>",lambda ev:_ok())

    def _load_clipboard(self) -> None:
        text = self.wm.clip.paste()
        if text:
            self._load_json_text(text)
        else:
            notify(self.wm.root,"Clipboard","Nothing to paste",kind="warning")

    def _save_formatted(self) -> None:
        if not self._json_data:
            self._validate_json(); return
        path = self._file_path or VFS.DOCS+"/formatted.json"
        self.wm.vfs.write(path, json.dumps(self._json_data,indent=2,ensure_ascii=False))
        notify(self.wm.root,"Saved",VFS.basename(path),kind="success")

    def _save_minified(self) -> None:
        if not self._json_data:
            self._validate_json(); return
        path = VFS.DOCS + "/minified.json"
        self.wm.vfs.write(path, json.dumps(self._json_data,separators=(",",":")))
        notify(self.wm.root,"Saved",VFS.basename(path),kind="success")

    def _update_status(self) -> None:
        if not self._json_data:
            self._set_status("Invalid JSON"); return
        raw = self._raw_txt.get("1.0","end-1c")
        def _count(d):
            if isinstance(d,dict): return sum(_count(v) for v in d.values()) + len(d)
            elif isinstance(d,list): return sum(_count(v) for v in d)
            return 1
        total = _count(self._json_data)
        top_type = type(self._json_data).__name__
        self._set_status(
            f"Valid JSON  │  Type: {top_type}  │  "
            f"{total} total values  │  "
            f"{len(raw):,} chars  │  "
            f"{self._file_path or 'Unsaved'}")


# Register
APP_REGISTRY.append({
    "id":"json_viewer","name":"JSON Viewer","icon":"📦",
    "desc":"Collapsible tree viewer and editor for JSON with formatting, search and JSONPath",
    "category":"Development","pinned":False,"launcher":"open_json_viewer",
    "version":"1.0","size":"0.7 MB",
})
def _wm_open_json_viewer(self: WM): JsonViewerWin(self)
WM.open_json_viewer = _wm_open_json_viewer  # type: ignore


# ═══════════════════════════════════════════════════════════════════════════════
#  §53  CLOCK & WORLD TIME  (new bonus app)
# ═══════════════════════════════════════════════════════════════════════════════

class ClockWin(BaseWin):
    """
    World clock, stopwatch, countdown timer and alarms app.
    Tabs:
      Clock      — large analog + digital display, world clocks grid
      Stopwatch  — millisecond precision, lap times
      Timer      — countdown with presets, custom input, alarm flash
      Alarms     — add/edit/delete alarms, enabled toggle
    """

    CITIES_TZ: List[Tuple[str, str, int]] = [
        ("New York",   "🇺🇸", -5),  ("London",  "🇬🇧",  0),
        ("Paris",      "🇫🇷",  1),  ("Berlin",  "🇩🇪",  1),
        ("Dubai",      "🇦🇪",  4),  ("Mumbai",  "🇮🇳",  5),
        ("Singapore",  "🇸🇬",  8),  ("Tokyo",   "🇯🇵",  9),
        ("Sydney",     "🇦🇺", 10),  ("Auckland","🇳🇿", 12),
        ("São Paulo",  "🇧🇷", -3),  ("Toronto", "🇨🇦", -5),
        ("Moscow",     "🇷🇺",  3),  ("Cairo",   "🇪🇬",  2),
    ]

    def __init__(self, wm: WM):
        self._sw_running   = False
        self._sw_elapsed   = 0.0
        self._sw_start:    Optional[float] = None
        self._sw_laps:     List[float] = []
        self._timer_secs   = 0
        self._timer_remain = 0
        self._timer_running= False
        self._timer_presets= [60, 300, 600, 900, 1800, 3600]
        self._alarms:      List[Dict] = [
            {"id":1,"label":"Wake Up","time":"07:00","enabled":True,"days":"Every day"},
            {"id":2,"label":"Meeting","time":"09:30","enabled":False,"days":"Mon-Fri"},
        ]
        self._next_alarm_id = 10
        self._alarm_after:  Optional[str] = None
        super().__init__(wm, "Clock", 720, 560, "⏰")

    def _build(self) -> None:
        self._show_menubar()
        self._add_menu("Clock", [
            ("Add World Clock", self._add_world_clock),
            ("12h / 24h Toggle",lambda: None),
        ])
        self._show_statusbar()
        self.client.config(bg=T["bg_base"])

        tabs = FlTabView(self.client, bg_key="bg_base")
        tabs.pack(fill="both", expand=True)
        clock_f  = tabs.add_tab("🕐  Clock")
        sw_f     = tabs.add_tab("⏱  Stopwatch")
        timer_f  = tabs.add_tab("⏳  Timer")
        alarm_f  = tabs.add_tab("🔔  Alarms")

        self._build_clock_tab(clock_f)
        self._build_stopwatch_tab(sw_f)
        self._build_timer_tab(timer_f)
        self._build_alarms_tab(alarm_f)
        self._tick_clock()

    # ─── Clock tab ────────────────────────────────────────────────────────────
    def _build_clock_tab(self, f: tk.Frame) -> None:
        top = tk.Frame(f, bg=T["bg_base"]); top.pack(fill="x")

        # Analog clock canvas
        self._analog_cv = tk.Canvas(top, width=200, height=200,
                                     bg=T["bg_base"], highlightthickness=0)
        self._analog_cv.pack(side="left", padx=20, pady=20)

        # Digital display
        dig = tk.Frame(top, bg=T["bg_base"]); dig.pack(side="left", fill="y", pady=20)
        self._clock_time_var = tk.StringVar()
        self._clock_date_var = tk.StringVar()
        fam = FONTS.get("display_2xl",("",36))[0]
        tk.Label(dig, textvariable=self._clock_time_var,
                 font=(fam,48,"bold"),
                 fg=T["fg_primary"], bg=T["bg_base"]).pack(anchor="w")
        tk.Label(dig, textvariable=self._clock_date_var,
                 font=FONTS.get("h3",()),
                 fg=T["fg_secondary"], bg=T["bg_base"]).pack(anchor="w", pady=4)
        tk.Label(dig, text="PyOS City  ·  Local Time",
                 font=FONTS.get("small",()),
                 fg=T["fg_tertiary"], bg=T["bg_base"]).pack(anchor="w")

        fl_separator(f).pack(fill="x", padx=20, pady=4)

        # World clocks grid
        tk.Label(f, text="World Clocks",
                 font=FONTS.get("h3",()),
                 fg=T["fg_secondary"], bg=T["bg_base"],
                 padx=20, pady=8, anchor="w").pack(fill="x")

        scroll = ScrollableFrame(f, bg_key="bg_base")
        scroll.pack(fill="both", expand=True)
        inner = scroll.inner

        now_utc = datetime.datetime.utcnow()
        for i, (city, flag, offset) in enumerate(self.CITIES_TZ):
            city_time = now_utc + datetime.timedelta(hours=offset)
            col_i, row_i = i % 4, i // 4
            card = tk.Frame(inner, bg=T["bg_card"])
            card.grid(row=row_i, column=col_i, padx=6, pady=4, sticky="ew")

            tk.Label(card, text=flag, font=FONTS.get("emoji_sm",()),
                     bg=T["bg_card"]).pack(side="left", padx=10, pady=8)
            info = tk.Frame(card, bg=T["bg_card"]); info.pack(side="left", fill="x", expand=True, pady=6)
            tk.Label(info, text=city, font=FONTS.get("small_bold",()),
                     fg=T["fg_primary"], bg=T["bg_card"], anchor="w").pack(fill="x")
            tk.Label(info, text=city_time.strftime("%H:%M"),
                     font=FONTS.get("h2",()),
                     fg=T["accent"], bg=T["bg_card"], anchor="w").pack(fill="x")
            tk.Label(info, text=city_time.strftime("%a %b %d"),
                     font=FONTS.get("micro",()),
                     fg=T["fg_tertiary"], bg=T["bg_card"], anchor="w").pack(fill="x")

            offset_lbl = f"UTC{offset:+d}"
            tk.Label(card, text=offset_lbl, font=FONTS.get("micro",()),
                     fg=T["fg_tertiary"], bg=T["bg_card"], padx=8).pack(side="right")

        for col in range(4): inner.columnconfigure(col, weight=1)

    def _draw_analog(self) -> None:
        cv = self._analog_cv; cv.delete("all")
        cx, cy, r = 100, 100, 85
        now = datetime.datetime.now()
        # Face
        cv.create_oval(cx-r,cy-r,cx+r,cy+r, fill=T["bg_card"], outline=T["border"], width=2)
        # Hour ticks
        for i in range(12):
            angle  = math.radians(i*30 - 90)
            r1, r2 = r-6, r-14
            x1 = cx + r1*math.cos(angle); y1 = cy + r1*math.sin(angle)
            x2 = cx + r2*math.cos(angle); y2 = cy + r2*math.sin(angle)
            cv.create_line(x1,y1,x2,y2, fill=T["fg_tertiary"], width=2 if i%3==0 else 1)
        # Hour numbers
        for i,n in enumerate(["12","3","6","9"]):
            angle = math.radians(i*90 - 90)
            tx = cx + (r-22)*math.cos(angle)
            ty = cy + (r-22)*math.sin(angle)
            cv.create_text(tx,ty, text=n, font=FONTS.get("small",()),
                           fill=T["fg_secondary"])
        # Hands
        h_angle = math.radians((now.hour%12 + now.minute/60)*30 - 90)
        m_angle = math.radians(now.minute*6 - 90)
        s_angle = math.radians(now.second*6 - 90)
        for angle, length, width, color in [
            (h_angle, r*0.55, 4, T["fg_primary"]),
            (m_angle, r*0.75, 3, T["fg_primary"]),
            (s_angle, r*0.85, 1, T["danger"]),
        ]:
            ex = cx + length*math.cos(angle)
            ey = cy + length*math.sin(angle)
            cv.create_line(cx,cy,ex,ey, fill=color, width=width, capstyle="round")
        cv.create_oval(cx-5,cy-5,cx+5,cy+5, fill=T["danger"], outline="")

    def _tick_clock(self) -> None:
        if self._closed: return
        now = datetime.datetime.now()
        use24 = self.wm.settings.get("24h_clock", True)
        fmt   = "%H:%M:%S" if use24 else "%I:%M:%S %p"
        if hasattr(self,"_clock_time_var"):
            self._clock_time_var.set(now.strftime(fmt))
            self._clock_date_var.set(now.strftime("%A, %B %d, %Y"))
        if hasattr(self,"_analog_cv") and self._analog_cv.winfo_exists():
            self._draw_analog()
        if hasattr(self,"_sw_time_var") and self._sw_running:
            self._sw_elapsed = time.time() - self._sw_start
            self._sw_time_var.set(self._fmt_sw(self._sw_elapsed))
        if hasattr(self,"_timer_time_var") and self._timer_running:
            elapsed = int(time.time() - self._timer_start_ts)
            self._timer_remain = max(0, self._timer_secs - elapsed)
            self._timer_time_var.set(self._fmt_timer(self._timer_remain))
            if hasattr(self,"_timer_ring_cv"):
                self._draw_timer_ring()
            if self._timer_remain == 0:
                self._timer_running = False
                self._timer_alarm()
        self._check_alarms(now)
        self.frame.after(1000, self._tick_clock)

    # ─── Stopwatch tab ────────────────────────────────────────────────────────
    def _build_stopwatch_tab(self, f: tk.Frame) -> None:
        self._sw_time_var = tk.StringVar(value="00:00.000")
        fam = FONTS.get("display_2xl",("",36))[0]
        tk.Label(f, textvariable=self._sw_time_var,
                 font=(fam,64,"bold"),
                 fg=T["fg_primary"], bg=T["bg_base"],
                 pady=30).pack()

        ctrl = tk.Frame(f, bg=T["bg_base"]); ctrl.pack(pady=12)
        self._sw_btn = tk.Label(ctrl, text="▶  Start",
                                 font=FONTS.get("h2",()),
                                 fg=T["fg_on_accent"],
                                 bg=T["success"],
                                 cursor="hand2", padx=24, pady=10)
        self._sw_btn.pack(side="left", padx=8)
        self._sw_btn.bind("<Button-1>", lambda e: self._sw_toggle())

        for sym, tip, cmd in [
            ("⏮","Reset", self._sw_reset),
            ("🏁","Lap",  self._sw_lap),
        ]:
            b = tk.Label(ctrl, text=sym, font=FONTS.get("h2",()),
                          fg=T["fg_secondary"], bg=T["bg_base"],
                          cursor="hand2", padx=12)
            b.pack(side="left")
            b.bind("<Button-1>", lambda e, c=cmd: c())
            _attach_tooltip(b, tip)

        fl_separator(f).pack(fill="x", padx=20, pady=8)
        tk.Label(f, text="Lap Times",
                 font=FONTS.get("h4",()),
                 fg=T["fg_secondary"], bg=T["bg_base"],
                 anchor="w", padx=24).pack(fill="x")
        self._lap_scroll = ScrollableFrame(f, bg_key="bg_base")
        self._lap_scroll.pack(fill="both", expand=True, padx=20)
        self._lap_inner = self._lap_scroll.inner

    def _sw_toggle(self) -> None:
        if self._sw_running:
            self._sw_running = False
            self._sw_elapsed = time.time() - self._sw_start
            self._sw_btn.config(text="▶  Resume", bg=T["success"])
        else:
            self._sw_start   = time.time() - self._sw_elapsed
            self._sw_running = True
            self._sw_btn.config(text="⏸  Pause", bg=T["warning"])

    def _sw_reset(self) -> None:
        self._sw_running = False
        self._sw_elapsed = 0.0
        self._sw_start   = None
        self._sw_laps    = []
        self._sw_time_var.set("00:00.000")
        self._sw_btn.config(text="▶  Start", bg=T["success"])
        for w in self._lap_inner.winfo_children(): w.destroy()

    def _sw_lap(self) -> None:
        if self._sw_running:
            self._sw_laps.append(self._sw_elapsed)
            n  = len(self._sw_laps)
            t  = self._sw_elapsed
            prev = self._sw_laps[-2] if len(self._sw_laps)>1 else 0
            split = t - prev
            best  = self._sw_laps.index(min(self._sw_laps)) + 1 if self._sw_laps else 0
            row   = tk.Frame(self._lap_inner, bg=T["bg_base"]); row.pack(fill="x", pady=2)
            color = T["success"] if n == best else T["fg_secondary"]
            tk.Label(row, text=f"Lap {n}",
                     font=FONTS.get("small_bold",()),
                     fg=color, bg=T["bg_base"], width=8, anchor="w").pack(side="left")
            tk.Label(row, text=self._fmt_sw(split),
                     font=FONTS.get("mono",()),
                     fg=color, bg=T["bg_base"], width=12).pack(side="left")
            tk.Label(row, text=self._fmt_sw(t),
                     font=FONTS.get("small",()),
                     fg=T["fg_tertiary"], bg=T["bg_base"]).pack(side="right")

    @staticmethod
    def _fmt_sw(secs: float) -> str:
        m  = int(secs) // 60
        s  = int(secs) % 60
        ms = int((secs - int(secs)) * 1000)
        return f"{m:02}:{s:02}.{ms:03}"

    # ─── Timer tab ────────────────────────────────────────────────────────────
    def _build_timer_tab(self, f: tk.Frame) -> None:
        # Presets
        preset_row = tk.Frame(f, bg=T["bg_base"]); preset_row.pack(fill="x", padx=20, pady=12)
        tk.Label(preset_row, text="Presets:",
                 font=FONTS.get("body",()),
                 fg=T["fg_secondary"], bg=T["bg_base"]).pack(side="left", padx=(0,8))
        for secs in self._timer_presets:
            m = secs // 60
            label = f"{m}m" if m < 60 else f"{m//60}h"
            b = tk.Label(preset_row, text=label,
                          font=FONTS.get("body",()),
                          fg=T["fg_primary"], bg=T["bg_card"],
                          cursor="hand2", padx=10, pady=4)
            b.pack(side="left", padx=3)
            b.bind("<Button-1>", lambda e, s=secs: self._timer_set(s))
            b.bind("<Enter>", lambda e, b2=b: b2.config(bg=T["bg_hover"]))
            b.bind("<Leave>", lambda e, b2=b: b2.config(bg=T["bg_card"]))

        # Custom input
        custom_row = tk.Frame(f, bg=T["bg_base"]); custom_row.pack(fill="x", padx=20, pady=4)
        for lbl, key in [("H:","h"),("M:","m"),("S:","s")]:
            tk.Label(custom_row, text=lbl, font=FONTS.get("body",()),
                     fg=T["fg_tertiary"], bg=T["bg_base"]).pack(side="left")
            e = tk.Entry(custom_row, width=4,
                          font=FONTS.get("h3",()),
                          bg=T["bg_input"], fg=T["fg_primary"],
                          insertbackground=T["accent"],
                          relief="flat", bd=0, justify="center")
            e.pack(side="left", padx=(0,6))
            e.insert(0, "00")
            setattr(self, f"_timer_{key}_entry", e)

        fl_button(custom_row, "Set",
                  lambda: self._timer_set_custom(), style="secondary").pack(side="left", padx=8)

        # Ring canvas + time display
        ring_frame = tk.Frame(f, bg=T["bg_base"]); ring_frame.pack(pady=12)
        self._timer_ring_cv = tk.Canvas(ring_frame, width=200, height=200,
                                         bg=T["bg_base"], highlightthickness=0)
        self._timer_ring_cv.pack(side="left", padx=20)
        self._timer_time_var = tk.StringVar(value="00:00")
        fam = FONTS.get("display_2xl",("",36))[0]
        tk.Label(ring_frame, textvariable=self._timer_time_var,
                 font=(fam, 48, "bold"),
                 fg=T["fg_primary"], bg=T["bg_base"]).pack(side="left", pady=40)
        self._draw_timer_ring()

        ctrl = tk.Frame(f, bg=T["bg_base"]); ctrl.pack(pady=8)
        self._timer_btn = tk.Label(ctrl, text="▶  Start",
                                    font=FONTS.get("h2",()),
                                    fg=T["fg_on_accent"], bg=T["accent"],
                                    cursor="hand2", padx=22, pady=10)
        self._timer_btn.pack(side="left", padx=8)
        self._timer_btn.bind("<Button-1>", lambda e: self._timer_toggle())
        reset_lbl = tk.Label(ctrl, text="↺",
                              font=FONTS.get("h2",()),
                              fg=T["fg_secondary"], bg=T["bg_base"],
                              cursor="hand2", padx=12)
        reset_lbl.pack(side="left")
        reset_lbl.bind("<Button-1>", lambda e: self._timer_reset())

    def _timer_set(self, secs: int) -> None:
        self._timer_secs   = secs
        self._timer_remain = secs
        self._timer_running = False
        self._timer_time_var.set(self._fmt_timer(secs))
        self._timer_btn.config(text="▶  Start", bg=T["accent"])
        self._draw_timer_ring()

    def _timer_set_custom(self) -> None:
        try:
            h = int(self._timer_h_entry.get() or 0)
            m = int(self._timer_m_entry.get() or 0)
            s = int(self._timer_s_entry.get() or 0)
            total = h*3600 + m*60 + s
            if total > 0: self._timer_set(total)
        except ValueError: pass

    def _timer_toggle(self) -> None:
        if self._timer_remain <= 0: return
        if self._timer_running:
            self._timer_running = False
            self._timer_btn.config(text="▶  Resume", bg=T["accent"])
        else:
            self._timer_start_ts = time.time() - (self._timer_secs - self._timer_remain)
            self._timer_running  = True
            self._timer_btn.config(text="⏸  Pause", bg=T["warning"])

    def _timer_reset(self) -> None:
        self._timer_running = False
        self._timer_remain  = self._timer_secs
        self._timer_time_var.set(self._fmt_timer(self._timer_remain))
        self._timer_btn.config(text="▶  Start", bg=T["accent"])
        self._draw_timer_ring()

    def _timer_alarm(self) -> None:
        # Visual flash
        notify(self.wm.root, "⏰ Timer Finished!", "Your timer has ended!", kind="success")
        self._timer_btn.config(text="▶  Restart", bg=T["success"])
        self._timer_remain = self._timer_secs
        self._draw_timer_ring()

    def _draw_timer_ring(self) -> None:
        cv = self._timer_ring_cv; cv.delete("all")
        cx, cy, r = 100, 100, 88
        pct = (self._timer_remain / max(1, self._timer_secs))
        color = (T["danger"] if pct < 0.2 else
                 T["warning"] if pct < 0.5 else T["accent"])
        cv.create_oval(cx-r,cy-r,cx+r,cy+r, outline=T["border"], width=10, fill="")
        if pct > 0:
            extent = int(-pct*360)
            cv.create_arc(cx-r,cy-r,cx+r,cy+r,
                           start=90, extent=extent,
                           outline=color, width=10, style="arc")

    @staticmethod
    def _fmt_timer(secs: int) -> str:
        h = secs // 3600; m = (secs%3600)//60; s = secs%60
        return f"{h:02}:{m:02}:{s:02}" if h else f"{m:02}:{s:02}"

    # ─── Alarms tab ───────────────────────────────────────────────────────────
    def _build_alarms_tab(self, f: tk.Frame) -> None:
        hdr = tk.Frame(f, bg=T["bg_base"]); hdr.pack(fill="x", padx=20, pady=12)
        tk.Label(hdr, text="Alarms",
                 font=FONTS.get("h3",()),
                 fg=T["fg_primary"], bg=T["bg_base"]).pack(side="left")
        fl_button(hdr, "＋ New Alarm", self._new_alarm_dialog,
                  style="primary").pack(side="right")

        self._alarm_list = tk.Frame(f, bg=T["bg_base"])
        self._alarm_list.pack(fill="both", expand=True, padx=20)
        self._rebuild_alarm_list()

    def _rebuild_alarm_list(self) -> None:
        for w in self._alarm_list.winfo_children(): w.destroy()
        if not self._alarms:
            tk.Label(self._alarm_list, text="No alarms set.",
                     font=FONTS.get("body",()),
                     fg=T["fg_tertiary"], bg=T["bg_base"], pady=30).pack()
            return
        for alarm in self._alarms:
            row = tk.Frame(self._alarm_list, bg=T["bg_card"])
            row.pack(fill="x", pady=6)
            inner = tk.Frame(row, bg=T["bg_card"])
            inner.pack(fill="x", padx=16, pady=12)

            left = tk.Frame(inner, bg=T["bg_card"]); left.pack(side="left", fill="x", expand=True)
            tk.Label(left, text=alarm["time"],
                     font=(FONTS.get("display_2xl",("",36))[0], 36, "bold"),
                     fg=T["fg_primary"] if alarm["enabled"] else T["fg_tertiary"],
                     bg=T["bg_card"]).pack(anchor="w")
            tk.Label(left, text=f"{alarm['label']}  ·  {alarm['days']}",
                     font=FONTS.get("body",()),
                     fg=T["fg_secondary"], bg=T["bg_card"]).pack(anchor="w")

            right_f = tk.Frame(inner, bg=T["bg_card"]); right_f.pack(side="right")
            ena_var = tk.BooleanVar(value=alarm["enabled"])
            fl_switch(right_f, ena_var,
                      command=lambda a=alarm, v=ena_var: (
                          a.__setitem__("enabled", v.get()),
                          self._rebuild_alarm_list(),
                      ),
                      bg_key="bg_card").pack()

            del_btn = tk.Label(right_f, text="🗑", font=FONTS.get("body",()),
                                fg=T["fg_tertiary"], bg=T["bg_card"],
                                cursor="hand2", pady=4)
            del_btn.pack(pady=4)
            del_btn.bind("<Button-1>",
                lambda e, aid=alarm["id"]: (
                    setattr(self,"_alarms",[a for a in self._alarms if a["id"]!=aid]),
                    self._rebuild_alarm_list()
                ))

    def _new_alarm_dialog(self) -> None:
        d = tk.Toplevel(self.frame); d.title("New Alarm")
        d.config(bg=T["bg_surface"]); d.geometry("360,260".replace(",","x")); d.grab_set()
        d.geometry("360x260")
        tk.Label(d, text="New Alarm", font=FONTS.get("h2",()),
                 fg=T["fg_primary"], bg=T["bg_surface"],
                 pady=12, padx=20).pack(anchor="w")
        fl_separator(d).pack(fill="x")
        fields = {}
        for label, default in [("Time (HH:MM):","07:00"),("Label:","Alarm"),("Days:","Every day")]:
            row = tk.Frame(d, bg=T["bg_surface"]); row.pack(fill="x",padx=16,pady=6)
            tk.Label(row, text=label, font=FONTS.get("body",()),
                     fg=T["fg_secondary"], bg=T["bg_surface"],
                     width=16, anchor="w").pack(side="left")
            e = fl_entry(row); e.pack(side="left",fill="x",expand=True)
            e.insert(0, default); fields[label] = e
        fields["Time (HH:MM):"].focus_set()
        def _save():
            self._alarms.append({
                "id":      self._next_alarm_id,
                "time":    fields["Time (HH:MM):"].get().strip(),
                "label":   fields["Label:"].get().strip() or "Alarm",
                "days":    fields["Days:"].get().strip() or "Every day",
                "enabled": True,
            })
            self._next_alarm_id += 1
            d.destroy(); self._rebuild_alarm_list()
        fl_button(d,"Save",_save,style="primary").pack(pady=10)
        fields["Label:"].bind("<Return>",lambda ev:_save())

    def _check_alarms(self, now: datetime.datetime) -> None:
        now_str = now.strftime("%H:%M")
        if now.second != 0: return
        for alarm in self._alarms:
            if alarm["enabled"] and alarm["time"] == now_str:
                notify(self.wm.root, f"⏰ {alarm['label']}", alarm["time"], kind="success")

    def _add_world_clock(self) -> None:
        notify(self.wm.root,"Clock","All world clocks are displayed in the Clock tab",kind="info")

    def _set_status(self, msg: str = "") -> None:
        now = datetime.datetime.now()
        super()._set_status(
            f"Local: {now.strftime('%H:%M:%S')}  │  "
            f"Alarms: {sum(1 for a in self._alarms if a['enabled'])} active")


