class VirtualDesktopManager:
    """
    Manages virtual desktops (workspaces) for the WM.
    Each workspace stores a set of window references.
    Users can switch between workspaces, drag windows between them.
    """
    MAX_DESKTOPS = 4

    def __init__(self, wm: "WM"):
        self.wm         = wm
        self._desktops: List[Dict[str, Any]] = [
            {"id": i, "name": f"Desktop {i+1}", "windows": []}
            for i in range(self.MAX_DESKTOPS)
        ]
        self._current   = 0
        self._overview_open = False

    @property
    def current(self) -> int:
        return self._current

    def switch(self, idx: int) -> None:
        if idx == self._current or not (0 <= idx < self.MAX_DESKTOPS):
            return
        self._current = idx
        self.wm.bus.emit(EventBus.SETTINGS_SAVED, {"desktop": idx})
        notify(self.wm.root, f"Desktop {idx+1}",
               self._desktops[idx]["name"], kind="info")

    def rename(self, idx: int, name: str) -> None:
        if 0 <= idx < self.MAX_DESKTOPS:
            self._desktops[idx]["name"] = name

    def add_window(self, idx: int, win_id: int) -> None:
        desk = self._desktops[idx]
        if win_id not in desk["windows"]:
            desk["windows"].append(win_id)

    def get_desktop_names(self) -> List[str]:
        return [d["name"] for d in self._desktops]


class TilingManager:
    """
    Automatic tiling layout for open windows on the WM desktop.
    Modes: columns, rows, grid, master-stack
    """

    def __init__(self, wm: "WM"):
        self.wm   = wm
        self.mode = "columns"

    def tile(self, mode: Optional[str] = None) -> None:
        if mode:
            self.mode = mode
        wins = [w for w in self.wm.all_wins() if not getattr(w,"_minimized",False)]
        if not wins:
            return
        d  = self.wm.desktop
        dw = d.winfo_width()  or SCREEN_W
        dh = d.winfo_height() or SCREEN_H
        n  = len(wins)

        if self.mode == "columns":
            col_w = dw // n
            for i, win in enumerate(wins):
                win.frame.place(x=i*col_w, y=0, width=col_w, height=dh)

        elif self.mode == "rows":
            row_h = dh // n
            for i, win in enumerate(wins):
                win.frame.place(x=0, y=i*row_h, width=dw, height=row_h)

        elif self.mode == "grid":
            cols = math.ceil(math.sqrt(n))
            rows = math.ceil(n / cols)
            cw   = dw // cols
            rh   = dh // rows
            for i, win in enumerate(wins):
                col_i = i % cols; row_i = i // cols
                win.frame.place(x=col_i*cw, y=row_i*rh, width=cw, height=rh)

        elif self.mode == "master_stack":
            if n == 1:
                wins[0].frame.place(x=0, y=0, width=dw, height=dh)
            else:
                master_w = dw * 2 // 3
                stack_h  = dh // (n - 1)
                wins[0].frame.place(x=0, y=0, width=master_w, height=dh)
                for i, win in enumerate(wins[1:]):
                    win.frame.place(x=master_w, y=i*stack_h,
                                    width=dw-master_w, height=stack_h)

        for win in wins:
            win._maximized = False
            win.focus()


class SnapZoneOverlay:
    """
    Shows snap zone guides when a window is dragged near screen edges.
    Activates on drag (via WM event), shows translucent rectangles.
    """

    ZONES = [
        ("left_half",    0,    0,    0.5,  1.0),
        ("right_half",   0.5,  0,    0.5,  1.0),
        ("top_half",     0,    0,    1.0,  0.5),
        ("bottom_half",  0,    0.5,  1.0,  0.5),
        ("top_left",     0,    0,    0.5,  0.5),
        ("top_right",    0.5,  0,    0.5,  0.5),
        ("bottom_left",  0,    0.5,  0.5,  0.5),
        ("bottom_right", 0.5,  0.5,  0.5,  0.5),
        ("maximized",    0,    0,    1.0,  1.0),
    ]
    ACTIVATION_PX = 40  # pixels from edge to activate

    def __init__(self, desktop: tk.Canvas):
        self.desktop = desktop
        self._frame: Optional[tk.Frame] = None
        self._active_zone: Optional[str] = None

    def check(self, x: int, y: int) -> Optional[str]:
        """Return the snap zone name if cursor is near an edge."""
        dw = self.desktop.winfo_width()
        dh = self.desktop.winfo_height()
        ap = self.ACTIVATION_PX

        if x <= ap and y <= ap:              return "top_left"
        if x >= dw-ap and y <= ap:           return "top_right"
        if x <= ap and y >= dh-ap:           return "bottom_left"
        if x >= dw-ap and y >= dh-ap:        return "bottom_right"
        if x <= ap:                          return "left_half"
        if x >= dw-ap:                       return "right_half"
        if y <= ap:                          return "top_half"
        if y >= dh-ap:                       return "bottom_half"
        return None

    def show(self, zone: str) -> None:
        if zone == self._active_zone:
            return
        self.hide()
        self._active_zone = zone
        dw = self.desktop.winfo_width()
        dh = self.desktop.winfo_height()
        for name, rx, ry, rw, rh in self.ZONES:
            if name == zone:
                x, y = int(rx*dw), int(ry*dh)
                w, h  = int(rw*dw), int(rh*dh)
                self._frame = tk.Frame(self.desktop,
                                        bg=T["accent_muted"],
                                        highlightthickness=2,
                                        highlightbackground=T["accent"])
                self._frame.place(x=x, y=y, width=w, height=h)
                break

    def hide(self) -> None:
        if self._frame and self._frame.winfo_exists():
            self._frame.destroy()
        self._frame = None
        self._active_zone = None


# ─── Patch WM to add tiling + virtual desktops ────────────────────────────────
def _wm_add_tiling_vdesktops(wm: WM) -> None:
    wm._tiling   = TilingManager(wm)
    wm._vdesktop = VirtualDesktopManager(wm)
    wm._snap_overlay = SnapZoneOverlay(wm.desktop)

    # Add tiling controls to taskbar
    tile_menu = tk.Label(
        wm._taskbar_frame,
        text="⊞",
        font=FONTS.get("body",()),
        fg=T["fg_tertiary"],
        bg=T["bg_taskbar"],
        cursor="hand2",
        padx=8, pady=8,
    )
    tile_menu.pack(side="right", padx=2)
    _attach_tooltip(tile_menu, "Tiling & Workspaces")

    def _show_tile_menu(e: tk.Event) -> None:
        items = [
            ("Tile: Columns",      lambda: wm._tiling.tile("columns")),
            ("Tile: Rows",         lambda: wm._tiling.tile("rows")),
            ("Tile: Grid",         lambda: wm._tiling.tile("grid")),
            ("Tile: Master-Stack", lambda: wm._tiling.tile("master_stack")),
            ("─────────",          None),
        ]
        for i in range(VirtualDesktopManager.MAX_DESKTOPS):
            name = wm._vdesktop.get_desktop_names()[i]
            active = i == wm._vdesktop.current
            items.append((
                ("● " if active else "○ ") + name,
                lambda i=i: wm._vdesktop.switch(i),
            ))
        wm._show_context_menu(e.x_root, e.y_root, items)

    tile_menu.bind("<Button-1>", _show_tile_menu)


