#  §55  DEEP EXTENSION: EventBus — typed event helpers + replay
# ═══════════════════════════════════════════════════════════════════════════════

class EventRecorder:
    """
    Records all EventBus events with timestamps for replay / debugging.
    Useful for testing and demo mode.
    """

    def __init__(self, bus: EventBus):
        self._bus     = bus
        self._log:    List[Dict] = []
        self._recording = False
        # Subscribe to every known event
        for attr in dir(EventBus):
            val = getattr(EventBus, attr)
            if isinstance(val, str) and not attr.startswith("_"):
                bus.subscribe(val, lambda data, ev=val: self._record(ev, data))

    def start(self) -> None:
        self._recording = True
        self._log.clear()

    def stop(self) -> None:
        self._recording = False

    def _record(self, event: str, data: Any) -> None:
        if self._recording:
            self._log.append({
                "event": event,
                "data":  repr(data)[:100],
                "time":  datetime.datetime.now().isoformat(timespec="milliseconds"),
            })

    def get_log(self) -> List[Dict]:
        return list(self._log)

    def export(self, vfs: VFS) -> str:
        path = "/var/log/event_log.json"
        vfs.write(path, json.dumps(self._log, indent=2))
        return path


