class VFSQuotaTracker:
    """
    Tracks VFS disk usage per user/path and enforces soft quotas.
    """
    SOFT_QUOTA_BYTES = 100 * 1024 * 1024   # 100 MB
    HARD_QUOTA_BYTES = 500 * 1024 * 1024   # 500 MB

    def __init__(self, vfs: VFS):
        self._vfs = vfs

    def usage(self) -> int:
        return self._vfs.get_size(VFS.HOME)

    def usage_human(self) -> str:
        return VFS.human_size(self.usage())

    def percent(self) -> float:
        return min(1.0, self.usage() / self.HARD_QUOTA_BYTES)

    def warn_if_needed(self, root: tk.Misc) -> None:
        pct = self.percent()
        if pct > 0.9:
            notify(root, "Storage Warning",
                   f"Disk usage critical: {self.usage_human()} / "
                   f"{VFS.human_size(self.HARD_QUOTA_BYTES)}", kind="danger")
        elif pct > 0.75:
            notify(root, "Storage",
                   f"Disk usage high: {self.usage_human()}", kind="warning")

    def summary(self) -> Dict[str, Any]:
        return {
            "used":   self.usage(),
            "soft":   self.SOFT_QUOTA_BYTES,
            "hard":   self.HARD_QUOTA_BYTES,
            "pct":    self.percent(),
            "human":  self.usage_human(),
            "status": ("critical" if self.percent()>0.9 else
                       "warning"  if self.percent()>0.75 else "ok"),
        }


# ═══════════════════════════════════════════════════════════════════════════════
#  §57  DEEP EXTENSION: ProcessManager — detailed proc info, CPU profiler
# ═══════════════════════════════════════════════════════════════════════════════

class ProcessProfiler:
    """
    Lightweight CPU profiler that samples process CPU usage over time.
    Builds a simple text-based flame graph.
    """

    def __init__(self, procs: ProcessManager):
        self._procs   = procs
        self._samples: List[Dict[str, float]] = []

    def sample(self) -> None:
        snapshot = {p.name: p.cpu for p in self._procs.list_all()}
        self._samples.append(snapshot)
        if len(self._samples) > 60:
            self._samples.pop(0)

    def top_consumers(self, n: int = 5) -> List[Tuple[str, float]]:
        if not self._samples:
            return []
        totals: Dict[str,float] = {}
        for snap in self._samples:
            for name, cpu in snap.items():
                totals[name] = totals.get(name,0) + cpu
        avg = {k: v/len(self._samples) for k,v in totals.items()}
        return sorted(avg.items(), key=lambda x: -x[1])[:n]

    def flame_text(self) -> str:
        """Simple ASCII flame graph of average CPU per process."""
        top = self.top_consumers(10)
        if not top:
            return "No profiling data yet."
        max_cpu = max(v for _,v in top) or 1
        lines   = ["CPU Flame Graph (avg over last 60 samples)", "─"*50]
        for name, cpu in top:
            bar_len = int(cpu / max_cpu * 30)
            bar     = "█" * bar_len + "░" * (30 - bar_len)
            lines.append(f"{name[:20]:<20} {bar} {cpu:.1f}%")
        return "\n".join(lines)

    def export(self, vfs: VFS) -> str:
        path = "/var/log/cpu_profile.txt"
        vfs.write(path, self.flame_text())
        return path


# ═══════════════════════════════════════════════════════════════════════════════
#  §58  DEEP EXTENSION: Theming — per-window accent overrides
# ═══════════════════════════════════════════════════════════════════════════════

class WindowThemeOverride:
    """
    Allows individual windows to have a different accent colour
    without changing the global theme.
    Usage:
        override = WindowThemeOverride(win, accent="#ff6b6b")
        override.apply()
        # ... later ...
        override.restore()
    """

    def __init__(self, win: BaseWin, accent: str):
        self._win    = win
        self._accent = accent
        self._saved  = T.get("accent", "#6c63ff")

    def apply(self) -> None:
        """Temporarily override the global accent for this window's widgets."""
        # Recolour title bar accent strip and focused border
        try:
            for child in self._win._titlebar.winfo_children():
                if hasattr(child, "cget"):
                    try:
                        if child.cget("bg") == T["accent"]:
                            child.config(bg=self._accent)
                    except tk.TclError:
                        pass
        except AttributeError:
            pass
        # Add a subtle tinted border
        self._win.frame.config(
            highlightthickness=2,
            highlightbackground=self._accent,
        )

    def restore(self) -> None:
        try:
            self._win.frame.config(highlightthickness=0)
        except Exception:
            pass


# ═══════════════════════════════════════════════════════════════════════════════
#  §59  DEEP EXTENSION: Accessibility helpers
# ═══════════════════════════════════════════════════════════════════════════════

class AccessibilityManager:
    """
    Manages accessibility features across PyOS:
      • High-contrast mode
      • Large text scaling
      • Reduced motion preference
      • Screen reader announcements (via status bar)
      • Keyboard focus ring enhancement
      • Colour blindness simulation filters
    """

    COLOUR_BLIND_MODES = {
        "none":          "No filter",
        "deuteranopia":  "Green-blind (Deuteranopia)",
        "protanopia":    "Red-blind (Protanopia)",
        "tritanopia":    "Blue-blind (Tritanopia)",
        "achromatopsia": "Full colour-blind (Achromatopsia)",
    }

    def __init__(self, settings: SettingsStore):
        self._settings    = settings
        self.high_contrast= settings.get("a11y_high_contrast", False)
        self.large_text   = settings.get("a11y_large_text",    False)
        self.reduced_motion=settings.get("a11y_reduced_motion",False)
        self.focus_ring   = settings.get("a11y_focus_ring",    True)
        self.cb_mode      = settings.get("a11y_colourblind",   "none")

    def apply_high_contrast(self) -> None:
        """Switch to a high-contrast theme."""
        T["bg_base"]    = "#000000"
        T["bg_surface"] = "#0a0a0a"
        T["fg_primary"] = "#ffffff"
        T["fg_secondary"]="#eeeeee"
        T["accent"]     = "#ffff00"
        T["border"]     = "#ffffff"

    def toggle_high_contrast(self) -> None:
        self.high_contrast = not self.high_contrast
        self._settings.set("a11y_high_contrast", self.high_contrast)
        self._settings.save()
        if self.high_contrast:
            self.apply_high_contrast()

    def save(self) -> None:
        self._settings.set("a11y_large_text",     self.large_text)
        self._settings.set("a11y_reduced_motion", self.reduced_motion)
        self._settings.set("a11y_focus_ring",     self.focus_ring)
        self._settings.set("a11y_colourblind",    self.cb_mode)
        self._settings.save()

    def announce(self, root: tk.Misc, message: str) -> None:
        """Simulate screen reader announcement via a brief status overlay."""
        if not root.winfo_exists():
            return
        lbl = tk.Label(root, text=f"♿ {message}",
                        font=FONTS.get("small",()),
                        fg="#000000", bg="#ffff00",
                        padx=10, pady=4)
        sw = root.winfo_width() or SCREEN_W
        lbl.place(x=0, y=0, width=sw)
        lbl.after(2500, lbl.destroy)


# ═══════════════════════════════════════════════════════════════════════════════
#  §60  FINAL GLUE — register all extensions + APP_REGISTRY patch
# ═══════════════════════════════════════════════════════════════════════════════

def _apply_all_extensions(wm: WM, kernel: Dict) -> None:
    """
    Called from _launch_desktop after WM is created.
    Wires up all deep extensions.
    """
    # Tiling + virtual desktops
    _wm_add_tiling_vdesktops(wm)

    # VFS quota tracker
    wm._quota = VFSQuotaTracker(kernel["vfs"])

    # Process profiler (sample every 5 seconds)
    wm._profiler = ProcessProfiler(kernel["procs"])
    def _sample_loop():
        if not wm.root.winfo_exists(): return
        wm._profiler.sample()
        wm.root.after(5000, _sample_loop)
    wm.root.after(5000, _sample_loop)

    # Event recorder (off by default)
    wm._event_recorder = EventRecorder(kernel["bus"])

    # Accessibility manager
    wm._a11y = AccessibilityManager(kernel["settings"])


# Patch _launch_desktop to call extensions
_orig_launch = _launch_desktop

def _launch_desktop_with_ext(root: tk.Tk, kernel: Dict) -> None:
    _orig_launch(root, kernel)
    # Find the WM instance (stored after creation)
    # WM is accessible through the taskbar frame's master chain
    # We do a best-effort search after a delay
    def _attach():
        children = root.winfo_children()
        for child in children:
            if hasattr(child, "_taskbar_frame"):
                _apply_all_extensions(child, kernel)
                return
    root.after(200, _attach)

_launch_desktop = _launch_desktop_with_ext  # type: ignore


# ─── Final APP_REGISTRY sort and dedup ────────────────────────────────────────
def _finalise_registry() -> None:
    """Remove duplicate IDs, sort alphabetically within categories."""
    seen: Set[str] = set()
    unique = []
    for app in APP_REGISTRY:
        if app["id"] not in seen:
            seen.add(app["id"])
            unique.append(app)
    APP_REGISTRY.clear()
    APP_REGISTRY.extend(
        sorted(unique, key=lambda a: (a["category"], a["name"]))
    )

_finalise_registry()


# ─── Helper functions needed by several classes ───────────────────────────────

def _parse_hex(hex_color: str) -> Tuple[int, int, int]:
    """Parse #RRGGBB → (r, g, b) integers."""
    h = hex_color.lstrip("#")
    if len(h) == 3:
        h = "".join(c*2 for c in h)
    if len(h) < 6:
        return 128, 128, 128
    try:
        return int(h[0:2],16), int(h[2:4],16), int(h[4:6],16)
    except ValueError:
        return 128, 128, 128


