# ═══════════════════════════════════════════════════════════════════════════════
#  §64  SELF-TEST MODULE  — validates all major systems on startup
# ═══════════════════════════════════════════════════════════════════════════════

class PyOSSelfTest:
    """
    Lightweight self-test suite that validates critical PyOS systems
    without requiring a display. Runs automatically before main() if
    invoked with --test flag.
    """

    def __init__(self):
        self._results: List[Tuple[str, bool, str]] = []

    def run_all(self) -> bool:
        """Run all tests. Returns True if all pass."""
        self._test_vfs()
        self._test_event_bus()
        self._test_clipboard()
        self._test_settings()
        self._test_theme()
        self._test_app_registry()
        self._test_formula_engine()
        self._test_unit_converter()
        self._test_colour_parsing()
        self._test_boot_messages()
        return all(ok for _, ok, _ in self._results)

    def _assert(self, name: str, condition: bool, msg: str = "") -> None:
        self._results.append((name, condition, msg))

    def _test_vfs(self) -> None:
        vfs = VFS()
        vfs.mkdir("/tmp/test_dir")
        vfs.write("/tmp/test.txt", "hello world")
        self._assert("VFS mkdir",     vfs.is_dir("/tmp/test_dir"))
        self._assert("VFS write",     vfs.is_file("/tmp/test.txt"))
        self._assert("VFS read",      vfs.read("/tmp/test.txt") == "hello world")
        self._assert("VFS basename",  VFS.basename("/a/b/c.txt") == "c.txt")
        self._assert("VFS dirname",   VFS.dirname("/a/b/c.txt") == "/a/b")
        self._assert("VFS join",      VFS.join("/a", "b") == "/a/b")
        self._assert("VFS human_size",VFS.human_size(1024) == "1.0 KB")
        vfs.delete("/tmp/test.txt")
        self._assert("VFS delete",    not vfs.is_file("/tmp/test.txt"))

    def _test_event_bus(self) -> None:
        bus = EventBus()
        received = []
        bus.subscribe(EventBus.NOTIFICATION, lambda d: received.append(d))
        bus.emit(EventBus.NOTIFICATION, "test")
        self._assert("EventBus subscribe+emit", len(received) == 1)
        self._assert("EventBus data",           received[0] == "test")
        bus.pause()
        bus.emit(EventBus.NOTIFICATION, "paused")
        self._assert("EventBus pause",          len(received) == 1)
        bus.resume()
        self._assert("EventBus resume",         len(received) >= 1)

    def _test_clipboard(self) -> None:
        bus = EventBus()
        clip = ClipboardManager(bus)
        clip.copy("hello", "test")
        self._assert("Clipboard copy",  clip.paste() == "hello")
        clip.copy("world", "test")
        self._assert("Clipboard history", len(clip.get_history()) >= 2)
        clip.pin("hello")
        self._assert("Clipboard pin",   len(clip.get_pinned()) >= 1)

    def _test_settings(self) -> None:
        vfs = VFS()
        s = SettingsStore(vfs)
        s.set("test_key", 42)
        self._assert("Settings set/get", s.get("test_key") == 42)
        s.set("theme", "dark")
        self._assert("Settings theme",   s.get("theme") == "dark")

    def _test_theme(self) -> None:
        set_theme("dark",    "#6c63ff")
        self._assert("Theme dark",    T["bg_base"] != "")
        set_theme("light",   "#6c63ff")
        self._assert("Theme light",   T["bg_base"] != "")
        set_theme("midnight","#6c63ff")
        self._assert("Theme midnight",T["bg_base"] != "")
        set_theme("dark",    "#6c63ff")  # restore
        c = lerp_color("#000000","#ffffff",0.5)
        self._assert("lerp_color",    c.startswith("#"))

    def _test_app_registry(self) -> None:
        self._assert("APP_REGISTRY not empty", len(APP_REGISTRY) > 0)
        for app in APP_REGISTRY:
            ok = all(k in app for k in ("id","name","icon","desc","category","launcher"))
            if not ok:
                self._assert(f"APP_REGISTRY {app.get('id','?')}", False, "missing keys")
                return
        self._assert("APP_REGISTRY all valid", True)
        ids = [a["id"] for a in APP_REGISTRY]
        self._assert("APP_REGISTRY no dupes", len(ids) == len(set(ids)))

    def _test_formula_engine(self) -> None:
        # Test SpreadsheetWin formula evaluation
        sheet: Dict = {"cells": {
            (0,0):{"value":"10","formula":"","fmt":{}},
            (1,0):{"value":"20","formula":"","fmt":{}},
            (2,0):{"value":"30","formula":"","fmt":{}},
        }}
        try:
            result = SpreadsheetWin._eval_formula(
                SpreadsheetWin.__new__(SpreadsheetWin),
                "SUM(A1:A3)", sheet
            )
            self._assert("Formula SUM",     float(result) == 60.0)
        except Exception as ex:
            self._assert("Formula SUM",     False, str(ex))

    def _test_unit_converter(self) -> None:
        # 1 km = 1000 m
        km = UnitConverterWin.UNITS["Length (metres)"]["Kilometre (km)"]
        m  = UnitConverterWin.UNITS["Length (metres)"]["Metre (m)"]
        result = 1.0 * km / m
        self._assert("Unit km→m",    result == 1000.0)
        # Celsius to Fahrenheit
        f = UnitConverterWin._convert_temp(0, "Celsius (°C)", "Fahrenheit (°F)")
        self._assert("Temp 0°C=32°F", f == 32.0)
        f2 = UnitConverterWin._convert_temp(100, "Celsius (°C)", "Fahrenheit (°F)")
        self._assert("Temp 100°C=212°F", f2 == 212.0)

    def _test_colour_parsing(self) -> None:
        r, g, b = _parse_hex("#ff0000")
        self._assert("parse_hex red",   r==255 and g==0 and b==0)
        r2,g2,b2 = _parse_hex("#00ff00")
        self._assert("parse_hex green", r2==0 and g2==255 and b2==0)
        r3,g3,b3 = _parse_hex("abc")   # 3-char shorthand
        self._assert("parse_hex short", r3==0xaa and g3==0xbb and b3==0xcc)

    def _test_boot_messages(self) -> None:
        msgs = BootScreen.BOOT_MESSAGES
        self._assert("Boot messages present",  len(msgs) >= 10)
        self._assert("Boot messages format",
                     all(isinstance(m,tuple) and len(m)==2 for m in msgs))

    def print_results(self) -> None:
        total  = len(self._results)
        passed = sum(1 for _,ok,_ in self._results if ok)
        failed = total - passed
        print(f"\nPyOS Self-Test Results: {passed}/{total} passed")
        print("─" * 40)
        for name, ok, msg in self._results:
            status = "✅" if ok else "❌"
            line   = f"  {status}  {name}"
            if msg: line += f"  ({msg})"
            print(line)
        if failed:
            print(f"\n⚠  {failed} test(s) failed.")
        else:
            print(f"\n✅  All tests passed!")
        print()


def run_tests() -> None:
    """Entry point for --test flag."""
    suite = PyOSSelfTest()
    all_ok = suite.run_all()
    suite.print_results()
    sys.exit(0 if all_ok else 1)


# ─── CLI argument handling ────────────────────────────────────────────────────
if len(sys.argv) > 1 and sys.argv[1] == "--test":
    run_tests()
elif len(sys.argv) > 1 and sys.argv[1] == "--version":
    print(f"PyOS {VERSION} Build {BUILD} ({CODENAME})")
    sys.exit(0)
elif len(sys.argv) > 1 and sys.argv[1] == "--apps":
    for app in sorted(APP_REGISTRY, key=lambda a: a["name"]):
        print(f"  {app['icon']}  {app['name']:<28}  [{app['category']}]")
    print(f"\nTotal: {len(APP_REGISTRY)} apps")
    sys.exit(0)


