# ─── Quick stats function ─────────────────────────────────────────────────────
def pyos_stats() -> None:
    """Print a summary of PyOS statistics to stdout."""
    print(f"\nPyOS {VERSION} \"{CODENAME}\" — Statistics")
    print("═" * 48)
    for key, value in PYOS_MANIFEST.items():
        if isinstance(value, list):
            print(f"  {key:<20}: {len(value)} items")
        elif isinstance(value, dict):
            print(f"  {key:<20}: {len(value)} entries")
        else:
            print(f"  {key:<20}: {value}")
    print()

